-- Aboleth (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Wissenschaften: Geistesverbindung, Massenbeherrschung; Hingabe: falsche Sinneswahrnehmung.'),
  combat_tactics  = COALESCE(combat_tactics, 'Der Aboleth greift mit seinen Tentakeln an und verursacht jeweils 1W6 Schadenspunkte. Wenn ein von einem Tentakel getroffenes Opfer einen Rettungswurf gegen Zauber verfehlt, verwandelt sich die Haut des Opfers in 1W4+1 Runden in eine klare, schleimige Membran. Geschieht dies, muss das Opfer die Membran mit kühlem Wasser feucht halten oder erleidet 1W12 Schadenspunkte pro Runde. Ein auf das Opfer gewirkter Krankheit heilen-Zauber, bevor sich die Membran vollständig gebildet hat, stoppt die Verwandlung. Andernfalls bewirkt schwere Wunden heilen, dass die Membran wieder zu normaler Haut wird.'),
  habitat_society = COALESCE(habitat_society, 'Eine Aboleth-Brut besteht aus einem Elternteil und einem bis drei Nachkommen. Obwohl die Nachkommen genauso groß und stark wie das Elternteil sind, ordnen sie sich dem Elternteil in allen Belangen unter und gehorchen ihm bedingungslos.'),
  ecology         = COALESCE(ecology, 'Der allesfressende Aboleth frisst jede organische Materie, gewöhnlich Algen und Mikroorganismen, aber er bevorzugt auch intelligente Beute, damit er gleichzeitig Nährstoffe und Informationen aufnehmen kann. Aboleth haben keine natürlichen Feinde, da selbst die mächtigsten Meereskreaturen ihnen aus dem Weg gehen. Aboleth-Schleim wird manchmal als Komponente für Tränke des Wasseratmens verwendet.'),
  no_appearing    = COALESCE(no_appearing, '1d4')
WHERE id = '505bceb1-21a8-46f1-a062-2d04c1d7d848' AND is_custom = FALSE;

-- Ankheg (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Der Ankheg ist ein grabendes Monster, das gewöhnlich in Wäldern oder erstklassigem Ackerland zu finden ist. Aufgrund seiner Vorliebe für frisches Fleisch stellt der Ankheg eine Bedrohung für jede Kreatur dar, die das Unglück hat, ihm zu begegnen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Die bevorzugte Angriffsmethode des Ankhegs ist es, 1,5 bis 3 m unter der Erdoberfläche zu liegen, bis seine Antennen die Annäherung eines Opfers wahrnehmen. Er gräbt sich dann unter dem Opfer nach oben und versucht, es mit seinen Mandibeln zu packen, wobei er es zerquetscht und zermahlt und dabei 3W6 Schadenspunkte pro Runde verursacht, während er ätzende Verdauungsenzyme absondert, die zusätzliche 1W4 Schadenspunkte pro Runde verursachen, bis das Opfer aufgelöst ist. Der Ankheg kann alle sechs Stunden einen Strahl ätzender Enzyme auf eine Distanz von 9,1 m spritzen. Da er jedoch sechs Stunden lang keine Nahrung verdauen kann, nachdem er Enzyme gespritzt hat, nutzt er diese Angriffstechnik nur in verzweifelten Situationen. Ein Opfer, das von dem Strahl ätzender Enzyme getroffen wird, erleidet 8W4 Schadenspunkte (halber Schaden, wenn das Opfer einen erfolgreichen Rettungswurf gegen Gift schafft).'),
  habitat_society = COALESCE(habitat_society, 'Der Ankheg nutzt seine Mandibeln, um kontinuierlich gewundene Tunnel von 9,1-12,2 m Tiefe in die reiche Erde von Wäldern oder Ackerland zu graben. Das ausgehöhlte Ende eines Tunnels dient als temporärer Bau zum Schlafen, Fressen oder für den Winterschlaf. Wenn ein Ankheg die Nahrungsversorgung in einem bestimmten Wald oder Feld erschöpft hat, zieht er zu einem anderen weiter.'),
  ecology         = COALESCE(ecology, 'Obwohl ein hungriger Ankheg für einen Bauern tödlich sein kann, kann er für das Ackerland sehr vorteilhaft sein. Sein Tunnelsystem durchzieht den Boden mit Gängen für Luft und Wasser, während die Abfallprodukte des Ankhegs reiche Nährstoffe hinzufügen. Der Ankheg frisst verrottende organische Materie in der Erde, bevorzugt aber frisches Fleisch. Alle bis auf die wildesten Raubtiere meiden Ankhegs. Getrocknete und gehärtete Ankhegpanzer können zu Rüstung mit einer RK von 2 verarbeitet werden, und seine Verdauungsenzyme können als gewöhnliche Säure verwendet werden.'),
  no_appearing    = COALESCE(no_appearing, '1-6')
WHERE id = '9cbaef5e-b8c7-4bec-a09b-2b487589b40d' AND is_custom = FALSE;

-- Baatezu, Greater, Pit Fiend (matched by override)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Die schrecklichsten Baatezu, Grubendrachen sind riesige geflügelte Humanoide, gargoylenhaft in ihrer Erscheinung, mit gewaltigen Fledermausflügeln, die sich um ihren Körper zur Verteidigung schlingen können, großen Reißzähnen, die von widerwärtiger, grüner Flüssigkeit triefen, und massigen roten, schuppigen Körpern, die in Flammen ausbrechen, wenn sie erzürnt oder erregt sind.'),
  combat_tactics  = COALESCE(combat_tactics, 'Kein Baatezu ist im Kampf schrecklicher als ein Grubendrache. Der Grubendrache nutzt seine 18/00 Stärke (+6 Schadensmodifikation), um sechs Mal pro Runde anzugreifen und teilt seine Angriffe bei Bedarf auf bis zu sechs verschiedene Gegner auf. Er kann mit zwei harten, schuppigen Flügelschlägen angreifen (je 1W4 Schadenspunkte), mächtigen Klauen (1W6 Punkte) und einem Biss (2W6 Punkte und Gift; Rettungswurf gegen Gift oder Tod in 1W4 Runden). Der Biss infiziert das Opfer auch mit einer Krankheit, unabhängig davon, ob es den Rettungswurf gegen das Gift besteht.'),
  habitat_society = COALESCE(habitat_society, 'Grubendrachen sind die Herren von Baator, die Baatezu mit der größten Macht und dem höchsten Rang. Grubendrachen sind in ganz Baator zu finden, aber sehr selten in den oberen Schichten und in der eisigen Kälte von Caina, der achten Schicht. Grubendrachen sind sehr selten in Avernus, Dis und Minauros. Sie sind selten in Phlegethos, Stygia, Malbolge und Maladomini. Im furchtbaren Reich von Nessus sind die Grubendrachen häufig.'),
  ecology         = COALESCE(ecology, 'Grubendrachen entstehen aus den mächtigen Gelugons von Baators achter Schicht. Wenn Gelugons für würdig befunden werden, werden sie für 1001 Tage in die Grube der Flammen geworfen. Sie gehen als Grubendrachen hervor.'),
  no_appearing    = COALESCE(no_appearing, '1-4')
WHERE id = '485d4c87-7cc8-4769-91ee-2eb752b2c916' AND is_custom = FALSE;

-- Banshee (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Die Banshee oder Klagendes Gespenst ist der Geist einer bösen weiblichen Elfe - etwas sehr seltenes. Banshees hassen die Lebenden, empfinden deren Anwesenheit als schmerzhaft und versuchen jedem zu schaden, dem sie begegnen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Banshees sind furchtbare Gegner. Schon ihr Anblick verursacht Furcht, es sei denn, ein erfolgreicher Rettungswurf gegen Zauber wird gewürfelt. Jene, die versagen, müssen 10 Runden lang vor Schrecken fliehen und lassen mit 50%iger Wahrscheinlichkeit alle Gegenstände fallen, die sie in den Händen trugen.'),
  habitat_society = COALESCE(habitat_society, 'Banshees verabscheuen alle lebenden Dinge und machen daher ihre Heime in trostloser Landschaft oder alten Ruinen. Dort verstecken sie sich tagsüber, wenn sie nicht klagen können, und wandern nachts durch die umgebende Landschaft. Das Land rund um den Bau eines Klagenden Gespenstes ist übersät mit den Knochen von Tieren, die den Schrei des Klagenden Gespenstes hörten. Einmal etabliert ein Klagendes Gespenst ihren Bau, bleibt sie dort.'),
  ecology         = COALESCE(ecology, 'Banshees sind eine Plage, wo immer sie sich niederlassen. Sie töten wahllos und ihr einziges Vergnügen ist das Unglück und Elend anderer. Zusätzlich zum Töten von Mensch und Tier hat das Klagen eines Klagenden Gespenstes eine mächtige Wirkung auf die Vegetation. Blumen und zarte Pflanzen verwelken und sterben, und Bäume wachsen verdreht und krank, während widerstandsfähigere Pflanzen, Disteln und dergleichen, gedeihen. Nach einigen Jahren bleibt im Umkreis von acht Kilometern um den Bau eines Klagenden Gespenstes nur eine trostlose Wildnis aus verkrüppelten Bäumen und Dornen gemischt mit den Knochen jener Kreaturen übrig, die es wagten, in das Gebiet des Klagenden Gespenstes einzudringen.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = '3fe4449b-f076-46ed-b5af-102709c4644d' AND is_custom = FALSE;

-- Basilisk (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Diese reptilienartigen Monster besitzen alle einen Blick, der es ihnen ermöglicht, jede fleischliche Kreatur zu Stein zu verwandeln; ihr Blick reicht bis in die Astral- und Ätherebene.'),
  combat_tactics  = COALESCE(combat_tactics, 'Während er starke, bezahnte Kiefer hat, ist der Blick die Hauptwaffe des Basilisks. Wenn jedoch sein Blick reflektiert wird und er seine eigenen Augen sieht, wird er selbst versteinert, aber dies erfordert Licht, das mindestens hellem Fackelschein entspricht, und einen guten, glatten Reflektor. In der Astralebene tötet sein Blick; in der Ätherebene verwandelt er Opfer in ätherischen Stein. Diese werden nur von jenen gesehen, die sich in der Ätherebene befinden oder ätherische Objekte sehen können.'),
  habitat_society = COALESCE(habitat_society, NULL),
  ecology         = COALESCE(ecology, NULL),
  no_appearing    = COALESCE(no_appearing, '1-4')
WHERE id = '7b933cd7-6d39-4d90-a0ea-fcfa0dd6005c' AND is_custom = FALSE;

-- Chimera (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Wie Chimären erschaffen wurden, ist ein dunkles Geheimnis, das besser unerforscht bleibt. Die Chimäre hat die Hinterläufe einer großen, schwarzen Ziege und die Vorderläufe eines riesigen, gelbbraunen Löwen. Ihr Körper hat bräunlich-schwarze Flügel wie die eines Drachen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Ihre vielen Köpfe und ihre mächtige Statur machen die Chimäre zu einem tödlichen Feind im Kampf. Das Monster bevorzugt es, seine Opfer zu überraschen, oft indem es vom Himmel auf sie herabstößt. Sie kann 6 Mal pro Runde angreifen: mit den Klauen ihrer Vorderläufe, mit ihren beiden Hörnern stoßend und mit ihren Löwen- und Drachenköpfen beißend. Falls sie es wünscht, kann der Drachenkopf anstelle des Beißens einen etwa 4,6 m langen Flammenstrahl ausspeien. Das Feuer des Drachen verursacht 3-24 (3W8) Schadenspunkte, obwohl ein erfolgreicher Rettungswurf gegen Atemwaffen den Schaden halbiert. Die Chimäre wird immer zu atmen versuchen, wenn ihre Gegner in Reichweite sind. Falls mehr als eine Chimäre angetroffen wird, werden sie gemeinsam angreifen.'),
  habitat_society = COALESCE(habitat_society, 'Die Chimäre vereint als Hybridwesen die Vorlieben des Löwen, der Ziege und des Drachen in ihrem Lebensraum, ihrer Gesellschaft und Ökologie. Der drachenhafte Teil ihrer Natur gibt der Chimäre eine deutliche Vorliebe für Höhlen als Baue. Die Drachen- und Löwenteile scheinen miteinander zu streiten, denn manche Chimären sind drachenähnlich in ihrer Vorliebe für Einsamkeit, während andere in kleinen Rudeln leben. Selbst wenn sie sich paaren, sind Nachkommen selten.'),
  ecology         = COALESCE(ecology, 'Die Chimäre erfüllt die Rolle sowohl eines Allesfressers als auch eines Spitzenjägers in ihrem Ökosystem. Sie ist sehr anpassungsfähig. In Zeiten, in denen ihre Beute knapp oder nicht vorhanden ist, kann die Chimäre mit einer vegetarischen Ernährung auskommen.'),
  no_appearing    = COALESCE(no_appearing, '1-4')
WHERE id = '2fa8824e-cc97-47ae-879f-7c571b9ee144' AND is_custom = FALSE;

-- Cloaker (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Verhüller sind teuflische Schrecken, verwandt mit den Fallensteller, die an dunklen Orten weit unter der Erdoberfläche hausen. Sie versuchen generell, diejenigen zu töten, die ihre Baue betreten, außer sie können sich eine andere, amüsantere Art ausdenken, die Eindringlinge zu bestrafen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Wenn ein Verhüller sein Opfer angreift, bewegt er sich mit blendender Geschwindigkeit. Ohne Vorwarnung fliegt der Verhüller auf sein Ziel zu und, wenn der Angriffswurf erfolgreich ist, umhüllt er seine Beute in seinen Falten. Jede Kreatur, die diesem Angriff zum Opfer fällt, ist nahezu hilflos und kann leicht gebissen werden (kein Wurf erforderlich) für 1W4 Schadenspunkte plus der unmodifizierten Rüstungsklasse des Opfers. So erleidet ein Abenteurer in Kettenrüstung (RK 5) 1W4+5 Schadenspunkte pro Runde. Schilde bieten keinen Schutz gegen solche Angriffe.'),
  habitat_society = COALESCE(habitat_society, 'Die Denkprozesse von Verhüllern sind für die meisten anderen Lebensformen völlig fremd. Als solche können sie nur von Magiern kontaktiert werden, die lange Stunden damit verbracht haben, ihre Gedanken in der arkanen Disziplin zu schulen, die notwendig ist, um diese Kreaturen zu verstehen.'),
  ecology         = COALESCE(ecology, 'Es wird angenommen, dass Verhüller geschlechtslos sind, obwohl hierfür nie ein definitiver Beweis gefunden wurde.'),
  no_appearing    = COALESCE(no_appearing, '1-4')
WHERE id = '0a370bd8-1736-4d13-a8c0-a1a1835d5f78' AND is_custom = FALSE;

-- Cockatrice (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Der Cockatrice ist eine unheimliche, abstoßende Kreuzung aus Echse, Hahn und Fledermaus. Er ist berüchtigt für seine Fähigkeit, Fleisch zu Stein zu verwandeln.'),
  combat_tactics  = COALESCE(combat_tactics, 'Der Cockatrice greift alles erbittert an, Mensch oder anderes, was er als Bedrohung für sich selbst oder seinen Bau ansieht. Beim Angriff versucht der Cockatrice, seinen Gegner zu packen, entblößtes Fleisch zu berühren und es zu Stein zu verwandeln. Schwärme von Cockatrices werden ihr Äußerstes geben, um ihre Gegner zu überwältigen und zu verwirren, und sie fliegen manchmal direkt in die Gesichter ihrer Opfer.'),
  habitat_society = COALESCE(habitat_society, 'Der Cockatrice ist immun gegen die Versteinerungskräfte anderer seiner Art.'),
  ecology         = COALESCE(ecology, 'Der Cockatrice gedeiht in der Wildnis. Seine Versteinerungskraft macht ihn immun gegen die meisten Raubtiere und befähigt ihn, mit anderen Vögeln um Nahrung zu konkurrieren. Die Federn des Cockatrice werden von bestimmten Magiern geschätzt, da viele magische Schriftrollen mit Federn geschrieben werden müssen, die aus solchen Kielen gemacht sind. Viele Menschen suchen auch nach ungeschlüpften Eiern oder sogar lebenden Cockatrices als ungewöhnliche Haustiere oder Wächter.'),
  no_appearing    = COALESCE(no_appearing, '1-6')
WHERE id = '6c685aaa-012b-407e-87ef-71a4c080a28f' AND is_custom = FALSE;

-- Crypt Thing (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Gruftdinge sind seltsame untote Kreaturen, die manchmal Gräber, Grüfte und Leichname bewachen. Es gibt zwei Arten von Gruftdingen - ahnenhafte und beschworene. Die erstere Art sind „natürliche" Kreaturen, während die anderen von einem Magier oder Priester mindestens der 14. Stufe ins Dasein gerufen werden.'),
  combat_tactics  = COALESCE(combat_tactics, 'Ein Gruftding existiert nur, um die Körper derer zu beschützen, die in seinem Bau zur letzten Ruhe gebettet wurden. Es handelt nur, um seine Gruft zu verteidigen. Sollten Grabräuber oder Vandalen versuchen einzudringen und die Heiligkeit seines Grabes zu entweihen, wird das Gruftding augenblicklich aktiv.'),
  habitat_society = COALESCE(habitat_society, 'Gruftdinge sind kein natürlicher Teil unserer Welt; sie haben keine organisierte Gesellschaft oder Kultur. Sie finden sich überall dort, wo Gräber und Grüfte liegen.'),
  ecology         = COALESCE(ecology, 'Das Gruftding ist kein Wesen dieser Welt und hat daher keine echte ökologische Nische. Es wird gemunkelt, dass das pulverisierte Mark aus den Knochen eines Gruftdings zur Herstellung eines Tranks der Untotenbeherrschung verwendet werden kann. Außerdem hat jeder, der die Knochen eines Gruftdings zur Herstellung von Pfeifen der Besessenheit verwendet, eine 80%ige Wahrscheinlichkeit, einen magischen Gegenstand zu erschaffen, der seinen Opfern einen Malus von -2 auf ihre Rettungswürfe auferlegt und doppelte normale Wirksamkeit besitzt, falls die Rettungswürfe fehlschlagen.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = '284a8820-f9cf-4b2a-bef7-336c33c53c5d' AND is_custom = FALSE;

-- Death Knight (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Ein Todesritter ist die schreckliche Verderbnis eines Paladins oder rechtschaffen guten Kriegers, der von den Göttern zu seiner furchtbaren Gestalt verflucht wurde als Strafe dafür, dass er den Ehrenkodex verraten hat, den er zu Lebzeiten befolgte.'),
  combat_tactics  = COALESCE(combat_tactics, 'Ein Todesritter behält die Kampffertigkeiten, die er in seinem früheren Leben hatte. Da er wenig Rücksicht auf seine eigene Sicherheit nimmt und einen intensiven Hass auf die meisten lebenden Kreaturen hegt, ist er ein äußerst gefährlicher Gegner. Dennoch behält ein Todesritter einen Anschein des Stolzes, den er als guter Krieger besaß, und kämpft ehrenhaft: Er überfällt Gegner niemals von hinten, noch greift er an, bevor ein Gegner die Gelegenheit hatte, seine Waffe bereitzumachen. Kapitulation ist einem Todesritter unbekannt, und er wird nur verhandeln, wenn er spürt, dass sein Gegner entscheidende Informationen hat (wie das Schicksal eines ehemaligen Familienmitglieds).'),
  habitat_society = COALESCE(habitat_society, 'Todesritter sind ehemalige gute Krieger, die von den Göttern schuldig unverzeihlicher Verbrechen wie Mord oder Verrat befunden wurden. (Zum Beispiel ermordete Krinns Lord Soth, der berühmteste aller Todesritter, seine Frau, damit er eine Affäre mit einer Elfenfrau fortsetzen konnte.) Todesritter sind verflucht, in ihren ehemaligen Domänen zu verbleiben, gewöhnlich Burgen oder andere Festungen. Sie sind ferner dazu verdammt, ihr Verbrechen in einem Lied an jeder Nacht zu erinnern, in der der Mond voll ist; wenige Geräusche sind so furchteinflößend wie die eisige Melodie eines Todesritters, die durch die mondscheinbeleuchtete Landschaft hallt. Todesritter greifen wahrscheinlich jede Kreatur an, die ihre Lieder unterbricht oder in ihre Domänen eindringt.'),
  ecology         = COALESCE(ecology, 'Todesritter haben keine physiologischen Funktionen. Sie werden manchmal von Skelettkriegern, Lichs und anderen Untoten begleitet, die ihnen als Gehilfen dienen.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = '9aa11f9a-3004-4328-b6ef-1355ebec85a6' AND is_custom = FALSE;

-- Displacer Beast (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Das Scheintierwesen ist ein magisches Geschöpf, das einem Puma mit zwei mächtigen schwarzen Tentakeln ähnelt, die aus seinen Schultern wachsen. Sehr selten, bleiben sie fern von menschlichen Siedlungen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Das Scheintierwesen ist ein wilder, grausamer Geschöpf, das alle Lebensformen hasst. Äußerst aggressiv, wird das Scheintierwesen bei Sichtkontakt angreifen und seine Tentakel einsetzen, um seinen Opfern 2-8 (2W4) Schadenspunkte zuzufügen.'),
  habitat_society = COALESCE(habitat_society, 'Scheintierwesen sind Fleischfresser. Außer wenn sie Junge aufziehen, laufen sie gewöhnlich in Rudeln und hinterlassen eine grausame Schneise der Zerstörung. Sie hassen alles Leben und töten manchmal rein aus Vergnügen. So wild und bösartig sie auch sind, kämpfen Scheintierwesen jedoch niemals untereinander. Das Rudel ist eine gut geführte und höchst effiziente Tötungsmaschine. Wenn sie in Rudeln angetroffen werden, sind Scheintierwesen mehr als ein ebenbürtiger Gegner für viele große Geschöpfe und es ist bekannt, dass sie eine Mahlzeit aus Orks, Goblins und Menschenbanden gemacht haben. Jedes Geschöpf, das ihr Territorium betritt, wird als potentielle Beute betrachtet.'),
  ecology         = COALESCE(ecology, 'Scheintierwesen haben wenig von anderen großen Raubtieren zu befürchten, außer vielleicht Trollen oder Riesen. Einige Magier und Alchemisten schätzen ihre Häute für die Verwendung in bestimmten magischen Zubereitungen und bieten großzügige Belohnungen dafür. Die Augen eines Scheintierwesens sind hochgeschätzte, wenn auch seltene Glücksbringer unter Dieben, die glauben, dass sie den Träger vor Entdeckung schützen werden.'),
  no_appearing    = COALESCE(no_appearing, '2-5 (1d4+1)')
WHERE id = '98744640-137b-4aff-97a6-bdd37c276be3' AND is_custom = FALSE;

-- Doppelganger (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Der Doppelgänger ist ein Meister der Nachahmung, der überlebt, indem er die Gestalt von Menschen, Halbmenschen und Humanoiden annimmt.'),
  combat_tactics  = COALESCE(combat_tactics, 'Dieses Monster ist imstande, die Gestalt jeder humanoiden Kreatur zwischen 1,2 und 2,4 m Größe anzunehmen. Der Doppelgänger wählt ein Opfer aus, kopiert dessen Gestalt und versucht dann, das Original zu töten und dessen Platz einzunehmen. Der Doppelgänger kann Gedankenlesen einsetzen und sein Opfer mit 90%iger Genauigkeit nachahmen, sogar dessen Kleidung und Ausrüstung duplizieren. Falls er nicht erfolgreich den Platz seines Opfers einnehmen kann, greift der Doppelgänger an und verlässt sich auf die entstehende Verwirrung, um ununterscheidbar von seinem Opfer zu werden. Ein Doppelgänger ist immun gegen Schlaf- und Bezauberungszauber und würfelt alle Rettungswürfe, als wäre er ein Kämpfer der 10. Stufe.'),
  habitat_society = COALESCE(habitat_society, 'Doppelgänger sollen künstliche Wesen sein, die vor langer Zeit von einem mächtigen Magier oder einer gottähnlichen Kreatur erschaffen wurden. Ursprünglich waren sie als Spione und Attentäter in einem uralten, höchst magischen Krieg gedacht. Ihr Schöpfer starb vor langer Zeit, aber sie leben weiter und arbeiten noch immer als Spione für böse Mächte, Diebe und Regierungen. Es ist sogar bekannt, dass sie als Attentäter arbeiten.'),
  ecology         = COALESCE(ecology, 'Doppelgänger sind raffinierte und gefährliche Parasiten, die von der Arbeit anderer leben. Sie müssen auch als clevere und effektive Spione und Attentäter gewertet werden, die in Machtpositionen politisches Chaos anrichten können. Böse Magier haben bei seltenen Gelegenheiten ganze Königreiche für kurze Zeiträume kontrolliert, indem sie einen König, Prinzen oder Ratsherren durch einen Doppelgänger ersetzten.'),
  no_appearing    = COALESCE(no_appearing, '3-12')
WHERE id = '6542721a-fd42-4579-9ed6-fa42584ba3f8' AND is_custom = FALSE;

-- Dracolich (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Der Dracolich ist eine untote Kreatur, die aus der unnatürlichen Verwandlung eines Drachen entsteht. Der geheimnisvolle Kult des Drachen beherrscht die mächtige Magie, die zur Erschaffung des Dracolich notwendig ist, obwohl auch andere Praktizierende existieren sollen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Dracoliche sind immun gegen Bezauberung, Schlaf, Schwächung, Verwandlung, Kälte (magisch oder normal), Elektrizität, Lähmung, Wahnsinn oder Todes-Zauber oder -Symbole. Sie können nicht vergiftet oder gelähmt werden und nicht von Priestern vertrieben werden. Sie haben dieselbe Magieresistenz wie ihre ursprünglichen Formen, aber nur magische Angriffe von Magiern der 6. Stufe oder höher oder Angriffe von Monstern mit 6 oder mehr Trefferwürfeln können Dracoliche verletzen.'),
  habitat_society = COALESCE(habitat_society, 'Die Erschaffung eines Dracolich ist ein komplexer Prozess, der die Verwandlung eines bösen oder neutralen Drachen durch arkane magische Kräfte beinhaltet, deren berüchtigtste Praktizierende die Mitglieder des Kults des Drachen sind. Der Prozess ist normalerweise eine Zusammenarbeit zwischen dem bösen Drachen und Magiern und/oder Priestern, aber besonders mächtige Magier und Priester sind dafür bekannt, einen bösen Drachen zu zwingen, die Verwandlung gegen seinen Willen zu durchlaufen. Priesterversionen dieses Verfahrens sind den magischen Versionen ähnlich, die hier beschrieben werden, aber Priester brauchen noch immer die Hilfe eines Magiers für bestimmte Aspekte des Verwandlungsprozesses, während Magier niemals die Hilfe eines Priesters benötigen - obwohl sie manchmal willkommen ist. Insbesondere die Kirche von Tiamat arbeitet daran, die Anforderungen für magische Unterstützung zu eliminieren.'),
  ecology         = COALESCE(ecology, NULL),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = '41630ff4-7acc-4309-a46e-0a8b18e8ed11' AND is_custom = FALSE;

-- Dragon, Chromatic, Black (matched by override)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Schwarze Drachen sind tyrannisch, jähzornig und verabscheuen jede Art von Eindringen. Sie mögen düstere Umgebung, dichte Vegetation und bevorzugen Dunkelheit gegenüber Tageslicht. Obwohl sie nicht so intelligent sind wie andere Drachen, sind schwarze Drachen instinktiv gerissen und bösartig.'),
  combat_tactics  = COALESCE(combat_tactics, 'Schwarze Drachen ziehen es vor, ihre Ziele aus dem Hinterhalt anzugreifen und nutzen ihre Umgebung als Deckung. Ihre bevorzugten Ziele sind Menschen, die sie manchmal mehrere Minuten lang verfolgen, um ihre Stärke und ihren Reichtum einzuschätzen, bevor sie angreifen. Gegen eine Gruppe von Menschen oder eine beeindruckende Kreatur kann der Sumpf die Ziele schwächen, bevor der Drache in den Kampf eingreift. Schwarze Drachen setzen auch ihre Atemwaffe ein, bevor sie in den Nahkampf gehen. Beim Kampf in stark bewachsenen Sümpfen und Mooren versuchen schwarze Drachen, im Wasser oder am Boden zu bleiben; die zahlreichen Bäume und belaubten Baumkronen beschränken ihre Flugmanövrierfähigkeit. Wenn sie einem Gegner gegenüberstehen, der eine zu große Bedrohung darstellt, wird ein schwarzer Drache versuchen, außer Sichtweite zu fliegen, damit er keine Spuren hinterlässt, und sich in einem tiefen Teich oder Sumpf verstecken.'),
  habitat_society = COALESCE(habitat_society, 'Schwarze Drachen findet man in Sümpfen, Mooren, Regenwäldern und Dschungeln. Sie schwelgen in einer dampfigen Umgebung, wo Baumkronen das meiste Sonnenlicht herausfiltern, Schwärme von Insekten die Luft erfüllen und stagnierende, moosbewachsene Teiche in Hülle und Fülle liegen. Schwarze Drachen sind ausgezeichnete Schwimmer und genießen es, in den düsteren Tiefen von Sümpfen und Mooren zu lauern. Sie sind auch anmutige Flieger; jedoch ziehen sie es vor, nachts zu fliegen, wenn ihre gewaltigen Gestalten von der Dunkelheit des Himmels verborgen werden. Schwarze Drachen sind extrem selbstsüchtig, und die Mehrheit der angetroffenen wird allein sein. Wenn eine Familie schwarzer Drachen angetroffen wird, werden die Erwachsenen ihre Jungen beschützen. Falls es jedoch so aussieht, als wären die Leben der Erwachsenen in Gefahr, werden sie ihre Jungen im Stich lassen, um sich selbst zu retten.'),
  ecology         = COALESCE(ecology, 'Schwarze Drachen können fast alles fressen, obwohl sie es vorziehen, sich hauptsächlich von Fischen, Weichtieren und anderen aquatischen Kreaturen zu ernähren. Sie sind gern von Aalen angetan, besonders von den Riesenvarianten. Sie jagen auch nach rotem Fleisch, aber sie mögen es, es zu "pökeln", indem sie es tagelang in Teichen innerhalb ihres Baus liegen lassen, bevor sie es fressen.'),
  no_appearing    = COALESCE(no_appearing, '1 (2-5)')
WHERE id = 'e71ad1b4-9c1a-4435-be38-a3571152d95a' AND is_custom = FALSE;

-- Dragon, Chromatic, Blue (matched by override)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Blaue Drachen sind extrem territorial und gefräßig. Sie lieben es, lange Stunden damit zu verbringen, Hinterhalte für Herdentiere und unvorsichtige Reisende vorzubereiten, und sie verbringen ebenso lange Stunden damit, über ihre Erfolge zu grübeln und ihre Trophäen zu bewundern.'),
  combat_tactics  = COALESCE(combat_tactics, 'Blaue Drachen kämpfen bevorzugt aus der Distanz, damit ihre Gegner deutlich die volle Kraft ihrer Odemwaffe miterleben können und damit für sie selbst wenig oder gar keine Bedrohung besteht. Oft greifen blaue Drachen von direkt oben an oder graben sich unter den Sand ein, bis Gegner in 30,5 m Entfernung kommen. Ältere blaue Drachen werden ihre besonderen Fähigkeiten, wie trügerisches Gelände, in Verbindung mit diesen Taktiken einsetzen, um das Land zu verschleiern und ihre Chancen auf Überraschung zu erhöhen. Blaue Drachen werden nur aus einem Kampf fliehen, wenn sie schwer verwundet sind, da sie Rückzug als feige betrachten.'),
  habitat_society = COALESCE(habitat_society, 'Blaue Drachen findet man in Wüsten; trockenen, windgepeitschten Ebenen; und heißen, feuchten Ödlanden. Sie genießen das karge Gelände, weil es nur wenige Hindernisse gibt - nur gelegentliche Felsvorsprünge oder Dünen - die den Blick auf ihre Territorien unterbrechen. Sie verbringen Stunden damit, über ihre Gebiete zu blicken, nach Eindringlingen Ausschau zu halten und ihr Eigentum zu bewundern. Die meisten der angetroffenen blauen Drachen werden allein sein, weil sie ihre Territorien nicht mit anderen teilen wollen. Jedoch, wenn eine Familie angetroffen wird, wird der männliche Drache erbittert angreifen und sein Eigentum - seine Gefährtin und Jungen - beschützen. Der weibliche Drache wird ebenfalls in den Angriff eingreifen, wenn sich die Bedrohung als bedeutend erweist.'),
  ecology         = COALESCE(ecology, 'Blaue Drachen können fast alles verzehren und sind manchmal gezwungen, Schlangen, Echsen und Wüstenpflanzen zu fressen, um ihren großen Hunger zu stillen. Jedoch sind sie besonders von Herdentieren wie Kamelen angetan, und sie werden sich an Karawanen dieser Kreaturen überfressen, die sie mit einem Blitzschlag garen.'),
  no_appearing    = COALESCE(no_appearing, '1 (2-5)')
WHERE id = '016bfcc1-3757-44d2-9e73-144007973401' AND is_custom = FALSE;

-- Dragon, Chromatic, Green (matched by override)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Grüne Drachen sind schlecht gelaunt, gemein, grausam und rüde. Sie hassen Güte und gut gesinnte Kreaturen. Sie lieben Intrigen und streben danach, andere Waldkreaturen zu versklaven, wobei sie jene töten, die nicht kontrolliert oder eingeschüchtert werden können.'),
  combat_tactics  = COALESCE(combat_tactics, 'Grüne Drachen beginnen Kämpfe mit wenig oder gar keiner Provokation und greifen Kreaturen jeder Größe an. Wenn die Zielkreatur den Drachen fasziniert oder schwer zu handhaben erscheint, wird der Drache die Kreatur verfolgen und seine Umgebung als Deckung nutzen, bis er den besten Zeitpunkt zum Angriff und die geeignetsten Taktiken bestimmt hat. Erscheint das Ziel bedrohlich, wird der Drache zuerst mit seiner Atemwaffe, magischen Fähigkeiten und Zaubern angreifen. Erscheint das Ziel jedoch schwach, wird der Drache seine Anwesenheit schnell bekannt machen, da er es genießt, Terror in seinen Zielen hervorzurufen. Wenn der Drache dieses Spiel satt hat, wird er die Kreatur mit seinen körperlichen Angriffen niederstrecken, damit der Kampf länger dauert und die Qual der Kreatur verlängert wird.'),
  habitat_society = COALESCE(habitat_society, 'Grüne Drachen findet man in subtropischen und gemäßigten Wäldern, je älter der Wald und größer die Bäume, desto besser. Die Anblicke und Gerüche der Wälder gefallen dem Drachen, und er betrachtet den gesamten Wald oder die Wälder als sein Territorium. Manchmal geht der Drache eine Beziehung mit anderen bösen waldlebenden Kreaturen ein, die den Drachen über die Geschehnisse im Wald und der Umgebung informieren im Austausch für ihr Leben. Wenn ein grüner Drache in einem Wald an einem Berghang lebt, wird er versuchen, Hügelriesen zu versklaven, die der Drache als seinen größten Feind betrachtet. Ein grüner Drache macht seinen Bau in unterirdischen Kammern tief unter seinem Wald.'),
  ecology         = COALESCE(ecology, 'Obwohl bekannt ist, dass grüne Drachen praktisch alles fressen, einschließlich Sträucher und kleine Bäume, wenn sie hungrig genug sind, schätzen sie besonders Elfen. Wenn der Wald an einem Berghang liegt, werden Hügelriesen die jüngeren Drachen jagen, die sie als Delikatesse betrachten.'),
  no_appearing    = COALESCE(no_appearing, '1 (2-5)')
WHERE id = '737b66d6-8137-42f4-bc8d-3cded31e17e3' AND is_custom = FALSE;

-- Dragon, Chromatic, Red (matched by override)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Rote Drachen sind die habgierigsten und gierigsten aller Drachen, die unaufhörlich danach streben, ihre Schatzhörter zu vergrößern. Sie sind von ihrem Reichtum besessen und prägen sich ein Inventar ein, das bis zum letzten Kupferstück genau ist. Sie sind außergewöhnlich eitel und selbstbewusst und betrachten sich nicht nur anderen Drachen, sondern allem anderen Leben im Allgemeinen als überlegen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Da rote Drachen so selbstbewusst sind, halten sie niemals inne, um einen Gegner einzuschätzen. Wenn sie ein Ziel bemerken, treffen sie eine spontane Entscheidung, ob sie angreifen, wobei sie eine von vielen "perfekten" Strategien verwenden, die sie vorher in der Einsamkeit ihrer Baue ausgearbeitet haben. Wenn die Kreatur klein und unbedeutend erscheint, wie etwa ein ungepanzerter Mann, wird der Drache landen, um mit seinen Klauen und seinem Biss anzugreifen, da er die Kreatur nicht mit seiner Atemwaffe vernichten möchte, weil jeder Schatz von den Flammen verschlungen werden könnte. Jedoch wird ein roter Drache, wenn er auf eine Gruppe gepanzerter Männer trifft, seine Atemwaffe, besonderen Fähigkeiten und Zauber (falls er alt genug ist, um sie zu haben) einsetzen, bevor er landet.'),
  habitat_society = COALESCE(habitat_society, 'Rote Drachen können auf großen Hügeln oder auf ragenden Bergen gefunden werden. Von einer hohen Warte aus überblicken sie hochmütig ihr Territorium, das sie als alles betrachten, was von ihrer Position aus gesehen werden kann. Sie bevorzugen es, in großen Höhlen zu hausen, die tief in die Erde hineinreichen.'),
  ecology         = COALESCE(ecology, 'Rote Drachen sind Fleischfresser, obwohl sie in der Lage sind, fast alles zu verdauen. Ihr Lieblingsfutter ist eine Jungfrau jedweder menschlichen oder halbmenschlichen Rasse. Manchmal sind die Drachen imstande, wichtige Dorfbewohner zu bezaubern, damit diese ihnen regelmäßig Jungfrauen opfern.'),
  no_appearing    = COALESCE(no_appearing, '1 (2-5)')
WHERE id = 'a1fbec0d-d22c-44b5-a80e-1cd1991a4ef8' AND is_custom = FALSE;

-- Dragon, Chromatic, White (matched by override)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Weiße Drachen, die kleinsten und schwächsten der bösen Drachen, sind schwerfällig, aber effiziente Jäger. Sie sind impulsiv, bösartig und animalisch, neigen dazu, nur die Bedürfnisse und Emotionen des Augenblicks zu berücksichtigen und haben weder Voraussicht noch Reue. Trotz ihrer geringen Intelligenz sind sie ebenso gierig und böse wie die anderen bösen Drachen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Unabhängig von der Größe eines Ziels besteht die bevorzugte Angriffsmethode eines weißen Drachen darin, seine Atemwaffe und Sonderfähigkeiten einzusetzen, bevor er zum Nahkampf übergeht. Diese Taktik wirkt manchmal zum Nachteil des Drachen, da er seine Atemwaffe an kleinerer Beute erschöpfen kann und dann einem größeren Wesen gegenübersteht, das er körperlich angreifen muss. Wenn ein weißer Drache Kreaturen im Wasser verfolgt, wie Eisbären oder Robben, wird er sie in ihrem Element im Nahkampf bekämpfen und mit seinen Klauen und seinem Biss kämpfen.'),
  habitat_society = COALESCE(habitat_society, 'Weiße Drachen leben in kühlen oder kalten Regionen und bevorzugen Länder, wo die Temperatur selten über den Gefrierpunkt steigt und Eis und Schnee immer den Boden bedecken. Wenn die Temperaturen zu warm werden, werden die Drachen träge. Weiße Drachen sonnen sich in den eisigen Winden, die über die Landschaft peitschen, und sie wälzen sich und spielen in tiefen Schneehaufen.'),
  ecology         = COALESCE(ecology, 'Obwohl weiße Drachen, wie alle anderen Drachen, in der Lage sind, fast alles zu fressen, sind sie sehr wählerisch und verzehren nur Nahrung, die gefroren wurde. Normalerweise, nachdem ein Drache eine Kreatur mit seiner Atemwaffe getötet hat, wird er sich daran machen, sie zu verschlingen, während der Kadaver noch steif und eisig ist. Er wird andere Beute in Schneehaufen vergraben, bis sie angemessen gefroren sind.'),
  no_appearing    = COALESCE(no_appearing, '1 (2-5)')
WHERE id = 'ec697d78-9c4b-4857-a350-4507a9b33fd7' AND is_custom = FALSE;

-- Dragon, Metallic, Brass (matched by override)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Messingdrachen sind große Schwätzer, aber nicht besonders gute Gesprächspartner. Sie sind egozentrisch und oft grob. Sie verfügen oft über nützliche Informationen, aber geben diese nur preis, nachdem sie viele Male vom Thema abgeschweift sind und nachdem sie Andeutungen gemacht haben, dass ein Geschenk geschätzt würde.'),
  combat_tactics  = COALESCE(combat_tactics, 'Messingdrachen reden lieber als zu kämpfen. Wenn eine intelligente Kreatur versucht, einen Messingdrachen zu verlassen, ohne ausführlich mit ihm zu sprechen, könnte der Drache einen Anfall von Verärgerung bekommen und versuchen, ein Gespräch mit Suggestion zu erzwingen oder indem er dem Opfer eine Dosis Schlafgas verabreicht. Falls das Opfer einschläft, erwacht es und stellt fest, dass es unter dem Drachen eingeklemmt oder bis zum Hals im Sand vergraben ist, bis der Drang des Drachen nach Smalltalk gestillt ist. Vor dem Nahkampf erzeugen Messingdrachen eine Staubwolke mit Staubteufel oder Winde kontrollieren, dann greifen sie an oder schnappen zu. Messingdrachen nutzen oft Temperatur kontrollieren, um Hitze zu erzeugen und ihre Gegner zu belästigen. Wenn sie echter Gefahr gegenüberstehen, fliegen jüngere Messingdrachen außer Sichtweite und verstecken sich dann durch Eingraben. Ältere Drachen verschmähen diese List.'),
  habitat_society = COALESCE(habitat_society, 'Messingdrachen findet man in trockenen, warmen Klimazonen; von Sandwüsten bis zu trockenen Steppen. Sie lieben intensive, trockene Hitze und verbringen die meiste Zeit damit, in der Sonne zu baden. Sie nisten in hohen Höhlen, vorzugsweise nach Osten ausgerichtet, wo die Sonne die Felsen erwärmen kann, und ihre Territorien enthalten immer mehrere Stellen, wo sie sich sonnen und unwissende Reisende in Gespräche locken können.'),
  ecology         = COALESCE(ecology, 'Wie andere Drachen können und werden Messingdrachen fast alles essen, wenn die Notwendigkeit entsteht. In der Praxis jedoch essen sie sehr wenig. Sie können Nahrung aus dem Morgentau gewinnen, einer seltenen Kostbarkeit in ihrem Lebensraum, und wurden dabei gesehen, wie sie ihn vorsichtig mit ihren langen Zungen von Pflanzen ableckten.'),
  no_appearing    = COALESCE(no_appearing, '1 (2-5)')
WHERE id = '071fedc3-323c-46a0-b96e-c347fb42c451' AND is_custom = FALSE;

-- Dragon, Metallic, Bronze (matched by override)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Bronzedrachen sind neugierig und mögen Menschen und Halbmenschen. Sie erfreuen sich daran, sich in kleine, freundliche Tiere zu verwandeln, damit sie Menschen und Halbmenschen, besonders Abenteurer, unaufdringlich beobachten können. Bronzedrachen gedeihen bei einfachen Herausforderungen wie Rätseln und harmlosen Wettkämpfen. Sie sind von Kriegsführung fasziniert und werden sich eifrig einer Armee anschließen, wenn die Sache gerecht und die Bezahlung gut ist.'),
  combat_tactics  = COALESCE(combat_tactics, 'Bronzedrachen mögen es nicht, Kreaturen mit tierischer Intelligenz zu töten und würden sie lieber bestechen (vielleicht mit Futter) oder sie mit Abstoßung vertreiben. Wenn sie intelligenten Gegnern gegenüberstehen, nutzen Bronzedrachen ihre GSP-Fähigkeit, um die Absichten ihrer Gegner zu erfahren. Beim Angriff blenden sie ihre Gegner mit Nebelwand und stürmen dann vor. Oder, falls sie fliegen, werden sie Gegner packen. Beim Kampf unter Wasser nutzen sie Luftiges Wasser, um die Wirksamkeit ihrer Atemwaffen zu erhalten und rein aquatische Gegner fernzuhalten. Gegen Boote oder Schiffe beschwören sie einen Sturm oder nutzen ihren Schwanzschlag, um die Rümpfe der Schiffe zu zertrümmern. Falls der Drache zu Milde neigt, könnten sich seefahrende Gegner lediglich in einer Flaute, nebelgebunden oder mit gebrochenen Masten wiederfinden.'),
  habitat_society = COALESCE(habitat_society, 'Bronzedrachen mögen es, in der Nähe von tiefem Süß- oder Salzwasser zu sein. Sie sind gute Schwimmer und besuchen oft die Tiefen, um sich abzukühlen oder um nach Perlen oder Schätzen von gesunkenen Schiffen zu jagen. Sie bevorzugen Höhlen, die nur vom Wasser aus zugänglich sind, aber ihre Baue sind immer trocken - sie legen keine Eier, schlafen nicht und lagern keine Schätze unter Wasser.'),
  ecology         = COALESCE(ecology, 'Bronzedrachen fressen Wasserpflanzen und einige Sorten von Meeresfrüchten. Sie schätzen besonders Haifischfleisch. Sie speisen auch gelegentlich eine Perle und können, wie andere Drachen, im Notfall fast alles fressen. Böse, amphibische Meereskreaturen (besonders Sahuagin), die ihre luftgefüllten Baue überfallen können, sind ihre größten Feinde.'),
  no_appearing    = COALESCE(no_appearing, '1 (2-5)')
WHERE id = 'e6e6cf4f-d456-4ba1-8f2b-b81c704620a0' AND is_custom = FALSE;

-- Dragon, Metallic, Copper (matched by override)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Kupferdrachen sind unverbesserliche Schelme, Witzeerzähler und Rätselsteller. Sie sind stolz und keine guten Verlierer, obwohl sie einigermaßen gute Gewinner sind. Sie sind besonders selbstsüchtig und für ihre Gesinnung gierig und haben eine fast neutrale Einstellung, was Reichtum angeht.'),
  combat_tactics  = COALESCE(combat_tactics, 'Kupferdrachen verspotten und ärgern gerne ihre Gegner, in der Hoffnung, dass sie aufgeben oder wütend werden und töricht handeln. Früh in einer Begegnung wird ein Kupferdrache von einer Seite eines Gegners zur anderen springen und auf unzugänglichen oder senkrechten Steinoberflächen landen. Wenn es keine solchen Plätze um den Bau eines Drachens gibt, wird der Drache sie im Voraus mit Stein formen, Erde bewegen und Steinwand erschaffen. Ein wütender Kupferdrache wird seine Gegner mit Fels zu Schlamm einschließen und Opfer, die dem Schlamm entkommen, mit Tritten hinein zwingen. Sobald Gegner im Schlamm gefangen sind, wird der Drache sie mit einer Steinwand zerquetschen oder sie packen und in die Luft tragen. Beim Kampf gegen fliegende Gegner wird ein Drache seine Feinde in enge, steinige Schluchten locken, wo er seine Spinnenklettern-Fähigkeit nutzen kann, um zu versuchen, den Feind dazu zu bringen, mit den Wänden zu kollidieren.'),
  habitat_society = COALESCE(habitat_society, 'Kupferdrachen mögen trockene, felsige Hochländer und Berge. Sie bauen ihre Höhlen in schmalen Grotten und verbergen oft die Eingänge mit Erde bewegen und Stein formen. Innerhalb des Baus konstruieren sie gewundene Labyrinthe mit offenen Decken. Diese ermöglichen es dem Drachen, über Eindringlinge hinwegzufliegen oder zu springen, die sich durch das Labyrinth kämpfen.'),
  ecology         = COALESCE(ecology, 'Kupferdrachen sind entschlossene Jäger, der gute Sport, den eine Jagd bietet, ist mindestens genauso wichtig wie die Nahrung, die sie bekommen. Sie sind dafür bekannt, fast alles zu fressen, einschließlich Metallerze. Jedoch schätzen sie riesige Skorpione und andere große giftige Kreaturen (sie sagen, das Gift schärft ihren Verstand). Das Verdauungssystem des Drachens kann das Gift sicher verarbeiten, obwohl injizierte Gifte sie normal beeinträchtigen.'),
  no_appearing    = COALESCE(no_appearing, '1 (2-5)')
WHERE id = 'de365c54-39e5-4a5d-85c8-e7b71ea96bdb' AND is_custom = FALSE;

-- Dragon, Metallic, Gold (matched by override)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Golddrachen sind weise, besonnen und wohlwollend. Sie begeben sich oft auf selbst auferlegte Questen, um das Gute zu fördern, und lassen sich nicht leicht davon abbringen. Sie hassen Ungerechtigkeit und Falschspiel. Ein Golddrache nimmt häufig menschliche oder tierische Gestalt an und wird normalerweise in Verkleidung angetroffen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Golddrachen verhandeln normalerweise vor dem Kampf. Wenn sie sich mit intelligenten Geschöpfen unterhalten, setzen sie Lüge entdecken- und Edelsteine entdecken-Zauber ein, um die Oberhand zu gewinnen. Im Kampf nutzen sie schnell Segen und Glücksbonus. Ältere Drachen verwenden den Glücksbonus zu Beginn jeden Tages, wenn die Dauer einen Tag oder mehr beträgt. Sie machen im Kampf ausgiebig Gebrauch von Zaubern. Zu ihren Favoriten gehören Schlaf, Stinkende Wolke, Verlangsamung, Feuerschild, Giftwolke, Kugel der Unverletzlichkeit, Verzögerte Explosion, Feuerball und Labyrinth.'),
  habitat_society = COALESCE(habitat_society, 'Golddrachen können überall leben. Ihre Baue sind abgeschieden und immer aus solidem Stein gebaut, entweder Höhlen oder Burgen. Diese haben normalerweise treue Wachen: entweder Tiere, die zum Gelände passen, oder Sturm- oder gute Wolkenriesen. Die Riesen dienen normalerweise als Wachen durch ein gegenseitiges Verteidigungsabkommen.'),
  ecology         = COALESCE(ecology, 'Golddrachen können fast alles fressen, jedoch ernähren sie sich normalerweise von Perlen oder kleinen Edelsteinen. Golddrachen, die Perlen und Edelsteine von guten oder neutralen Geschöpfen erhalten, werden den Schenkenden normalerweise wohlwollend gesinnt sein, solange das Geschenk nicht als plumpe Bestechung dargebracht wird. Im letzteren Fall wird der Drache das Geschenk annehmen, aber zynisch auf alle Bitten reagieren, die der Geber äußert.'),
  no_appearing    = COALESCE(no_appearing, '1 (2-5)')
WHERE id = 'c8d0744e-5ff6-4ba5-a423-3ccc0cb67672' AND is_custom = FALSE;

-- Dragon, Metallic, Silver (matched by override)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Silberdrachen sind gütig und hilfsbereit. Sie unterstützen gerne gutgesinnte Kreaturen, wenn deren Not aufrichtig ist. Sie nehmen oft die Gestalt freundlicher alter Männer oder schöner Jungfrauen an, wenn sie mit Menschen verkehren.'),
  combat_tactics  = COALESCE(combat_tactics, 'Silberdrachen sind nicht gewalttätig und vermeiden Kämpfe, außer wenn sie hochgradig bösen oder aggressiven Feinden gegenüberstehen. Falls nötig, nutzen sie Federfall, um Geschosse abzuwehren, die auf sie abgefeuert werden. Sie setzen Nebelwand oder Wetter beherrschen ein, um Gegner zu blenden oder zu verwirren, bevor sie Nahkampfangriffe durchführen. Wenn sie zornig sind, nutzen sie Schwerkraft umkehren, um Feinde hilflos in die Luft zu schleudern, wo sie geschnappt werden können. Gegen fliegende Gegner versteckt sich ein Silberdrache in Wolken (oft erschafft er welche mit Wetter beherrschen an klaren Tagen), bleibt dort mittels Wolkenwandeln und springt dann zum Angriff, wenn er im Vorteil ist.'),
  habitat_society = COALESCE(habitat_society, 'Silberdrachen bevorzugen Luftbaue auf abgelegenen Berggipfeln oder inmitten der Wolken selbst. Wenn sie in Wolken hausen, gibt es immer einen verzauberten Bereich mit festem Boden zum Eierlegen und zur Schatzlagerung.'),
  ecology         = COALESCE(ecology, 'Silberdrachen bevorzugen menschliche Nahrung und können unbegrenzt von solcher Kost leben.'),
  no_appearing    = COALESCE(no_appearing, '1 (2-5)')
WHERE id = '17fe4c9b-cc38-43f8-ae49-3b920c777843' AND is_custom = FALSE;

-- Dragon, Shadow (matched by token_sort)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Schattendrachen sind verschlagen und hinterhältig. Sie sind instinktiv gerissen und neigen nicht dazu, Risiken einzugehen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Schattendrachen greifen bevorzugt aus dem Hinterhalt an und nutzen gewöhnlich Unsichtbarkeit oder verstecken sich in Schatten. Sie verwenden Illusions-/Phantasmazauber, um Feinde zu verwirren und in die Irre zu führen. Ältere Drachen sind besonders stolz auf ihre Fähigkeit der Entdeckungsimmunität.'),
  habitat_society = COALESCE(habitat_society, 'Schattendrachen hassen sowohl helles Licht als auch völlige Dunkelheit und bevorzugen abwechslungsreiche Beleuchtung mit Flecken diffusen Lichts und tiefen, tintenartigen Schatten. Auf der Primär-Materiellen Ebene sind ihre Baue immer Orte, die für den größten Teil des Tages schattiges Licht bieten. Sie bevorzugen alte Ruinen, wo sie sich unterirdisch verstecken können, wenn die Sonne hell scheint, und dennoch bei Sonnenauf- und -untergang Schatten über der Erde finden können. Auf der Ebene der Schatten leben sie in dichten Dickichten aus Bäumen und Dornengestrüpp, befestigten Burgen oder labyrinthartigen Höhlen. Auf beiden Ebenen ziehen sie es vor, ihre Baue in der Nähe von Kolonien anderer Kreaturen anzulegen, die sie vor potentiellen Feinden oder Opfern warnen können. Die Drachen kooperieren jedoch selten tatsächlich mit diesen Verbündeten, obwohl die Drachen sie gewöhnlich als Beute betrachten.'),
  ecology         = COALESCE(ecology, 'Schattendrachen fressen fast alles. Ihr Lieblingsfutter ist verwesendes Aas, obwohl sie oft zum Vergnügen töten. Getötete Opfer werden zum Verwesen liegen gelassen, bis sie entsprechend faulig werden. Diese Drachen mögen ebenso gern frostgetötete, durchnässte oder salzverseuchte Pflanzen.'),
  no_appearing    = COALESCE(no_appearing, '1 (2-5)')
WHERE id = '3447c7e6-2699-4acb-a204-e1cd69c6d142' AND is_custom = FALSE;

-- Dragon Turtle (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Drachenschildkröten sind eine der schönsten, ehrfurchtgebietendsten und gefürchtetsten Kreaturen des Wassers. Mit ihren tödlichen Kiefern und ihrer Atemwaffe und ihrer Neigung, Schiffe zum Kentern zu bringen, werden Drachenschildkröten von Seefahrern auf großen Gewässern gefürchtet, sowohl in Süß- als auch Salzwasser.'),
  combat_tactics  = COALESCE(combat_tactics, 'Obwohl Drachenschildkröten für den angenehmen Anblick von Licht, das auf Wasser glitzert, gehalten werden können, wird diese Illusion niemals lange aufrechterhalten. Drachenschildkröten sind wilde Kämpfer und greifen generell jede Kreatur an, die ihr Territorium bedroht oder sich als potenzielle Mahlzeit präsentiert. Im Kampf werden Drachenschildkröten gewöhnlich (90%) zuerst mit ihren furchtbaren Klauen und Zähnen angreifen. Ihr Panzer bietet der Schildkröte exzellenten Schutz, obwohl sie, sobald die Drachenschildkröte ein Opfer trifft, selten auf diese Sicherheitsvorkehrung angewiesen ist.'),
  habitat_society = COALESCE(habitat_society, 'Drachenschildkröten sind extrem einzelgängerische Kreaturen. Große, trostlose Meereshöhlen und geheime unterirdische Kavernen, die nur durch das Wasser erreichbar sind, sind ihre bevorzugten Baue. Diese Baue sind schwer zu finden, aber Abenteurer, die die Höhle einer Drachenschildkröte ausfindig machen, werden sie voller Schätze aller Art finden. Die Schildkröte sammelt diese Schätze, die sie bis zum Tod verteidigen wird, von den in ihrem Territorium versunkenen Schiffen.'),
  ecology         = COALESCE(ecology, 'Drachenschildkröten sind fleischfressend und werden fast jede Kreatur fressen, einschließlich Menschen oder andere Drachenschildkröten, um ihren unersättlichen Appetit zu befriedigen. Große Fische scheinen die bevorzugte Nahrung für Drachenschildkröten zu sein, und die Schildkröten können oft dabei angetroffen werden, wie sie im Unkraut und Schlamm am Boden eines Sees oder Meeres lauern und auf vorbeiziehende Fische warten. In besonders schlechten Jahren für Fische war es bekannt, dass Drachenschildkröten ihre Atemwaffe einsetzen, um große Gruppen von Seevögeln zu töten, die sich zu nah an das Wasser wagen, um Nahrung zu suchen.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = '420f276d-4f13-4298-8215-97426f08e953' AND is_custom = FALSE;

-- Dryad (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Dryaden sind wunderschöne, intelligente Baumkobolde. Sie sind jedoch so schwer fassbar wie verführerisch, und Dryaden werden selten gesehen, außer sie werden überrascht - oder sie wollen entdeckt werden.'),
  combat_tactics  = COALESCE(combat_tactics, 'Dryaden sind scheue, gewaltlose Wesen. Sie tragen selten Waffen, aber manchmal führen sie Messer als Werkzeuge mit sich. Obwohl eine Dryade dies als Waffe in einem Kampf verwenden kann, wird sie nicht zum Einsatz eines Messers greifen, außer sie ist ernsthaft bedroht.'),
  habitat_society = COALESCE(habitat_society, 'Einige Legenden behaupten, dass Dryaden die belebten Seelen sehr alter Eichen sind. Ob dies wirklich der Fall ist, es ist wahr, dass Dryaden an eine einzige, sehr große Eiche in ihrem Leben gebunden sind und aus keinem Grund mehr als 329,2 m von diesem Baum entfernt gehen können. Wenn eine Dryade weiter wegwandert, wird sie schwach und stirbt innerhalb von 6W6 Stunden, außer sie wird zu ihrem Heim zurückgebracht. Die Eichen der Dryaden strahlen keine Magie aus, aber jemand, der das Heim einer Dryade findet, hat große Macht über sie. Eine Dryade erleidet Schaden für jeden Schaden, der ihrem Heimatbaum zugefügt wird. Jeder Angriff auf den Baum einer Dryade wird natürlich eine rasende Verteidigung durch die Dryade zur Folge haben.'),
  ecology         = COALESCE(ecology, 'Dryaden sind standhafte Beschützerinnen der Wälder und Haine, in denen sie leben. Jede Handlung, die das Gebiet schädigt, und besonders sein Pflanzenleben, wird mit wenig Toleranz begegnet.'),
  no_appearing    = COALESCE(no_appearing, '1 or 1-6')
WHERE id = '92334491-6039-4655-a7e6-2b63cf58dccf' AND is_custom = FALSE;

-- Dwarf, Derro (matched by override)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Derro sind eine degenerierte Rasse von zwergenhafter Statur. Sie haben seit Ewigkeiten in der Unterdunkelheit gehaust, wurden aber erst vor fünf Jahrhunderten von den Gedankenräubern entdeckt, und von den Drow nur kurz davor. Die Derro haben sich durch ihre ausgeprägte Grausamkeit einen Namen gemacht. Es heißt, dass ein Derro für zwei Dinge lebt: den langsamen und demütigenden Tod von Oberflächenhalbmenschen und besonders Menschen, und die Pervertierung von Wissen für ihre eigenen dunklen Zwecke.'),
  combat_tactics  = COALESCE(combat_tactics, 'Derro sind eine der geschicktesten humanoiden Rassen (im Durchschnitt 15-18) und ihre Rüstungsklasse muss entsprechend angepasst werden. Normalerweise ist eine Derro-Gruppe gut mit Waffen und Zaubern ausgerüstet. Alle Derro tragen kleine, ornamentale Klingen namens Secari, die als Dolche behandelt werden können, aber die meisten nutzen auch andere Waffen.'),
  habitat_society = COALESCE(habitat_society, 'Derro leben in großen unterirdischen Komplexen, näher an der Oberfläche als die Kuo-Toa und Drow, aber tiefer als Goblins und Trolle. Sie setzen sich niemals direktem Sonnenlicht aus, da es ihnen übel wird. Sonnenlicht würde einen Derro töten, sollte er ihm für einige Tage ausgesetzt sein. Dennoch besuchen Derro gelegentlich nachts die Oberflächenwelt, überfallen Menschen oder führen die Pläne eines Gelehrten aus.'),
  ecology         = COALESCE(ecology, 'Derro können von einer Diät aus unterirdischen Pilzen leben, aber sie finden das Zeug widerlich schmeckend, wenn es als mehr als nur Gewürze verwendet wird.'),
  no_appearing    = COALESCE(no_appearing, '3-30')
WHERE id = '57753c72-30f1-480c-9b4a-a9f12dbe368c' AND is_custom = FALSE;

-- Dwarf, Duergar (matched by override)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Die Duergar oder Grauzwerge sind eine bösartige Rasse, die in den extremen Tiefen des Untergrunds lebt. Duergar können Kämpfer, Priester oder Diebe sein. Mehrkategorien-Duergar können Kämpfer/Priester, Kämpfer/Diebe oder Priester/Diebe sein. Dieb-Duergar sind im Umgang mit Gift bewandert.'),
  combat_tactics  = COALESCE(combat_tactics, 'Für jeden vier normalen 1-TW-Duergar, die außerhalb eines Baus angetroffen werden, gibt es einen mit 2+4 TW. Wenn eine Bande von neun Duergar außerhalb eines Baus angetroffen wird, führt immer ein zehnter Duergar mit 3+6 TW oder 4+8 TW die Gruppe an.'),
  habitat_society = COALESCE(habitat_society, 'Die Duergar sind anderen Zwergenkulturen ähnlich, obwohl das Leben viel härter ist aufgrund ihrer feindlichen Umgebung tief unter der Erde. Sie wagen sich nur nachts oder an den düstersten Tagen an die Oberfläche. Duergar leben länger als ihre oberflächenbewohnenden Verwandten. Die Lebensspanne kann 400 Jahre oder mehr erreichen.'),
  ecology         = COALESCE(ecology, 'Duergar verachten die anderen Zwergenrassen, die sie als verwöhnt, schwach und selbstsüchtig betrachten. Sie mögen sich mit bösen Zwergen verbünden und sogar Lebensraum teilen, aber die feindselige Natur der Duergar macht solche Allianzen extrem selten.'),
  no_appearing    = COALESCE(no_appearing, '2-9 or 201-300')
WHERE id = '3109c1b1-8242-4a1a-b533-e9bf12507de4' AND is_custom = FALSE;

-- Elemental, Air Kin (matched by override)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Sylphen sind wunderschöne, humanoide Frauen mit Flügeln wie Libellen. Ihre Flügel sind 1,2-1,5 m lang und durchscheinend, klar oder mit schillernden Farben gefleckt. Ihr langes, leuchtendes Haar kann jede "normale" Farbe haben oder blau, violett oder grün sein. Sie tragen fließende, durchsichtige Gewänder, die ihre Flügel oder ihr Haar betonen. Sylphen sind mit Luftelementaren und Nymphen verwandt, möglicherweise entstanden als Kreuzung zwischen Nymphen und Luftdienern. Sie sprechen die Gemeinsprache und ihre eigene melodische Sprache.'),
  combat_tactics  = COALESCE(combat_tactics, 'Sylphen greifen ihre Gegner nicht körperlich an. Stattdessen verwenden sie eine Vielzahl magischer Fähigkeiten.'),
  habitat_society = COALESCE(habitat_society, 'Sylphen berühren selten den Boden im Flachland. Sie reisen gerne, und es ist selten, eine in der Nähe ihres Zuhauses zu finden.'),
  ecology         = COALESCE(ecology, 'Sylphen halten normalerweise Abstand zu den gewöhnlicheren humanoiden Völkern, verkehren aber frei mit Nymphen und Dryaden. Flugmonster nähren sich gelegentlich von ihnen, aber sie sind in größerer Gefahr durch böse humanoide Männchen, die versuchen, sie für dunkle Zwecke zu fangen.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = '7d185771-221e-4269-8543-497e8737c3d2' AND is_custom = FALSE;

-- Elemental, Earth Kin (matched by override)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Die Pech sind Kreaturen der Ebene des elementaren Erds, obwohl einige ausgedehnte Minen in den tiefsten Regionen der Hauptmateriellen Ebene haben. Sie leben an dunklen Orten und bearbeiten Stein.'),
  combat_tactics  = COALESCE(combat_tactics, 'Die Pech verwenden Spitzhacken und Torfhämmer (behandle als Kriegshämmer) für Arbeit und Bewaffnung und sind gewöhnlich mit gleicher Anzahl von beiden ausgerüstet. Pech haben 18/50 Stärke.'),
  habitat_society = COALESCE(habitat_society, 'Pech sind grundsätzlich gute und friedliche Kreaturen, die in Ruhe gelassen werden wollen. Sie hassen helles Licht und offenen Himmel, und sie bitten andere schnell darum, Lichter zu löschen. Ihre Baue sind mit zahlreichen Engpässen konstruiert, sodass Steinwälle schnell Eindringlinge stoppen können. Ihr Bau beherbergt 10-40 Individuen, mit gleicher Anzahl von Weibchen und Männchen, und Junge entsprechend 20-50% der Weibchen.'),
  ecology         = COALESCE(ecology, 'Die Heimatebene der Pech ist feindlich, daher reisen viele zur Hauptmateriellen Ebene, um nach einem besseren Leben zu suchen. Sie haben dort wenige Feinde. Pech sparen keine großen Mengen Schätze; sie schürfen nach Dingen, die sie mit anderen gegen Nahrung oder Dienstleistungen tauschen können. Sie erschaffen manchmal einfache, unauffällige Ziergegenstände für den täglichen Gebrauch. Ein Pech-Bau kann 50-100 Handelsjuwelen plus 5-30 aus Stein und Rohmetall gearbeitete Geschirr und Utensilien enthalten. Diese Gegenstände sind nicht sehr wertvoll und kosten durchschnittlich 150 GM pro Stück.'),
  no_appearing    = COALESCE(no_appearing, '5-20')
WHERE id = '79d7f51a-5278-4a6b-8596-4dca881c76ba' AND is_custom = FALSE;

-- Elemental, Fire Kin (matched by override)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Salamander sind Eingeborene der Elementarebene des Feuers und gedeihen daher an heißen Orten. Diese grausamen, bösen Kreaturen kommen aus nur ihnen bekannten Gründen auf die Erste Materielle Ebene.'),
  combat_tactics  = COALESCE(combat_tactics, 'Ein Salamander greift normalerweise mit seinem Metallspeer an, der 1W6 Schadenspunkte plus die gleiche Menge für die Hitze des Speers verursacht. Gleichzeitig kann er mit seinem schlangenartigen Schwanz ausschlagen und einen Gegner umschlingen, wobei er 2W6 Schadenspunkte durch Zusammenschnürung verursacht, plus zusätzliche 1W6 Schadenspunkte durch die Hitze seines Körpers. Während feuerresistente Kreaturen nicht unter dem Hitzeschaden des Salamanders leiden, sind sie dennoch dem Speer- und Zusammenschnürungsschaden unterworfen.'),
  habitat_society = COALESCE(habitat_society, 'Salamander sind Eingeborene der Elementarebene des Feuers. Sie kommen aus nur ihnen bekannten Gründen auf die Erste Materielle Ebene, obwohl es Gerüchte gibt, dass mächtige Magier und Priester bestimmter Religionen sie für kurze Zeit herbeirufen können. Salamander hassen Kälte und bevorzugen Temperaturen von 150 Grad oder mehr; sie können niedrigere Temperaturen nur für wenige Stunden ertragen. Ihre Baue sind normalerweise mindestens 260 Grad heiß. Alle dort gefundenen Schätze sind solche, die dieser Hitze standhalten können, wie Schwerter, Rüstungen, Stäbe, andere eisenhaltige Gegenstände und Juwelen. Brennbare Dinge wie Pergament und Holz, weiche Metalle wie Gold und Silber und Flüssigkeiten, die schnell verdampfen, werden niemals in Salamander-Bauen gefunden.'),
  ecology         = COALESCE(ecology, 'Das Blut dieser feurigen Kreaturen ist nützlich bei der Herstellung von Tränken der Feuerresistenz, und das Metall ihrer Speere kann zur Erschaffung von Ringen der Feuerresistenz verwendet werden.'),
  no_appearing    = COALESCE(no_appearing, '2-5')
WHERE id = '288432a5-3ef5-45bc-8819-40d253c17be7' AND is_custom = FALSE;

-- Elf, Drow (matched by override)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Diese gefürchteten, bösen Kreaturen waren einst Teil der Elfengemeinschaft, die noch immer durch die Wälder der Welt wandelt. Nun bewohnen diese Dunkelelfen schwarze Höhlen und gewundene Tunnel unter der Erde, wo sie düstere Pläne gegen die Völker schmieden, die noch unter der Sonne auf der Oberfläche der grünen Erde wandeln.'),
  combat_tactics  = COALESCE(combat_tactics, 'Die Welt der Drow ist eine, in der gewalttätige Konflikte Teil des Alltags sind. Es sollte daher nicht überraschen, dass die meisten angetroffenen Drow, ob allein oder in einer Gruppe, kampfbereit sind. Drow, die außerhalb einer Drow-Stadt angetroffen werden, sind mindestens Kämpfer der 2. Stufe.'),
  habitat_society = COALESCE(habitat_society, 'Vor langer Zeit waren Dunkelelfen Teil der Elfenrasse, die durch die Wälder der Welt wandelte. Nicht lange nach ihrer Erschaffung fanden sich die Elfen jedoch in rivalisierende Fraktionen gespalten - eine folgte den Grundsätzen des Bösen, die andere besaß die Ideale des Guten (oder zumindest der Neutralität). Ein großer Bürgerkrieg zwischen den Elfen folgte, und die selbstsüchtigen Elfen, die den Pfaden des Bösen und Chaos folgten, wurden in die Tiefen der Erde getrieben, in die düsteren, lichtlosen Höhlen und tiefen Tunnel der Unterwelt. Diese Dunkelelfen wurden zu den Drow.'),
  ecology         = COALESCE(ecology, 'Die Drow stellen ungewöhnliche Waffen und Kleidung mit quasi-magischen Eigenschaften her. Einige Schreiber und Forscher vermuten, dass es die seltsame Strahlung um Drow-Städte ist, die Drow-Handwerk besonders macht. Andere theoretisieren, dass feine Handwerkskunst ihren wunderbar starken Metallen und überlegenem Stoff seine einzigartigen Eigenschaften verleiht. Was auch immer der Grund ist, es ist klar, dass die Drow einen Weg entdeckt haben, ihre Kleidung und Waffen ohne den Einsatz von Magie herzustellen.'),
  no_appearing    = COALESCE(no_appearing, '5-50')
WHERE id = '43284770-cfb7-47dc-b83e-9762c1325745' AND is_custom = FALSE;

-- Galeb Duhr (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Der Galeb Duhr ist ein merkwürdiges felsblockartiges Wesen mit Gliedmaßen, die als Hände und Füße fungieren. Diese intelligenten Kreaturen sind sehr groß und bewegen sich langsam. Sie leben in felsigen oder bergigen Gebieten, wo sie die Erdkraft spüren und die Felsen um sie herum kontrollieren können.'),
  combat_tactics  = COALESCE(combat_tactics, 'Galeb Duhr sind ziemlich einzelgängerische Kreaturen, die es vorziehen, mit einigen ihrer eigenen Art zu leben, und mit keiner anderen Art, einschließlich Erdelementaren. Wenn sie genähert werden, neigen Galeb Duhr dazu, der Begegnung auszuweichen, indem sie in der Erde verschwinden. Wenn sie jedoch verfolgt oder anderweitig gereizt werden, zögern Galeb Duhr nicht, den Eindringling zu bekämpfen.'),
  habitat_society = COALESCE(habitat_society, 'Galeb Duhr, von denen angenommen wird, dass sie von der Elementarebene der Erde stammen, werden manchmal in kleinen Familiengruppen in bergigen Regionen der Hauptmateriellen Ebene angetroffen. Es ist nicht bekannt, wie (oder ob) sich Galeb Duhr fortpflanzen, aber "junge" Galeb Duhr wurden gelegentlich berichtet - diese angetroffenen Exemplare waren kleiner als normal.'),
  ecology         = COALESCE(ecology, 'Galeb Duhr haben keine natürlichen Feinde, außer denen, die nach den Edelsteinen gieren, die sie sammeln. Galeb Duhr fressen Gestein und bevorzugen Granit vor anderen Arten, während sie jede Sedimentart verschmähen. Die Felsen, die sie fressen, werden Teil der riesigen Kreaturen; eine solche Mahlzeit muss nur alle zwei oder drei Monate stattfinden.'),
  no_appearing    = COALESCE(no_appearing, '1-4')
WHERE id = 'c57eda81-68da-4c6d-923e-086a0c7beffa' AND is_custom = FALSE;

-- Ghost (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Geister sind die Seelen von Menschen, die entweder im Leben außerordentlich böse waren oder deren Tod so ungewöhnlich emotional war, dass sie mit der Gabe des Untotenstatus verflucht wurden. Daher wandeln sie nachts oder an dunklen Orten umher. Diese Geister hassen Güte und Leben und hungern danach, die Lebensessenz von den Lebenden zu ziehen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Da Geister unkörperlich (ätherisch) sind, begegnet man ihnen gewöhnlich nur als Kreatur in einem ähnlichen Zustand, obwohl sie von nicht-ätherischen Kreaturen gesehen werden können. Die übernatürliche Macht eines Geistes ist jedoch derart, dass der bloße Anblick eines Geistes jedes humanoide Wesen 10 Jahre altern lässt und es für 2-12 (2W6) Runden panisch fliehen lässt, es sei denn, ein Rettungswurf gegen Zauber gelingt. Priester über der 6. Stufe sind gegen diesen Effekt immun, und alle anderen Humanoiden über der 8. Stufe dürfen +2 zu ihren Rettungswürfen addieren.'),
  habitat_society = COALESCE(habitat_society, 'In den meisten Fällen ist ein Geist auf ein kleines physisches Gebiet beschränkt, das der Geist heimsucht. Diejenigen, die Geschichten über ein verfluchtes Gebiet gehört haben, können daher versuchen, es zu ihrer eigenen Sicherheit zu meiden.'),
  ecology         = COALESCE(ecology, 'Die schreckliche Furcht, die der Geist verursacht und die ein Opfer 10 Jahre altern lässt, wird vom gewöhnlichen Menschen nicht gut verstanden, der sie oft der Tatsache zuschreibt, dass ein Geist "tot" ist. Wenn dies der Fall wäre, dann hätten sicherlich Skelette und Zombies denselben Effekt, was sie jedoch nicht haben.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = 'a4ccb67d-9f4f-4ab4-9ef6-26fdb76bcf20' AND is_custom = FALSE;

-- Ghoul (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Ghule sind untote Kreaturen, einst Menschen, die sich nun vom Fleisch von Leichen nähren. Obwohl der Wandel vom Menschen zum Ghul ihren Verstand zerrüttet und zerstört hat, besitzen Ghule eine schreckliche Verschlagenheit, die es ihnen ermöglicht, ihre Beute höchst wirkungsvoll zu jagen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Ghule greifen an, indem sie mit ihren schmutzigen Nägeln kratzen und mit ihren Reißzähnen beißen. Ihre Berührung bewirkt, dass Menschen (einschließlich Zwerge, Gnome, Halbelfen und Halblinge, aber ausgenommen Elfen) erstarren, es sei denn, ein Rettungswurf gegen Lähmung ist erfolgreich. Diese Lähmung dauert 3-8 (2+1W6) Runden oder bis sie von einem Priester aufgehoben wird.'),
  habitat_society = COALESCE(habitat_society, 'Ghule und Ghasts werden am häufigsten in der Nähe von Friedhöfen angetroffen, wo sie reichlich Leichen finden können, von denen sie sich nähren.'),
  ecology         = COALESCE(ecology, 'Ghule (und Ghasts, wie später beschrieben) erfreuen sich an widerlichen und abscheulichen Dingen - woraus wir unsere Adjektive "ghulisch" und "grässlich" ableiten.'),
  no_appearing    = COALESCE(no_appearing, '2-24 (2d12)')
WHERE id = '78386fa7-ba98-408c-90f5-f07fabbf6e56' AND is_custom = FALSE;

-- Giant, Cloud (matched by token_sort)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Wolkenriesen betrachten sich selbst als über allen anderen Riesen stehend, außer den Sturmriesen, die sie als Gleichgestellte ansehen. Sie sind kreativ, schätzen schöne Dinge und sind Meisterstrategen im Kampf.'),
  combat_tactics  = COALESCE(combat_tactics, 'Wolkenriesen kämpfen in gut organisierten Einheiten und verwenden sorgfältig entwickelte Schlachtpläne. Sie ziehen es vor, aus einer Position über ihren Gegnern zu kämpfen. Eine beliebte Taktik besteht darin, den Feind zu umkreisen und ihn mit Steinen zu bombardieren, während die Riesen mit magischen Fähigkeiten ihn mit Zaubersprüchen angreifen. Wolkenriesen können Steine bis zu einer maximalen Reichweite von 219,5 m schleudern und dabei 2-24 (2W12) Schadenspunkte verursachen. Ihre riesigen Morgensterne verursachen 6-24 (6W4) +11 Schadenspunkte, das Dreifache des normalen (menschengroßen) Schadens plus ihren Stärkebonus. Einer von 10 Wolkenriesen wird eine magische Waffe besitzen.'),
  habitat_society = COALESCE(habitat_society, 'Wolkenriesen leben in kleinen Sippen von höchstens sechs Riesen. Diese Sippen kennen jedoch die Lage von 1-8 anderen Sippen und werden sich mit einigen dieser Sippen für Feierlichkeiten, Schlachten oder zum Handel zusammenschließen. Diese vereinten Sippen werden einen von ihnen als ihren Anführer anerkennen - dies ist gewöhnlich ein älterer Wolkenriese, der magische Fähigkeiten besitzt. Einer von 10 Wolkenriesen wird Zaubersprüche haben, die einem Magier der 4. Stufe entsprechen, und einer von 20 Wolkenriesen wird einem Priester der 4. Stufe entsprechen. Ein Wolkenriese kann nicht sowohl Priester- als auch Magierfähigkeiten haben.'),
  ecology         = COALESCE(ecology, 'Wolkenriesen bevorzugen sorgfältig zubereitete Speisen mit Gewürzen und Saucen und schätzen erlesene, gereifte Weine.'),
  no_appearing    = COALESCE(no_appearing, '1-10')
WHERE id = 'ee6abec1-6722-4373-9748-65992fc5de87' AND is_custom = FALSE;

-- Giant, Fire (matched by token_sort)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Feuerriesen sind brutal, rücksichtslos und militaristisch.'),
  combat_tactics  = COALESCE(combat_tactics, 'Feuerriesen sind immun gegen nichtmagisches Feuer und Hitze sowie gegen den Atem Roter Drachen. Sie sind resistent gegen alle Arten von magischem Feuer; solche Angriffe verursachen -1 Trefferpunkt pro Schadenswürfel. Erwachsene Feuerriesen können Steine für 2-20 (2W10) Schadenspunkte schleudern. Ihre Mindestreichweite beträgt 2,7 m, während ihre Maximalreichweite 182,9 m ist. Sie können ähnlich große Geschosse zu 50% der Zeit abfangen. Sie kämpfen üblicherweise in disziplinierten Gruppen und werfen Steine, bis ihnen die Munition ausgeht oder der Gegner in den Nahkampf kommt. Feuerriesen warten oft in Hinterhalten an Lavaseen oder heißen Quellen und schleudern erhitzte Steine auf Opfer für zusätzliche 1-6 Schadenspunkte.'),
  habitat_society = COALESCE(habitat_society, 'Feuerriesen leben in gut organisierten militärischen Gruppen und bewohnen große Burgen oder Höhlen. Wenn sie in ihrem Bau angetroffen werden, sind dort 13-20 (1W8+12) Riesen, von denen die Hälfte unreife Riesen sind. Um die Reife eines Riesen zu bestimmen, würfle 1W4. Ein Wurf von 4 zeigt ein Kleinkind ohne Kampffähigkeit und mit den Trefferpunkten eines Ogres an, während Würfe von 1-3 ältere Nachkommen mit um 1, 2 bzw. 3 reduzierten Trefferwürfeln, Schaden und Angriffswürfen anzeigen.'),
  ecology         = COALESCE(ecology, 'Feuerriesen leben überall dort, wo es viel Hitze gibt. Sie bevorzugen vulkanische Gebiete oder Bereiche mit heißen Quellen. Häufig teilen sie ihre Baue mit anderen feuerbewohnenden Kreaturen wie Salamandern oder Feuerelementaren.'),
  no_appearing    = COALESCE(no_appearing, '1-8')
WHERE id = 'a41b6f32-3409-4a2d-97e8-5c1e4a715f6c' AND is_custom = FALSE;

-- Giant, Frost (matched by token_sort)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Wie alle bösen Riesen haben Frostriesen einen Ruf für Rohheit und Dummheit. Dieser Ruf ist berechtigt, aber Frostriesen sind verschlagene Kämpfer.'),
  combat_tactics  = COALESCE(combat_tactics, 'Frostriesen sind immun gegen Kälte. Erwachsene Frostriesen können Steine für 2-20 (2W10) Schadenspunkte schleudern. Ihre Mindestreichweite beträgt 2,7 m, während ihre Maximalreichweite 182,9 m beträgt. Sie können ähnliche große Geschosse zu 40% der Zeit abfangen. Normalerweise beginnen sie den Kampf aus der Distanz und werfen Steine, bis ihnen die Munition ausgeht oder der Gegner näher kommt. Eine ihrer bevorzugten Strategien ist es, Opfer zu überfallen, indem sie sich im Schnee an der Spitze eines eisigen oder schneereichen Hangs vergraben, wo Gegner Schwierigkeiten haben werden, sie zu erreichen.'),
  habitat_society = COALESCE(habitat_society, 'Frostriesen leben in kleinen Banden, die aus einem Anführer, seinen Handlangern und ihren Mitläufern bestehen. Eine Bande besetzt normalerweise eine primitive Burg oder eisige Höhle. Wenn sie in ihrem Bau angetroffen werden, sind 9-16 (1W8+8) Riesen anwesend; die Hälfte davon ist unreif. Um die Reife eines Riesen zu bestimmen, wirf 1W4. Ein Wurf von 4 zeigt einen Säugling ohne Kampffähigkeiten und mit den Trefferpunkten eines Oggers an; Würfe von 1-3 zeigen ältere Nachkommen mit Trefferwürfeln, Schaden und Angriffswürfen eines Steinriesen an.'),
  ecology         = COALESCE(ecology, 'Frostriesen leben in eiskalten, arktischen Ländern mit Gletschern und starkem Schneefall. Frostriesen essen hauptsächlich Fleisch, das sie selbst jagen und töten können. Sie überfallen menschliche und Halbmenschen-Siedlungen wegen Nahrungsmitteln und anderer Beute.'),
  no_appearing    = COALESCE(no_appearing, '1-8')
WHERE id = 'a822e9d0-3341-437d-b493-bdc155be2a0a' AND is_custom = FALSE;

-- Giant, Hill (matched by token_sort)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Hügelriesen sind selbstsüchtige, gerissene Bestien, die durch Jagd und durch Terrorisierung und Plünderung nahegelegener Gemeinden überleben. Trotz ihrer niedrigen Intelligenz sind sie fähige Kämpfer.'),
  combat_tactics  = COALESCE(combat_tactics, 'Hügelriesen ziehen es vor, ihre Gegner von hohen Felsklippen aus zu bekämpfen, wo sie ihre Ziele mit Steinen und Felsbrocken bombardieren können, während sie die Risiken für sich selbst begrenzen.'),
  habitat_society = COALESCE(habitat_society, 'Ein Hügelriesenbau wird 9-16 (1d8+8) Riesen haben; gewöhnlich eine Großfamilie. Manchmal nehmen diese Familien einzelne Hügelriesen in ihre Reihen auf. Wenn sechs oder mehr Riesen in einem Bau angetroffen werden, ist die Hälfte von ihnen männlich, ein Viertel weiblich und der Rest sind unreife Riesen. Um die Reife eines Riesen zu bestimmen, würfle 1d4. Ein Wurf von 4 zeigt einen Säugling ohne Kampffähigkeit und mit Trefferpunkten eines Gnolls an; Würfe von 1-3 zeigen ältere Nachkommen mit Trefferwürfeln, Schaden und Angriffswürfen gleich denen eines Ogers.'),
  ecology         = COALESCE(ecology, 'Die Hauptnahrung der Hügelriesen besteht aus Fleisch, das sie durch Jagd erlangen. Das Fleisch junger Grüner Drachen gilt als Delikatesse, und häufig organisieren Riesen, die auf bewaldeten Hügeln und Bergen leben, Jagdgruppen auf der Suche nach Grünen Drachen-Horten. Im Gegenzug ist bekannt, dass Grüne Drachen Hügelriesen jagen.'),
  no_appearing    = COALESCE(no_appearing, '1-12')
WHERE id = '17692fd9-dd69-4f43-b41b-aaa638cd195e' AND is_custom = FALSE;

-- Giant, Stone (matched by token_sort)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Steinriesen sind schlank, aber muskulös. Ihr hartes, haarloses Fleisch ist glatt und grau, wodurch sie leicht mit ihrer bergigen Umgebung verschmelzen können. Ihre hageren Gesichtszüge und tiefen, eingesunkenen schwarzen Augen lassen sie stets grimmig erscheinen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Wenn möglich, kämpfen Steinriesen aus der Entfernung. Sie können Steine über eine Mindestentfernung von 2,7 m bis zu einer Maximalentfernung von 274,3 m schleudern und verursachen mit jedem Stein 3-30 (3W10) Schadenspunkte. Diese Riesen können Steine und ähnliche Wurfgeschosse zu 90% der Zeit abfangen. Eine beliebte Taktik der Steinriesen ist es, nahezu bewegungslos vor Felsen zu stehen, mit dem Hintergrund zu verschmelzen, dann hervorzutreten und Steine zu werfen, um ihre Feinde zu überraschen. Viele Riesen errichten Steinhaufen in der Nähe ihrer Baue, die wie eine Lawine ausgelöst werden können, wenn Eindringlinge zu nahe kommen.'),
  habitat_society = COALESCE(habitat_society, 'Steinriesen bevorzugen es, in tiefen Höhlen hoch auf felsigen, sturmgepeitschten Bergen zu wohnen. Normalerweise leben sie in Gesellschaft ihrer Verwandten, obwohl solche Sippen gewöhnlich nicht mehr als 10 Riesen umfassen. Riesensippen errichten ihre Baue jedoch nahe beieinander, um Gemeinschaftsgefühl und Schutz zu haben. Ein Gebirgszug beherbergt üblicherweise 2-8 Sippen.'),
  ecology         = COALESCE(ecology, 'Steinriesen sind Allesfresser, aber sie essen nur frische Nahrung. Sie kochen und essen ihr Fleisch schnell, nachdem es getötet wurde. Sie verwenden die Häute der Tiere als Decken und tauschen, was sie nicht brauchen, mit nahegelegenen menschlichen Gemeinschaften gegen Stoffballen oder Herdentiere ein, die sie als Nahrung verwenden. Viele Steinriesengruppen halten Riesenziegen in und nahe ihren Bauen, damit sie eine kontinuierliche Versorgung mit Milch, Käse und Butter haben.'),
  no_appearing    = COALESCE(no_appearing, '1-10')
WHERE id = '1a4628fd-cde4-4067-904a-89584c34647d' AND is_custom = FALSE;

-- Giant, Storm (matched by token_sort)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Sturmriesen sind sanftmütig und zurückgezogen lebend. Sie sind normalerweise tolerant gegenüber anderen, können aber sehr gefährlich werden, wenn sie wütend sind.'),
  combat_tactics  = COALESCE(combat_tactics, 'Alle Sturmriesen sind immun gegen Elektrizität und Blitze. Sie verwenden Waffen und besondere Fähigkeiten anstatt Steine zu schleudern, können aber große Geschosse zu 65% der Zeit abfangen.'),
  habitat_society = COALESCE(habitat_society, 'Sturmriesen sind zurückgezogen und einzelgängerisch, aber nicht schüchtern. Sie leben in Burgen, die auf Wolkeninseln (60%), Berggipfeln (20%) oder unter Wasser (10%) erbaut sind. Sie führen ein ruhiges, nachdenkliches Leben und verbringen ihre Zeit damit, über die Welt zu sinnieren, Musik zu komponieren und zu spielen sowie ihr Land zu bestellen oder Nahrung zu sammeln. Land- und luftbewohnende Sturmriesen stehen gewöhnlich auf gutem Fuß mit benachbarten Silberdrachen und guten Wolkenriesen und arbeiten mit ihnen zur gemeinsamen Verteidigung zusammen. Wasserlebende Sturmriesen haben ähnliche Beziehungen zu Meermenschen und Bronzedrachen.'),
  ecology         = COALESCE(ecology, 'Sturmriesen leben vom Land in der unmittelbaren Umgebung ihrer Bauten. Wenn die natürliche Ernte nicht ausreicht, um sie zu versorgen, schaffen und bestellen sie sorgfältig große Gebiete von Gärten, Feldern und Weinbergen. Sie halten keine Tiere als Nahrung, sondern ziehen es vor zu jagen.'),
  no_appearing    = COALESCE(no_appearing, '1 (2-4)')
WHERE id = 'f97dd1c6-b4d2-498b-8a7e-2d7ffb424e11' AND is_custom = FALSE;

-- Githyanki (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Githyanki sind eine uralte Rasse, die von Menschen abstammt. Sie bewohnen die Astralebene, verlassen diese Ebene aber oft, um anderen Rassen den Krieg zu erklären. Sie sind in einen langwierigen Krieg mit den Githzerai verwickelt.'),
  combat_tactics  = COALESCE(combat_tactics, 'Die Githyanki hatten lange Jahre Zeit, die Kriegskunst zu perfektionieren. Ihre bloße Existenz zeugt von ihrer Kampftüchtigkeit. Jeder einzelne Githyanki hat eine Charakterklasse und Stufe, von denen Dinge wie ETW0, Rüstungsklasse, Zaubergebrauch usw. abgeleitet werden.'),
  habitat_society = COALESCE(habitat_society, 'Die Geschichte liefert einige Informationen über die Githyanki - ihre Rasse ist sowohl uralt als auch zurückgezogen lebend. Gelehrte glauben, dass sie einst Menschen waren, die von Gedankenschindern gefangen genommen wurden, um als Sklaven und Vieh zu dienen. Die Gedankenschinder behandelten ihre menschlichen Sklaven grausam und das Volk hegte einen tiefen Groll gegen die Illithiden. Jahrhundertelang steigerten diese Menschen ihren Hass, konnten aber nicht die notwendige Kraft aufbringen, um sich zu befreien. So warteten sie viele Jahre, entwickelten heimlich ihre Macht und warteten auf eine Gelegenheit, gegen ihre Herren zu schlagen. Schließlich trat eine mächtige Frau unter ihnen hervor, eine Befreierin namens Gith. Sie überzeugte das Volk, sich gegen ihre grausamen Herren zu erheben. Der Kampf war lang und bösartig, aber schließlich befreiten sich die Menschen. Sie hatten ihre Freiheit verdient und wurden zu den Githyanki (was in ihrer Sprache Söhne von Gith bedeutet).'),
  ecology         = COALESCE(ecology, 'Githyanki haben eine ähnliche Ökologie wie die der Menschen. Jedoch bietet die Astralebene nicht dieselben Arten von Umgebungen wie die Primäre Materialebene, daher sind ihre kulturellen Gruppen sehr anders. In einer Gesellschaft, wo Bauern und Handwerker unnötig sind, haben sich einzigartigere, spezialisierte Gruppen entwickelt.'),
  no_appearing    = COALESCE(no_appearing, '2-8 (away from lair)')
WHERE id = '5802a342-dcf4-43d4-aae3-fd2ada78867a' AND is_custom = FALSE;

-- Githzerai (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Githzerai sind die klösterlichen, chaotisch neutralen Gegenstücke zu den Githyanki. Die beiden Völker teilen einen Abschnitt ihrer Geschichte; die Githzerai sind der geringere und stärker unterdrückte Ableger des ursprünglichen Volkes, dem die Kriegerin Gith vor Jahrtausenden zur Flucht aus der Sklaverei unter den Gedankendieben verhalf.'),
  combat_tactics  = COALESCE(combat_tactics, 'Die Githzerai sind schmucklos und rücksichtslos geradlinig in ihrem Kampf und ihrer Magie. Ihre starke Magieresistenz scheint ihre allgemein schlechtere Kampffähigkeit auszugleichen.'),
  habitat_society = COALESCE(habitat_society, 'Die Githzerai waren ursprünglich Nachkommen einer Menschenrasse, die von der Sklaverei unter Gedankendieben durch eine große weibliche Kriegerin namens Gith befreit wurden. Diese Männer und Frauen entschieden sich jedoch nicht, Giths Wegen zu folgen, nachdem sie gegen ihre Sklavenhalter revoltierten. Stattdessen fielen sie den Lehren eines mächtigen Magiers anheim, der sich zum König - und später zum Gott - des Volkes erklärte. Die Githzerai trennten sich dann von den Githyanki und begannen einen großen Rassenkrieg, der die langen Jahrtausende ohne Nachlassen überdauert hat.'),
  ecology         = COALESCE(ecology, 'Solange Menschen von der Fähigkeit wissen, durch die Ebenen zu reisen, haben sie sich über die natürliche Macht der Githzerai gewundert, nach Belieben von Ebene zu Ebene zu wandern. Obwohl Mensch und Githzerai keine natürlichen Feinde sind, werden häufig Schlachten zwischen den beiden Völkern geführt, teilweise aufgrund des Verlangens einiger Menschen, einen lebenden Githzerai zum Studium zu fangen. Bis heute wurde kein solches Wesen gesichert.'),
  no_appearing    = COALESCE(no_appearing, '2-8 (away from lair)')
WHERE id = 'efaefbf8-50ba-45f3-8658-dd7cfba2ec40' AND is_custom = FALSE;

-- Goblin (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Diese kleinen, bösen Humanoiden wären nur lästige Schädlinge, wären da nicht ihre großen Zahlen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Goblins hassen helles Sonnenlicht und kämpfen mit -1 auf ihre Angriffswürfe, wenn sie ihm ausgesetzt sind. Diese ungewöhnliche Lichtempfindlichkeit dient den Goblins jedoch unter der Erde gut und verleiht ihnen Infrasicht bis zu 18,3 m.'),
  habitat_society = COALESCE(habitat_society, 'Menschen würden die Höhlen und unterirdischen Behausungen der Goblins als feucht und düster betrachten. Jene wenigen Stämme, die oberirdisch leben, finden sich in Ruinen und sind nur nachts oder an sehr dunklen, bewölkten Tagen aktiv. Sie verwenden keinerlei sanitäre Einrichtungen, und ihre Baue haben einen üblen Gestank. Goblins scheinen einigermaßen widerstandsfähig gegen die Krankheiten zu sein, die in solchem Schmutz gedeihen.'),
  ecology         = COALESCE(ecology, 'Goblins werden nur etwa 50 Jahre alt. Sie müssen nicht viel essen, töten aber allein aus Vergnügen. Sie fressen jede Kreatur von Ratten und Schlangen bis zu Menschen. In mageren Zeiten fressen sie Aas.'),
  no_appearing    = COALESCE(no_appearing, '4-24 (4d6)')
WHERE id = '3331794c-ecfc-4d56-9e23-1f211a9120c3' AND is_custom = FALSE;

-- Griffon (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Halb Löwe, halb Adler, sind Greifen wilde gefiederte Fleischfresser, die Pferde und ihre Verwandten (Hippogreifen, Pegasi und Einhörner) jagen. Dieser Hunger nach Pferdefleisch bringt Greifen oft in direkten Konflikt mit Menschen und Halbmenschen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Greifen jagen in Gruppen von höchstens 12 und durchsuchen die Ebenen und Wälder in der Nähe (innerhalb von 32,2 km) ihres Baus nach Pferden und Herdentieren. Mit ihrer überlegenen Sicht und ihrem Geruchssinn können Greifen Beute bis zu zwei Meilen Entfernung entdecken. Wenn die Beute ein Pferd oder ein Pferderverwandter ist, greifen Greifen zu 90% an, auch wenn die Pferde Reiter haben. Greifen jagen nur nach Nahrung, daher kann ein Reiter, der ein oder zwei Pferde freigibt, meist unverletzt entkommen (obwohl sein Pferd höchstwahrscheinlich nicht überlebt). Jeder Versuch, ein Pferd zu schützen, zieht die volle Wut der angreifenden Greifen auf den Beschützer.'),
  habitat_society = COALESCE(habitat_society, 'Greifen bevorzugen felsige Lebensräume in der Nähe offener Ebenen. Sobald Greifen ihr Territorium etabliert haben, bleiben sie dort, bis die Nahrungsversorgung erschöpft ist.'),
  ecology         = COALESCE(ecology, 'Wenn sie von sehr frühem Alter an (drei Jahre oder weniger) trainiert werden, dienen Greifen als Reittiere. Das Training ist jedoch sowohl zeitaufwändig als auch teuer und erfordert die Fachkenntnis eines Tierbändigers für zwei Jahre. Einmal ausgebildet sind Greifen jedoch wilde und treue Reittiere, die sich ein Leben lang an einen Meister binden und ihn sogar bis in den Tod beschützen. Ein Greifenreittier kennt keine Furcht im Kampf, greift aber Pferde oder Pferderverwandte anderen Gegnern vor.'),
  no_appearing    = COALESCE(no_appearing, '2-12')
WHERE id = '98979f50-f737-4a52-8b7c-eb86dd4603e3' AND is_custom = FALSE;

-- Hook Horror (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Der Hakenschrecken ist ein zweibeiniges, unterirdisch lebendes Monster, das wie eine Kreuzung zwischen einem Geier und einem Menschen mit Haken anstelle von Händen aussieht.'),
  combat_tactics  = COALESCE(combat_tactics, 'Hakenschrecken haben scharfes Gehör und werden nur bei einem Wurf von 1 überrascht. Sie kennen immer ihr Territorium und versuchen ahnungslose Reisende oder Höhlenbewohner zu überfallen. Jede Runde schlagen sie mit beiden Haken zu. Wenn in einer Runde beide treffen, trifft ihr Schnabel in derselben Runde automatisch. Sie fügen automatisch 2W6 Schadenspunkte jede Runde mit dem Schnabel zu, bis mindestens einer der Haken gelöst wird.'),
  habitat_society = COALESCE(habitat_society, 'Der offensichtliche Nachteil, Haken anstelle von Händen zu haben, ist, dass Hakenschrecken keine Waffen oder Werkzeuge verwenden können. Sie können Gegenstände nur mit ihren Schnäbeln aufheben. Dies schränkt ihre Fähigkeit, große Schätze anzuhäufen, stark ein.'),
  ecology         = COALESCE(ecology, 'Obwohl Hakenschrecken grundsätzlich Allesfresser sind, bevorzugen sie Fleisch. Sie können fast jeden höhlenbewohnenden Pilz, Pflanzen, Flechten oder Tiere fressen. Hakenschrecken sind gut an das Höhlenleben angepasst. Sie haben wenige natürliche Feinde, obwohl alles, was es schafft, einen zu fangen, versuchen würde, ihn zu fressen. Das Exoskelett des Hakenschreckens trocknet aus und wird nach etwa einem Monat zu spröde für die Verwendung.'),
  no_appearing    = COALESCE(no_appearing, '2-12')
WHERE id = '07f3428c-6230-4949-bbab-202102c4e26d' AND is_custom = FALSE;

-- Imp (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Kobolde sind winzige Kreaturen böser Natur, die durch die Welt wandern und als Vertraute für rechtschaffen böse Magier und Priester dienen.'),
  combat_tactics  = COALESCE(combat_tactics, 'In seiner natürlichen Form greift der Kobold mit dem bösartigen Stachel an seinem Schwanz an. Zusätzlich zu 1-4 Schadenspunkten injiziert dieser Stachel ein mächtiges Gift, das so tödlich ist, dass diejenigen, die ihren Rettungswurf gegen Gift verfehlen, sofort daran sterben. Wenn er verwandelt ist, greift der Kobold mit den natürlichen Waffen seiner angenommenen Form an, obwohl die Ziegen- und Rabenform keine schadenverursachenden Angriffe besitzen.'),
  habitat_society = COALESCE(habitat_society, 'Kobolde sind Wesen sehr böser Natur, die aus den dunkelsten bösen Ebenen stammen. Ihr Hauptzweck auf der Materiellen Hauptebene ist es, das Böse zu verbreiten, indem sie rechtschaffen bösen Magiern und Priestern helfen. Wenn eine solche Person des Dienstes eines Kobolds für würdig befunden wird, kommt der Kobold als Antwort auf einen Vertrauten finden-Zauber.'),
  ecology         = COALESCE(ecology, 'Kobolde sind die Laufburschen der mächtigen bösen Wesen, die über die dunkelsten Ebenen herrschen. Sie handeln oft als Abgesandte und Agenten, aber ihre Hauptaufgabe ist es, die Ausbreitung des Bösen in unserer Welt zu verstärken.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = 'c10da93a-c336-4e25-b3a9-03f84d2c9bb8' AND is_custom = FALSE;

-- Intellect Devourer (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Wissenschaft: ektoplasmatische Form; Hingabe: Körpergleichgewicht.'),
  combat_tactics  = COALESCE(combat_tactics, 'Der Ustilagor greift an, indem er mit seinem flexiblen Fühler zuschlägt. Der Fühler sondert eine alkalische Substanz ab, die bei einem erfolgreichen Treffer 1W4+1 Schaden verursacht sowie weitere 1W4+1 Schaden in der folgenden Runde, es sei denn, das Opfer besteht einen erfolgreichen Rettungswurf gegen Gift. Die Kreatur ist ziemlich beweglich und kann schnell springen und huschen.'),
  habitat_society = COALESCE(habitat_society, 'Intellektverschlinger leben unter der Erde oder in trostlosen Wildnisgebieten. Ihre Fortpflanzungsmethode ist unbekannt. Der Intellektverschlinger schützt selten seine Jungen und kann sie sogar verschlingen. Ustilagor entwickeln eine symbiotische Beziehung mit einem bizarren Pilz, der sich von residualen Gedankenausstrahlungen der Opfer des Ustilagor nährt. Ein Ustilagor wird erwachsen, indem er das Gehirn einer psionischen Kreatur verschlingt.'),
  ecology         = COALESCE(ecology, 'Gedankenschinder züchten Intellektverschlinger, behandeln die Ustilagor als kulinarische Leckerbissen und verwenden Erwachsene als Wachhunde. Beide Formen der Kreatur können als Komponenten in Gegenständen und Tränken verwendet werden, die mit ASW und Geisteskontrolle in Verbindung stehen.'),
  no_appearing    = COALESCE(no_appearing, '1-2')
WHERE id = '3d99e134-3e9a-4b92-8169-3e43f3c3e8db' AND is_custom = FALSE;

-- Invisible Stalker (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Der Unsichtbare Pirscher ist ein Wesen von der Elementarebene der Luft. Jene, die auf der Primär-Materiellen Ebene angetroffen werden, sind fast immer von Magiern beschworen worden, um eine spezielle Aufgabe zu erfüllen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Unsichtbare Pirscher greifen an, indem sie die Luft selbst als Waffe nutzen. Sie sind imstande, einen plötzlichen, intensiven Wirbel zu erschaffen, der ein Opfer mit 4-16 (4W4) Schadenspunkten traktiert. Solche Angriffe betreffen ein einzelnes Opfer auf derselben Ebene wie der Unsichtbare Pirscher.'),
  habitat_society = COALESCE(habitat_society, 'Wenig ist über das Leben dieser Kreaturen auf ihrer Heimatebene bekannt. Es wird angenommen, dass sie normalen Luftelementaren ähneln, wenn sie dort angetroffen werden.'),
  ecology         = COALESCE(ecology, 'Unsichtbare Pirscher sind eine Spezies, die unfreiwillig auf die Primär-Materielle Ebene verpflanzt wurde. Sie sind Sklaven, deren Dienstbedingungen ihre kurzen Aufenthalte beherrschen. Jene, die großen Härten unterworfen waren, sehr schwierige Aufgaben zugewiesen bekamen oder dem Tod durch die Hände von Humanoiden ins Auge blickten, neigen dazu, ein Misstrauen oder offenen Hass gegen sie zu bewahren. Jene, die während vergangener Dienstperioden eine leichte Zeit hatten oder zum ersten Mal auf der Primär-Materiellen Ebene eintreffen, mögen einfacher zu behandeln sein. Solche Gefühle mögen sich übertragen und Begegnungen mit Humanoiden beeinflussen, die durch die Luftebene reisen. Jeder, der in der Vergangenheit einen Unsichtbaren Pirscher zum Freund gewonnen hat, wird feststellen, dass Reisen durch die Elementarebene der Luft weit weniger gefährlich sind, als sie andernfalls gewesen wären.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = 'a46a7077-56d6-44d5-9ed7-5015cb864eb7' AND is_custom = FALSE;

-- Kobold (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Kobolde sind eine feige, sadistische Rasse kleiner Humanoider, die heftig mit Menschen und Halbmenschen um Lebensraum und Nahrung kämpfen. Sie mögen Gnome besonders nicht und greifen sie auf Sicht an.'),
  combat_tactics  = COALESCE(combat_tactics, 'Der Kampfansatz der Kobolde nutzt erdrückende Übermacht oder Tricks. Kobolde greifen Gnome auf Sicht an, aber werden zweimal überlegen, bevor sie Menschen, Elfen oder Zwerge angreifen, es sei denn, die Kobolde sind mindestens zwei zu eins in der Überzahl. Sie schleudern oft Speere und Wurfspieße und ziehen es vor, nicht näher zu kommen, bis sie sehen, dass ihre Feinde geschwächt wurden.'),
  habitat_society = COALESCE(habitat_society, 'Kobolde leben an dunklen, feuchten Orten unter der Erde und in überwucherten Wäldern. Sie können in fast jedem Klima gefunden werden. Da Kobolde gute Bergleute sind, ist jedes Gebiet mit Bergbaupotenzial ein möglicher Ort für eine Ansiedlung.'),
  ecology         = COALESCE(ecology, 'Vielleicht sind Kobolde so grausam, weil sie leichte Beute für größere Humanoide und hungrige Monster sind. Sie haben viele Feinde, und sogar die Zwerge mussten zugeben, dass die zahlreichen Kobold-Goblin-Kriege die Anzahl der Goblins auf einem sicheren Niveau gehalten haben.'),
  no_appearing    = COALESCE(no_appearing, '5-20 (5d4)')
WHERE id = '7445eca8-e871-4986-93b4-e33bbab980d9' AND is_custom = FALSE;

-- Lycanthrope, Wererat (matched by override)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Werratten, auch Rattenmenschen genannt, sind Menschen, die sich in drei Formen verwandeln können - menschlich, menschengroßer Rattenmensch und Riesenratte. Sie sind verschlagen und böse und bewohnen üblicherweise Tunnelkomplexe unter Städten.'),
  combat_tactics  = COALESCE(combat_tactics, 'In allen drei Formen verlassen sich Werratten auf Waffen für ihre Angriffe und bevorzugen Kurzschwerter und Dolche. Jeder, der von einer echten Werratte verletzt wird, hat eine 1%ige Chance pro Schadenspunkt, selbst zu einer Werratte zu werden. In ihren Rattenmenschen- und Riesenrattenformen können Werratten nur durch Silber oder magische Waffen verletzt werden.'),
  habitat_society = COALESCE(habitat_society, 'Werratten leben in Rudeln, unabhängig von ihrer Form, und sind niemals allein, wenn sie es vermeiden können. Einzelgängerische Werratten sind entweder Alleinsüberlebende oder mit Unfug beschäftigt. Sie bilden keine zwischenmenschlichen Bindungen wie Liebe oder Ehe. Tatsächlich paaren sich Werratten selten mit ihresgleichen. Nachkommen einer Werratte und einer menschlichen Frau sind Menschen, obwohl sie klein sind wie ihre Väter. Nachkommen einer weiblichen Werratte ähneln Riesenratten mit menschenähnlichen Pfoten. Diese Rattenjungen wachsen in zwei Jahren zur Reife heran und erlangen die Fähigkeit, sich in menschliche Kinder zu verwandeln mit einem scheinbaren Alter von etwa dem Dreifachen des tatsächlichen Alters des Rattenjungen.'),
  ecology         = COALESCE(ecology, 'Werratten sind Parasiten. Sie erkennen, dass sie körperlich schwächer sind als die meisten Arten, die die Oberfläche beherrschen. Sie haben die eine Nische gefunden und ausgebeutet, wo sie eine Chance haben zu dominieren: die Welt unter den Städten. Sie ernähren sich von Menschen und stehlen deren Reichtümer. Menschen schützen unwissentlich die Werratten sowohl vor oberflächenbewohnenden Kreaturen als auch vor jenen, die von weit unten heraufgraben könnten. Außerdem bezahlen die Menschen für die Instandhaltung des Kanalisationsreichs der Werratten.'),
  no_appearing    = COALESCE(no_appearing, '4-24 (4d6)')
WHERE id = '97bd3238-3bb4-4cec-92bb-fc39e6552d19' AND is_custom = FALSE;

-- Mind Flayer (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Der Illithide oder Gedankenschinder ist ein böses und gefürchtetes Geschöpf der Unterwelt; seine Kräfte sind beeindruckend und er nährt sich von den Gehirnen aller Kreaturen, denen er begegnet. Mit arkanen Kräften versklavt oder vernichtet er seine Feinde, zu denen so mächtige Kreaturen wie Drow und Kuo-Toa gehören.'),
  combat_tactics  = COALESCE(combat_tactics, 'Die bevorzugte Angriffsmethode eines Gedankenschinders ist der Gedankenblitz, der in einem Kegel von 18,3 m Länge projiziert wird, 1,5 m breit am Gedankenschinder und 6,1 m breit am gegenüberliegenden Ende. Alle innerhalb des Kegels müssen einen Rettungswurf gegen Stäbe machen oder werden betäubt und können 3W4 Runden lang nicht handeln. Der Illithide versucht ein oder zwei betäubte Opfer zu packen (normale Angriffswürfe sind erforderlich, falls andere dies zu verhindern suchen) und mit ihnen zu entkommen.'),
  habitat_society = COALESCE(habitat_society, 'Gedankenschinder hassen Sonnenlicht und meiden es wenn möglich. Sie leben in unterirdischen Städten von 200 bis 2.000 Illithiden, plus mindestens zwei Sklaven pro Illithide. Alle Sklaven stehen unter den Effekten von Person bezaubern oder Monster bezaubern und gehorchen ihren Illithiden-Herren ohne zu fragen.'),
  ecology         = COALESCE(ecology, 'Gedankenschinder leben etwa 125 Jahre. Sie sind warmblütige Amphibien und verbringen die ersten 10 Lebensjahre als Kaulquappen, schwimmend im Ältestengehirn-Becken, bis sie entweder sterben (was die meisten tun) oder zu erwachsenen Illithiden heranwachsen. In unregelmäßigen Abständen füttern erwachsene Illithiden die Kaulquappen mit Gehirnen, die das Ältestengehirn nicht belästigen. Illithiden sind zwittrig; jeder kann zweimal in seinem Leben eine Kaulquappe hervorbringen.'),
  no_appearing    = COALESCE(no_appearing, '1-4')
WHERE id = '5e78ea65-6cf1-4b05-a8f3-a1915215fe8c' AND is_custom = FALSE;

-- Nightmare (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Alpträume, die bösen Streitrosse der Unteren Ebenen, dienen als Reittiere für Baatezu, Tanar''ri, Nachthexen und mächtige Untotenfürsten. Sie sehen aus wie große, kräftige Pferde mit pechschwarzem Fell. Alpträume haben glühend rote Augen, flammend orangefarbene Nüstern und Hufe, die wie Glut brennen. Ihre langen Mähnen und Schweife sind zerzaust und wild. Sie verstehen Befehle böser Reiter und verständigen sich untereinander durch Empathie.'),
  combat_tactics  = COALESCE(combat_tactics, 'Alpträume hassen alles Leben. Sie greifen oft jede Kreatur an, die nicht von den Unteren Ebenen stammt (und manchmal auch Wesen der Unteren Ebenen). Ihre Reißzähne verursachen 2W4 Schadenspunkte, ihre beiden brennenden Vorderhufe verursachen je 1W6+4 Schadenspunkte und entzünden brennbare Materialien.'),
  habitat_society = COALESCE(habitat_society, 'Alpträume dienen vielen Kreaturen der Unteren Ebenen. Sie sind intelligent und können nicht so beiläufig behandelt werden wie ein Pferd. Sie dienen bereitwillig als Reittier für jede Mission, die Böses beinhaltet. Jedoch können sich für den unvorsichtigen Reiter die eigenen Ambitionen eines Alptraums als unüberwindlich erweisen. Diese hasserfüllten Streitrosse tun oft, was sie wollen, anstatt den Wünschen ihres "Meisters" zu folgen. Ein Alptraum bereitet dieselben Probleme wie magische Waffen mit großem Ego.'),
  ecology         = COALESCE(ecology, 'Alpträume haben keine biologische Verbindung zu echten Pferden. Ein Alptraum ist ein Diener des Bösen, ohne Bedürfnis nach Nahrung oder Luft. Alpträume werden als Fleischfresser aufgeführt, weil sie gefallene Feinde fressen. Jedoch deutet nichts darauf hin, dass die Alpträume daraus Nahrung ziehen; wahrscheinlicher ist, dass sie ihre Kraft durch den Dienst am Bösen gewinnen.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = 'c3153758-ed0c-40c6-b8ce-9be7d6f0a6a4' AND is_custom = FALSE;

-- Nixie (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Nixen sind Wasserfeen, die in Süßwasserseen leben, und obwohl sie keinen Groll gegen die Menschheit hegen, erfreuen sie sich daran, Männer als ihre Lasttiere zu versklaven.'),
  combat_tactics  = COALESCE(combat_tactics, 'Wenn sich ein oder mehrere Männer bis auf 9 m einer Gruppe von Nixen nähern, bündeln die Kreaturen ihre Magie, um einen mächtigen Bezauberungszauber zu erschaffen - einen solchen Zauber für je 10 Nixen -, der vom Opfer einen Rettungswurf gegen Zauber mit -2 auf den Würfelwurf verlangt. Sobald eine Person bezaubert ist, aber bevor sie ins Wasser geht, besteht eine 75%ige Chance, dass ein Magie bannen-Zauber die Bezauberung bricht. Sobald sie im Wasser ist, sinkt die Chance, die Magie zu bannen, auf 10%. Nixen behalten ihre bezauberten Sklaven ein ganzes Jahr lang, zwingen sie, all ihre schwere Arbeit zu verrichten, aber danach lässt die Bezauberung nach und das Opfer wird freigelassen. Während dieser Versklavung halten die Nixen einen Wasseratmung-Zauber auf dem menschlichen Gefangenen aufrecht, denn Nixen können diesen Zauber einmal täglich auf jede Kreatur wirken oder bannen (Dauer ist ein Tag).'),
  habitat_society = COALESCE(habitat_society, 'Nixenbauten sind aus lebenden Seetangen gewoben und es ist nur zu 5% wahrscheinlich, dass ihr Bau in einer Entfernung unter 6 m bemerkt wird (aus mehr als 6 m Entfernung ist er unmöglich zu entdecken). Nixen halten Riesenfische als Wächter, entweder 1-2 Knochenhechte (20%) oder 2-5 Hechte (80%), und diese werden gelehrt, einfachen Befehlen zu gehorchen. Kleine Zierfische oder regenbogenfarbene Fische werden als Haustiere gehalten und darauf trainiert, kunstvolle Tricks auszuführen. Forellen, Barsche und Welse werden als Nahrung gehütet. Nixen können auch 10-100 kleine Fische herbeirufen (dies dauert 1-3 Runden).'),
  ecology         = COALESCE(ecology, 'Seen mit Nixenstämmen werden sauber und gut bestückt gehalten, und oft werden die menschlichen Sklaven dazu eingesetzt, die Umwelt durch das Entfernen von Müll und Hindernissen zu verbessern. Nixenkunstgegenstände umfassen Schmuck aus Muscheln, Perlen und Opalen, Seide von Wasserspinnen und Tränke der Wasseratmung.'),
  no_appearing    = COALESCE(no_appearing, '20-80 (2d4×10)')
WHERE id = '61bdf113-1e71-4ac6-99a1-1a637746fb23' AND is_custom = FALSE;

-- Owlbear I (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Eulenbären sind wahrscheinlich die gekreuzte Schöpfung eines wahnsinnigen Magiers; angesichts der Tödlichkeit dieser Kreatur ist es sehr wahrscheinlich, dass der Magier, der sie erschuf, nicht mehr am Leben ist. Eulenbären sind bösartig, gefräßig, aggressiv und zu jeder Zeit schlecht gelaunt.'),
  combat_tactics  = COALESCE(combat_tactics, 'Der Eulenbär greift Beute beim ersten Anblick an und kämpft immer bis zum Tod (ignoriere die Moralwertung bei der Bestimmung eines Rückzugs). Er greift mit seinen Klauen und seinem schnappenden Schnabel an. Wenn ein Eulenbär einen Klauenhieb mit einem Wurf von 18 oder höher erzielt, zerrt er sein Opfer in eine Umarmung und quetscht seinen Gegner anschließend für 2-16 Schadenspunkte pro Runde, bis entweder das Opfer oder der Eulenbär getötet wird. Der Eulenbär kann auch seinen Schnabelangriff gegen in seinem Griff gefangene Opfer einsetzen, kann aber seine Klauen nicht verwenden. Ein einzelner Versuch eines Stangen biegen/Tore heben-Wurfs kann unternommen werden, um sich aus dem Griff eines Eulenbären zu befreien. Beachte, dass wenn die Rüstungsklasse eines Opfers hoch genug ist, dass 18 nicht ausreicht um zu treffen, die Umarmung nicht wirksam ist und kein Schaden genommen wird.'),
  habitat_society = COALESCE(habitat_society, 'Eulenbären bewohnen die Tiefen verworrener Wälder in gemäßigten Klimazonen sowie unterirdische Labyrinthe und leben in Höhlen oder hohlen Baumstümpfen.'),
  ecology         = COALESCE(ecology, 'Eulenbären haben eine Lebensspanne von 20 Jahren. Sie sind warmblütige Säugetiere, legen aber Eier. Sie jagen alles, von Kaninchen über Bären bis zu Trollen, Schlangen und Reptilien. Eulenbären bevorzugen gemäßigte Klimazonen, aber einige gedeihen auch in subarktischen Umgebungen. Als Hybride zweier Tiere, eines tagaktiven und eines nachtaktiven, haben sie eine ungewöhnliche Aktivitätszeit: Sie erwachen mittags, jagen tagsüber aktive Tiere und jagen dann nachtaktive Kreaturen, bevor sie um Mitternacht schlafen gehen. Eulenbären sind in den Sommermonaten aktiv und halten während der kalten Jahreszeit Winterschlaf. Es gibt Gerüchte über weiße arktische Eulenbären, eine Kreuzung zwischen arktischen Eulen und Eisbären, aber es wurden niemals Exemplare gefangen.'),
  no_appearing    = COALESCE(no_appearing, '1 (2-8)')
WHERE id = 'd5362fc5-8ae7-4672-a570-35d59d1d49f5' AND is_custom = FALSE;

-- Peryton (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Hoch über den Bergen und felsigen Hügeln der meisten Länder fliegt ein scharfäugiges Monster, das als Peryton bekannt ist. Intelligent, geduldig und böswillig beobachtet und wartet es auf Beute - um ihr das Herz herauszureißen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Ein Peryton hat nur zweitrangiges Interesse an seiner Beute als Nahrung. Sein Hauptinteresse an Menschen und Humanoiden gilt dem Herzen seiner Beute. Er ist unnatürlich treffsicher im Kampf. Spieltechnisch erhält ein Peryton einen +2 Bonus auf seinen Angriffswurf.'),
  habitat_society = COALESCE(habitat_society, 'Perytons nisten in Höhlen hoch oben auf Klippen oder Berggipfeln. Sie siedeln sich in Nestern von 2W4 Kreaturen an, wobei jedes Nest unabhängig von anderen ist und sich keine zwei Nester innerhalb mehrerer Kilometer voneinander befinden, außer unter ungewöhnlichen Umständen - wie einer Zwergengemeinschaft in den Bergen, die ihnen reichlich Beute bietet.'),
  ecology         = COALESCE(ecology, 'Der Peryton ist ein Raubtier ohne natürliche Feinde (nur wenige könnten seine magisch resistente Haut durchdringen). Humanoide und besonders Menschen sind seine bevorzugte Beute. Ein weiblicher Peryton benötigt ein frisches, schlagendes Herz zur Fortpflanzung, und Menschenherzen sind die bevorzugte Sorte. Sobald ein Peryton ein Herz gefressen hat, verändert sich sein Schatten zu dem seiner normalen Gestalt und die Kreatur wird für 3W6 Stunden fruchtbar. Unausgebrütete Peryton-Eier können für 10W12 GM pro Stück verkauft werden.'),
  no_appearing    = COALESCE(no_appearing, '2-8')
WHERE id = '33b48c1d-3cb2-4fa1-a18b-9f87aed3c4a7' AND is_custom = FALSE;

-- Pixie (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Von allen magischen Feenvölkern (Brownies, Sprites, Nixen, Kobolde und Pixies) sind Pixies vielleicht die intelligentesten und verschlagensten. Diese von Natur aus unsichtbaren Kreaturen leben in idyllischen Waldländern und haben besonderen Gefallen daran, Reisende mit ihren Streichen zu plagen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Pixies tragen winzige Schwerter und Bögen. Ihre Schwerter entsprechen Dolchen. Ihre Bögen haben die halbe Reichweite eines Kurzbogens. Sie verwenden drei Arten von Pfeilen, von denen jeder einen +4 Bonus auf den Angriffswurf hat (ETW0 16). Der erste Pfeil ist ihr Kriegspfeil, der 1W4 +1 Schadenspunkte verursacht. Die zweite Art verursacht Schlaf in einem komatösen Zustand für 1W6 Stunden bei jeder Kreatur, die ihren Rettungswurf gegen Zauber verfehlt, wenn sie getroffen wird. Der dritte Angriff schadet dem Ziel nicht körperlich, aber das Ziel muss einen Rettungswurf gegen Zauber würfeln. Ein Fehlschlag zeigt an, dass das Opfer einen vollständigen Gedächtnisverlust erlitten hat, der nur durch einen priesterlichen Heilzauber oder einen begrenzten Wunsch wiederhergestellt werden kann.'),
  habitat_society = COALESCE(habitat_society, 'Pixies leben in tiefen Waldhöhlen und tanzen in mondscheinbeschienenen Lichtungen zur Musik von Grillen und Fröschen. Sie ziehen es vor, fern von Menschen zu leben, aber nahe genug, um sie zu belästigen. Pixies sind Schelme, die es besonders lieben, Reisende in die Irre zu führen. Sie nutzen ihre Illusionskräfte, um dies zu bewerkstelligen, daher der Ausdruck „von Pixies geführt" für jemanden, der sich verirrt hat. Sie erschrecken gerne junge Mädchen, klopfen an Wände, blasen Kerzen aus und treiben ihr Spiel auf dem Wasser.'),
  ecology         = COALESCE(ecology, 'Pixies sind, wie alle Feenvölker, Kreaturen der Magie. Pixies essen Früchte und Nektar und halten Scheingelage und Feste ab, während sie feiern. Das berühmteste Nebenprodukt von Pixies ist Pixiestaub, auch bekannt als Staub des Verschwindens. Pixies haben eine natürliche Verschwinde-Fähigkeit, aber durch das Zermahlen von 50 Pixieflügeln zu einem feinen Pulver ist es größeren Kreaturen möglich, diese Fähigkeit nachzuahmen (solange der Staub anhält). Fünfzig Pixieflügel reichen für eine Dosis des Pulvers.'),
  no_appearing    = COALESCE(no_appearing, '5-20')
WHERE id = '10805627-1e77-4329-9eb7-18ace29f696c' AND is_custom = FALSE;

-- Revenant (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Revenants sind rachsüchtige Geister, die aus dem Grab erstanden sind, um ihre Mörder zu vernichten. Der Revenant erscheint als gespenstische, verweste Version seines Aussehens zum Zeitpunkt seines Todes. Seine fahle Haut ist straff über die Knochen gespannt. Das Fleisch ist kalt und feucht. Die eingefallenen Augen sind stumpf und schwer umlidert, doch wenn der Revenant seinem beabsichtigten Opfer gegenübersteht, lodern die Augen mit unnatürlicher Intensität. Der Revenant trägt eine Aura der Trauer, des Zorns und der Entschlossenheit.'),
  combat_tactics  = COALESCE(combat_tactics, 'Ein Revenant greift an, indem er seine klauenartigen Hände um die Kehle seines Opfers schlingt. Diese Strangulation verursacht 2W8 Schadenspunkte pro Runde. Er löst seinen Griff nicht, bis entweder der Revenant zerstört wird oder sein Opfer tot ist. Er verwendet niemals Waffen.'),
  habitat_society = COALESCE(habitat_society, 'Unter außergewöhnlichen Umständen kann ein Charakter, der eines gewaltsamen Todes gestorben ist, als Revenant aus dem Grab auferstehen, um Rache an seinem Mörder zu nehmen. Um diesen Übergang zu vollziehen, müssen zwei Voraussetzungen erfüllt sein. Die Konstitution des toten Charakters muss 18 betragen und entweder seine Weisheit oder Intelligenz muss größer als 16 sein. Außerdem muss die Summe seiner sechs Eigenschaftswerte 90 oder mehr betragen. Selbst wenn diese Bedingungen erfüllt sind, besteht nur eine 5%ige Chance, dass der tote Charakter zu einem Revenant wird. Wenn sowohl Intelligenz als auch Weisheit über 16 liegen, steigt die Chance auf 10%. Wenn Intelligenz, Weisheit und Konstitution alle 18 betragen, kann die Kreatur nach Belieben in jeden frisch getöteten Humanoiden wechseln, falls der Revenant einen erfolgreichen Rettungswurf gegen Tod würfelt.'),
  ecology         = COALESCE(ecology, 'Revenants geben Mordopfern eine Chance, ihre eigenen Morde zu rächen. Sie verfolgen ihre Ziele allein ohne Verlangen oder Bedürfnis nach Verbündeten. Jedoch, wenn der Revenant einem mächtigen Feind gegenübersteht, der imstande ist, die neue Form des Revenant zu zerstören, kann der Revenant entscheiden, Abenteurer als Schachfiguren in seinem Rachefeldzug zu benutzen.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = '013447d5-3ec4-4cb0-9b29-62831c6ed203' AND is_custom = FALSE;

-- Shambling Mound (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Wankende Hügel oder "Wanker" erscheinen als Haufen verfaulender Vegetation. Sie sind tatsächlich eine intelligente Form pflanzlichen Lebens, grob humanoider Gestalt, mit einer Höhe von 1,8 bis 2,7 m und einem Umfang von etwa 1,8 m an ihrer Basis (Beine bis Taille) und 0,6 m an ihrem Gipfel (dem "Kopf").'),
  combat_tactics  = COALESCE(combat_tactics, 'Wankende Hügel sind furchtlose Angreifer und sind vielleicht die tödlichste bekannte Form pflanzlichen Lebens. Ihre gewaltigen armähnlichen Fortsätze verursachen bei jedem Treffer 2-16 Punkte Quetschschaden, und ein unglückliches Opfer, das von beiden Armen in derselben Runde getroffen wird, verfängt sich in den schleimigen Ranken und der verfaulenden Pflanzenmaterie der Kreatur. Verfangene Kreaturen ersticken im Schleim in 2W4 Runden, es sei denn, der Wanker wird getötet oder das Opfer befreit sich (bei erfolgreichem Wurf für Stäbe biegen/Tore heben).'),
  habitat_society = COALESCE(habitat_society, 'Wankende Hügel findet man nur in Gebieten mit starkem Niederschlag und dichter Vegetation. Düstere Sümpfe, Marschland und Regenwälder sind ihre bevorzugten Klimazonen, aber auch einige feuchte unterirdische Orte dienen als Baue der Wanker. Sie sind Einzelgänger und leben nur selten im selben Gebiet wie andere Wanker - normalerweise nur in Gebieten, wo die Nahrungsquelle konstant ist (z.B. in der Nähe berühmter Ruinen oder verlassener Goldminen usw.).'),
  ecology         = COALESCE(ecology, 'Der wankende Hügel ist ein belebter Klumpen Vegetation mit einem kleinen gehirnähnlichen Kontrollzentrum, das tief in der "Brust"-Höhle liegt. Einen wankenden Hügel zu enthaupten schadet ihm daher nicht im Geringsten. Da die "Gliedmaßen" eines wankenden Hügels lediglich zusammengeballte Klumpen aus Ranken und Moos sind, behindert auch die Entfernung einer oder mehrerer von ihnen die Kreatur nicht. Verbleibende Ranken entlang des Rumpfes verbinden sich bis zur nächsten Runde zu einem neuen Glied. Erst wenn genug vom wankenden Hügel weggehackt wurde, stirbt die Kreatur.'),
  no_appearing    = COALESCE(no_appearing, '1-3')
WHERE id = 'e9036941-45b8-4944-baff-a2b51627cb04' AND is_custom = FALSE;

-- Skeleton (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Alle Skelette sind magisch belebte untote Monster, die von mächtigen bösen Magiern und Priestern als Wächter oder Krieger erschaffen werden.'),
  combat_tactics  = COALESCE(combat_tactics, 'Menschengroße humanoide Skelette kämpfen immer mit Waffen, gewöhnlich einem rostigen Schwert oder Speer. Aufgrund ihrer magischen Natur kämpfen sie nicht so gut wie lebende Wesen und verursachen nur 1-6 Schadenspunkte bei einem Treffer. Tierskelette beißen fast immer für 1-4 Schadenspunkte, außer sie würden offensichtlich weniger verursachen (d.h. Rattenskelette sollten nur 1-2 Punkte verursachen, usw.). Monsterskelette, die immer aus humanoiden Kreaturen konstruiert werden, verwenden riesengroße Waffen, die den gleichen Schaden wie ihre lebenden Gegenstücke verursachen, aber ohne Stärkeboni.'),
  habitat_society = COALESCE(habitat_society, 'Skelette haben kein soziales Leben oder interessante Gewohnheiten. Sie können überall gefunden werden, wo es einen Magier oder Priester gibt, der mächtig genug ist, sie zu erschaffen. Zu beachten ist, dass einige neutrale Priester von Gottheiten der Toten oder Sterbenden oft ganze Armeen belebter Anhänger in Zeiten der Not auferstehen lassen. Gute Priester können Skelette nur erschaffen, wenn das tote Wesen die Erlaubnis erteilt hat (entweder vor oder nach dem Tod) und wenn die Gottheit des Priesters ausdrückliche Erlaubnis dazu gegeben hat. Andernfalls ist die Verletzung der ewigen Ruhe jedes Wesens oder Tieres etwas, was die meisten guten Gottheiten höchst missbilligen.'),
  ecology         = COALESCE(ecology, 'Sofern die Überreste des Skeletts nicht zerstört oder weit voneinander verstreut werden, kann das Skelett durch die Anwendung eines weiteren Zaubers der Totenerweckung neu erschaffen werden. Gerüchte über hochstufige Zauber der Totenerweckung, die Skelette erschaffen, die sich selbst reformieren können, um nach ihrer Zerstörung weiterzukämpfen, wurden nicht zuverlässig bestätigt.'),
  no_appearing    = COALESCE(no_appearing, '3-30 (3d10)')
WHERE id = '50f2e1ae-27d8-4f61-866a-15dac799536f' AND is_custom = FALSE;

-- Skeleton, Warrior (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Ehemals mächtige Kämpfer sind Skelettkrieger untote Fürsten, die von mächtigen Magiern oder bösen Halbgöttern in ihren alptraumhaften Zustand gezwungen wurden, welche ihre Seelen in goldenen Reifen gefangen hielten. Der einzige Grund, warum Skelettkrieger auf der Ersten Materiellen Ebene verweilen, ist die Suche nach den Reifen, die ihre Seelen enthalten, um diese zurückzuerlangen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Jeder, der den Reifen eines Skelettkriegers besitzt, kann dessen Handlungen kontrollieren, solange der Kontrolleur innerhalb von 73,2 m vom Krieger entfernt bleibt. Der Kontrolleur befindet sich entweder in aktiver Kontrolle über den Krieger oder im passiven Modus. Bei aktiver Kontrolle kann der Kontrolleur alles sehen, was das Skelett sieht, und er kann es mental befehligen zu kämpfen, nach Schätzen zu suchen oder andere Handlungen zu unternehmen; jedoch ist der Kontrolleur selbst unfähig, Zauber zu wirken, sich zu bewegen oder andere Handlungen zu unternehmen, während er in aktiver Kontrolle ist. Im passiven Modus kann der Kontrolleur normale Handlungen ausführen, aber er kann nicht durch die Augen des Kriegers sehen; der Skelettkrieger bleibt träge, während der Kontrolleur im passiven Modus ist. Der Kontrolleur kann nach Belieben zwischen dem passiven Modus und der aktiven Kontrolle wechseln.'),
  habitat_society = COALESCE(habitat_society, 'Skelettkrieger werden gewöhnlich in der Nähe der Gebiete gefunden, wo sie in ihrem früheren Leben starben oder wo sie begraben wurden. Ein Skelettkrieger besitzt normalerweise eine beträchtliche Schatzmenge, die Überreste eines Lebens voller Abenteuer. Da ein Skelettkrieger damit beschäftigt ist, seinen Reif zurückzuerlangen, hat der Schutz seines Schatzes keine Priorität.'),
  ecology         = COALESCE(ecology, 'Skelettkrieger werden von ihren Kontrolleuren als Leibwächter, Diener oder Arbeiter eingesetzt. Da Skelettkrieger von ihren Reifen besessen und daher unzuverlässig sind, verkehren böse Kreaturen und andere Untote selten mit ihnen. Skelettkrieger essen nicht, schlafen nicht und führen keine anderen physiologischen Funktionen aus.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = '88ea38ea-669a-494d-9683-c040edc7cc2a' AND is_custom = FALSE;

-- Troll (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Trolle sind scheußliche Fleischfresser, die in allen Klimazonen zu finden sind, von arktischen Ödlanden bis zu tropischen Dschungeln. Die meisten Kreaturen meiden diese Bestien, da Trolle keine Furcht kennen und ununterbrochen angreifen, wenn sie hungrig sind. Ihr Körperbau wirkt dünn und zerbrechlich, aber Trolle besitzen überraschende Stärke. Ihre Arme und Beine sind lang und ungeschickt. Die Beine enden in großen dreizehigen Füßen, die Arme in breiten, kraftvollen Händen mit geschärften Klauen. Die gummiartige Haut der Trolle ist moosgrün, grün-grau gesprenkelt oder faulig grau gefärbt. Eine sich windende haarähnliche Masse wächst aus ihren Schädeln und ist meist grünlich-schwarz oder eisengrau. Ihre stumpfen, eingesunkenen schwarzen Augen besitzen 27,4 m Infrasicht. Weibchen sind leicht von den Männchen zu unterscheiden; sie sind sowohl größer als auch kraftvoller als ihre männlichen Artgenossen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Trolle greifen mit zwei bekrallten Händen und ihrem Biss an und können mehrere Gegner gleichzeitig attackieren. In dem seltenen Fall, dass ein Troll eine Waffe führt, greift er mit einem Schadensbonus von +8 an. Trolle regenerieren mit erstaunlicher Geschwindigkeit. Beginnend drei Runden nach dem ersten Blutvergießen, erholt sich die Kreatur um 3 Trefferpunkte pro Runde, bis sie geheilt ist. Trolle, die auf 0 oder weniger Trefferpunkte reduziert werden, fallen zu Boden, kampfunfähig aber nicht getötet. Kampfunfähige Trolle regenerieren weiter und stehen wieder auf zum Kampf, sobald sie eine positive Anzahl von Trefferpunkten haben.'),
  habitat_society = COALESCE(habitat_society, 'Trolle können in allen Klimazonen überleben, bevorzugen aber dichte Wälder und unterirdische Orte, da helles Sonnenlicht ihre Augen schmerzt; Trolle erleiden deswegen keine Kampfnachteile. Sie errichten ihre Baue normalerweise in Höhlen und verwenden große Felsbrocken, um die Eingänge zu blockieren. Innerhalb einer Trollhöhle befinden sich mehrere grobe Nester aus Stroh und Gras sowie verstreute Knochen und Schätze von Opfern. Wenn es in einem Gebiet keine Höhlen gibt, graben sich Trolle ein Trollloch und bedecken dessen Öffnung mit Zweigen und Blättern. Trolllöcher werden normalerweise in der Nähe von Bäumen gebaut und sind zu 90% nicht entdeckbar. Jeder, der auf ein Trollloch tritt, fällt zu 75% durch die belaubte Tür und stürzt in die darunter liegende Höhle.'),
  ecology         = COALESCE(ecology, 'Trolle jagen alle Kreaturen außer den mächtigsten. Sie respektieren und fürchten Drachen, aber sie hassen Riesen guter Gesinnung und führen häufig Krieg gegen sie. Das grüne Blut der Trolle wird zur Herstellung sowohl von Giftgegenmitteln als auch von Heiltrünken verwendet. Das Blut von einem Troll im Wert von 400 GM kann drei solche Tränke herstellen.'),
  no_appearing    = COALESCE(no_appearing, '1-12')
WHERE id = '1b08f873-2cee-422d-8f1c-17099381f8a9' AND is_custom = FALSE;

-- Vampire (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Von allen chaotisch bösen untoten Kreaturen, die durch die Welt wandeln, ist keine furchtbarer als der Vampir. Lautlos durch die Nacht ziehend, machen Vampire ohne Gnade oder Mitleid Jagd auf die Lebenden. Außer wenn sie sich tief unter der Erde befinden, müssen sie zu den Särgen zurückkehren, in denen sie die Tagesstunden verbringen, und selbst im ersteren Fall müssen sie gelegentlich dorthin zurückkehren, um zu ruhen, denn ihre Macht wird durch Kontakt mit Erde aus ihren Gräbern erneuert.'),
  combat_tactics  = COALESCE(combat_tactics, 'Wenn sie in Kampf verwickelt sind, sind Vampire wilde und furchtbare Gegner. Sie sind körperlich sehr stark, mit einem Stärke-Wert von 18/76, und erhalten einen Bonus von +2 auf Angriffe und +4 auf Schaden. Die zerschmetternden Schläge eines Vampirangriffs sind so heftig, dass sie 5-10 Schadenspunkte verursachen.'),
  habitat_society = COALESCE(habitat_society, 'Vampire leben in Gebieten des Todes und der Verwüstung, wo sie nicht an die Leben erinnert werden, die sie zurückgelassen haben. Ruinierte Schlösser oder Kapellen und große Friedhöfe sind beliebte Baue für sie, ebenso wie Stätten großer Tragödien oder Schlachten. Vampire fühlen oft eine starke Bindung zu bestimmten Gebieten mit morbider Bedeutung, wie dem Grab eines Selbstmörders oder dem Ort eines Mordes.'),
  ecology         = COALESCE(ecology, 'Der Vampir hat keinen Platz in der Welt lebender Kreaturen. Er ist ein Wesen der Finsternis, das nur existiert, um Böses und Chaos zu bringen. Fast ohne Ausnahme wird der Vampir von jenen gefürchtet und gehasst, die in den Regionen wohnen, in denen er sich entscheidet, sein Heim zu errichten. Die unnatürliche Gegenwart des Vampirs ist allgegenwärtig und wird Hunde und ähnliche Tiere dazu bringen, einen Alarmruf bei der Anwesenheit der Kreatur zu erheben.'),
  no_appearing    = COALESCE(no_appearing, '1-4')
WHERE id = '1f5f82ef-c0c2-430f-881e-467200e28331' AND is_custom = FALSE;

-- Xorn (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Die Xorn sind auf der Elementarebene der Erde beheimatet.'),
  combat_tactics  = COALESCE(combat_tactics, 'Xorn greifen Fleischkreaturen nicht an, außer um sich selbst oder ihr Eigentum zu verteidigen, da sie Fleisch nicht verdauen können. Xorn hegen weder übermäßige Liebe noch Hass für Kreaturen der Primären Materialebene. Die einzige Ausnahme davon sind Personen, die eine beträchtliche Menge an Edelmetallen oder Mineralien mit sich führen, die sie bis zu 6,1 m weit riechen können. Die normalerweise friedlichen Xorn können recht aggressiv werden, wenn sie auf Nahrungssuche sind, besonders auf der Primären Materialebene, wo solche Nahrung schwerer zu finden ist als auf ihrer heimatischen Ebene. Xorn erwarten, dass ihnen ein angemessener Anteil für freien Durchgang gegeben wird, oder sie greifen an 90% Wahrscheinlichkeit, um an Nahrung zu gelangen.'),
  habitat_society = COALESCE(habitat_society, 'Ein Xorn wird normalerweise auf der Elementarebene der Erde gefunden. Er ist nur auf der Primären Materialebene, wenn er gewaltsam herbeigerufen wurde oder das Opfer eines interplanaren Unfalls war.'),
  ecology         = COALESCE(ecology, 'Auf der Primären Materialebene sind sie Besucher, die keine ökologische Funktion erfüllen. Auf ihrer eigenen Ebene sind sie Sammler, die nur Stein und Mineralien fressen. Die leeren Taschen im Stein werden schnell von verschiedenen Kreaturen der Ebene bewohnt. Dao jagen sie bekanntermaßen zum Vergnügen. Ebenso oft dienen Xorn den Dao als Sklaven.'),
  no_appearing    = COALESCE(no_appearing, '1-4')
WHERE id = '06417257-3e71-4507-b673-33aa7e149834' AND is_custom = FALSE;

-- ─── INSERTs (new monsters not previously seeded) ───────────────────

-- Aarakocra (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Aarakocra',
  'Aarakocra',
  'Monstrous Manual',
  FALSE,
  'Tropical and temperate mountains',
  'Very rare',
  'Tribal',
  'Day',
  'Carnivore',
  'Average (8-10)',
  'D',
  'Neutral good',
  '1-10',
  7,
  '6, Fl 36 (C)',
  '1+2',
  1,
  19,
  '2',
  '1-3/1-3 or 2-8 (weapon)',
  'Dive +4',
  'Nil',
  0,
  'M',
  'Steady (11)',
  11,
  65,
  'Die Aarakocra sind eine Rasse intelligenter Vogelmenschen, die auf den Gipfeln der höchsten Berge leben und ihre Tage damit verbringen, friedlich und einsam auf den Thermikwinden zu gleiten.',
  'Im Luftkampf kämpft ein Aarakocra entweder mit Krallen oder mit den schweren befiederten Speeren, die er in seinen unteren Händen umklammert. Ein Aarakocra trägt typischerweise ein halbes Dutzend Speere in einzelnen Scheiden an seine Brust geschnallt. Die Speere, die zum Werfen oder Stechen verwendet werden können, verursachen 2W4 Schadenspunkte. Aufgrund der bemerkenswerten Fertigkeit des Aarakocra beim Speerwerfen in der Luft erleidet er keine Angriffsmali für Luftgeschossfeuer. Ein Aarakocra wird seinen letzten Speer immer zum Stechen aufheben, anstatt ihn zu werfen. Sein Lieblingsangriff ist es, mit einem Speer in jeder Hand auf ein Opfer herabzustürzen, dann kurz vor dem Erreichen des Ziels aus dem Sturzflug auszubrechen und mit einem markerschütternden Schrei zuzuschlagen. Dieser Angriff erhält einen +4 Bonus auf den Angriffswurf und verursacht doppelten Schaden, aber ein Aarakocra muss mindestens 61 m stürzen, um ihn ordnungsgemäß auszuführen.',
  'Aarakocra leben in kleinen Stämmen von etwa 11-30 (1W20+10) Mitgliedern. Jeder Stamm hat ein Jagdrevier von etwa 26.000 Quadratkilometern mit bunten Bannern und Wimpeln, die die Grenzen markieren.',
  'Aarakocra haben wenig mit anderen Arten zu schaffen, einschließlich benachbarter Aarakocra-Stämme, und verlassen ihr Heimatgebiet nur unter extremen Umständen. Sie begegnen Menschen selten, außer bei gelegentlichen Vorstößen in ländliche Gemeinden, um ein verirrtes Nutztier zu schnappen; dies ist keine absichtlich bösartige Handlung, da Aarakocra nicht zwischen Haus- und Wildtieren unterscheiden können. Ein Mensch, der in Aarakocra-Territorium eindringt, kann möglicherweise einen davon überzeugen, als Führer oder Späher im Austausch gegen einen glänzenden Edelstein oder eine Münze zu dienen.'
);

-- Ant (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Ameise',
  'Ant',
  'MC2 Volume II',
  FALSE,
  'Tropical/Forest, hills and plains',
  'Rare',
  'Colony',
  'Day',
  'Omnivore',
  'Animal (1)',
  'Q×3,S',
  'Neutral',
  '1-100',
  3,
  '18',
  'Worker: 2',
  1,
  16,
  '1',
  'Worker: 1-6',
  'Warriors have poison sting',
  'Nil',
  0,
  'T',
  'Average (9)',
  9,
  35,
  'Riesenameisen bilden kooperative Kolonien in tropischen Regionen. Normalerweise sind sie friedlich, können aber erbitterte Kämpfer werden, wenn ihr Nest bedroht wird.',
  'Sowohl Arbeiter- als auch Kriegerameisen werden kämpfen. Wenn es einer Kriegerameise gelingt zu beißen, wird sie auch versuchen zu stechen und dabei 3W4 Schadenspunkte verursachen. Ein erfolgreicher Rettungswurf gegen Gift reduziert den Stichschaden auf 1W4 TP. Die Königin hat 10 Trefferwürfel, bewegt sich aber nicht und greift nicht an. Wird sie getötet, werden die verbleibenden Ameisen für sechs Runden verwirrt (als wären sie vom Zauber betroffen) und stürmen dann aus dem Nest.',
  'Eine Riesenameisenkolonie baut ihr Nest unterirdisch in einer Reihe von Kammern und Gängen. Haufen aus Erde und Zweigen markieren die Eingänge. Die Gänge können eine Tiefe von 4,9 m erreichen, und das gesamte Nest kann sich über ein Gebiet von mehreren tausend Quadratmetern erstrecken.',
  'Riesenameisen fressen bevorzugt Samen und Gräser, aber sie werden auch Fleisch fressen, wenn sich die Gelegenheit bietet. Weder Riesenameisen noch ihre Eier haben einen kommerziellen Wert, obwohl einige Feinschmecker ihren Honig genießen. Im Notfall sind Riesenameisen eine gute Proteinquelle.'
);

-- Ant Lion, Giant (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Ameisenlöwe, Riesenameisenlöwe',
  'Ant Lion, Giant',
  'MC2 Volume II',
  FALSE,
  'Tropical and temperate/Mountains, hills, and plains',
  'Rare',
  'Solitary',
  'Any',
  'Carnivore',
  'Animal (1)',
  'See below',
  'Neutral',
  '1',
  2,
  '9, Br 1 (in loose soil)',
  '8',
  8,
  12,
  '1',
  '5-20',
  'See below',
  'Nil',
  0,
  'L',
  'Average (8)',
  8,
  1,
  'Der Ameisenlöwe ist ein riesiges, bösartiges Insekt, das auf dem Grund tiefer Gruben lauert und sich von Kreaturen ernährt, die das Pech haben, hineinzufallen. Ameisenlöwen leben in Ödland, Wüstenrändern und anderen Gebieten mit lockerem Boden und Sand.',
  'Der Ameisenlöwe pirscht oder verfolgt selten Beute. Stattdessen gräbt er tiefe, sich verjüngende Gruben von etwa 18,3 m Durchmesser, vergräbt sich am Boden unter einer Abdeckung aus Sand, Kies und Steinen und wartet dann geduldig auf fallende Opfer. Etwa 50% der Zeit sieht der Eingang zur Grube wie ein mit Sand ausgekleideter Trichter aus. Den Rest der Zeit sieht er wie der Eingang zu einer Höhle oder einem Bau aus. Eine Kreatur, die sich bis auf 0,9 m an den Rand des Eingangs nähert, hat eine 20%ige Chance, im lockeren Boden und Sand auszurutschen und in die Grube zu rutschen. Eine Kreatur, die die Grube betritt, hat eine 50%ige Chance pro Runde, zum Boden zu rutschen. Ein Charakter, der Vorsichtsmaßnahmen beim Nähern oder Betreten der Grube trifft, wie sich mit einem Seil an einem Baum zu sichern, wird nicht in die Grube rutschen.',
  'Ameisenlöwen paaren sich einmal pro Jahr im Hochsommer. Das männliche Exemplar wird vom Weibchen durch aromatische Sekrete angezogen, die sie freisetzt, wenn sie ihren Paarungszyklus beginnt. Nur Ameisenlöwen können diese Sekrete riechen. Sobald ein Männchen das Weibchens Bau betritt, hört sie auf zu sezernieren, und das Paar beginnt, mit ihren Mandibeln gegeneinander zu klicken. Dieses rituelle Klicken dauert drei volle Tage, während der das Paar weder schläft noch frisst. Das Klicken hat eine tranceartige Wirkung auf die Ameisenlöwen; selbst wenn sie angegriffen werden, dauert es 1W4 Runden, bis die Ameisenlöwen ihre Trance brechen und auf einen Eindringling reagieren. Am Ende des Klick-Rituals befruchtet das Männchen das Weibchen und verlässt dann ihr Nest. Innerhalb einer Woche legt das Weibchen zwischen einem und vier Eiern und vergräbt sie in einem Loch im Boden. Die jungen Ameisenlöwen schlüpfen nach etwa sechs Monaten und graben sich sofort weg, um eigene Baue zu errichten. Ein junger Ameisenlöwe hat 4 Trefferwürfel, besitzt aber ansonsten alle Fähigkeiten eines Erwachsenen. Er erreicht die volle Reife in etwa einem Jahr.',
  'Ameisenlöwen in der Nähe zivilisierter Regionen gelten als gefährliche Raubtiere. Belohnungen sind oft für den Beweis ihrer Vernichtung verfügbar. Ameisenlöwen fressen jede Kreatur, die in ihre Gruben fällt, obwohl sie Rieseninsekten bevorzugen und normalerweise eine oder mehrere Riesenameisen pro Tag verzehren. Ameisenlöwen haben keinen kommerziellen Wert, obwohl Bauern einiger primitiver Kulturen ihre Mandibeln als Pflüge verwenden.'
);

-- Ape, Carnivorous (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Fleischfressender Affe',
  'Ape, Carnivorous',
  'MC2 Volume II',
  FALSE,
  'Tropical/Forest, hills, and plains',
  'Rare',
  'Family',
  'Day',
  'Carnivore',
  'Low (7)',
  'C',
  'Neutral',
  '2-8',
  6,
  '12, 9 in trees',
  '5',
  5,
  15,
  '3',
  '1-4/1-4/1-8',
  'Rending',
  '+2 bonus: to surprise roll',
  0,
  'L',
  'Steady (11)',
  11,
  175,
  'Der fleischfressende Affe ist ein größerer, stärkerer und aggressiverer Verwandter des Gorillas. Er lebt in tropischen Dschungeln und Ebenen und hält sich manchmal in hohen Bäumen auf.',
  'Fleischfressende Affen besitzen eine angemessene Intelligenz und sind sehr gerissen. Aufgrund ihrer scharfen Sinne erhalten sie einen Bonus von +2 auf ihren Überraschungswurf. Typischerweise verstecken sie sich in Bäumen und verfolgen ihre Beute meilenweit, um dann herabzuspringen und anzugreifen, wenn ihr Opfer anhält, um aus einem Bach zu trinken oder anderweitig unaufmerksam ist. In Ebenen oder anderen baumfreien Gebieten verstecken sie sich in hohem Gras und dichtem Gebüsch und springen ihr Opfer von hinten an. Fleischfressende Affen greifen an, indem sie sich auf ihre Hinterbeine aufrichten, mit ihren massigen Armen schlagen und mit ihren kräftigen Kiefern zubeißen. Wenn ein Affe seinen Gegner in derselben Runde mit beiden Händen trifft, fügt er zusätzlich 1W8 Punkte Zerreißschaden zu. Wenn ein fleischfressender Affe einen Gegner besiegt oder einen Eindringling einschüchtern will, richtet er sich auf seine Hinterbeine auf, schlägt mit den Händen gegen seine Brust und brüllt donnernd. Das Gebrüll eines Affen kann bekanntlich Feiglinge in Panik versetzen.',
  'Fleischfressende Affen leben in Familien von zwei bis 20 Mitgliedern mit etwa doppelt so vielen Weibchen wie Männchen. Ein trächtiges Weibchen gebiert nach etwa neun Monaten. Ein Jungtier verlässt seine Mutter niemals in den ersten drei Lebensjahren, klammert sich fest an ihr langes Haar und reitet auf ihrem Rücken, wohin auch immer die Familie geht. Das größte Männchen dient als Anführer, bestimmt den Tagesablauf und verteidigt die Familie vor Gefahren. Der Anführer wird gelegentlich von jüngeren Männchen herausgefordert, wobei die Herausforderung durch einen brutalen, aber nicht tödlichen Ringkampf entschieden wird. Der Verlierer verlässt die Familie in Schande; ein geschlagener Herausforderer schließt sich schließlich einer anderen Familie an, aber ein geschlagener Anführer bleibt allein und verbringt den Rest seines Lebens in Verbitterung.',
  'Obwohl von Natur aus aggressiv, töten fleischfressende Affen normalerweise nur für Nahrung oder zur Verteidigung ihrer Familien. Sie mögen Früchte und Nüsse, aber der größte Teil ihrer Nahrung besteht aus Nagetieren, kleinen Reptilien, Eiern und Fischen sowie gelegentlichen Rieseninsekten oder Aas. Wild ergänzt den Familienspielplan: Antilopen, Büffel, Hirsche und Löwen und andere Raubtiere. Es ist nicht ungewöhnlich, dass ein Löwenrudel eine Familie fleischfressender Affen gewaltsam um Jagdrechte in strittigen Gebieten herausfordert; die Affen werden meist umziehen, anstatt das Leben ihrer Familien zu riskieren.'
);

-- Arcane (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Arkane',
  'Arcane',
  'Monstrous Manual',
  FALSE,
  'Any',
  'Very rare',
  'Entourage',
  'Any',
  'Omnivore',
  'Genius (17-18)',
  'R',
  'Lawful neutral',
  '1 (1-6)',
  5,
  '12',
  '10',
  10,
  11,
  '1',
  '1-8 (weapon)',
  'Nil',
  'Invisibility, dimension door',
  40,
  'L',
  'Champion (15)',
  15,
  3,
  'Die Arkane sind eine Rasse von Händlern, die überall dort zu finden sind, wo es potenziellen Handel mit magischen Gegenständen gibt. Sie erscheinen als große, hagere, blaue Riesen mit länglichen Gesichtern und dünnen Fingern; jeder Finger hat ein Gelenk mehr, als bei den meisten humanoiden Lebewesen üblich ist. Die Arkane kleiden sich in Roben, obwohl es Individuen gibt, die in schwererer Rüstung anzutreffen sind, einer Kombination aus Kettengliedern mit Plattenteilen (RK 3).',
  'Für Kreaturen ihrer Größe sind die Arkane bemerkenswert schwach und nicht kampflustig. Sie können sich bei Bedarf verteidigen, ziehen es aber vor, sich aus gefährlichen Situationen herauszureden und/oder freizukaufen. Wenn sie ein potenziell gefährliches Gebiet betreten (wie die meisten menschlichen Städte), heuert der Arkane eine Gruppe von Abenteurern als sein Gefolge an.',
  'Nichts ist über die Herkunft der Arkane bekannt; sie kommen und gehen, wie es ihnen beliebt, und sind in den bekannten Welten zu finden. Wenn sie reisen, tun sie dies auf den Schiffen und Fahrzeugen anderer Rassen. Solche Schiffe mit Arkane an Bord zu finden ist selten, und es wird vermutet, dass die Arkane eine andere Art haben, über große Entfernungen zu reisen.',
  'Die Arkane als Rasse müssen essen und atmen wie alle normalen Kreaturen: sie können nicht die Leere atmen oder für längere Zeit ohne Nahrung überleben. Sie werden oft Geschäfte mit beiden Seiten in einem Konflikt machen und sind sich völlig bewusst, dass die Menge an Feuerkraft, die sie liefern, alle ihre potenziellen Kunden in einer Sphäre vernichten wird. Ihr Markt ist groß genug, dass solche kleinen Verluste wie ein ganzer Planet und eine Rasse keine ernsthafte Auswirkung auf ihren Handel haben.'
);

-- Aurumvorax (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Aurumvorax',
  'Aurumvorax',
  'Monstrous Manual',
  FALSE,
  'Temperate hills',
  'Very rare',
  'Solitary',
  'Day',
  'Carnivore (see below)',
  'Animal (1)',
  'Special',
  'Neutral',
  '1',
  10,
  '9, Br 3',
  '12',
  12,
  9,
  '1',
  '2-8',
  '2-8 claws for 2-8 each',
  'See below',
  0,
  'S',
  'Fearless (19-20)',
  19,
  9,
  'Obwohl der Aurumvorax oder Goldschlucker nur die Größe eines großen Dachses hat, ist er eine unglaublich gefährliche Kreatur. Das Tier ist mit grobem goldenen Haar bedeckt und hat kleine silberne Augen mit goldenen Pupillen. Es hat acht kräftige Beine, die in 7,5 cm langen kupfernen Klauen enden. Die Schultern des Aurumvorax sind massiv bemuskelt, während sein schwerer Kiefer voller kupferfarbener Zähne ist.',
  'Der Aurumvorax stürmt auf jede Kreatur los, die sein Territorium betritt, und verursacht einen Malus von -3 auf die Überraschungswürfe der Gegner, wenn er aus seinem Bau angreift. Ein Weibchen der Art erhält einen Bonus von +2 auf Angriffswürfe, wenn es seine Jungen bewacht.',
  'Der Aurumvorax macht sein einsames Zuhause in lichten Wäldern, Hügeln und an der Baumgrenze an Berghängen. Ein Aurumvorax wählt einen geeigneten Platz und nutzt dann seine kraftvoll bekrallten Beine, um einen Bau zu schaffen, manchmal in festen Fels hinein.',
  'Um zu überleben, ergänzt der Aurumvorax seine fleischfressende Ernährung mit Mengen von Gold. Die Fähigkeit, Gold und andere Erze zu verdauen und zu verwerten, ermöglicht es der Kreatur, das dichte Fell, die Haut und die Knochen zu entwickeln, die sie so gut schützen.'
);

-- Baatezu, Lesser, Abishai (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Baatezu, Niedere, Abishai',
  'Baatezu, Lesser, Abishai',
  'Monstrous Manual',
  FALSE,
  'Baator',
  'Common',
  'Solitary',
  'Any',
  'Carnivore',
  'Average (8-10)',
  'Nil',
  'Lawful evil',
  '2-20',
  5,
  '9, Fl 12 (C)',
  '4+1',
  4,
  17,
  '3',
  '1d4/1d4/1d4+1',
  'Poison, dive',
  '+1 or better weapons to hit, regeneration',
  30,
  'L',
  'Average (8-10)',
  8,
  7,
  'Abishai sind auf der ersten und zweiten Ebene von Baator weit verbreitet. Sie sehen aus wie gotische Wasserspeier, dünn und reptilienartig, mit langen, greiffähigen Schwänzen und großen Flügeln. Die drei Varietäten der Abishai haben unterschiedliche Hautfarben - in aufsteigender Rangordnung schwarz, grün und rot. Alle haben einen essigartigen Geruch und kratzende Stimmen. Die Luft scheint in ihrer Gegenwart spürbar wärmer zu werden.',
  'Im Kampf schlägt der Abishai mit zwei Klauen zu (jeweils 1W4 Schadenspunkte) und seinem beweglichen Schwanz (1W4+1 Schadenspunkte und Gift; zu beachten ist, dass das Gift tödlich ist, es sei denn, ein erfolgreicher Rettungswurf gegen Gift wird geschafft).',
  'Abishai sind gefräßig und böse. Sie ergötzen sich daran, jene wenigen Baatezu zu quälen, die niedriger in der Rangordnung stehen als sie selbst. Abishai versuchen Sterbliche, die kühn genug sind, nach Baator zu reisen, indem sie ihre Fähigkeiten Gestalt wechseln und Person bezaubern verwenden, um sich als mächtigere Baatezu auszugeben.',
  'Die Abishai bilden große, böse Armeen, die gegen die Tanar''ri und Eindringlinge in Baator kämpfen. In manchen Fällen kann sich ein roter Abishai als würdig genug erweisen, eine Streitmacht von Lemuren zu befehligen. Wenn erfolgreich, kann der rote Abishai zu einer höheren Form der Baatezu befördert werden.'
);

-- Baatezu, General Information (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Baatezu',
  'Baatezu, General Information',
  'Monstrous Manual',
  FALSE,
  NULL,
  'common',
  NULL,
  NULL,
  NULL,
  NULL,
  NULL,
  NULL,
  NULL,
  10,
  '',
  '1',
  1,
  20,
  '1',
  '',
  NULL,
  NULL,
  0,
  'M',
  '',
  10,
  0,
  'Baatezu sind eine starke, böswillige, wohlorganisierte Rasse von Unholden. In ihrem starren Kastensystem leitet sich Autorität nicht nur aus Macht ab, sondern auch aus der Stellung. Veränderungen in der Stellung ergeben sich aus der Teilnahme am Blutkrieg oder (wie häufiger der Fall) aus der hohen Verlustrate in den oberen Rängen. Wenn ein Baatezu eine große Tat vollbringt, die dem Feind schadet, wird er durch eine Beförderung belohnt - tatsächlich eine körperliche Verwandlung - zu einer höheren Stellung.',
  'Alle Baatezu außer Lemuren, Nupperibo und Spinagons haben die zauberähnlichen Fähigkeiten fortgeschrittene Illusion, Tote beleben, Person bezaubern, Infrasicht, Gesinnung erkennen (immer aktiv), Suggestion und Teleportation ohne Fehler.',
  NULL,
  NULL
);

-- Baboon (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Pavian',
  'Baboon',
  'MC2 Volume II',
  FALSE,
  'Tropical and subtropical/',
  'Common',
  'Tribal',
  'Day',
  'Herbivore',
  'Low (5-7)',
  'Nil',
  'Neutral',
  '10-40',
  7,
  '12, 12 in trees',
  '1+1',
  1,
  18,
  '1',
  '1-4',
  'Nil',
  'Climbing',
  0,
  'S',
  'Unsteady (5)',
  5,
  35,
  'Paviane sind große, pflanzenfressende Affen. Sie leben normalerweise in den Bäumen tropischer und subtropischer Dschungel, aber Stämme findet man manchmal auch in tropischen Bergen und Ebenen.',
  'Wenn das Heimatgebiet des Stammes betreten wird, versuchen die Paviane, die Eindringlinge zu vertreiben, aber es ist zu 90% wahrscheinlich, dass ein Pavianstamm flieht, wenn er bedroht oder überrascht wird, sich in Bäumen oder hinter Bodenvegetation versteckend, bis die Gefahr vorüber ist. Extrem beweglich können Paviane in fünf Runden langen Schüben mit doppelter normaler Bewegungsrate klettern, wenn sie vor einem Feind fliehen. Jedoch können Paviane, wenn sie in die Enge getrieben werden oder wenn ein Jungtier gefährdet ist, bösartige Kämpfer sein, besonders die größeren Männchen. Paviane greifen an, indem sie sich von oben auf ihre Opfer fallen lassen oder anstürmen und springen, beißend mit ihren scharfen Zähnen für 1W4 Schadenspunkte. Der Stamm wird von 2W4 großen Männchen angeführt, die als erste Verteidigungslinie dienen und einen +1 Schadensbonus auf ihre Angriffe erhalten. Männliche Paviane versuchen manchmal, Eindringlinge abzuschrecken, indem sie ihre Fangzähne entblößen und kreischen.',
  'Paviane leben in Stämmen von 10-40, obwohl manche Stämme bis zu 100 Mitglieder umfassen. Etwa die Hälfte des Stammes sind Jugendliche oder Jungtiere; der Rest sind erwachsene Männchen und Weibchen. Die Jungen greifen nicht an, und Weibchen greifen generell nur an, wenn ihre Kinder bedroht sind. Weibchen gebären jedes Jahr ein Kind.',
  'Paviane fressen Früchte, Samen, Gras, Wurzeln und Blätter. Sie mögen auch Vogeleier und Insekten. Wenn Nahrung knapp ist, fressen Paviane lebende Beute wie Mäuse und Frösche. Gruppen großer Männchen sind dafür bekannt, kleine Antilopen und Leoparden zu jagen und zu töten, obwohl dies extrem ungewöhnlich ist. Bei Gelegenheit fressen die meisten Raubtiere Paviane. Da Dschungelpaviane die meiste Zeit in den hohen Bäumen verbringen, sind sie generell vor Angriffen sicher. Riesenschlangen sind ihre meistgefürchteten natürlichen Feinde. Bergpaviane haben es schwerer; ihre Feinde umfassen Berglöwen, Säbelzahntiger und Wolfsrudel.'
);

-- Badger (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Dachs',
  'Badger',
  'MC2 Volume II',
  FALSE,
  'Temperate/Forests, plains, swamp and mountains',
  'Uncommon',
  'Family',
  'Night',
  'Carnivore',
  'Semi- (2-4)',
  'Nil',
  'Neutral',
  '2-5',
  4,
  '6, Br 3',
  '1+2',
  1,
  19,
  '3',
  '1-2/1-2/1-3',
  'Nil',
  'Nil',
  0,
  'S',
  'Average (8)',
  8,
  35,
  'Dachse sind fleischfressende grabende Tiere, die unterirdisch leben und nachts jagen. Dachse sind jähzornig und mutig; wenn sie bedroht werden, greifen Dachse ohne zu zögern Kreaturen an, die um ein Vielfaches größer sind als sie selbst.',
  'Wenn ein Dachs außerhalb seines Baus angetroffen wird, versucht er normalerweise wegzulaufen und sich zu verstecken. Wird er jedoch in seinem Bau gestört oder in die Enge getrieben, kämpft er mit überraschender Bösartigkeit, unabhängig von der Größe oder Stärke seines Gegners. Der Dachs greift an, indem er seine scharfen Zähne bleckt und sich auf seinen Gegner stürzt und versucht zu beißen und zu krallen. Schnappend, kauend und schlagend geht der Dachs an die Kehle seines Gegners, wenn sie in Reichweite ist, andernfalls greift er den Bauch des Gegners an; alle ungeschützten Bereiche eines Gegners, wie Gesicht oder Arme, sind ebenfalls wahrscheinliche Ziele eines Dachsangriffs. Ein Dachs knurrt und sabbert während des Angriffs und kämpft in den meisten Fällen bis zum Tod.',
  'Dachse sind extrem geschickte Gräber. Sie graben ihre Baue bevorzugt in die weiche Erde von Waldböden und Ackerland, aber sie können auch in Bergen und an Hügelhängen gedeihen. Der Eingang zu einem Dachsbau ist ein kreisrundes Loch von etwa 30 bis 60 cm Durchmesser, umgeben von einem Erdring aus der ursprünglichen Ausgrabung. Der Tunnel führt sanft in die Erde hinab, ist meist etwa 1,2 bis 1,8 m lang und endet in einer Kammer, die je nach Größe der Familie nur 1,2 m breit oder bis zu 3 m breit sein kann. Der Boden des Baus ist typischerweise übersät mit Überresten früherer Mahlzeiten und Lagern aus Blättern und Gras zum Schlafen. Dachse sind keine besonders guten Haushalter; wenn ein Bau übermäßig schmutzig wird, kann die Familie in ein nahegelegenes Gebiet umziehen und neue Wohnräume graben.',
  'Dachsfleisch ist fettig, zäh und nicht besonders appetitlich. Wegen ihrer bösartigen Natur ist die Jagd auf Dachse für die meisten Raubtiere nicht der Mühe wert, obwohl gelegentlich ein hungriger Wolf oder Fuchs dabei beobachtet werden kann, wie er am Eingang eines Dachsbaus scharrt. Dachse fressen Nagetiere, Eichhörnchen, Gopher und andere kleine Tiere.'
);

