-- Boar (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Wildschwein',
  'Boar',
  'MC1 Volume I (w/binder #1)',
  FALSE,
  'Any land',
  'Common',
  'Family',
  'Day',
  'Omnivore',
  'Semi- (2-4)',
  'Nil',
  'Neutral',
  '1-12',
  7,
  '15',
  '3+3',
  3,
  17,
  '1',
  '3-12',
  'Nil',
  'Nil',
  0,
  'S',
  'Average (8-10)',
  8,
  175,
  'Wildschweine, eine Art von Wildschweinen, sind die Vorfahren unserer domestizierten Schweine. Wildschweine sind natürlich aggressiver als die Hoftiere, und eine unerwartete Begegnung mit einer Familie dieser Kreaturen oder einem großen Individuum kann tödlich enden.',
  'Wildschweine sind gefährliche Gegner, wenn sie gereizt werden. Sie haben einen bösartigen Biss und diejenigen mit Hauern können diese einsetzen, um ungeschütztes Fleisch mit großer Wirksamkeit aufzureißen.',
  'Wildschweine leben in der Regel in Familienverbänden. Wenn mehr als ein Wildschwein angetroffen wird, werden die anderen Bachen sein (3 Trefferwürfel, 2-8 (2W4) Trefferpunkte Schaden/Angriff) oder Frischlinge, mit einem 1:4 Verhältnis (Bachen:Frischlinge). Wenn also 12 angetroffen werden, wird es 1 Wildschwein, 3 Bachen und 8 Jungtiere geben.',
  'Wildschweine sind echte Allesfresser, die praktisch alles fressen. Während das Essen einer Vielfalt von Nahrungsmitteln allgemein als gesund gilt, kann dies im Fall des Wildschweins zu Problemen führen. Ein kleiner Rundwurm, Trichinella spiralis, ist ein Parasit, der den Körper eines Wildschweins bewohnen kann. Dies schafft ein Problem, wenn ein Mensch das Wildschwein isst, ohne es richtig zu kochen, da Trichinose, die durch diesen Parasiten verursachte Krankheit, leicht auf Menschen übertragbar ist. Einmal mit dem Parasiten infiziert, leidet der Wirt unter Fieber, Schwitzen und schmerzenden Muskeln, bis ein Krankheit heilen Zauber gewirkt wird.'
);

-- Bookworm (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Bücherwurm',
  'Bookworm',
  'MC1 Volume I (w/binder #1)',
  FALSE,
  'Any land',
  'Rare',
  'Solitary',
  'Any',
  'Special',
  'Non- (0)',
  'See below',
  'Neutral',
  '1-2 (10-40)',
  2,
  '12, Br 3',
  '¼ (2 hit points)',
  1,
  20,
  '0',
  'Nil',
  'See below',
  'See below',
  0,
  'T',
  'Special',
  10,
  15,
  'Dieser kleine Wurm, nur 2,5 cm lang, wird von Magiern sehr gefürchtet, da er von Papier in allen Formen angezogen wird. Er kann Schriftrollen, Karten, arkane Folianten und Zauberbücher auf eine Entfernung von 18,3 m riechen.',
  'Der Bücherwurm verhängt anfangs einen Malus von -7 auf die Überraschungswürfe von Abenteurern aufgrund seiner Farbwechselfähigkeit. Kann das Opfer unsichtbare Dinge sehen, reduziert sich der Modifikator des Bücherwurms auf -4. Diese Chancen gelten sogar für Kreaturen, die normalerweise schwer zu überraschen sind (wie Waldläufer und Mönche), wegen seiner geringen Größe, Geschwindigkeit (sehr hoch im Verhältnis zu seiner Größe) und harmlosen Natur. Gelingt dem Bücherwurm zunächst die Überraschung, kann er dann (25%) an der Außenseite des Beins oder Rucksacks eines Opfers entdeckt werden. Andernfalls bleibt er unbemerkt, es sei denn, das Opfer, das Papier bei sich trägt, hört das laute Kauen der Kreatur (Grundchance 50% pro Runde). Ein fressender Bücherwurm bleibt reglos, bis er angegriffen wird. Nach jedem Angriff flieht er (falls möglich), indem er zunächst 3 m springt und dann mit Höchstgeschwindigkeit zu seinem Bau zurückkriecht.',
  'Ein Bücherwurmbau ist immer eine Bibliothek oder ein Lagerraum irgendeiner Art, sei er in Benutzung oder längst vergessen. Wird ein Bücherwurm angetroffen, können noch unbeschädigte Papiergegenstände übrig sein (30% Chance). In solchen Fällen sind die überlebenden Objekte wie folgt: eine Karte (60%), Schriftrolle (30%) oder ein arkanes Werk der Magierstufe 1-8 (10%). Werden Zauberbücher angezeigt, sollten sie für die Stufe der Charaktere angemessen sein, die sie finden, aber zu 0-90% (1W10-1) von den Würmern zerstört sein.',
  'Ein Bücherwurm wird immer von der größten Papiermenge in einem Bereich angezogen.'
);

-- Brain Mole (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Gehirnmaulwurf',
  'Brain Mole',
  'Monstrous Manual',
  FALSE,
  'Any/Below ground',
  'Very rare',
  'Family',
  'Night',
  'Psionic energy',
  'Animal (1)',
  'Nil',
  'Neutral',
  '1-3',
  9,
  '1, Br 3',
  '1 hp',
  1,
  20,
  '0',
  'Nil',
  'Psionic',
  'Psionic',
  0,
  'T',
  'Unsteady (5-7)',
  5,
  35,
  'Wissenschaften: Geistesverbindung, Gedächtnislöschung; Hingabe: Kontakt.',
  'Ein Gehirnmaulwurf greift sein Opfer gewöhnlich in Wäldern oder im Untergrund an; in beiden Fällen befindet sich die Kreatur normalerweise außerhalb der direkten Sichtlinie. Der Maulwurf wartet darauf, dass ein psionisch begabtes Wesen über ihm erscheint, oder er gräbt sich auf der Suche nach Beute durch die Erde.',
  'Gehirnmaulwürfe leben in Familienverbänden, die ein Männchen, ein Weibchen und 1W6 Junge umfassen (von denen eines alt genug sein kann, um sich selbst zu nähren). Große Gehirnmaulwurf-Siedlungen von bis zu 3W6 Familienverbänden wurden berichtet. Natürlich kommen diese nur an Orten vor, die häufig von psionisch Begabten bereist werden.',
  'Obwohl Gehirnmaulwürfe für manche gefährlich sein können, halten andere sie als Haustiere. Die Maulwürfe sind ziemlich freundlich und leicht zu zähmen. Sie werden von Adeligen bevorzugt, die den besonderen Schutz schätzen, den nur Gehirnmaulwürfe bieten können. Einige Gelehrte behaupten, dass sogar ein toter Gehirnmaulwurf Schutz vor psionischen Angriffen bieten kann, vorausgesetzt, der Kadaver wird als Medaillon um den Hals getragen. Manchmal schicken Adelige, die von einem bestimmten Psioniker belästigt wurden, Helden auf Questen nach den kleinen pelzigen Nagetieren aus. Auf dem freien Markt verkaufen sich ausgewachsene Gehirnmaulwürfe für 50 GM. Jungtiere verkaufen sich für je 5 GM.'
);

-- Broken One (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Gebrochene',
  'Broken One',
  'Monstrous Manual',
  FALSE,
  'Any land',
  'Rare',
  'Pack',
  'Any (night)',
  'Varies',
  'Low (5-7)',
  'I,K,M',
  'Neutral evil',
  '3-12 (3d4)',
  7,
  '9',
  '3',
  3,
  17,
  '1',
  '1-6 (or by weapon)',
  'See below',
  'Regeneration',
  0,
  'M',
  'Unsteady (5-7)',
  5,
  175,
  'Gebrochene (oder Tiermenschen) sind die tragischen Überlebenden wissenschaftlicher und magischer Experimente, die fehlschlugen. Während sie einst Menschen waren, sind ihre Wesen mit denen von Tieren vermischt worden und ihre wahre Natur wurde durch den Schock dieses Ereignisses für immer verändert. Es wird gemunkelt, dass manche Gebrochene das Ergebnis fehlgeschlagener Versuche der Auferstehung, Reinkarnation oder Verwandlungsmagie sind.',
  'Gebrochene neigen dazu, zurückgezogene Kreaturen zu sein und Kämpfe mit ihnen sind selten. Dennoch sind sie starke Gegner. Gebrochene sind fast immer mit größerer als menschlicher Ausdauer gesegnet, was sich darin widerspiegelt, dass sie immer mindestens 5 Trefferpunkte pro Trefferwürfel haben. Somit hat der schwächste Gebrochene mindestens 15 Trefferpunkte. Zusätzlich heilen Gebrochene mit stark beschleunigter Geschwindigkeit und regenerieren 1 Trefferpunkt pro Runde.',
  'Gebrochene neigen dazu, sich in Gruppen von 10 bis 60 Personen zu sammeln. Da sie selten Akzeptanz in menschlichen Gesellschaften finden, suchen sie Ihresgleichen auf und wohnen in abgelegenen Gebieten dichter Wälder oder felsiger Ödländer, weit entfernt von den Heimen der Menschen. Von Zeit zu Zeit werden sie ein menschliches Dorf oder eine Karawane angreifen, entweder für Vorräte, zur Selbstverteidigung oder einfach aus Rache für wirkliche oder eingebildete Kränkungen. Wenn möglich, werden sie versuchen, ihren Schöpfer aufzuspüren und ihn für die Verwandlungen zu vernichten, die er über sie gebracht hat.',
  'Gebrochene sind unnatürliche Kombinationen aus Menschen und Tieren. Ihre individuellen Ernährungsweisen und Gewohnheiten werden größtenteils von ihrer tierischen Natur bestimmt. Somit wäre ein Gebrochener mit löwenartigen Eigenschaften fleischfressend, während einer, der mit der Essenz eines Pferdes durchdrungen ist, Vegetarier wäre. Es gibt keine bekannten Beispiele eines Gebrochenen, der mit der Essenz einer intelligenten nichtmenschlichen Kreatur geformt wurde.'
);

