  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Couatl',
  'Couatl',
  'Monstrous Manual',
  FALSE,
  'Tropical and subtropical jungles',
  'Very rare',
  'Solitary',
  'Any',
  'Carnivore',
  'Genius (17-18)',
  'B,I',
  'Lawful good',
  '1-4',
  5,
  '6, Fl 18 (A)',
  '9',
  9,
  11,
  '2',
  '1-3/2-8 (2d4)',
  'Poison, magic use',
  'Etherealness',
  0,
  'L',
  'Elite (13-14)',
  13,
  6,
  'Wissenschaft: Aurasicht; Andachten: Rundumblick, Schall sehen.',
  'Ein Couatl greift selten ohne Provokation an, obwohl er stets Übeltäter attackiert, die auf frischer Tat ertappt werden. Wann immer möglich, greift ein Couatl aus der Luft an.',
  'Diese geflügelte Schlange ist in warmen, dschungelartigen Gebieten heimisch, kann aber auch durch den Äther fliegend angetroffen werden. Ihre Intelligenz und Güte haben sie zu Objekten der Verehrung durch die Einheimischen der Gebiete gemacht, die sie bewohnen. Als göttlich betrachtet, gibt es viele Legenden, in denen der Couatl der Wohltäter der Menschheit und der Verleiher so kostbarer Gaben wie Ackerbau und Medizin ist. Es gibt sogar Schreine in bestimmten Gebieten, die dem Couatl geweiht sind, und jeder, der einen Couatl angreift oder verletzt, wird automatisch als der schwärzeste Schurke betrachtet.',
  'Der Couatl herrscht gewöhnlich unumschränkt in seinem Dschungel und hat von den meisten anderen Monstern wenig zu befürchten.'
);

-- Crabman (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Krabbenmann',
  'Crabman',
  'Monstrous Manual',
  FALSE,
  'Temperate to tropical sea coasts',
  'Rare',
  'Tribal',
  'Any',
  'Omnivore',
  'Low to average (5-10)',
  '(K×5,L×5,C)',
  'Neutral',
  '2-12',
  4,
  '9, Sw 6',
  '3',
  3,
  17,
  '2',
  '1-6/1-6',
  'Nil',
  'Nil',
  0,
  'M',
  'Steady (11-12)',
  11,
  65,
  'Krabbenmänner sind menschengroße intelligente Krabben. Sie gehen aufrecht auf zwei Beinpaaren. Die kleinen Scheren an den Enden der kurzen Arme über ihren Beinen werden für feine Manipulationen verwendet. Die zwei längeren Arme enden in großen Klauen. Zwei schlanke Augenstiele wippen über der schnabelartigen Ansammlung von Mandibeln, die das Maul des Krabbenmannes bildet. Männliche Krabbenmänner sind oft leuchtend gefärbt und Weibchen können rötlich-braun, grün oder schwarz sein.',
  'Obwohl generell friedlich, werden Krabbenmänner mit ihren großen Klauen zurückschlagen, wenn sie angegriffen werden, und dabei 1W6 Schadenspunkte pro Treffer verursachen. Männchen bestimmter Unterarten haben eine vergrößerte Klaue auf einer Seite, die 1W8 Schaden verursacht. Es ist nie bekannt geworden, dass Krabbenmänner Waffen führen.',
  'Krabbenmänner leben als einfache Jäger und Sammler und ernähren sich hauptsächlich von Aas und Algen. Ein Großteil des Tages jedes Krabbenmannes wird mit Jagen, Algenfiltern oder Plündern entlang der Küste verbracht. Krabbenmänner sammeln oft große Mengen Sand in ihre Mäuler, saugen das gesamte organische Material heraus und spucken faustgroße Pellets aus Sand und Schmutz aus. Diese gehärteten Pellets verraten die Anwesenheit eines nahen Krabbenmann-Baus.',
  'Krabbenmann-Artefakte können manchmal gute Preise von Sammlern erzielen, obwohl sie oft zerbrechlich sind und leicht zerfallen, falls sie aus Pflanzen gemacht sind.'
);

-- Crawling Claw (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Kriechende Klaue',
  'Crawling Claw',
  'Monstrous Manual',
  FALSE,
  'Any',
  'Rare',
  'Swarm',
  'Any',
  'Special',
  'Non- (0)',
  'Any',
  'Neutral',
  '1-20',
  7,
  '9',
  '2-4 hit points',
  2,
  20,
  '1',
  '1-4 (armored foes)',
  'Nil',
  'See below',
  0,
  'T',
  'Fearless (19-20)',
  19,
  35,
  'Die sehr gefürchtete kriechende Klaue wird häufig als Wächter von jenen Magiern und Priestern eingesetzt, die das Geheimnis ihrer Erschaffung erlernt haben.',
  'Wenn eine Klaue ein potentielles Opfer entdeckt, springt sie zum Angriff. Obwohl es nicht so aussehen mag, als wäre sie zu einer solchen Leistung imstande, ermöglicht ihr ihre große Stärke dies zu tun. Die maximale Entfernung, die eine Klaue springen kann, beträgt 4,6 m.',
  'Kriechende Klauen sind nichts weiter als die belebten Hände und Pfoten einst lebender Kreaturen. Als solche haben sie keine nennenswerte Kultur oder Gesellschaft. Trotzdem haben kriechende Klauen eine begrenzte Fähigkeit, miteinander zu kommunizieren. Dies erfolgt in Form einer grundlegenden telepathischen Verbindung zwischen allen Klauen einer einzelnen "Charge". Wann immer eine Klaue ein Opfer findet, bewegen sich alle anderen in der Gegend, die zur gleichen Zeit erschaffen wurden, herbei, um ihr zu helfen.',
  'Kriechende Klauen können von jedem Magier oder Priester erschaffen werden, der Kenntnis der dafür erforderlichen Techniken besitzt. Zu Beginn muss der Erschaffer die abgetrennten Gliedmaßen sammeln, die belebt werden sollen. Die maximale Anzahl von Klauen, die zu einem beliebigen Zeitpunkt erschaffen werden kann, entspricht der Stufe der Person, die sie verzaubert. Die Hände (oder Pfoten) können entweder frisch, skelettartig oder in jedem Verwesungsstadium dazwischen sein.'
);

-- Crocodile (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Krokodil',
  'Crocodile',
  'Monstrous Manual',
  FALSE,
  'Subtropical and tropical/',
  'Common',
  'None',
  'Day',
  'Carnivore',
  'Animal (1)',
  'Nil',
  'Neutral',
  '3-24',
  5,
  '6, Sw 12',
  '3',
  3,
  17,
  '2',
  '2-8/1-12',
  'Surprise',
  'Nil',
  0,
  'L',
  'Average (9)',
  9,
  65,
  'Das Krokodil ist ein großes, gefährliches Raubtierreptil, das in tropischen und subtropischen Gebieten heimisch ist. Es verbringt die meiste Zeit untergetaucht in Sümpfen, Flüssen oder anderen großen Gewässern.',
  'Stets gefräßig greifen hungrige Krokodile alles an, was essbar aussieht, einschließlich Menschen. Sie ziehen es vor, auf ihre Beute zu lauern (-2 Malus auf den Überraschungswurf des Gegners) und sind außergewöhnlich empfindlich für Bewegungen im Wasser. Es ist bekannt, dass sie schnell und lautlos zum Ufer schwimmen und einen Menschen packen, um ihn unter die Wasseroberfläche zu zerren. Sie greifen bevorzugt mit ihren kraftvollen Kiefern an, die 2W4 Schadenspunkte verursachen, und schlagen mit ihren Schwänzen für 1W12 Schadenspunkte zu. Krokodile kämpfen untereinander um jede Beute, die sie in ihren Kiefern packen, und reißen ihr Opfer manchmal in Stücke. Das Einzige, was ein Krokodil verlangsamen kann, ist Kälte. Sie werden langsam und träge (auf 50% ihrer normalen Bewegung reduziert), wenn die Temperatur unter 4°C fällt.',
  'Krokodile versammeln sich manchmal in großer Zahl, aber sie sind von Natur aus nicht gesellig und kooperieren nicht bei der Jagd. Sie haben gut verborgene Baue und schleppen ihre Beute oft in ihre Baue, bevor sie sie fressen. Wenn ein leckerer Bissen ihren Weg kreuzt, gerät eine Gruppe von Krokodilen in einen Fressrausch, wobei jedes versucht, einen Teil des Festmahls zu ergattern. Sie jagen fast täglich, hauptsächlich im Wasser, selten an Land. Ihre Geschmäcker sind vielfältig: Fische, Menschen, kleine Säugetiere, Wasservögel und sogar ein unvorsichtiger Löwe ist gelegentlich in ihre Fänge geraten. Hungrige Krokodile lassen manchmal Boote kentern, um zu sehen, was herausfällt.',
  'Das Krokodil ist ein gewaltiger Jäger und hat wenig Konkurrenz um Nahrung von anderen Wasserkreaturen. Eines der wenigen Monster, die mit ihm konkurrieren können, ist die Drachenschildkröte. Selbst an den Flussufern hat es wenig von rivalisierenden Raubtieren zu befürchten; die meisten würden es vorziehen, sich nicht mit einem Krokodil anzulegen. Der einzige Jäger, den das Krokodil fürchten muss, ist der Mensch, der es wegen seiner zähen Haut jagt, die in schönes, glänzendes Leder verwandelt werden kann. Krokodile werden auch gejagt, um die Gefahr zu beseitigen, die sie für Gemeinden am Flussufer darstellen.'
);

-- Crustacean, Giant (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Krebstier, Riesig',
  'Crustacean, Giant',
  'Monstrous Manual',
  FALSE,
  'Any seashore',
  'Rare',
  'None',
  'Any',
  'Omnivore',
  'Non- (0)',
  'Nil',
  'Neutral',
  '2-12',
  3,
  '9',
  '3',
  3,
  17,
  '2',
  '2-8/2-8',
  'Nil',
  'Surprise',
  0,
  'L',
  'Elite (13)',
  13,
  65,
  'Riesenkrebstiere sind eigenartige Mutationen von Krabben und Süßwasser-Flusskrebsen. Erstere bewohnen Salzwasserregionen, während letztere nur in Süßwasser zu finden sind.',
  'Krabben sind stets hungrig und bevorzugen es, ihre Beute zu beschleichen (-3 Malus auf den Überraschungswurf des Gegners) und sie mit ihren Scheren zu packen, zu zerstückeln und zu fressen. Ein erfolgreicher Angriff mit den Scheren verursacht 2W4 Schadenspunkte. Sobald sie etwas Essbares gefangen haben, halten sie inne, um es zu fressen, außer sie werden angegriffen. Falls eine Krabbe ihre Mahlzeit in Frage stellt, versucht sie mit der Beute davonzuschwirren, möglicherweise in ihren Bau.',
  'Die Riesenkrabbe lebt an der Küste, durchsucht Strände nach Nahrung und wagt sich ins Wasser auf der Suche nach Fischen und anderen Wassertieren. Sie ist gut an diese Lebensweise angepasst, da sie sowohl Luft als auch Wasser atmen kann. Riesenkrabben fressen häufig große tote Fische und anderes Aas, das an die Küste gespült wird. Sie funktionieren gleichermaßen gut an Land und im Wasser. Riesenkrabben graben sich manchmal tagsüber in den Sand ein und tauchen nur bei Dämmerung und Morgendämmerung auf, um zu fressen. Zu diesen Zeiten ist der Strand nicht nur von den Riesenkrabben belebt, sondern auch von ihren winzigen Verwandten. Die Riesen können auch tagsüber und nachts jagen.',
  'Die Riesenkrabbe erfüllt eine nützliche ökologische Funktion, indem sie die Meeresküsten von großem Aas befreit, das andernfalls verrotten würde. An der Küste wird sie von den ultimativen Räubern gejagt - Menschen und Halbmenschen - wegen ihres hervorragenden Fleisches und ihres harten chitinösen Panzers, der von manchen für die Herstellung von Rüstungen und Schilden geschätzt wird.'
);

-- Dinosaur I (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Dinosaurier I',
  'Dinosaur I',
  'Monstrous Manual',
  FALSE,
  'Any land',
  'Uncommon',
  'Solitary',
  'Day',
  'Herbivore',
  'Animal (1)',
  'Nil',
  'Neutral',
  '2-5',
  10,
  '6',
  '9',
  9,
  11,
  '1',
  '3-18',
  'Nil',
  'Nil',
  0,
  'H',
  'Elite (13)',
  13,
  1,
  'Dinosaurier sind auf alternativen Existenzebenen oder sogar auf verlorenen Kontinenten zu finden. Die angegebenen Häufigkeitszahlen gelten für Gebiete, wo Dinosaurier normalerweise vorkommen; an allen anderen Orten sind sie bestenfalls sehr selten. Dinosaurier oder "schreckliche Echsen" sind Reptilien, die von urtümlichen Reptilien namens Thecodontier abstammen. Die zwei Arten von Dinosauriern sind Saurischia ("Echsenhüfter") und Ornithischia ("Vogelhüfter"), benannt nach Begriffen, die ihre Beckenstruktur beschreiben. Zu den Saurischia gehören die fleischfressenden Theropoden, hier vertreten durch den Tyrannosaurus, und die pflanzenfressenden Sauropoden, hier vertreten durch den Diplodocus. Zu den Saurischia gehören auch Ornithomimosaurier und die verwandten Dromaeosaurier, hier vertreten durch den Deinonychus.',
  'Dinosaurier scheinen eine Mischung aus endothermen ("warmblütigen") und exothermen ("kaltblütigen") Wesen zu sein. Sie regulieren ihre Körpertemperatur innerlich, sind aber auch etwas von externer Wärme abhängig. Obwohl sie an einem kalten Morgen langsam sein mögen, sind sie vielleicht nicht so langsam wie ein typisches Reptil.',
  'Dinosaurier können in fast jeder Art von Umgebung gefunden werden, außer Wüsten, hohen Bergen und gefrorenen Einöden. Sie haben keine Gesellschaft und wenig Familienleben, wobei die meisten Arten ihre Eier verlassen, bevor sie ausschlüpfen.',
  'Gelehrte verstehen nicht, was Dinosaurier auf bestimmten Welten aussterben ließ, aber sie existieren in den "verlorenen Landen" auf mehreren Welten. Es mag Orte geben, wo Dinosaurier sich weiter zu verschiedenen Formen entwickelt haben; sie könnten Vorfahren moderner Echsenmenschen sein.'
);

-- Dog (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Hund',
  'Dog',
  'Monstrous Manual',
  FALSE,
  'Any',
  'Common',
  'Pack',
  'Any',
  'Omnivorous',
  'Semi- (2-4)',
  'Nil',
  'Neutral',
  '4-16 (4d4)',
  7,
  '15',
  '1+1',
  1,
  19,
  '1',
  '1-4',
  'Nil',
  'Nil',
  0,
  'S',
  'Unsteady',
  10,
  35,
  'Kleiner als Wölfe variiert das Aussehen des wilden Hundes von Ort zu Ort. Die meisten erscheinen sehr wolfsähnlich, während andere das Aussehen eines Wolfes und eines Schakals zu kombinieren scheinen.',
  'Wilde Hunde kämpfen als organisiertes Rudel. Sie bevorzugen kleines Wild und greifen Menschen und menschliche Siedlungen nur in Zeiten großen Hungers an. Der Biss eines wilden Hundes verursacht 1-4 Schadenspunkte.',
  'Wilde Hunde findet man fast überall. Sie laufen in Rudeln und werden vom dominanten Männchen angeführt. Das Rudel jagt normalerweise verschiedenes Wild und greift sogar Hirsche oder Antilopen an. Welpen werden im Frühling geboren. Wilde Hunde können gezähmt werden, wenn sie von ihrem Rudel getrennt werden.',
  'Wilde Hunde sind Allesfresser, die normalerweise von einer Kombination aus Jagen und Sammeln leben.'
);

-- Dolphin (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Delfin',
  'Dolphin',
  'Monstrous Manual',
  FALSE,
  'Any saltwater',
  'Uncommon',
  'School',
  'Any',
  'Carnivore',
  'Very (11-12)',
  'Nil',
  'Lawful good',
  '2-20',
  5,
  '30',
  '2+2',
  2,
  19,
  '1',
  '2-8',
  'Nil',
  'Save as 4th-lvl fighter',
  0,
  'M',
  'Steady (11)',
  11,
  120,
  'Delfine sind intelligente Meeressäugetiere.',
  'Von Natur aus friedlich, greifen Delfine im Allgemeinen nur an, wenn sie bedroht werden. Außer wenn sie 2 zu 1 in der Unterzahl sind, greifen Delfine immer Haie an. Ob sie einen Feind angreifen oder ihre Schule verteidigen, Delfine kämpfen als organisierte Einheit und reagieren auf Befehle ihres Anführers. Sie kämpfen mit besonderer Vehemenz zum Schutz ihrer Jungen, und eine ausgewählte Anzahl von Delfinen kann manchmal ein Verzögerungsgefecht führen und sich selbst opfern, damit der Rest der Schule in Sicherheit schwimmen kann.',
  'Delfine sind vollständig fleischfressend und leben von einer Diät aus Fischen. Obwohl sie mehrere Minuten lang unter Wasser bleiben können, müssen sie regelmäßig zum Atmen an die Oberfläche. Anders als bei den meisten Säugetieren ist das Atmen bei Delfinen eine bewusste, nicht unbewusste Handlung; mit anderen Worten, sie müssen sich buchstäblich daran erinnern zu atmen. Neugeborene Delfine werden von ihren Müttern und einer weiblichen Delfin-Geburtshelferin zum Atmen an die Oberfläche gebracht. Delfine sind von Natur aus verspielt, gutmütig und rechtschaffen gut, sie verachten böse Kreaturen. Die meisten durchstreifen die Ozeane in Schulen von bis zu 20 Delfinen und schwimmen, wohin ihre Laune sie führt. Sie kämpfen niemals untereinander oder mit anderen Delfinarten. Delfine sind berühmt für die große Freude, die sie am Leben haben; beim Schwimmen führen sie oft blendende Wasserstunts auf und springen auf spektakuläre Weise in und aus dem Wasser. Sie spielen auch mit Gegenständen, die sie finden, und erfreuen sich an Spielen. Delfine folgen manchmal Schiffen und unterhalten Besatzung und Passagiere mit ihren Kapriolen.',
  'Der Delfin ist sowohl Jäger als auch Gejagter in seiner Meereswelt. Haie und andere große böse Meereskreaturen jagen den Delfin mit Begeisterung. Trotz seiner vielen Feinde hat der Delfin viele ausgeprägte Vorteile, die es ihm ermöglichen zu überleben und sogar zu gedeihen. Er ist nicht nur ein starker, schneller Schwimmer, sondern seine Intelligenz und sein organisierter Lebensstil sind hocheffektive Verteidigungen gegen seine Feinde.'
);

-- Dragon, Brown (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Brauner Drache',
  'Dragon, Brown',
  'Monstrous Manual',
  FALSE,
  'Arid/Desert',
  'Very rare',
  'Solitary or clan',
  'Any',
  'Special',
  'High (13-14)',
  'Special',
  'Neutral (evil)',
  '1 (2-5)',
  2,
  '12, Br 24',
  '14 (base)',
  14,
  7,
  '3 + special',
  '1-4/1-4/3-30',
  'See below',
  'Varies',
  0,
  'G',
  'Fanatic (17-18)',
  17,
  0,
  'Braune Drachen, auch als große Wüstendrachen bekannt, wanderten aus der Wüste Raurin ab und frequentieren nun große Teile der Ödlande im östlichen Mulhorand. Braune Drachen sind wilde Bestien; obwohl sie intelligent sind, betrachten sie Menschen als Nahrung und finden es eigenartig, mit ihrer Mahlzeit zu sprechen. Sie haben keine Flügel und können nicht fliegen.',
  'Braune Drachen graben bevorzugt tiefe Gräben in den Sand und warten, bis Beute erscheint, um sie zu überfallen. Sie haben eine 90%ige Chance, die Schritte einer menschengroßen Kreatur auf dem Wüstensand aus einer Tiefe von bis zu 152,4 m zu hören.',
  'Braune Drachen findet man in Wüsten, oft nahe besiedelten Gebieten. Sie wohnen typischerweise in tiefen Bauten fast 0,3 m unter dem Sand, wo sie sich weitläufige Kammern aushöhlen.',
  'Braune Drachen können Sand und andere mineralische Materialien verdauen, um sich über lange Zeiträume zu erhalten. Jedoch ist Fleisch die bevorzugte Nahrung, wobei Pferdefleisch ein besonderer Favorit ist.'
);

-- Dragon, Deep (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Tiefendrache',
  'Dragon, Deep',
  'Monstrous Manual',
  FALSE,
  'Hill and mountain caverns, subterranean',
  'Rare',
  'Solitary or clan',
  'Any',
  'Carnivorous',
  'Exceptional (15-16)',
  'Special',
  'Chaotic evil',
  '1 (2-5)',
  10,
  '12, Fl 30 (C), Br 6, Sw 9',
  '14 (base)',
  14,
  7,
  '3 + special',
  '3-12/3-12/3-24',
  'See below',
  'Variable',
  0,
  'H',
  'Fanatic (17-18)',
  17,
  0,
  'Tiefendrachen sind an der Oberfläche kaum bekannt. Sie sind die Jäger der Schattenlande. Verschlagen und geduldig stellen sie ihr Überleben, gefolgt von ihrer Jagdfreude, über alles andere. Tiefendrachen sammeln sorgfältig Schätze und verstecken sie in verschiedenen Verstecken, die mit Fallen und Magie bewacht werden. Sie können die meisten magischen Gegenstände benutzen und behalten jene, die sie erbeuten, für den persönlichen Gebrauch.',
  'Tiefendrachen graben sich durch den Boden und kämpfen mit ihren mächtigen, steinzerreißenden Klauen. Sie lieben es zu kämpfen und Beute durch die lichtlosen Höhlen der Schattenlande zu jagen, wobei sie ihre verschiedenen Formen einsetzen. In Schlangenform haben sie RK 6, BW 3, Fl 1(S), Schw 3,3, verlieren Klauenangriffe, erhalten aber einen Umschlingungsangriff (Angriffswurf erforderlich, verursacht 3W8 Schadenspunkte pro Runde, behindert Bewegung, Zauberwirken und verursacht -1 auf Angriffswürfe und 1 Punkt RK-Malus).',
  'Tiefendrachen durchstreifen die Schattenlande. Sie sind große Erforscher und wagen sich sogar (besonders wenn sie junge Erwachsene sind) von Zeit zu Zeit an die Oberfläche - besonders um gestohlene Schätze zurückzuholen, sich an Feinden zu rächen und Magie zu erbeuten oder zu stehlen.',
  'Es ist bekannt, dass Tiefendrachen fast alles fressen, aber sie schätzen besonders das Fleisch von Muscheln, Fischen, Kuo-Toa und Aboleth. Sie betrachten Mantelwesen und Gedankenschinder als gefährliche Rivalen in den Schattenlanden. Tiefendrachen meiden Konfrontationen mit anderen Drachen und kämpfen niemals gegen andere ihrer Art oder bestehlen sie.'
);

-- Dragon, Gem, Amethyst (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
