  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Amethystdrache',
  'Dragon, Gem, Amethyst',
  'Monstrous Manual',
  FALSE,
  'Temperate, cold/mountain lakes',
  'Very rare',
  'Solitary or clan',
  'Any',
  'Special',
  'Genius (17-18)',
  'Special',
  'Neutral',
  '1 (2-5)',
  -4,
  '12, Fl 40 (C), Sw 12',
  '14 (base)',
  14,
  7,
  '3',
  '1-10/1-10/5-30',
  'Varies',
  'Varies',
  0,
  'G',
  'Fanatic (17-18)',
  17,
  0,
  'Wissenschaften: detonieren, Kraft projizieren, Telekinese; Andachten: Körper kontrollieren, Trägheitsbarriere, molekulare Erregung.',
  'Amethystdrachen ziehen Verhandlungen dem Kampf vor. Wenn Verhandlungen schlecht verlaufen, greift der Drache zuerst mit seiner Atemwaffe an, dann mit Psionik und Zaubern. Sie verstecken sich nie oder versuchen einen Hinterhalt. Amethystdrachen betrachten Rückzug als unehrenhaft, tun es aber, wenn sie dem Tod gegenüberstehen.',
  'Amethystdrachen leben an den Ufern abgelegener Bergseen und -tümpel, manche in Höhlen unter dem Wasser. Sie sind gute Eltern, glauben aber, dass ihre Jungen für sich selbst sorgen sollten, sobald sie junge Erwachsene werden. Amethystdrachen mögen rote und weiße Drachen nicht und betrachten silberne und kupferne Drachen als töricht.',
  'Amethystdrachen fressen bevorzugt Fisch und eine große Anzahl von Edelsteinen. Sie sind nicht von Natur aus Feinde irgendeiner Lebensform.'
);

-- Dragon, Gem, Crystal (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Kristalldrache',
  'Dragon, Gem, Crystal',
  'Monstrous Manual',
  FALSE,
  'Temperate, cold/Mountains',
  'Very rare',
  'Solitary or clan',
  'Any',
  'Special',
  'Exceptional (15-16)',
  'Special',
  'Chaotic neutral',
  '1 (2-5)',
  10,
  '9, Fl 24 (C), Jp 3',
  '10 (base)',
  10,
  11,
  '3 + special',
  '1-6/1-6/2-12',
  'Varies',
  'Varies',
  0,
  'L',
  'Fanatic (17-18)',
  17,
  0,
  'Wissenschaften: Hellhören, Hellsehen, Präkognition; Hingabe: beliebig.',
  'Kristalldrachen bevorzugen Unterhaltung stark gegenüber Kampf und setzen oft früh in jedem Gespräch Person bezaubern ein. Sie verstecken sich anfangs nicht, aber falls Besucher feindselig werden, zieht sich ein Kristalldrache sofort zurück, um seine Feinde mit seinen besonderen Fähigkeiten zu beobachten und einen Angriff zu planen. Oft setzt er zuerst seine Atemwaffe ein, um Feinde zu schwächen und zu verwirren. Zauber und andere Fähigkeiten werden nach Bedarf eingesetzt, wobei Klauen und Biss das letzte Mittel sind.',
  'Kristalldrachen bevorzugen kalte, offene Gebiete mit klarem Himmel und schauen gerne zu den Sternen. Es ist bekannt, dass sie Schneefestungen bauen, schöne Schneeskulpturen erschaffen und Schneebälle auf verschiedene Ziele werfen. Sie sind lebenslustig und schelmisch. Kristalldrachen sind einigermaßen gute Eltern, wenn auch etwas verantwortungslos.',
  'Kristalldrachen bevorzugen Edelsteine und Metallerze vor allen anderen Nahrungsmitteln.'
);

-- Dragon, Gem, Emerald (new)
