  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Smaragddrache',
  'Dragon, Gem, Emerald',
  'Monstrous Manual',
  FALSE,
  'Tropical, subtropical/Extinct volcanoes',
  'Very rare',
  'Solitary or clan',
  'Any',
  'Special',
  'Exceptional (15-16)',
  'Special',
  'Lawful neutral',
  '1 (2-5)',
  -2,
  '9, Fl 30 (C), Br 3',
  '12 (base)',
  12,
  9,
  '3',
  '1-8/1-8/3-18',
  'Varies',
  'Varies',
  0,
  'H',
  'Fanatic (17-18)',
  17,
  0,
  'Wissenschaften: Aura-Sicht, Objektlesung, Präkognition; Hingaben: Rundumsicht, Kampfgeist, Gefahrensinn.',
  'Smaragddrachen errichten normalerweise Fallen und Alarmanlagen um ihre Baue, um sie vor Besuchern zu warnen. Sie verstecken sich oft vor Eindringlingen, nutzen besondere Fähigkeiten zur Beobachtung und kommen selten heraus, um zu sprechen. Wenn Eindringlinge angreifen oder sich dem Schatz des Drachen nähern, gräbt sich der Drache darunter ein, um seine Opfer zu überraschen, dann setzt er Atemwaffe und Klauen ein und versucht, so viele wie möglich schnell kampfunfähig zu machen. Wenn er überlegenen Streitkräften gegenübersteht, zieht sich der Drache zurück und wartet notfalls Jahre auf Rache.',
  'Smaragddrachen sind zurückgezogen lebend und errichten ihre Baue in den Kegeln erloschener oder selten aktiver Vulkane. Diese Drachen sind beschützende Eltern und bevorzugen es, dass ihre Jungen so lange wie möglich im Bau bleiben, um sich gegenseitig zu schützen. Smaragddrachen leben manchmal in der Nähe von Saphirdrachen und sie fürchten die gefräßige Gier der Roten Drachen.',
  'Smaragddrachen fressen alles, bevorzugen aber Echsen und Riesen. Sie sind aktiv feindselig gegenüber Feuerriesen.'
);

-- Dragon, Gem, Sapphire (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
