-- Dragon, Steel (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Stahldrache',
  'Dragon, Steel',
  'Monstrous Manual',
  FALSE,
  'Temperate cities (rarely temperate hills, plains, and forests.)',
  'Very rare',
  'Solitary',
  'Any',
  'Special',
  'Supra-genius (19-20)',
  'Special',
  'Lawful neutral (good)',
  '1',
  10,
  '9, Fl 30(D), Sw 6',
  '11 (base)',
  11,
  9,
  '3 + special',
  '1-10/1-10/3-30',
  'Special',
  'Variable',
  0,
  'H',
  'Fanatic (17-18)',
  17,
  0,
  'Stahldrachen lieben es, menschliche und halbmenschliche Gefährten zu haben, und sie ziehen es vor, inmitten des geschäftigen Treibens großer Städte zu leben. Sie geben sich oft als Gelehrte, Wissenschaftler, Magier oder andere Intellektuelle aus.',
  'Stahldrachen bevorzugen Wortgefechte gegenüber dem Kampf. Wenn sie bedrängt werden, beginnen sie gewöhnlich mit einem Zauberangriff und vermeiden den Nahkampf. Wenn sie ernsthaft verletzt oder bedroht werden, nehmen sie wieder Drachengestalt an und setzen ihre Atemwaffen ein. Sie hauchen jeden Gegner an, den sie im Nahkampf bekämpfen wollen, und sie suchen ihre Feinde in der Wolke zu halten, bis das Gas seine Wirksamkeit verliert.',
  'Stahldrachen bevorzugen menschliche Unterkünfte, die gut mit starken Räumen oder Gewölben ausgestattet sind, um ihre Schätze zu schützen.',
  'Stahldrachen bevorzugen menschliche Nahrung. Anders als andere gestaltwandelnde Drachen können sie nicht unbegrenzt von solcher Kost leben, da sie genug essen müssen, um ihre wahre Körpermasse zu erhalten. Ein- oder zweimal im Monat verlassen sie ihre angenommenen Städte und gehen in die Wildnis, um Nahrung zu jagen. Sie erklären ihre Abwesenheit auf eine Weise, die mit ihren menschlichen Identitäten vereinbar ist.'
);

-- Dragon, Yellow (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Gelber Drache',
  'Dragon, Yellow',
  'Monstrous Manual',
  FALSE,
  'Desert',
  'Very rare',
  'Solitary',
  'Any',
  'Omnivore',
  'Very (11-12)',
  'See below',
  'Chaotic evil',
  '1 (1-4)',
  10,
  '12, Fl 30 (C)',
  '13 (base)',
  13,
  7,
  '3 + special',
  '1-8/1-8/2-16',
  'See below',
  'Variable',
  0,
  'G',
  'Champion (15-16)',
  15,
  0,
  'Obwohl die Existenz gelber Drachen von Gelehrten schon lange vorhergesagt wurde (basierend auf Theorien der Grundfarben), wurde das erste Exemplar erst vor etwa fünf Jahren gesichtet. Diese Kreaturen sind einzelgängerisch und verschwiegen und ziehen es vor, in sorgfältig vorbereiteten Fallen auf Beute zu lauern, anstatt aktiv zu jagen.',
  'Obwohl sie List dem Kampf und Hinterhalt dem Angriff vorziehen, sind gelbe Drachen wilde und gerissene Kämpfer. Selbst wenn sie in eine Situation gedrängt werden, in der direkter Kampf unvermeidlich ist, setzen sie immer noch ihre Zauber und angeborenen Fähigkeiten ein, um ihre Gegner irrezuführen, fehlzuleiten und abzulenken.',
  'Gelbe Drachen lieben Wüsten und bevorzugen Gebiete sandiger, windgepeitschter Trostlosigkeit. Sie fühlen sich bei Tagestemperaturen von 40 Grad und darüber am wohlsten, obwohl sie problemlos Temperaturen unter dem Gefrierpunkt in der Nacht überleben können. Sie teilen sich weitgehend dasselbe Territorium wie Messingdrachen; daher geraten die Arten gelegentlich in Konflikt.',
  'Obwohl sie alles fressen können, bevorzugen gelbe Drachen frisches Fleisch. (Halb)Menschen gelten als Delikatesse, ebenso wie die ungeschlüpften Eier von Messingdrachen. (Gelbe kommen selten in den Genuss dieser letzteren Mahlzeit.)'
);

-- Dragonfish (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Drachenfisch',
  'Dragonfish',
  'MC1 Volume I (w/binder #1)',
  FALSE,
  'Subtropical to temperate, shallow fresh water pools, slow streams and rivers',
  'Rare',
  'Solitary',
  'Dusk and night',
  'Scavenger',
  'Non- (0)',
  'Nil',
  'Nil',
  '1',
  5,
  'Sw 6',
  '2',
  2,
  19,
  '1',
  '1-6',
  'Spines and poison',
  'Natural camouflage',
  0,
  'T',
  'Irregular (5)',
  5,
  270,
  'Diese scheuen, einzelgängerischen Aasfresser sind nur daran interessiert, am Leben zu bleiben und zu fressen. Dennoch machen die zwei ausgezeichneten Selbstverteidigungsmethoden, die diese Kreaturen entwickelt haben, sie zu einem potentiell tödlichen Feind für ungeschickte, unaufmerksame Abenteurer.',
  'Drachenfische sind in ihrer natürlichen Umgebung extrem schwer zu entdecken. Ihre gesprenkelte braune Färbung erlaubt es ihnen, mit den Felsen und dem Schlamm am Grund der Gewässer, die sie bewohnen, zu verschmelzen. Da ihre natürliche Tarnung so erfolgreich ist, können Drachenfische nur zu 15% der Zeit entdeckt werden, und auch nur, wenn die Suchenden wissen, wonach sie suchen. Da Drachenfische außerdem dazu neigen, nachts aktiv zu sein, ist es immer extrem schwierig, einen zu finden.',
  'Drachenfische neigen dazu, nahe dem Grund seichter Gewässer zu leben. Ihre Nahrung besteht größtenteils aus langsamen Schnecken, kleinen Fischen und den Überresten anderer Kreaturen, die kürzlich im Wasser gestorben sind. Jedoch ist bekannt, dass der Drachenfisch fast alles frisst, was er schlucken kann, einschließlich kleiner Metallstücke wie Münzen oder Ringe. Die starken Verdauungssäuren im Magen des Fisches zersetzen alles, was er schluckt, sehr schnell, wodurch es fast unmöglich wird, unbeschädigte Schätze aus dem Magen eines Drachenfisches zu bergen.',
  'Intelligente Rassen haben eine große Anzahl von Verwendungsmöglichkeiten für den Drachenfisch entdeckt. Drachenfischgift ist hochgiftig und ein ausgewachsener Drachenfisch kann genug liefern, um eine große Anzahl von Kreaturen zu töten. Es ist natürlich, dass Kreaturen, die häufig Gift verwenden, eine Standardmethode zum Fangen von Drachenfischen haben. Außerdem ergeben Drachenfischstacheln ausgezeichnete Wurfpfeile, da sie extrem stark und sehr scharf sind. (Die Stacheln wachsen auch am Fisch nach, so dass ihre Ernte möglich ist.) Die Drachenfischhaut wird auch nicht verschwendet, da sie ausgezeichnetes Material für Schuppenpanzer abgibt. Die Verwendung jedes Teils des Drachenfisches ist potentiell tödlich, es sei denn, die Giftsäcke und Stacheln werden zuerst sorgfältig entfernt.'
);

-- Dragonne (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Dragonne',
  'Dragonne',
  'Monstrous Manual',
  FALSE,
  'Warm temperate to tropical/Hills and desert',
  'Very rare',
  'Solitary',
  'Dusk to dawn',
  'Carnivore',
  'Low (5-7)',
  'B,S,T',
  'Neutral',
  '1',
  6,
  '15, Fl 9 (E)',
  '9',
  9,
  11,
  '3',
  '1-8/1-8/3-18',
  'Roar',
  'Nil',
  0,
  'M',
  'Champion (15)',
  15,
  2,
  'Der Dragonne vereint einige der gefährlichsten Eigenschaften eines Löwen und eines Messingdrachen und ist ein bösartiger und tödlicher Jäger sowie eine Bedrohung für viele, die in wärmeren Klimazonen reisen.',
  'Dragonnes greifen normalerweise zuerst mit ihren Vorderklauen an und verursachen mit jedem Satz 1W8 Schadenspunkte, sowie mit ihren furchtbaren Kiefern, die 3W6 Schadenspunkte verursachen. Dies reicht normalerweise aus, um die meisten Kreaturen zu töten, denen der Dragonne begegnet. Falls ein Dragonne jedoch gegen einen besonders tödlichen Gegner kämpft oder in einer Schlacht mit einem schwächeren Gegner verwundet wird, setzt er sein tödliches Brüllen ein.',
  'Dragonnes bevorzugen es, in felsigen Vorgebirgen und Wüsten zu leben. Sie nehmen große, natürliche Höhlen als ihre Baue und lagern ihre kleinen Mengen an Schätzen, normalerweise von getöteten Abenteurern genommen, in lockeren Haufen um ihre felsigen Heime. Ihre Territorien sind normalerweise sehr groß, da sie generell öde Gebiete bewohnen.',
  'Der Dragonne bevorzugt Herdentiere wie Ziegen als Nahrung, besonders da sie nicht so heftig zurückkämpfen wie Menschen. Er greift einen Menschen oder Halbmenschen nur dann als Nahrung an, wenn kein anderes Wild verfügbar ist. Dragonnes sind nicht zwangsläufig aggressiv gegenüber Fremden, und der Ruf der Kreatur als gedankenloser Verschlinger hilfloser Reisender ist mehr das Produkt von Unwissen als gut erforschte Tatsache. Ein Dragonne wird fast immer jede Kreatur angreifen, die in seinen Bau eindringt oder sein Territorium bedroht. Das bedeutet, dass Abenteurer, die über eine Dragonne-Höhle stolpern, oder Siedler, die entscheiden, im Territorium eines Dragonnes zu bauen, oft heftigem und sofortigem Angriff ausgesetzt sind. Kreaturen, die den Bau des Dragonnes nicht bedrohen oder einfach durch sein Territorium ziehen, werden normalerweise in Ruhe gelassen. Obwohl die Intelligenz des Dragonnes niedrig ist, kann er den Unterschied zwischen einem harmlosen Reisenden und einem potentiell problematischen Siedler erkennen.'
);

-- Dragonet, Faerie Dragon (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Feendrache',
  'Dragonet, Faerie Dragon',
  'Monstrous Manual',
  FALSE,
  'Temperate, tropical, and subtropical forests',
  'Very rare',
  'Solitary or clan',
  'Any',
  'Herbivore',
  'Genius (17-18)',
  'S,T U',
  'Chaotic good',
  '1-6',
  5,
  '6, Fl 24 (A)',
  'See below',
  1,
  17,
  '1',
  '1-2',
  'Breath weapon, spells',
  'Invisibility',
  0,
  'T',
  'Steady (11)',
  11,
  3,
  'Ein chaotischer Ableger des Pseudodrachens, der Feendrache lebt in friedlichen, verworrenen Wäldern und gedeiht durch Streiche, Unfug und praktische Scherze.',
  'Feendrachen können nach Belieben unsichtbar werden und können angreifen, Zaubersprüche verwenden und Atemwaffen einsetzen, während sie unsichtbar sind. Sie greifen als 4-TW-Monster an und beißen für 1-2 Schadenspunkte. Die meisten (65%) Feendrachen verwenden Magierzauber als Magier der auf der beigefügten Tabelle angegebenen Stufe; 35% verwenden Priesterzauber der folgenden Sphären: Tier, Pflanze, Elementar und Wetter. Fast alle Zaubersprüche werden wegen ihres Unfugpotentials gewählt. Die zwei häufigsten Zaubersprüche der Feendrachen sind Wasseratmung und Legendenwissen; andere Favoriten sind Bauchreden, Unsichtbarer Diener, Vergessen, Suggestion, Entfernungsverzerrung, Begrenzter Wunsch, Verschleierung, Tierwachstum und Fels beleben.',
  'Feendrachen bauen ihre Baue in den Höhlen hoher Bäume, vorzugsweise in der Nähe eines Teichs oder Bachs, da sie sehr gerne schwimmen und tauchen. Sie leben oft in Gesellschaft einer Gruppe von Feen oder Kobolden.',
  'Feendrachen fressen Obst, Gemüse, Nüsse, Wurzeln, Honig und Getreide. Sie sind besonders gerne Obstkuchen zugetan und sind dafür bekannt, große Anstrengungen zu unternehmen, um einen frischen Apfelkuchen zu bekommen.'
);

-- Dragonet, Fire Drake (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Feuerdrache',
  'Dragonet, Fire Drake',
  'Monstrous Manual',
  FALSE,
  'Temperate/Hills and mountains',
  'Rare',
  'Familial lair',
  'Day',
  'Carnivore',
  'Semi- (2-4)',
  'Nil',
  'Neutral',
  '2-8',
  5,
  '6, Fl 18(C)',
  '4',
  4,
  17,
  '1',
  '2-8',
  'Breath weapon',
  'Nil',
  0,
  'S',
  'Average (9)',
  9,
  420,
  'Obwohl er bei der ersten Sichtung häufig für einen jungen roten Drachen gehalten wird, ist der Feuerdrache weder so intelligent noch so mächtig wie sein drachischer Verwandter. Er reagiert mit Flammen auf jeden Reiz.',
  'Wenn ein Feuerdrache gestört wird, besteht eine 50-prozentige Chance, dass er angreift. Sein Hauptangriff ist seine Atemwaffe (Feuer), die er bis zu fünfmal täglich einsetzen kann. Das Feuer bildet einen Kegel von der Schnauze des Drachen zu einem 3 m großen Kreis am äußersten Ende seiner 18 m Reichweite und verursacht 2-16 Schadenspunkte bei allen Betroffenen (Rettungswurf gegen Atemwaffe für halben Schaden). Die Klauen des Feuerdrachen werden nicht im Kampf eingesetzt, aber sein Biss verursacht 2-8 Schadenspunkte.',
  'Feuerdrachen sind familiäre Kreaturen, wobei ein verpaartes Männchen und Weibchen Wohnsitz in einem Bau nehmen, der gewöhnlich eine kleine Höhle oder ein Felssims unter einem Vorsprung oder Felsüberhang ist. Gewöhnlich werden sechs bis acht Eier gelegt und vom Paar gehütet, wobei sie durch die reichliche Körperwärme der Eltern warm gehalten werden. Die Eier, die im Frühsommer gelegt werden, brauchen etwa 60 Tage zum Ausbrüten. Die jungen Feuerdrachen lernen Feuer zu speien, noch bevor sie fliegen lernen, und sind sogar nervöser als die Erwachsenen, wobei sie während dieser Zeit mehrmals täglich Flammen im Bau oder in der Nähe ausspeien. Der erste Flug erfolgt etwa 60 Tage nach dem Schlüpfen.',
  'Feuerdrachen haben eine kurze Lebensspanne im Vergleich zu ihren größeren Verwandten, den Drachen, und leben gewöhnlich nur 75 bis 100 Jahre.'
);

-- Dragonet, Pseudodragon (new)
