  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Pseudodrache',
  'Dragonet, Pseudodragon',
  'Monstrous Manual',
  FALSE,
  'Temperate or subtropical forests and caves',
  'Very rare',
  'Solitary',
  'Day',
  'Omnivore',
  'Average (8-10)',
  'Q (×10)',
  'Neutral (good)',
  '1 (50% chance of 1-8 in nests)',
  2,
  '6, Fl 24 (B)',
  '2',
  2,
  19,
  '1',
  '1-3+special',
  'Poison sting',
  'Chameleon power',
  35,
  'T',
  'Champion (15)',
  15,
  420,
  'Pseudodrachen sind eine Art kleiner fliegender Echsen, die in dicht bewaldeten Wildnisgebieten leben. Diese verspielten, gutartigen Kreaturen haben magische Kräfte, die sie mit anderen teilen können, weshalb sie oft als Begleiter gesucht werden.',
  'Der Pseudodrache kann mit seinen kleinen, drachenartigen Kiefern einen bösartigen Biss austeilen, aber seine Hauptwaffe ist sein mit einem Stachel ausgerüsteter Schwanz. Die Kreatur kann ihn mit blitzartiger Geschwindigkeit bewegen und trifft mit +4 auf Angriffswürfe. Jede getroffene Kreatur muss einen Rettungswurf gegen Gift bestehen oder in einen Zustand der Katalepsie fallen, der 1-6 Tage anhält. Das Opfer scheint vollkommen tot, aber am Ende dieser Zeit wird der Charakter entweder unversehrt aufwachen (75% Chance) oder sterben (25% Chance).',
  'Diese waldbewohnenden Kreaturen errichten ihre Baue in den Höhlen großer Bäume oder in großen Höhlen.',
  'Pseudodrachen sind Allesfresser, bevorzugen aber Fleisch. Ihre Nahrung besteht hauptsächlich aus Nagetieren und kleinen Vögeln mit gelegentlichen Blättern, Früchten und Beeren. In der Wildnis leben Pseudodrachen ein Einzelgängerleben und beschützen kleine persönliche Schatzhörter in ihren Nestern. Sie versammeln sich einmal im Jahr zur Paarung, im frühen Frühling, wenn Zusammenkünfte von Dutzenden von Pseudodrachen nicht ungewöhnlich sind. Nach der Paarung trennen sich Männchen und Weibchen; die Weibchen legen gesprenkelten braune Eier in Gelegen von vier bis sechs, die im Hochsommer schlüpfen; die Weibchen ziehen die Jungen allein auf. Pseudodrachen halten Winterschlaf; die Jungen verlassen das Nest im Frühling zur Paarung.'
);

-- Dwarf (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Zwerg',
  'Dwarf',
  'Monstrous Manual',
  FALSE,
  'Subarctic to subtropical rocky hills',
  'Common',
  'Clans',
  'Any',
  'Omnivore',
  'Very (11-12)',
  'M×5 (G,Q×20,R)',
  'Lawful good',
  '40-400',
  4,
  '6',
  '1',
  1,
  20,
  '1',
  '1-8 (weapon)',
  'See below',
  'See below',
  0,
  'S',
  'Elite (13-14)',
  13,
  175,
  'Zwerge sind ein edles Volk von Halbmenschen, die unter der Erde wohnen, große Städte errichten und gewaltige Kriege gegen die Mächte des Chaos und Bösen führen. Zwerge haben auch viel mit den Steinen und Edelsteinen gemein, mit denen sie gerne arbeiten, denn beide sind hart und unnachgiebig. Es wird oft gesagt, dass es einfacher ist, einen Stein zum Weinen zu bringen, als einen Zwerg umzustimmen.',
  'Zwerge sind mutige, hartnäckige Kämpfer, die Magie abgeneigt sind. Sie verwenden niemals magische Zauber oder bilden sich als Magier aus, obwohl sie Priester werden und die Zauber dieser Gruppe nutzen können. Aufgrund ihrer unmagischen Natur erhalten sie sogar einen speziellen Bonus auf alle Rettungswürfe gegen magische Stäbe, Zauberstäbe, Ruten und Zauber. Zwerge erhalten einen +1-Bonus auf Rettungswürfe gegen diese magischen Angriffe für jeweils 3,5 Punkte Konstitutionswert. Siehe Tabelle 9 im Spielerhandbuch für spezifische Boni.',
  'Gewöhnlich um profitable Minen herum errichtet, sind zwergische Städte weite, schöne Komplexe, die in massiven Stein gehauen sind. Zwergische Städte brauchen Hunderte von Jahren zur Fertigstellung, aber einmal vollendet stehen sie Jahrtausende ohne jede Art von Reparatur. Da Zwerge ihre Heime nicht oft verlassen und immer zu ihnen zurückkehren, erschaffen sie ihre Städte mit Dauerhaftigkeit im Sinn. Truppen bewachen zwergische Städte zu jeder Zeit, und manchmal (60% Chance) verwenden Zwerge auch Tiere als Wachen - entweder 2W4 Braunbären (75% Chance) oder 5W4 Wölfe (25% Chance).',
  'Da ein Großteil ihrer Kultur darauf fokuss'
);

-- Dwarf, Gully (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Rinnensalzwerg',
  'Dwarf, Gully',
  'MC2 Volume II',
  FALSE,
  'Tropical, subtropical, and temperate/Plain, swamp, forest, jungle, hill, and mountain',
  'Rare',
  'Clan',
  'Any',
  'Omnivore',
  'Varies (3-9)',
  'J (׼); (J,K)',
  'Varies, but usually chaotic neutral',
  '2-20',
  7,
  '6',
  '1',
  1,
  19,
  '1 or 2',
  '1-4/1-4 (fist/bite) or by weapon (1-4)',
  'See below',
  'See below',
  0,
  'S',
  'Unsteady (7)',
  7,
  0,
  'Rinnensalzwerge, auch als Aghar bekannt, sind dumm, schmutzig und widerwärtig.',
  'Da sie Feigheit als Tugend betrachten, haben Rinnensalzwerge das Kriechen zur Kunstform erhoben. Werden sie von einem gefährlichen Gegner konfrontiert, aber nicht sofort angegriffen, werden Rinnensalzwerge entweder ohnmächtig, weinen, betteln um Gnade, ergießen Ströme von Informationen, laufen davon oder stehen da und zittern. Wenn sie angegriffen werden, verteidigen sich Rinnensalzwerge, aber manchmal kämpfen sie mit geschlossenen Augen. Rinnensalzwerge sind nicht zu schade zum Stehlen, Lügen oder Tyrannisieren, und schmutzige Tricks gehören zu ihren Lieblingstaktiken.',
  'Rinnensalzwerg-Gemeinschaften sind recht klein und überschreiten selten mehr als 2W10 Mitglieder. Ein typischer Clan von 11 Mitgliedern umfasst einen Häuptling (einen Kämpfer der Stufe 2-6), etwa vier Kämpfer der 1. Stufe (von denen einer als Schamane des Clans dient, obwohl er keine magischen Fähigkeiten hat), einen Kämpfer der Stufe 2-4 (oder einen Dieb derselben Stufenspanne); der Rest sind Weibchen und Kinder. Die meisten Clans leben in verlassenen Dörfern oder in der Wildnis in alten Minen und Höhlen. Andere leben in Slums, Müllhalden oder den Kanalisationssystemen großer Städte. Wenn mehrere Clans zusammenleben, wird der stärkste und klügste Häuptling zum örtlichen König, dessen Titel durch das Voranstellen des Präfixes "Hoch" vor seinen Clannamen entsteht. Jeder nachfolgende König nennt sich oft "der Erste", aufgrund der Unfähigkeit der Rinnensalzwerge zu zählen.',
  'Andere Völker meiden Rinnensalzwerge, aber sie werden gelegentlich angeheuert, um niedere Arbeiten zu verrichten. Gnome heuern sie gelegentlich als Attentäter und Spione an, obwohl Rinnensalzwerge bei diesen Aufgaben nicht besonders geschickt sind. Rinnensalzwerge essen alles. Viele Rinnensalzwerge halten einen Topf mit Eintopf ständig kochend und werfen alles hinein, was tot oder fast tot ist.'
);

-- Eagle (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Adler',
  'Eagle',
  'MC2 Volume II',
  FALSE,
  'Subarctic to subtropical/',
  'Rare',
  'Solitary or flock',
  'Day',
  'Carnivore, scavenger',
  'Animal (1)',
  'See below',
  'Neutral',
  '1 or 2/5-12',
  6,
  '1, Fl 30 (C)',
  '1+3',
  1,
  18,
  '3',
  '1-2/1-2/1-2',
  'See below',
  'See below',
  0,
  'S',
  'Average (9)',
  9,
  175,
  'Adler sind majestätische Raubvögel, die selten zur Jagd verwendet werden, aber oft wegen ihrer Schönheit und legendären Tapferkeit begehrt sind.',
  'Ein Adler nutzt seine Krallen und seinen Schnabel zum Kampf, von denen jeder 1-2 Schadenspunkte verursacht. Ein Adler greift normalerweise aus großer Höhe an, faltet seine Flügel zurück und lässt die Schwerkraft ihn auf seine Beute hinabstürzen. Wenn ein Adler über 30 m hinabstürzt, ist seine Sturzgeschwindigkeit doppelt so hoch wie seine normale Fluggeschwindigkeit und der Adler ist darauf beschränkt, nur mit seinen beiden Krallensätzen anzugreifen. Jedoch erhalten diese Hochgeschwindigkeitsangriffe einen +2-Bonus auf den Angriffswurf und verursachen doppelten Schaden.',
  'Hohe Felsklippen und große, breite Bäume sind die bevorzugten Nistplätze für Adler. Sobald ein Adler ein Nest baut, behält er dieses Heim und erweitert es mit jeder vorübergehenden Saison, bis das Nest zerstört wird oder der Adler stirbt. Es besteht immer eine 50%-Chance, dass 1W4 Eier in einem Nest vorhanden sind. Wenn keine Eier vorhanden sind, besteht eine 20%-Chance, dass stattdessen 1W4 junge Adler anwesend sind. Es besteht immer eine 10%-Chance, dass der Adler einige kleine, glänzende Gegenstände im Nest lagert (wie Goldmünzen oder Edelsteine).',
  'Adler sind Fleischfresser und jagen im Allgemeinen Nagetiere, Fische und andere kleine Tiere. Adler ernähren sich bekanntermaßen auch vom Aas kürzlich getöteter Kreaturen. Außer bei außergewöhnlichem Hunger wird ein Adler niemals einen Menschen oder Halbmenschen angreifen, obwohl kleine Kreaturen wie Wichtel vor einem jagenden Adler auf der Hut sein müssen, der sie für Kaninchen halten könnte.'
);

-- Eel (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
