  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Aal',
  'Eel',
  'MC2 Volume II',
  FALSE,
  'Warm, fresh water',
  'Rare',
  'Solitary',
  'Any',
  'Carnivore',
  'Non- (0)',
  'Nil',
  'Neutral',
  '1-3',
  9,
  'Sw 12',
  '2',
  2,
  16,
  '1',
  '1-3',
  'Electric shock',
  'Immune to electrical attacks',
  0,
  'L',
  'Unsteady (7)',
  7,
  65,
  'Aale sind lange, schlangenartige Fische, die normalerweise nicht aggressiv sind. Dennoch hat die Natur die verschiedenen Aalarten mit interessanten - und gefährlichen - Verteidigungsmethoden ausgestattet.',
  'Ein angreifender Aal, sei es zur Selbstverteidigung oder auf der Jagd nach Nahrung, entlädt einen Stromstoß. Diese Ladung hat eine Reichweite von 4,6 m Radius. Kreaturen, die weniger als 1,5 m vom Aal entfernt sind, erleiden 3W8 Schadenspunkte; Kreaturen in 1,5 bis 3 m Entfernung erhalten 2W8 Schadenspunkte; alle anderen Kreaturen in Reichweite erleiden 1W8 Schadenspunkte. Ein Aal muss sich eine Stunde lang (sechs Runden) zwischen Angriffen aufladen.',
  'Seichte, langsam fließende Süßwasserflüsse in wärmeren Klimazonen sind die Wohnorte des Zitteraals. Der Zitteraal ist kein geselliges Tier und lebt ein einsames Leben, außer während der Paarungszeit. Wenn jedoch ein Aal Elektrizität entlädt, besteht eine 80%ige Chance, dass sich 1-2 andere Aale in der Nähe nähern in der Hoffnung, etwas zu fressen zu bekommen.',
  NULL
);

-- Elemental (Athas), General Information (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Elementar (Athas), Allgemeine Informationen',
  'Elemental (Athas), General Information',
  'Monstrous Manual',
  FALSE,
  NULL,
  'common',
  NULL,
  NULL,
  NULL,
  NULL,
  NULL,
  NULL,
  NULL,
  10,
  '',
  '1',
  1,
  20,
  '1',
  '',
  NULL,
  NULL,
  0,
  'M',
  '',
  10,
  0,
  'Von Priestern in ganz Athas verehrt und respektiert, repräsentieren Elementare den Inbegriff der bekannten Elemente: Luft, Erde, Feuer und Wasser. Die vier Elementare stellen die Kräfte dar, die das Alltagsleben der Bewohner des belagerten Planeten formen. Luft repräsentiert den Akt des Lebens, da ein Kind sie beim ersten Betreten der Welt einatmet und ein Sterbender sie als seinen letzten Akt vor dem Tod ausatmet. Wasser ist das Leben selbst, immer benötigt und niemals als selbstverständlich betrachtet. Erde repräsentiert die Welt, immer im Wandel, immer hart, aber verlässlich immer da. Feuer repräsentiert die Hitze der Sonne, die brennende Wüste und alles was verloren war.',
  NULL,
  NULL,
  NULL
);

-- Elemental, Composite (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Elementar, Verbundelement',
  'Elemental, Composite',
  'Monstrous Manual',
  FALSE,
  'Any outside',
  'Very rare',
  'Solitary',
  'Any',
  'See below',
  'Low to average (5-10)',
  'K',
  'Chaotic neutral',
  '1',
  2,
  'Fl 24',
  '9-12',
  9,
  9,
  '1',
  '2-16',
  'Whirlwind, lightning',
  '2 or better weapon to hit; see below',
  0,
  'G',
  'Champion (15-16)',
  15,
  9,
  'Der Sturm ist ein lebender Unwetter, der als dunkle Sturmwolke von vergleichsweise kleiner Größe erscheint. Menschliche oder tierische Züge sind oft in den brodelnden Dämpfen des Sturms zu erkennen. Silberne Adern erstrecken sich über die Kreatur und tragen die elektrischen Impulse, die die Energie des Sturms aufrechterhalten.',
  'Stürme sind territorial und betrachten jede Verletzung ihres Luftraums als direkte Herausforderung. Sie nähren sich von Feuchtigkeit aus Tieren und jagen oft in und um ihre Territorien. Sie haben eine Reihe angeborener Fähigkeiten, mit denen sie anderen Kreaturen das Leben schwer machen können. Sofern nicht anders angegeben, werden alle besonderen Fähigkeiten so eingesetzt, als wäre der Sturm ein Magier der 9. Stufe. Ein Sturm kann zwei Angriffe pro Runde ausführen, einen mit seinen Windkräften und einen mit seiner Blitzkraft.',
  'Es gibt viele Spekulationen über den Ursprung dieser Wesen, die offenbar mit Elementaren und Dschinn-Geschlecht verwandt sind. Stürme bestehen aus allen vier Grundelementen: Feuer, Erde, Luft und Wasser; Feuer in Form von Blitzen, Erde in ihrem silbernen "Kreislaufsystem", Luft in ihren Winden und Wasser in Form von Regen. Sie können versehentlich beschworen werden, wenn ein Zauberwirker versucht, einen Elementar zu beschwören, besonders einen der Luft oder des Wassers. Nach Ermessen des SL kann bei einer gestörten Beschwörung dem Zauberer eine 10%-50% Chance gewährt werden, einen Sturm zu beschwören. Diese Wesen können auch von einem Wetterbeschwörungszauber angezogen werden, mit einer 1% (nicht kumulativen) Chance zu erscheinen, jedes Mal wenn ein Zauber gewirkt wird.',
  'Stürme nähren sich von der in Tierkörpern gefundenen Feuchtigkeit. Obwohl sie nicht imstande sind, lebenden Kreaturen durch Entzug ihrer Feuchtigkeit Schaden zuzufügen, schweben sie nach einem Kampf dicht über dem Boden, um das Wasser aus toten Gegnern sowie alles Wasser zu saugen, das sie während des Kampfes niedergeschlagen haben könnten. Sie werden manchmal beim Plündern nach großen Schlachten zwischen Menschen gefunden. Indem sie Wasser aus einem Leichnam entfernen, machen sie ihn ungeeignet für eine Rückkehr zum Leben durch einen Tote erwecken-Zauber, obwohl Auferstehung und andere Zauber normal wirken.'
);

-- Elemental, General Information (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Elementar, Allgemeine Informationen',
  'Elemental, General Information',
  'Monstrous Manual',
  FALSE,
  NULL,
  'common',
  NULL,
  NULL,
  NULL,
  NULL,
  NULL,
  NULL,
  NULL,
  10,
  '',
  '1',
  1,
  20,
  '1',
  '',
  NULL,
  NULL,
  0,
  'M',
  '',
  10,
  0,
  'Elementare sind empfindungsfähige Wesen, die Körper aus einem der vier Grundelemente besitzen können, aus denen die Primärmaterielle Ebene besteht - Luft, Erde, Feuer oder Wasser. Normalerweise leben sie auf einer elementaren Inneren Ebene und werden nur auf der Primärmateriellen Ebene angetroffen, wenn sie durch magische Mittel herbeigerufen werden. (Siehe das Manual of the Planes für weitere Informationen über die Natur der verschiedenen Elementarebenen.) Jeder Elementar muss auf der Primärmateriellen Ebene eine Hülle aus dem Grundelement annehmen, das er repräsentiert, und sobald diese Hülle zerstört wird, kehrt der Elementar zu seiner heimatlichen Ebene zurück. Obwohl es viele mächtigere und intelligentere Bewohner der Elementarebenen gibt, ist der gewöhnliche Elementar am einfachsten zu kontaktieren und daher am häufigsten herbeigerufen.',
  NULL,
  NULL,
  NULL
);

-- Elf (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Elf',
  'Elf',
  'Monstrous Manual',
  FALSE,
  'Temperate to subtropical forest',
  'Uncommon',
  'Bands',
  'Any',
  'Omnivore',
  'High to Supra-genius (14-20)',
  'Individual: N; G,S,T in lair',
  'Chaotic good',
  '20-200',
  5,
  '12',
  '1+1',
  1,
  19,
  '1',
  '1-10',
  '+1 to hit with bow or sword',
  'See below',
  90,
  'M',
  'Elite (13)',
  13,
  420,
  'Obwohl ihre Leben mehrere Menschengenerationen überdauern, erscheinen Elfen auf den ersten Blick schwächlich im Vergleich zum Menschen. Jedoch besitzen Elfen eine Reihe besonderer Talente, die ihre etwas schwächere Konstitution mehr als ausgleichen.',
  'Elfen sind vorsichtige Kämpfer und nutzen immer ihre Stärken zu ihrem Vorteil, wenn möglich. Eine ihrer größten Stärken ist die Fähigkeit, sich lautlos und nahezu unsichtbar durch natürliche Umgebung, Wälder oder Forste zu bewegen. Indem sie sich leise bewegen und in der Vegetation Deckung suchen, können Elfen oft eine Person oder Gruppe überraschen (Gegner haben einen Überraschungsmodifikator von -4). Solange sie nicht angreifen, können die sich im Wald versteckenden Elfen nur von jemandem oder etwas entdeckt werden, das die Fähigkeit besitzt, unsichtbare Objekte zu sehen. Der militärische Wert dieser Fertigkeit ist immens, und elfische Armeen werden immer Späher aussenden, um den Feind auszuspionieren, da solche Spione selten gefangen - oder überhaupt gesehen - werden.',
  'Elfen schätzen ihre individuelle Freiheit sehr hoch, und ihre Gesellschaftsstruktur basiert auf unabhängigen Banden. Diese kleinen Gruppen, normalerweise bestehend aus nicht mehr als 200, erkennen die Autorität eines königlichen Oberherren an, der wiederum einem König oder einer Königin Treue schuldet. Jedoch sind die Gesetze und Beschränkungen, die der elfischen Gesellschaft auferlegt werden, sehr wenige im Vergleich zur menschlichen Gesellschaft und praktisch vernachlässigbar im Vergleich zur zwergischen Gesellschaft.',
  'Elfen produzieren feine Kleidung, wunderschöne Musik und brillante Poesie. Für diese Dinge kennen andere Kulturen das Waldvolk am besten. In ihrer Welt innerhalb des Waldes jedoch halten Elfen die dunklen Kräfte des Bösen und die Kreaturen in Schach, die den Wald plündern und dann weiterziehen würden, um einen anderen zu plündern. Allein aus diesem Grund sind Elfen unersetzlich.'
);

-- Elf, Aquatic (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Elf, Wasseself',
  'Elf, Aquatic',
  'Monstrous Manual',
  FALSE,
  'Temperate/Shallow salt water',
  'Very rare',
  'Bands',
  'Any',
  'Omnivore',
  'High to genius (14-18)',
  'K,Q, (I,O,X,Y)',
  'Chaotic good',
  '20-120',
  6,
  '9, Sw 15',
  '1+1',
  1,
  19,
  '1 or 2',
  '1-8 (weapon)',
  '+1 with spears and tridents',
  'See below',
  90,
  'M',
  'Elite (13)',
  13,
  420,
  'Unter den schäumenden Wogen wilder Küstenlinien lebt der Wasseself, der aquatische Verwandte der Waldelfen in Verhalten und Weltanschauung.',
  'Wasserelfen sind eine friedliebende Kultur. Es ist ein seltener Anblick, einen Wasserelfen einen Angriff starten zu sehen, und noch seltener für eine ganze Bande, sich zum Krieg zu rüsten. Wasserelfen werden ihre Heimstätten nur verlassen, um in die Schlacht zu ziehen, wenn die gesamte Gemeinschaft in Gefahr ist oder gegen große Feinde. Wenn sie zum Krieg gezwungen werden, beeindrucken sie alle Gegner mit ihrer wilden Tapferkeit und ihrem Geschick.',
  'Kleine Gemeinschaften von 3W100+100 normalen Einwohnern sind die Regel des wasserelfischen Lebensstils. Diese Gemeinschaften finden sich oft in dichten Tangbetten in geschützten Gewässern, obwohl die Wasserelfen auch Heime in Höhlen am Boden von Lagunen und Korallenriffen errichten können. Wasserfelfengemeinschaften halten durch einen kunstvollen und ineffizienten Brauch wandernder Herold/Boten Kontakt zueinander, die von einer Bande zur anderen reisen, ähnlich wie Postboten, die mündliche Nachrichten übermitteln. In jeder Gemeinschaft gibt es mehrere Anführertypen, wie früher umrissen, regiert von einem Kämpfer der 10.-12. Stufe mit einer persönlichen Garde aus acht elfischen Kämpfern der 7. Stufe. Magische Waffen würden vom Anführer oder einem seiner Wachen getragen.',
  'Jede Bande von Wasserelfen ist selbstgenügsam, baut ihren Tang an und jagt Fische, wenn nötig. Wasserelfen durchsuchen Wrackteile. Sie sind von der Vorstellung der Magie verzaubert, aber sie erkennen, dass Landelfen besser ausgerüstet sind, damit umzugehen. Sie handeln oft seltene oder dekorative Gegenstände, die sie gefunden haben, mit den Hochelfen gegen Metallwaffen und Werkzeuge, die sie nicht unter Wasser schmieden können.'
);

-- Ettercap (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Ettercap',
  'Ettercap',
  'Monstrous Manual',
  FALSE,
  'Heavily wooded forest',
  'Rare',
  'Solitary or pairs',
  'Any',
  'Carnivore',
  'Low (5-7)',
  'Nil',
  'Neutral evil',
  '1-2',
  6,
  '12',
  '5',
  5,
  15,
  '3',
  '1-3/1-3/1-8',
  'Poison',
  'Traps (see below)',
  0,
  'M',
  'Elite (13)',
  13,
  650,
  'Ettercaps sind hässliche zweibeinige Kreaturen, die sehr gut mit allen Arten von Riesenspinnen auskommen. Diese Geschöpfe von geringer Intelligenz sind außerordentlich grausam, sehr verschlagen und geschickt im Aufstellen von Fallen - sehr tödlichen Fallen - ganz wie die Spinnen, die oft in ihrer Nähe leben.',
  'Wenn ein Ettercap in einen Kampf verwickelt wird, schlägt er zuerst mit seinen Klauen zu und verursacht 1-3 Schadenspunkte mit jedem Satz. Die Kreatur versucht dann, ihren Gegner zu beißen und fügt mit ihren Zähnen und kräftigen Kiefern 1W8 Schadenspunkte zu. Ein erfolgreicher Bissangriff eines Ettercaps ermöglicht es dem Monster, seinem Opfer ein starkes Gift aus den Drüsen über den Fangzähnen des Ettercaps zu injizieren.',
  'Ettercaps ziehen es vor, im tiefsten Teil eines Waldes zu leben, nahe Pfaden, die häufig von Wild oder Reisenden frequentiert werden. Die Nester der Kreaturen bestehen aus einem Rahmen aus Strängen, gefüllt mit verrottenden Blättern und Moos. Die Baue befinden sich oft am Boden, können aber auch oben in großen, stabilen Bäumen gefunden werden. In Ettercap-Bauen ist kein Schatz zu finden, aber gelegentlich werden Gegenstände gefunden, die von Abenteurern fallen gelassen wurden, die in Ettercap-Fallen geraten sind.',
  'Ein Ettercap frisst jedes Fleisch, unabhängig von der Art der Kreatur, von der es stammt. Nach dem Fangen eines Opfers vergiftet der Ettercap es, damit es nicht entkommen kann; sobald die Kreatur tot ist, verschlingt der Ettercap sofort so viel von dem Kadaver wie möglich. Typischerweise kann ein Ettercap einen ganzen Hirsch oder einen großen Humanoiden in einer einzigen Sitzung verzehren. Alles, was übrig bleibt, nachdem sich der Ettercap vollgefressen hat, wird den Aasfressern überlassen.'
);

-- Eyewing (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Augenflügel',
  'Eyewing',
  'Monstrous Manual',
  FALSE,
  'The Abyss (preferred)',
  'Rare',
  'Band',
  'Any',
  'None known',
  'Low (5-7)',
  'Nil',
  'Lawful evil',
  '1-20',
  4,
  'Fl 24 (B)',
  '3',
  3,
  17,
  '3 or 1',
  '1-6/1-6/1-4 or eyewing tears',
  'Tears',
  'See below',
  0,
  'L',
  'Steady (12)',
  12,
  650,
  'Augenflügel sind abscheuliche Bewohner des Abgrunds. Sie sind gehorsam, loyal und dumm - perfekte Diener für die dunklen Götter und ihre mächtigeren Schergen.',
  'Ein Augenflügel hat zwei Hauptangriffsformen. Die häufigste Form ist der Einsatz seiner Klauen und seines Schwanzes, um seine Gegner zu treffen. Es kann entweder auf sie herabstoßen oder schweben und zuschlagen. Seine zweite Angriffsform besteht darin, seine Feinde mit einer großen Augenflügel-Träne zu bombardieren, die von dem lederartigen Augenlid aus dem großen Augapfel herausgepresst wird. Es hat erstaunliche Kontrolle über die Freisetzung der Träne - es hat die gleiche Trefferchance mit einer Träne wie mit seinen Nahkampfangriffen. Es setzt eine Träne frei, wenn es sich innerhalb von 30,5 m von seinem Ziel befindet. Es kann diesen Angriff sowohl beim Schweben als auch beim Sturzflug ausführen.',
  'Augenflügel sind übernatürliche Kreaturen, die nur existieren, um ihren dunklen Herren zu dienen. Wenn sie ohne Befehle gelassen werden, werden sie träge und lustlos. Das sollte nicht bedeuten, dass sie weniger gefährlich sind. Diese Lustlosigkeit ist ihr Ausdruck von Langeweile, aber nichts lindert die Langeweile eines Augenflügels so sehr wie das Zerreißen unschuldiger Kreaturen.',
  'Augenflügel sind geschlechtslose Kreaturen, die nicht Teil der Natur sind. Sie töten sogar dann, wenn sie nicht dazu befohlen werden, nur zum Vergnügen. Augenflügel wurden auf dem Mond angetroffen, wo es keine Luft zum Atmen und kein Wasser zum Trinken gibt. Es wird angenommen, dass sie keine Luft oder Wasser benötigen. Sie wurden nie beim Essen gesehen; die meisten, die sie studiert haben, nehmen an, dass sie von Magie genährt werden. Die mächtigeren Kreaturen des Abgrunds haben keine Bedenken, einen Augenflügel als Snack zu verspeisen, sollte einer in der Nähe sein, aber sie sind nicht die natürliche Beute irgendeiner Kreatur.'
);

-- Feyr (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Feyr',
  'Feyr',
  'Monstrous Manual',
  FALSE,
  'Urban',
  'Very rare',
  'Loose band',
  'Night',
  'Emotions',
  'Low (5)',
  'Nil',
  'Chaotic evil',
  '1-4',
  2,
  '12',
  '4',
  4,
  17,
  '1',
  '1-4',
  'Fear',
  'Nil',
  10,
  'S',
  'Fanatic (18)',
  18,
  975,
  'Feyrs (ausgesprochen wie „Fears") entstehen aus den Überresten gewöhnlicher Albträume, vermischt mit magischen Restenergien, und werden unbewusst durch die starken Emotionen großer Menschengruppen zum Leben erweckt. Sie sind am häufigsten in großen Städten anzutreffen, die eine beträchtliche Anzahl von Magiern, Priestern und anderen Zauberkundigen beherbergen. Gewöhnliche Feyrs durchstreifen nachts die Straßen und suchen nichts weiter, als Chaos zu stiften. Große Feyrs hingegen sind die Verbindung kleinerer Feyrs und können überall angetroffen werden, obwohl sie viel seltener sind als die gewöhnlichen Feyrs.',
  'Die horizontalen Kiefer des Feyrs, die unter seinem Bauch hängen, sind die hauptsächliche Angriffsform der Kreatur und verursachen 1W4 Schadenspunkte bei gewöhnlichen Feyrs und 2W6 Punkte bei großen Feyrs. Der Feyr nutzt seine Kiefer nicht zum Fressen, sondern um Terror in die Herzen derer zu schlagen, die seine wilden und blutigen Angriffe mitansehen. Wer den Angriff beider Feyr-Arten miterlebt, muss einen erfolgreichen Rettungswurf gegen Zauber schaffen oder wird von Furcht erfasst (wie der gleichnamige Zauber). Diese Furcht wirkt 1W4 Runden bei gewöhnlichen Feyrs und 2W6 Runden bei großen Feyrs. Diese Form der Furcht tritt nur ein, wenn die Kreatur angreift. Der bloße Anblick eines gewöhnlichen Feyrs löst keine Furcht aus.',
  'Einzelne gewöhnliche Feyrs werden vom Morgenlicht getötet. Gelegentlich verbinden sich mehrere gewöhnliche Feyrs zu einem großen Feyr, der zusätzlich zu seiner Immunität gegen die Auswirkungen der Sonne viel intelligenter ist. Der größere Feyr sucht noch stärkere Emotionen zu wecken, die er dann nutzen kann, um am Leben zu bleiben. Während gewöhnliche Feyrs nicht weit von ihrem Ursprungsort reisen, können große Feyrs lange Reisen unternehmen, angelockt von starken emotionalen Zuständen.',
  'Gewöhnliche Feyrs werden durch die Emotionen großer Menschenmassen erschaffen und große Feyrs durch Zusammenschlüsse kleinerer Feyrs. Die Grundmaterialien für solche Kreaturen finden sich in jeder städtischen Siedlung, und wenn zusätzliche Spannungen in der Luft liegen, durchstreifen die Feyrs die Nacht. Belagerte Städte, von Rivalitäten oder Bürgerkriegen gespaltene Ortschaften, unterdrückte Völker und Siedlungen, die unter erbarmungsloser Sommerhitze schmoren, sind allesamt mögliche Brutstätten für Feyrs. Wach- und Patrouillentrupps reichen normalerweise aus, um mit gewöhnlichen Feyrs fertig zu werden, da diese alles angreifen, was sich bewegt. Aber die gefährlicheren großen Feyrs müssen von einem Magier oder ähnlich hochstufigen Individuum bekämpft werden, das sowohl dem Angriff des Feyrs standhalten als auch ihn vernichten kann.'
);

