-- Fungus (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Pilz',
  'Fungus',
  'Monstrous Manual',
  FALSE,
  'Subterranean',
  'Rare',
  'Multicellular',
  'Any',
  'Scavenger',
  'Non- (0)',
  'Nil',
  'Neutral',
  '1-4',
  7,
  '1',
  '3',
  3,
  17,
  '1-4',
  'See below',
  'See below',
  'Nil',
  0,
  'M',
  'Steady (12)',
  12,
  175,
  'Pilze sind einfache Pflanzen, denen Chlorophyll, echte Stängel, Wurzeln und Blätter fehlen. Pilze sind nicht zur Photosynthese fähig und leben als Parasiten oder Saprophyten.',
  'Gewöhnliche Pilze greifen weder an noch verteidigen sich selbst, aber sie sind fruchtbar und können sich dort ausbreiten, wo sie unerwünscht sind.',
  'Der Körper der meisten echten Pilze besteht aus schlanken, wattigen Fäden. Jeder, der dies selbst sehen möchte, braucht nur ein feuchtes Stück Brot für ein oder zwei Tage in einem Schrank zu lassen. Die Untersuchung des schwarzen Schimmels auf dem Brot mit einer Lupe zeigt nicht nur die Fäden, sondern auch die Sporenkörper an deren Spitzen. Die Sporen sind es, die dem Schimmel seine Farbe verleihen.',
  'Pilze zersetzen organische Materie und spielen somit eine wichtige Rolle im Stickstoffkreislauf, indem sie tote Organismen zu Ammoniak abbauen. Ohne die Wirkung von Speisepilzen und Baumpilzen könnte die Bodenerneuerung nicht so leicht stattfinden, wie sie es tut.'
);

-- Gargantua (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Gargantua',
  'Gargantua',
  'Monstrous Manual',
  FALSE,
  'Tropical and subtropical islands',
  'Rare',
  'Solitary or mated pair',
  'Night',
  'Special',
  'Low (5-7)',
  'Nil',
  'Chaotic neutral',
  '1-2',
  2,
  '18, Sw 12',
  '50',
  50,
  5,
  '3',
  '3-30/3-30/6-60',
  'See below',
  'Regeneration',
  0,
  'G',
  'Elite (14)',
  14,
  43,
  'Gargantua sind wahrhaft monströse Spezies, sowohl in ihrer Größe als auch Wildheit. Ob sie Rückfälle in ein anderes Zeitalter, Aberrationen natürlicher Prozesse oder Ergebnisse verrückter magischer Experimente sind, ist unbekannt.',
  'Obwohl er einen gewissen Grad von Intelligenz besitzt, sind die Handlungen des reptilienhaften Gargantua - zusammen mit den Handlungen der meisten Gargantua - die von geistlosen Rohlingen, die auf Zerstörung um der Zerstörung willen aus sind. Er greift mit schwingenden Hieben seiner Vorderklauen und vorstößenden Bissen seiner mächtigen Kiefer an. Wenn er sich aufrecht bewegt, kann er Opfer niedertrampeln und 10-100 (10W10) Schadenspunkte verursachen. Er fegt kontinuierlich den Boden mit seinem massiven Schwanz und schwingt ihn 27,4 m hinter sich und zu jeder Seite. Jede Kreatur in Reichweite des Schwanzes muss einen erfolgreichen Rettungswurf gegen Tod schaffen oder 8-80 (8W10) Schadenspunkte erleiden.',
  'Einige wenige reptilienhafte Gargantua machen ihr Zuhause auf den Böden subtropischer Ozeane. Die meisten jedoch leben auf entlegenen tropischen Inseln, weit entfernt von zivilisierten Ländern. Solche Inseln sind über die Ozeane von Kara-Tur verstreut, wobei die meisten von ihnen nicht kartographiert sind. Die bemerkenswerteste Ausnahme ist die Insel der Gargantua, eine der Äußeren Inseln vor der südwestlichen Spitze von Wa. Diese Insel wird vollständig von Gargantua verschiedener Arten bewohnt.',
  'Der reptilienhafte Gargantua ist ein Allesfresser. Er frisst hauptsächlich Pflanzen und verschlingt ganze Bäume in einem einzigen Schluck. Aber er genießt auch lebende Beute aller Arten. Er kann sogar Mineralien, Edelsteine und andere anorganische Substanzen verzehren, wenn Vegetation und Wild knapp sind.'
);

-- Gargoyle I (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Gargoyle',
  'Gargoyle I',
  'Monstrous Manual',
  FALSE,
  'Any land, subterranean, ocean',
  'Uncommon',
  'Tribe',
  'Any',
  'Carnivore',
  'Low (5-7)',
  'M×10 (C)',
  'Chaotic evil',
  '2-16',
  5,
  '9, Fl 15 (C)',
  '4+4',
  4,
  15,
  '4',
  '1-3/1-3/1-6/1-4',
  'Nil',
  '+1 or better weapon to hit',
  0,
  'M',
  'Steady (11)',
  11,
  420,
  'Diese Monster sind grausame Raubtiere magischer Natur, die man gewöhnlich inmitten von Ruinen oder in unterirdischen Höhlen antrifft. Sie haben ihre eigene kehlige Sprache.',
  'Gargoyles greifen alles an, was sie entdecken, unabhängig davon, ob es gut oder böse ist, und zwar zu 90% der Zeit. Am liebsten foltern sie hilflose Beute zu Tode.',
  'Gargoyles leben in kleinen Gruppen mit anderen ihrer Art und sind an wenig mehr interessiert, als andere Kreaturen zu verletzen. Kleinere Tiere sind für diese abscheulichen Monster kaum der Mühe wert, die es vorziehen, Menschen oder andere intelligente Kreaturen anzugreifen.',
  'Ursprünglich waren Gargoyles geschnitzte Dachrinnen, die groteske Menschen- und Tierfiguren darstellten. Sie wurden so gestaltet, dass das durch die Rinnen fließende Wasser von der Wand weggeschleudert wurde, um Flecken und Erosion zu verhindern. Später verwendete ein unbekannter Magier eine mächtige Verzauberung, um diese schrecklichen Skulpturen zum Leben zu erwecken. Die Rasse der Gargoyles hat geblüht und sich über die ganze Welt ausgebreitet.'
);

-- Genie (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Dschinn',
  'Genie',
  'Monstrous Manual',
  FALSE,
  'Air',
  'Very rare',
  'Caliphate',
  'Day',
  'Omnivore',
  'Average to highly (8-14)',
  'Nil',
  'Chaotic good',
  '1',
  4,
  '9, Fl 24 (A)',
  '7+3',
  7,
  13,
  '1',
  '2-16 (2d8)',
  'See below',
  'See below',
  0,
  'L',
  'Elite (13-14)',
  13,
  5,
  'Dschinns stammen aus den Elementarebenen. Dort, unter ihresgleichen, haben sie ihre eigenen Gesellschaften. Dschinns werden manchmal auf der Primär-Materiellen Ebene angetroffen und oft gezielt beschworen, um irgendeinen Dienst für einen mächtigen Magier oder Priester zu erfüllen. Alle Dschinns können zu jeder der Elementarebenen reisen, ebenso zur Primär-Materiellen und zur Astralebene. Dschinns sprechen ihre eigene Sprache und die aller intelligenten Wesen, denen sie begegnen, durch eine begrenzte Form der Telepathie.',
  'Die magische Natur der Djinn ermöglicht es ihnen, einmal pro Tag folgende Fähigkeiten zu nutzen: nahrhafte Speisen für 2W6 Personen erschaffen und Wasser oder Wein für 2W6 Personen erschaffen; weiche Waren (bis zu 16 Kubikmeter) oder hölzerne Gegenstände (bis zu 9 Kubikmeter) von dauerhafter Natur erschaffen; Metall erschaffen, bis zu 45,4 kg Gewicht mit kurzer Lebensdauer (je härter das Metall, desto weniger Zeit hält es; Gold hat etwa eine 24-stündige Existenz, während Djinni-Stahl nur eine Stunde anhält); Illusion erschaffen wie ein Magier der 20. Stufe mit sowohl sichtbaren als auch hörbaren Komponenten, die ohne Konzentration anhalten, bis sie berührt oder magisch aufgelöst werden; Unsichtbarkeit, Gasgestalt oder Windwandeln nutzen.',
  'Das heimatliche Land der Djinn ist die Elementarebene der Luft, wo sie auf schwimmenden Inseln aus Erde und Stein leben, die zwischen 0,9 m und mehreren Kilometern Durchmesser haben. Sie sind vollgestopft mit Gebäuden, Höfen, Gärten, Springbrunnen und Skulpturen aus elementaren Flammen. In einem typischen Djinn-Landbesitz leben 3W10 Djinn verschiedener Altersstufen und Mächte, sowie 1W10 Jann und 1W10 Elementarkreaturen niedriger Intelligenz. Alle werden vom örtlichen Scheich regiert, einem Djinn mit maximalen Trefferpunkten.',
  NULL
);

-- Giant, Cyclops (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Riese, Zyklop',
  'Giant, Cyclops',
  'Monstrous Manual',
  FALSE,
  'Temperate/Hills and mountains',
  'Rare',
  'Clan',
  'Any',
  'Omnivore',
  'Low to average (5-10)',
  'C',
  'Chaotic (evil)',
  '1-8',
  3,
  '12',
  '5',
  5,
  15,
  '1',
  'by weapon +4 (Str bonus)',
  'Nil',
  'Nil',
  0,
  'L',
  'Elite (13)',
  13,
  270,
  'Ein zwergenhafter Verwandter der wahren Riesen, Zyklopsskin sind einäugige Riesen, die allein oder in kleinen Gruppen leben.',
  'Zyklopsskin sind entweder mit einer Keule oder einer Bardiche bewaffnet. Jeder trägt auch einen schweren Wurfspeer (1W6 Schaden) und eine Schleuder großer Größe (1W6 Schaden) bei sich. Sie tragen niemals Rüstung oder verwenden Schilde, da ihre zähe Haut ihnen ausreichend Schutz vor den meisten Angriffen gewährt.',
  'Die einäugigen Humanoiden meiden organisierte Siedlungen. Wenn sie in Ruhe gelassen werden, neigen sie dazu, bewaffnete Gruppen in Ruhe zu lassen, obwohl sie nicht davor zurückschrecken, eine viel schwächere Streitmacht anzugreifen, wenn sie auf eine solche stoßen. Zyklopsskin haben keinerlei Achtung vor irgendeiner anderen Lebensform als sich selbst. Gefangene werden entweder versklavt oder gefressen. Dies geschieht nicht sehr oft, da die Zyklopsskin dazu neigen, in abgelegenen felsigen Gegenden zu leben. Sie wandern selten mehr als 16,1 km von ihren Höhlen weg.',
  'Zyklopsskin können von fast jeder tierischen oder pflanzlichen Nahrung überleben. Sie mögen Fleisch aller Art und schätzen es über pflanzliche Nahrung. Während sie vom Land leben, leben sie nicht mit ihm. Sie haben absolut keine sanitären Praktiken und kochen selten sogar ihre Mahlzeiten. Sie treffen keine Vorkehrungen, um ihre Umgebung beim Jagen zu erhalten, und gelten als eine der am leichtesten zu verfolgenden Kreaturen ihrer Größe.'
);

-- Giant, Ettin (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Riese, Ettin',
  'Giant, Ettin',
  'Monstrous Manual',
  FALSE,
  'Subarctic to temperate/Hills and mountains',
  'Very rare',
  'Solitary',
  'Night',
  'Carnivore',
  'Low (5-7)',
  'O (C,Y)',
  'Chaotic evil',
  '1 or 1-4',
  3,
  '12',
  '10',
  10,
  11,
  '2',
  '1-10/2-12 + weapon',
  'Nil',
  'Surprised only on a 1',
  0,
  'H',
  'Elite (14)',
  14,
  3,
  'Ettins oder Zweiköpfige Riesen, wie sie oft genannt werden, sind bösartige und unberechenbare Jäger, die nachts auf die Pirsch gehen und jedes Fleisch fressen, das sie erbeuten können.',
  'Zwei Köpfe zu haben ist definitiv ein Vorteil für die Ettins, da einer immer wachsam ist und nach Gefahr und potentieller Nahrung Ausschau hält. Das bedeutet, dass ein Ettin nur bei einem Wurf von 1 auf 1W10 überrascht wird. Ein Ettin hat auch Infrasicht bis zu 27,4 m, was ihm ermöglicht, auch im Dunkeln effektiv zu jagen und zu kämpfen. Obwohl Ettins eine niedrige Intelligenz haben, sind sie gerissene Kämpfer. Sie ziehen es vor, ihre Opfer aus dem Hinterhalt anzugreifen, anstatt in einen direkten Kampf zu stürmen, aber sobald die Schlacht begonnen hat, kämpfen Ettins meist wütend, bis alle Feinde tot sind oder sich das Blatt gegen sie wendet. Ettins ziehen sich nicht leicht zurück und tun dies nur, wenn ein Sieg unmöglich ist.',
  'Ettins errichten gerne ihre Baue in abgelegenen, felsigen Gebieten. Sie bewohnen dunkle, unterirdische Höhlen, die nach verwesendem Futter und Abfall stinken. Ettins sind im Allgemeinen Einzelgänger, und Paarungspaare bleiben nur wenige Monate zusammen, nachdem ihnen ein junger Ettin geboren wurde. Junge Ettins reifen sehr schnell, und acht bis zehn Monate nach ihrer Geburt sind sie selbständig genug, um auf eigene Faust loszuziehen.',
  'Da die Ettingesellschaft so primitiv ist, produzieren sie wenig von Wert für zivilisierte Kreaturen. Ettins dulden die Anwesenheit anderer Kreaturen wie Orks in der Nähe ihres Baus, wenn sie auf irgendeine Weise nützlich sein können. Ansonsten neigen Ettins dazu, gewalttätig isolationistisch zu sein und zermalmen Eindringlinge ohne zu zögern.'
);

-- Giant, Firbolg (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Riese, Firbolg',
  'Giant, Firbolg',
  'Monstrous Manual',
  FALSE,
  'Temperate/Hills and forests',
  'Very rare',
  'Clan',
  'Any',
  'Omnivore',
  'Average to genius (8-18)',
  'E,Y (M×10,Q)',
  'Neutral (chaotic good)',
  '1-4 or 4-16',
  2,
  '15',
  '13+7',
  13,
  9,
  '1',
  '1-10 (weapon) +7 (Str bonus)',
  'Spells',
  'Swat away missiles',
  15,
  'L',
  'Champion (16)',
  16,
  8,
  'Von allen Riesenarten sind die Firbolg die mächtigsten, aufgrund ihrer natürlichen Intelligenz und beträchtlichen magischen Kraft.',
  'Firbolg können alle großen Waffen verwenden; sie verschmähen den Gebrauch von Rüstung oder Schilden. Von menschengemachten Waffen bevorzugen sie zweihändige Schwerter und Hellebarden, die sie beide ohne Abzug einhändig führen können. Waffen ihrer eigenen Herstellung sind doppelt so große Entsprechungen menschlicher Waffen, für die sie einen Stärkebonus erhalten (19 Stärke, +7 Schaden). Wenn sie diese riesigen Waffen jedoch mit beiden Händen führen, verursachen sie den doppelten normalen Schaden plus den Stärkebonus.',
  'Firbolg leben in abgelegenen Wäldern und Hügeln. Diese Riesenart misstraut den meisten anderen zivilisierten Völkern und hält sich von ihnen fern. Sie halten sich mit Druiden und Feenwesen einschließlich Elfen auf gutem Fuß, bitten weder um viel noch geben sie viel, vermeiden aber Beleidigungen oder Verletzungen. Fremden begegnen sie mit Vorsicht, häufig in illusionärer Verkleidung als Angehörige ihres eigenen Volkes. Sie greifen nicht ohne Grund an oder töten, erfreuen sich aber an Streichen, besonders solchen, die Fremde um ihre Schätze erleichtern.',
  'Firbolg leben vom Land und mit ihm. Ihre Häuser werden aus Bäumen gebaut, die um das Haus herum gerodet werden. Der Clan hält ein Feld für die Ernte, aber nur genug, um seine Ernährung zu ergänzen. Sie tauschen Arbeiten, die große Stärke erfordern, gegen Nahrung, normalerweise mit anderen friedlichen Völkern in den Wäldern oder Hügeln. Der Rest ihrer Nahrung wird durch Sammeln und Jagen in einem Gebiet von bis zu 32,2 km um ihr Gehöft erhalten. Fleisch wird in kleinen Mengen für die meisten Mahlzeiten verwendet, obwohl große Feiern immer einen großen Braten beinhalten.'
);

-- Giant, Fog (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Nebelriese',
  'Giant, Fog',
  'Monstrous Manual',
  FALSE,
  'Temperate/Swamps, marshes, boggy forests, and coastal regions',
  'Very rare',
  'Clan, Hunting Group',
  'Day',
  'Omnivore',
  'Average to highly (8-14)',
  'E,R',
  'Neutral (good 50%, evil 50%)',
  '1-4 (rarely 1-6)',
  1,
  '15',
  '14',
  14,
  7,
  '1',
  '1-10, or by weapon (3-18+11)',
  'Rock hurling',
  'See below',
  0,
  'H',
  'Elite (14)',
  14,
  5,
  'Verwandt mit den Wolkenriesen, sind diese großen Felswurfspezialisten intelligenter und heimtückischer als in Geschichten oder Liedern dargestellt.',
  'Nebelriesen jagen normalerweise in Gruppen von 2-5 Männchen, obwohl sie sich manchmal mit ein oder zwei Wolkenriesen zusammentun, um eine Jagdgruppe von 3-7 zu bilden. Sie bevorzugen Angriffe aus der Deckung (Nebel wird am meisten bevorzugt). Nach einigem Fernkampf mit Felswurf, um ihre Gegner zu zerstreuen, stürmen sie in den Nahkampf mit fliegenden Fäusten und Schwertern. Erwachsene Nebelriesen können Felsen bis zu 82-219,5 m weit schleudern und dabei 2-20 Schadenspunkte bei jedem Getroffenen verursachen. Sie haben auch eine 45% Chance, geworfene Waffen ähnlicher Größe zu fangen, können aber keine abgeschossenen Geschosse wie Pfeile, Bolzen und Schleudersteine fangen. Im Nahkampf kämpfen sie normalerweise mit Keulen und Fäusten, obwohl Geschichten über schwertbewaffnete Nebelriesen häufig sind.',
  'Nebelriesen sind stolz auf ihre Stärke und Kampffähigkeiten und spielen oft Spiele während Jagdausflügen, um zu versuchen, einander zu übertreffen. Ihr liebstes solches Spiel heißt "Copsi" und besteht darin, dass sich die Riesen paarweise zusammentun, um immer größere Felsbrocken zu ihren Partnern zu werfen, bis eines der Paare seinen Wurf verfehlt.',
  'Aufgrund ihrer Größe verbrauchen Nebelriesen große Mengen an Nahrung und benötigen ein beträchtliches Territorium pro Jagdgruppe, um sich zu ernähren. Die Riesen errichten oft territoriale Markierungen aus Felsbrocken und Baumstämmen, um die Grenzen zwischen ihren Jagdgebieten zu definieren. Sie sehen es nicht gern, wenn jemand diese Markierungen niederreißt oder bewegt. Ihre regulären Pfade sind schwer zu verbergen und werden stattdessen mit Steinschlägen und Baumstämmen eingefallen, um Eindringlinge abzuschrecken.'
);

-- Giant, Fomorian (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Riese, Fomorianischer',
  'Giant, Fomorian',
  'Monstrous Manual',
  FALSE,
  'Any mountain and subterranean',
  'Uncommon',
  'Solitary',
  'Any',
  'Omnivore',
  'Average (8-10)',
  'D,Q×10',
  'Neutral evil',
  '1-4',
  3,
  '9',
  '13+3',
  13,
  9,
  '1',
  '2× weapon, +8 (Str bonus)',
  'Surprise',
  'Only surprised on a 1',
  0,
  'H',
  'Elite (14)',
  14,
  6,
  'Fomorianer sind die abscheulichsten, entstelltesten und bösartigsten aller Riesenverwandten.',
  'Fomorianer verwenden alle Arten von Keulen und anderen stumpfen Instrumenten. Unabhängig von der Waffe verursacht sie doppelten Schaden plus 8 Punkte für Stärke, während ihre Fäuste allein 2W4+8 Schadenspunkte verursachen. Ihre Entstellungen hindern sie daran, Felsbrocken zu schleudern wie echte Riesen. Sie arbeiten alle Metallstücke, die sie finden und sammeln können, in ihre Kleidung ein, um ihre Rüstungsklasse zu verbessern. Der typische Fomorianer hat RK 3, während ein besonders gut gepanzerter oder einer mit einem Schild eine RK von 1 erreichen könnte, aber nicht besser.',
  'Fomorianer leben in Berghöhlen, verlassenen Minen oder anderen unterirdischen Bereichen. Sie verändern ihre Behausungen selten, sondern passen sich an das an, was bereits vorhanden ist. Diese entstellten Riesen wandern durch den gesamten unterirdischen Komplex, über nahezu jede Entfernung, nur aufgehalten von Gefahren, denen sie sich nicht stellen wollen. Ein fomorianischer Clan wählt eine kleine, für sie verteidigbare Nische als Bau. Ihre Territorien sind manchmal durch die Körper ihrer Feinde markiert. Ihr Schatz besteht nur aus gestohlenen Gegenständen von Feinden. Rüstungsteile werden zu ihrem eigenen zusammengestückelten Schutz hinzugefügt. Da sie sich nicht darum kümmern, verschlechtert sich diese Rüstung schnell und wird wertlos.',
  'Diese verdrehten Riesen können wochenlang mit wenig oder gar keiner Nahrung überleben. Das ist gut, da ihre unterirdischen Behausungen keine Fülle davon bieten. Sie können fast jedes organische Material fressen, einschließlich Pilzen, Flechten, Pflanzen aller Art, Fledermäusen, Mäusen und Fischen. Sie schätzen besonders den Geschmack großer Säugetiere, vor allem solcher, die darum betteln, nicht gefressen zu werden. Die Zubereitung einer Mahlzeit beinhaltet gewöhnlich eher Folter als irgendwelche Bemühungen, den Geschmack zu verbessern.'
);

-- Giant, Mountain (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Riese, Berg-',
  'Giant, Mountain',
  'Monstrous Manual',
  FALSE,
  'Any/Mountains',
  'Very rare',
  'Family',
  'Any',
  'Omnivore',
  'Average (8-10)',
  'E',
  'Chaotic neutral',
  '1-4',
  4,
  '12',
  '15+3',
  15,
  5,
  '1',
  '1-8 or by weapon (4d10+10)',
  'Hurling rocks for 2-20',
  'Nil',
  0,
  'H',
  'Champion (15-16)',
  15,
  7,
  'Bergriesen sind riesige Humanoide, die in abgelegenen Berghöhlen leben.',
  'Bergriesen greifen immer auf direkte Art an, nicht aus dem Hinterhalt oder mit Täuschung. Sie lieben es, eine hohe, uneinnehmbare Position mit vielen Felsbrocken zu erreichen. In solch einer Position suchen Bergriesen selten Deckung, sondern stehen offen da, um ihre Geschosse zu schleudern. Sie können Felsbrocken auf ihre Gegner hinabschleudern und dabei jeweils 2W10 Schadenspunkte verursachen. Sie können ähnliche Geschosse zu 30% der Zeit abfangen.',
  'Das Heim einer Familie von Bergriesen befindet sich oft in einer großen Felshöhle in einem Berg. Häufig gibt es unerforschte Gänge, die aus dem Heim der Riesen herausführen. Sie haben selten Interesse an irgendetwas jenseits ihrer Höhle. Es besteht eine 75%ige Chance, dass herbeigerufene Kreaturen als Wachen und Untergebene in der Höhle fungieren.',
  'Bergriesen sind Sammler und Jäger. Ihr Lieblingsfutter sind Bergschafe. Sie essen auch Nüsse, Knollen und andere essbare Bergpflanzen. Nichts jagt Bergriesen, aber manchmal wählen sie die falsche Höhle, um sich häuslich niederzulassen. Da sie dazu neigen, nicht alle hinteren Tunnel vollständig zu erkunden, ist es vorgekommen, dass böse Dinge aus dem Untergrund schlafende Riesen angegriffen und verschlungen haben.'
);

-- Giant, Verbeeg (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Riese, Verbeeg',
  'Giant, Verbeeg',
  'Monstrous Manual',
  FALSE,
  'Temperate and arctic/Hills',
  'Uncommon',
  'Tribe',
  'Any',
  'Omnivore',
  'Average to very (8-12)',
  'B (K,L,M×5)',
  'Neutral (evil)',
  '1-6 or 5-30',
  4,
  '18',
  '5+5',
  5,
  15,
  '2',
  '1-6 (weapon) +3 to +6 (Str bonus)',
  'Nil',
  'Nil',
  0,
  'L',
  'Elite (13)',
  13,
  270,
  'Diese als "menschliche Kolosse" bekannten Menschenriesen bewohnen Gebiete, die von Hügelriesen und Ogern befallen sind.',
  'Verbeeg sind klug genug, andere zuerst den Feind schwächen zu lassen. Das bedeutet nicht, dass sie Feiglinge sind, nur egoistisch und praktisch veranlagt. Da sie gewöhnlich mit Hügelriesen und Ogern angetroffen werden, treiben Verbeeg in den ersten Kampfrunden ihre weniger intelligenten Gefährten vor sich in die Schlacht. Dies wird von vielen Flüchen, Schwüren und höchst anschaulichen Schilderungen der Abstammung der Riesen und Oger begleitet.',
  'Verbeeg findet man in denselben Klimazonen wie Oger und Hügelriesen. Diese menschlichen Kolosse werden niemals allein wandernd angetroffen. 30% der wandernden Verbeeg-Begegnungen treffen auf 1W6 dieser Riesenverwandten mit 1W4 Hügelriesen oder Ogern (gleiche Chance), die auch ihren Bau teilen; 50% der Zeit sind 1W6 Verbeeg mit 1W6 Wölfen oder Worgs zusammen (in polaren Klimazonen Winterwölfe oder Eisbären); den Rest der Zeit (20%) werden 1-2 von ihnen mit einer normal großen Gruppe wandernder Monster angetroffen, die in diesem Gebiet gefunden werden (der SL muss in diesem Fall vernünftige Beurteilung walten lassen).',
  'Verbeeg essen fast alles, aber sie lieben Fleisch aller Art. Sie unterhalten eine für beide Seiten vorteilhafte Beziehung zu den Riesen und Ogern, die ihren Bau teilen. Die Verbeeg stellen die Intelligenz und Führung bereit, die diesen Riesenarten fehlt, und die Riesen bieten durch ihre größere Kampfkraft Schutz. Eine Gruppe in Aktion zu beobachten kann urkomisch sein, solange man nicht ihr beabsichtigtes Opfer ist. Hügelriesen und Oger sind zu dumm, um viel selbst zu denken. Sie neigen dazu, Anweisungen zu wörtlich zu befolgen. Das bringt die Verbeeg gewöhnlich zur Weißglut. Sie hüpfen von einem Fuß auf den anderen und schreien Beleidigungen zu den verwirrten Riesen, die sie an Größe und Masse überragen, während selbst die einfachsten Anweisungen von diesen begriffsstutzigen Humanoiden falsch interpretiert werden.'
);

-- Giant, Wood (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Waldriese',
  'Giant, Wood',
  'Monstrous Manual',
  FALSE,
  'Temperate, subtropical/Forests',
  'Very rare',
  'Clan',
  'Day',
  'Herbivore',
  'High to exceptional (13-16)',
  'E',
  'Chaotic good',
  '1-4',
  8,
  '12',
  '7+7',
  7,
  13,
  '1',
  '1-10 (weapon) +3 to +6 (Strength bonus)',
  '-4 penalty to opponents'' surprise rolls',
  'Resistant to some spells',
  0,
  'L',
  'Steady (11-12)',
  11,
  1,
  'Waldriesen (auch als Voadkyn bekannt) gehören zu den kleinsten der niederen Riesenrassen und sehen aus wie riesengroße Waldelfen. Sie sind launisch, leichtsinnig und gute Freunde der Waldelfen.',
  'Voadkyn kämpfen nicht, es sei denn, sie sind gezwungen, sich selbst oder Verbündete zu verteidigen. Ihre Lieblingswaffe ist ihr riesiger, nicht-magischer Langbogen. Sie erhalten einen +1 Bonus auf Angriffswürfe und 50% bessere Reichweite aufgrund seiner ungewöhnlichen Größe. Die passenden Pfeile sind über 1,2 m lang und verursachen 1W8 Schadenspunkte. Waldriesen schleudern keine Steine oder Felsbrocken. Werden sie zum Nahkampf gedrängt, führen sie ihre zweihändigen Schwerter mit einer Hand.',
  'Waldriesen bewohnen dieselben Wälder wie Waldelfen. Sie haben keine Baue und ziehen es vor, unter den Sternen zu leben oder zeitweise bei den Waldelfen zu bleiben. Waldriesen, die im Wald angetroffen werden, sind größtenteils männlich (90%). Weibliche Waldriesen bleiben gewöhnlich in einem provisorischen Lager oder bei den Waldelfen in deren Bau. Nachkommen sind selten, da jedes Weibchen nur 1W4 Kinder in seinem Leben gebiert. Die Jungen werden tief in den Wäldern unter den Waldelfen geboren und aufgezogen, fern von neugierigen Blicken.',
  'Der Kiefer der Voadkyn ist groß wegen der übergroßen Mahlzähne darin. Diese Zähne sind völlig ungeeignet für das Fressen von Fleisch, aber sie sind perfekt für Gemüse und andere Pflanzen. Waldriesen können die Blätter und Wurzeln vieler Pflanzen essen, die für Menschen ungenießbar sind. Sie genießen besonders Nüsse und Samen.'
);

-- Gibberling (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Gibberling',
  'Gibberling',
  'Monstrous Manual',
  FALSE,
  'Temperate/Forest, subterranean',
  'Uncommon',
  'Herd',
  'Night (but see below)',
  'Carnivore',
  'Low (5-7)',
  'Nil',
  'Chaotic neutral',
  '40-400',
  10,
  '9',
  '1',
  1,
  19,
  '1',
  '1-8 (weapon)',
  'Mass assault',
  'Nil',
  0,
  'S',
  'Unsteady (5)',
  5,
  35,
  'Sie kommen schreiend, brabbelnd und heulend aus der Nacht. Dutzende, vielleicht Hunderte bucklige, nackte Humanoide schwärmen unaufhörlich vorwärts und schwingen Kurzschwerte. Sie denken weder an Sicherheit, noch an Finesse oder Strategie, und lassen anderen keine Hoffnung, ihren Massenangriff zu stoppen. Und dann, nachdem sie gekommen und getötet haben, ziehen die Gibberlinge wahllos wieder zurück in die Nacht.',
  'Gibberlinge greifen in großer Zahl an und stoßen grauenhafte Heuler, Klicklaute, Schreie und wahnsinniges Geschwätz aus, das selbst die mutigsten Söldlinge dazu bringt, jede Runde eine Moralprobe zu machen. Spielercharaktere müssen nur eine Moralprobe ablegen, wenn es für ihren Charakter angemessen ist. Die schreiende Horde ist völlig unorganisiert in ihrer Form und zufällig in ihrer Richtung.',
  'Es ist schwierig, sich eine soziale Struktur der Gibberlinge vorzustellen. Sie kann grob mit der sozialen Struktur von Lemmingen verglichen werden, die sich ins Meer stürzen, oder mit einem Piranhaschwarm in einem Fressrausch. Es gibt keinen Sinn, keine Organisation und keine Individualität. Obwohl sie eindeutig ein primitives Mittel haben, untereinander zu kommunizieren, besitzen sie keine erkennbare Sprache.',
  'Versuche, die Baue der Gibberlinge zu finden, haben unvermeidlich zu unterirdischen Gängen geführt, wo sich die Spur schließlich in den tiefsten steinbödigen Vertiefungen der Höhlen verliert.'
);

-- Gith (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Gith',
  'Gith',
  'Monstrous Manual',
  FALSE,
  'Arid tablelands and mountains',
  'Uncommon',
  'Tribal',
  'Day or night',
  'Carnivore',
  'Average (10)',
  'M (I)',
  'Chaotic evil',
  '10-100',
  8,
  '10',
  '3',
  3,
  17,
  '1 or 2',
  'By weapon or 1d4/1d4',
  'Springing',
  'Nil',
  0,
  'M',
  'Steady (12)',
  12,
  175,
  'Wissenschaften: Turm des eisernen Willens, Kraft projizieren; Devotionen: Ich-Einflüsterung, Geistesstoß, Kontakt.',
  'Wenn möglich, greifen die Gith in der Masse an, meist beginnend mit einem psionischen Angriff durch einen ihrer Anführer. Dann stürmt die gesamte Gruppe schnell in den Nahkampf. Ihr Hauptangriff wird oft durch einen Sprung von bis zu 6,1 m in einem einzigen gewaltigen Satz ausgeführt, um ihre Feinde zu erreichen. Wenn sie diesen Sprung einsetzen, verleiht er ihnen einen +2 Angriffsbonus in der ersten Kampfrunde.',
  'Die Gith leben in Stammesorganisationen. Das Individuum mit den mächtigsten psionischen Kräften fungiert generell als Anführer. Alle anderen sozialen Positionen werden nach seinem Belieben verteilt.',
  'Gebirgs-Gith leben in unterirdischen Bauen und beanspruchen eine bestimmte Schlucht oder ein Tal als ihr Territorium. Gith, die das Tafelland bewohnen, organisieren ihre Gesellschaft eher nach Art eines nomadischen Jagdclans und gehen dorthin, wo das Wild sie hinführt. Sie zögern nicht, Menschen- oder Halbmenschengruppen anzugreifen, da sie Menschen und Halbmenschen als erlesene Nahrungsquelle betrachten und diese anderem Fleisch vorziehen. Sie greifen sogar Thri-Kreen an, wenn sie hungrig genug sind, aber die Insektoiden schmecken schlecht und entkommen den Gith-Räubern gewöhnlich.'
);

-- Gith, Pirate of (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Gith-Pirat',
  'Gith, Pirate of',
  'Monstrous Manual',
  FALSE,
  'Wildspace',
  'Rare',
  'Ship/Military',
  'Any',
  'Carnivore',
  'Exceptional (15-16)',
  'A (N)',
  'Lawful evil',
  '20-40/As ship crew',
  10,
  '12',
  '7-11',
  7,
  20,
  'Varies',
  'By weapon',
  'See below',
  'See below',
  0,
  'M',
  'Champion (16)',
  16,
  0,
  'Als die Githyanki unter ihrer Befreierin Gith sich vom Joch der Illithiden-Sklaverei befreiten, floh dieser Zweig der Rasse nicht in die Astralebene, sondern in den arkanen Raum.',
  'Die Piraten von Gith können als Kämpfer, Magier oder Kämpfer/Magier agieren, mit einer Begrenzung auf Stufe 11 in jeder Klasse. Typischerweise führt der höchststufige Kämpfer das Schiff. Dies befreit alle Magier (einfach- und mehrklassige) für Spelljamming- oder Kampfaufgaben.',
  'Die Piratenphilosophie überträgt sich auf alle Lebensaspekte. Die Stärksten nehmen sich, was sie wollen. Jedes Schiff ist für seine Besatzung sehr wichtig, da es der primäre Faktor bei der Bestimmung der Hackordnung in einer Siedlung ist. Dies erklärt die ständige Suche der Piraten nach besseren Schiffen. Jede Siedlung wird gewaltsam von ihrem besten Schiff oder einer Koalition der besten Schiffe regiert.',
  'Die Gith-Piraten sind Fleischfresser, rein und einfach. Es ist ihnen egal, in welchem Zustand sich das Fleisch befindet, außer wenn es verwest ist. Einige der Piratenbanden betreiben auch Kannibalismus.'
);

-- Gloomwing (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Düsterflügel',
  'Gloomwing',
  'Monstrous Manual',
  FALSE,
  'Any, Demi-plane of Shadow',
  'Rare',
  'Solitary',
  'Night/Darkness',
  'Carnivore',
  'Animal (1)',
  'Nil',
  'Neutral',
  '1',
  1,
  '2, Fl 18 (D)',
  '5+1',
  5,
  15,
  '3',
  '1-3/1-3/1-8',
  'Pheromone',
  'Confusion',
  0,
  'M',
  'Average (8-10)',
  8,
  1,
  'Die Kreatur, die gemeinhin Düsterflügel genannt wird, ist das erwachsene Stadium des düsteren Wurms (siehe unten). Diese riesigen Motten sind auf der Halbebene der Schatten heimisch. Ihre Körper und Flügel sind mit schimmernden, geometrischen Mustern aus Schwarz und Silber bedeckt. Sie haben große, farnartige schwarze Fühler mit weißen Spitzen und acht Beine, die jeweils in einer perlmuttfarbenen Klaue enden.',
  'Die schimmernden Zeichnungen eines Düsterflügels machen ihn zu einem schwierigen Ziel. Jede Kreatur, die die Motte direkt von oben oder unten betrachtet, muss erfolgreich gegen Zauber würfeln oder wird für 5-8 (1W4+4) Runden verwirrt, wie durch den Magierzauber 4. Grades. Die Zeichnungen bieten auch ausgezeichnete Tarnung, und die Motte ist zu 50% unentdeckbar in Dunkelheit, Zwielicht oder Mondlicht. Erfolgreich getarnte Düsterflügel können keine Verwirrung verursachen.',
  'Düsterflügel-Motten sind kurzlebige, einzelgängerische Jäger. Sie verwenden verschiedene Pheromone, um Rivalen abzuwehren und Partner zu finden. Sie bilden Gruppen, aber nur um große Beute anzugreifen, und dann nur, wenn sie durch das Kampfpheromon angelockt werden. Wenn sich zwei Düsterflügel des gleichen Geschlechts treffen, fliehen sie, es sei denn, Kampfpheromon liegt in der Luft.',
  'Düsterflügel-Motten leben nur 4-9 (1W6+3) Wochen. Während dieser Zeit suchen sie nach Partnern und fressen gefräßig. Eiertragende Weibchen (½ Chance) nutzen Leichen von kleinen oder größeren Kreaturen als Brutkästen für ihre Eier. Die Eier schlüpfen nach 12 Tagen und bringen 1W6+4 kleine düstere Würmer hervor. Die Leiche kann nicht wiederbelebt werden, es sei denn, der Befall wird zuerst mit einem Krankheit heilen-Zauber entfernt. Wenn sie nicht getötet werden, verschlingen die jungen Würmer den Körper vollständig, wenn sie schlüpfen.'
);

-- Gnome (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Gnom',
  'Gnome',
  'Monstrous Manual',
  FALSE,
  'Hills',
  'Rare',
  'Clans',
  'Any',
  'Omnivore',
  'Varies (7-19)',
  'M×3 (C,Q×20)',
  'Neutral good',
  '4-12 (4d3)',
  6,
  '6',
  '1 (base)',
  1,
  19,
  '1',
  'By weapon',
  'Nil',
  'See below',
  0,
  'S',
  'Steady (12)',
  12,
  65,
  'Kleine Vettern der Zwerge, Gnome sind freundlich aber zurückhaltend, schnell dabei, ihren Freunden zu helfen, aber von anderen Völkern selten gesehen, außer sie wollen es. Sie neigen dazu, unterirdisch in hügeligen, bewaldeten Gebieten zu leben, wo sie ihren Interessen in Frieden nachgehen können. Gnome können Kämpfer oder Priester sein, aber die meisten ziehen es vor, stattdessen Diebe oder Illusionisten zu werden. Mehrkassencharaktere sind unter den Gnomen häufiger als bei jedem anderen Halbmenschenvolk.',
  'Gnome bevorzugen den Einsatz von Strategie gegenüber roher Gewalt im Kampf und verwenden oft Illusionen auf fantasievolle Weise, um "die Chancen auszugleichen". Ihr großer Hass auf Kobolde und Goblins, ihre traditionellen Feinde, gibt ihnen einen +1 auf ihre Angriffswürfe beim Kampf gegen diese Wesen. Sie sind geschickt darin, den Angriffen großer Gegner auszuweichen und zwingen alle Kreaturen der Riesenklasse (Gnolle, Großgoblins, Oger, Trolle, Riesen usw.) dazu, 4 von ihren Angriffswürfen abzuziehen, wenn sie gegen Gnome kämpfen.',
  'Gnome leben in unterirdischen Bauten in abgelegenen hügeligen, bewaldeten Gebieten. Sie sind sippenorientiert, mit freundschaftlichen Rivalitäten zwischen benachbarten Sippen. Sie verbringen ihr Leben mit dem Abbau von Erzen, der Herstellung feinen Schmucks und dem Genuss der Früchte ihrer Arbeit. Gnome arbeiten hart, und sie spielen hart. Sie begehen viele Feste und Feiertage, die normalerweise Spiele, Nasenmess-Wettbewerbe und das Austauschen großartiger Geschichten beinhalten. Ihre Gesellschaft ist gut organisiert, mit vielen Verantwortungsebenen, die in einem einzigen Häuptling gipfeln, der von Priestern in Angelegenheiten beraten wird, die direkt mit ihrer Berufung zusammenhängen.',
  'Gnome sind sehr viel ein magischer Teil der Natur, existieren in Harmonie mit dem Land, das sie bewohnen. Sie wählen, unterirdisch zu leben, aber bleiben nahe der Oberfläche, um ihre Schönheit zu genießen.'
);

-- Gnome, Spriggan (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Gnom, Spriggan',
  'Gnome, Spriggan',
  'Monstrous Manual',
  FALSE,
  'Any/Wilderness',
  'Very rare',
  'Pack',
  'Any',
  'Omnivore',
  'Average to exceptional (8-16)',
  'A',
  'Chaotic evil',
  '3-12',
  3,
  '9 or 15',
  '4 or 8+4',
  4,
  17,
  '2',
  '2-8/2-8 (weapon) +7 (Strength bonus)',
  'Spells, thief abilities',
  'See below',
  0,
  'S',
  'Champion (15-16)',
  15,
  3,
  'Diese hässlichen, mürrischen Vettern der Gnome können nach Belieben riesenhaft werden. In beiden Größen sehen Spriggans grundsätzlich gleich aus. Sie sind hässliche, dickleibige Humanoide mit blasser oder matt gelber Haut, braunem oder schwarzem Haar und roten Augen. In seltenen Fällen kann ein Spriggan rotes Haar haben, was sie für ein Symbol des Glücks halten. Ihre Nasen sind groß und knollig, aber nicht jenseits der menschlichen Norm. Sie sind sehr angetan von Schnurrbärten und buschigen Koteletten, aber sie säubern oder kämmen sie nie. Diese Politik der Unsauberkeit erstreckt sich auf ihre Körper und alle anderen Besitztümer. Spriggans riechen nach feuchter Erde, abgestandenem Schweiß und Schmutz.',
  'Spriggans sind tückisch und zäh im Kampf. Sie haben eine große Vielfalt an Kampfoptionen. Ihre Hauptfähigkeit ist es, nach Belieben von kleiner zu riesiger Größe zu wechseln. Waffen, Rüstung und andere unbelebte Gegenstände an ihrer Person schrumpfen und wachsen mit ihnen. Diese Handlung dauert die gesamte Runde, während der sie sich bis zu 9,1 m bewegen, aber nicht kämpfen können. Wenn sie klein sind, können Spriggans die folgenden zauberähnlichen Effekte anwenden: gewöhnliche Feuer beeinflussen, zerbrechen und erschrecken (mit einer Strafe von -2 auf den Rettungswurf aufgrund ihrer Hässlichkeit). Sie können eine dieser Fähigkeiten statt des Kampfes einsetzen, einmal in jeder Runde, so oft sie wollen. Wenn sie riesenhaft sind, können Spriggans keine Magie anwenden, außer wieder zu schrumpfen. In dieser Form sind sie so stark wie Hügelriesen (19).',
  'Spriggans reisen gewöhnlich in Rudeln, alle männlich. Die Weibchen halten sich in düsteren Bauen oder geheimen Verstecken in vergessenen Ruinen auf und wagen sich selten weiter hinaus als nötig, um Nahrung zu sammeln. Ein Weibchen hat dieselben Kampffähigkeiten wie ein Männchen, außer dass sie nur 7+4 Trefferwürfel in Riesenform haben.',
  'Die umherstreifenden Rudel der Männchen neigen dazu, Fleischfresser zu sein und ziehen es vor, ihre Nahrung zu jagen oder zu stehlen. Als solche müssen sie in Bewegung bleiben und weite Kontrollgebiete etablieren. Die Weibchen neigen dazu, Früchte und Getreide zu essen, die leicht in der Nähe ihrer Baue gesammelt werden können. Sie essen nur Fleisch, wenn es von einem Männchen als Teil des Paarungsrituals angeboten wird.'
);

-- Golem, General Information (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Golem, Allgemeine Informationen',
  'Golem, General Information',
  'Monstrous Manual',
  FALSE,
  NULL,
  'common',
  NULL,
  NULL,
  NULL,
  NULL,
  NULL,
  NULL,
  NULL,
  10,
  '',
  '1',
  1,
  20,
  '1',
  '',
  NULL,
  NULL,
  0,
  'M',
  '',
  10,
  0,
  'Golems sind magisch erschaffene Automaten von großer Macht. Ihre Erschaffung erfordert mächtige Magie und elementare Kräfte.',
  'Alle Golems teilen mehrere gemeinsame Eigenschaften. Sie sind alle immun gegen alle Formen von Gift und können nicht von Lähmung, Bezauberung, Furcht oder anderen geistbasierten Zaubern betroffen werden, da sie keinen eigenen Verstand haben. Bestimmte Zauber können Golems schaden; diese werden unten erwähnt.',
  NULL,
  NULL
);

-- Golem I (Greater Golem) (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Golem I (Größerer Golem)',
  'Golem I (Greater Golem)',
  'Monstrous Manual',
  FALSE,
  'Any',
  'Very rare',
  'Solitary',
  'Any',
  'None',
  'Non- (0)',
  'Nil',
  'Neutral',
  '1',
  5,
  '6',
  '14 (60 hp)',
  14,
  7,
  '1',
  '3-24 (3d8)',
  'See below',
  'See below',
  0,
  'L',
  'Fearless (19-20)',
  19,
  8,
  'Ein größerer Golem ist ein künstlicher humanoider Körper, der von einem Elementargeist beseelt wurde, aber unter der vollständigen Kontrolle seines Erschafers bleibt.',
  'Größere Golems sind im Kampf geistlos und folgen nur den einfachen Taktiken ihrer Meister. Sie sind völlig emotionslos und können in keiner Weise von ihren Anweisungen abgebracht werden. Sie werden keine Waffen aufheben und im Kampf verwenden, selbst wenn es ihnen befohlen wird, und bevorzugen immer ihre Fäuste. Steingolems haben eine Stärke von 22 zum Zweck des Zerbrechens oder Werfens von Gegenständen.',
  'Golems sind Automaten, künstlich erschaffen und unter der direkten Kontrolle ihres Erschafers. Sie haben keine Gesellschaft und sind mit keinem bestimmten Lebensraum verbunden. Sie werden häufig verwendet, um wertvolle Gegenstände oder Orte zu bewachen. Anders als die geringeren Golems stehen die größeren Golems immer unter der vollständigen Kontrolle ihres Meisters. Ein größerer Golem kann einfache Anweisungen mit direkten Handlungen und einfachen Bedingungsphrasen befolgen. Obwohl dies besser ist, als ein geringerer Golem befolgen kann, sind sie dennoch schlechte Diener. Jede gegebene Aufgabe könnte mehrere separate Befehle erfordern, um den Golem zu ihrer Vollendung zu führen.',
  'Golems sind keine natürlichen Kreaturen und spielen keine Rolle in der Ökologie der Welt. Sie essen nicht, schlafen nicht und "leben", bis sie zerstört werden, normalerweise im Kampf. Bestimmte Zauber (siehe oben) können verwendet werden, um jeden Schaden zu heilen oder zu reparieren, der ihnen im Kampf zugefügt wurde. Dies wird normalerweise von ihren Erschaffern getan, um langen und wertvollen Dienst zu gewährleisten.'
);

