  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Necrophidius und Vogelscheuche',
  'Golem V',
  'Monstrous Manual',
  FALSE,
  'Any',
  'Very rare',
  'Solitary',
  'Any',
  'None',
  'Non- (0)',
  'Nil',
  'Neutral',
  '1',
  2,
  '9',
  '2',
  2,
  19,
  '1',
  '1-8',
  'See below',
  'See below',
  0,
  'L',
  'Fearless (19-20)',
  19,
  270,
  'Der Necrophidius und die Vogelscheuche sind Konstrukte wie alle anderen Golems, aber sie sind weniger mächtig aufgrund der magischen Abkürzungen, die bei ihrer Erschaffung verwendet wurden.',
  'Der Necrophidius zieht es vor, Gegner zu überraschen, und seine Lautlosigkeit verhängt einen Malus von -2 auf ihre Überraschungswürfe. Wenn der Necrophidius nicht überrascht wird, führt er ein makabres Manöver namens Tanz des Todes durch, ein hypnotisches Schwanken, unterstützt von geringfügiger Magie. Der Tanz fesselt die Aufmerksamkeit aller, die ihn beobachten, es sei denn, ein erfolgreicher Rettungswurf gegen Zauber wird gewürfelt. Intelligente Opfer werden bewegungsunfähig gemacht, wie durch den Hypnose-Zauber. Dies erlaubt es dem Necrophidius, ohne Widerstand anzugreifen.',
  NULL,
  NULL
);

-- Gremlin, Jermlaine (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Gremlin, Jermlaine',
  'Gremlin, Jermlaine',
  'Monstrous Manual',
  FALSE,
  'Subterranean',
  'Uncommon',
  'Clan',
  'Any',
  'Omnivore',
  'Average (Genius cunning) (8-10)',
  'Per 10 individuals O,Q; in lair C,Q(×5),S,T',
  'Neutral evil (slight lawful tendencies)',
  '12-48',
  7,
  '15',
  '1-4 hp',
  1,
  20,
  '1',
  '1-2 or 1-4',
  'See below',
  'See below',
  0,
  'T',
  'Steady (12)',
  12,
  15,
  'Jermlaine sind eine winzige humanoide Rasse, die in Tunneln lebt und unglückliche Abenteurer aus dem Hinterhalt überfällt. Sie sind unter verschiedenen Namen bekannt, wie Unglücksbringer oder Fluch-Mücken.',
  'Jermlaine sind Feiglinge, die den Hinterhalt zur Kunst erhoben haben. Sie greifen nur an, wenn sie das Gefühl haben, dass es keinen ernsthaften Widerstand gibt. Sie bevorzugen es, verletzte, kranke oder schlafende Opfer anzugreifen. Sie vermeiden es, starken, wachsamen Gruppen direkt gegenüberzutreten, obwohl sie aus reiner Bosheit versuchen könnten, sie zu verletzen.',
  'Jermlaine sind extrem entfernte Verwandte der Gnome. Ihr tief verwurzeltes Minderwertigkeitsgefühl wegen ihrer eigenen winzigen Größe ist zu einem bösartigen Bedürfnis geworden, normalgroße Humanoide zu demütigen. Sie verdienen sich ihren Lebensunterhalt gut damit, unglückliche Abenteurer zu berauben, die Reichtümer, sadistische Unterhaltung und gelegentlich eine Mahlzeit bieten. Jermlaine erwerben eine große Vielfalt an Schätzen, obwohl solche Gegenstände meist kleine Objekte sind.',
  'Jermlaine sind opportunistische Räuber, die unvorsichtige Reisende in den unterirdischen Regionen jagen. Sie sind sich aller solcher Reisenden bewusst, einschließlich der Größe, Zusammensetzung und allgemeinen Verfassung einer Gruppe. Jermlaine können gegen eine angemessene Gebühr dazu überredet werden, solches Wissen mit Abenteurern zu teilen. Jermlaine können mit "Riesen" (jede Rasse größer als sie selbst) Geschäfte machen, wenn sie bestochen werden oder Zugang zu einem reichlichen Strom von Opfern oder Reichtümern erhalten. Sie verbünden sich niemals mit wahrhaft gut gesinnten Abenteurern, obwohl sie in einem Moment der Verschlagenheit vorgeben können, ein solches Bündnis einzugehen. Ungeachtet ihrer gesprochenen Absichten lügen oder wenden sich 75% der Jermlaine schließlich gegen ihre größeren "Verbündeten". Sie können ihre Baue in der Nähe der etablierten Territorien solcher Rassen wie Drow, Trolle oder Troglodyten errichten. Obwohl sie vorsichtig sind, direkten Konflikt mit solchen bösen Wesen zu vermeiden, jagen die Jermlaine fröhlich die Opfer ihrer Nachbarn und plündern die Schauplätze der Schlachten ihrer Nachbarn. Jermlaine können als Wächter für ihre Nachbarn fungieren, vorausgesetzt, geeignete Bedingungen können vereinbart werden.'
);

-- Gremlin (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Gremlin',
  'Gremlin',
  'Monstrous Manual',
  FALSE,
  'Any land',
  'Very rare',
  'Pack',
  'Night',
  'Omnivore',
  'Very (11-12)',
  'Q,X',
  'Chaotic evil',
  '1-6',
  4,
  '6, Fl 18 (B)',
  '4',
  4,
  17,
  '1',
  '1-4',
  'Nil',
  '+1 weapon needed to hit',
  25,
  'T',
  'Unsteady (5-7)',
  5,
  650,
  'Gremlins werden oft mit Wichten verwechselt, sind aber kleine, geflügelte Goblinoide. Es gibt viele Arten von Gremlins, und die meisten sind chaotisch und boshaft. Ihre Hautfarbe reicht von braun über schwarz bis grau, häufig in einer gesprenkelten Mischung. Ihre Ohren sind sehr groß und spitz, was ihnen eine 65%ige Chance verleiht, Geräusche zu hören. Ein Paar fledermausartiger Flügel ermöglicht es ihnen zu fliegen oder zu gleiten. Gremlins tragen niemals Kleidung oder Schmuck.',
  'Gremlins sind in echten Kämpfen wertlos; bei jeder Gelegenheit fliehen sie, anstatt von Angesicht zu Angesicht zu kämpfen. Was Gremlins am liebsten tun, ist Ärger zu bereiten. Je wütender ihre Opfer sind, desto glücklicher sind die Gremlins. Ihre bevorzugte Taktik ist es, eine Falle aufzustellen, um Gegner zu demütigen und sie vielleicht sogar dazu zu bringen, einen wertvollen Besitz zu beschädigen oder einen geliebten Menschen zu verletzen. Wenn der Gegner dabei auch noch verletzt wird, ist das nur recht. Zum Beispiel könnte der Gremlin einen Stolperdraht über eine Türöffnung spannen, der eine zerbrechliche Vase auf den Kopf des Opfers herabzieht. Ein Gebäude, das von einem Gremlin-Rudel befallen ist, kann in einer einzigen Nacht zu Trümmern reduziert werden.',
  'Gremlins sind magische Kreaturen, die aus einer unbekannten Existenzebene stammen. Sie sind hochgradig anfällig für Mutationen und können sich mit jeder Goblinoiden-Art paaren. Dies hat zu mehreren verschiedenen Gremlin-Rassen geführt, jede mit leicht unterschiedlichen Fähigkeiten und Naturen.',
  'Gremlins sind kein natürlicher Teil der Ökologie. Ihre Immunität gegen normale Waffen schützt sie vor normalen Raubtieren. Unbehelligt leben sie jahrhundertelang.'
);

-- Grimlock (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Grimlock',
  'Grimlock',
  'Monstrous Manual',
  FALSE,
  'Any/Mountainous',
  'Uncommon',
  'Tribal',
  'Night',
  'Carnivorous (Human Flesh)',
  'Average (8-10)',
  'Individual K,L,M; B in Lair',
  'Neutral Evil',
  '20-200',
  5,
  '12',
  '2 (and see below)',
  2,
  19,
  '1',
  '1-6, or by weapon type',
  'Nil',
  'See below',
  0,
  'M',
  'Steady (11) (and see below)',
  11,
  35,
  'Kräftig gebaute Humanoide, die nur in dunkle, schmutzige Lumpen gekleidet sind. Diese kriegerischen unterirdischen Kreaturen verlassen nachts ihre tiefen Höhlen, um nach unglücklichen Menschen zu suchen, die sie ihren Speisekammern hinzufügen können.',
  'Grimlocks sind immun gegen die Effekte von Zaubern, die das Sehvermögen beeinflussen. Dazu gehören Phantomkraft, Dunkelheit, Unsichtbarkeit, Spiegelbild und viele andere. Jedoch werden Zauber wie Hörbare Illusion oder jeder laute, andauernde Lärm sie teilweise "blenden". Dies reduziert ihre Fähigkeit, Gegner wahrzunehmen, auf eine Reichweite von 3 m und verschlechtert ihre Angriffswürfe um -2. Substanzen wie Schnupftabak oder starke Parfüms haben den gleichen Effekt, wenn sie von einem Grimlock eingeatmet oder ihm ins Gesicht geworfen werden.',
  'Grimlocks nisten in riesigen Höhlenkomplexen in gebirgigen Gebieten. Sie sind gut an diese Umgebung angepasst. In jedem felsigen Gelände verschmelzen sie so gut, dass sie, während sie bewegungslos sind, völlig unentdeckbar sind - es sei denn, man stößt tatsächlich mit ihnen zusammen. In jedem Grimlock-Bau wird es fast so viele Weibchen (1 Trefferwürfel und RK 6) wie Männchen geben, und mindestens so viele Junge (1 Trefferpunkt, RK 6 und Nichtkämpfer). Grimlock-Anführer und Champions üben tatsächlich eine gewisse Kontrolle über diese Gemeinschaften aus.',
  'Grimlocks fressen nur das rohe Fleisch humanoider Kreaturen und bevorzugen dabei das von Menschen bei weitem vor allen anderen. Beutezüge überfallen oft die Behausungen anderer unterirdischer Rassen, besonders jene, die große Sklavenpopulationen halten (wie die Drow). Sie stehen oft auf gutem Fuß mit Gedankenschindern, da Illithiden eine große Versorgung mit humanoiden Körpern haben, die weggeworfen werden, nachdem sie die Gehirne verschlungen haben. Grimlocks werden besonders von Githyanki aus diesem Grund gehasst. Da das Sklavenfleisch, das die Grimlocks oft (roh) konsumieren, häufig ungesund ist, werden ganze Gemeinschaften oft durch Krankheiten dezimiert.'
);

-- Grippli (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Grippli',
  'Grippli',
  'Monstrous Manual',
  FALSE,
  'Tropical/Swamps and jungles',
  'Rare',
  'Tribal',
  'Day',
  'Omnivore',
  'Very to high (11-14)',
  'Q×4,I',
  'Neutral',
  '1-10',
  9,
  '9, leap 15',
  '1+1',
  1,
  19,
  '1',
  '1-4 (weapon)',
  '-3 penalty to opponents'' surprise',
  'Nil',
  0,
  'S',
  'Average (8-10)',
  8,
  65,
  'Grippli ähneln kleinen, intelligenten, humanoiden Baumfröschen. Sie haben eine primitive Kultur und sind nicht aggressiv.',
  'Wegen der Färbung der Grippli erleiden Gegner einen Malus von -3 auf ihre Überraschungswürfe. Grippli verteidigen sich mit Schlingen, Netzen, vergifteten Pfeilen und gelegentlich Schwertern oder Dolchen. Alle Metallwaffen müssen anderswo für die Grippli hergestellt werden, daher sind Schwerter selten. Sie können sich an die Verwendung aller Waffen anpassen, und sie sind dafür bekannt, bei seltenen Gelegenheiten Speere und Blasrohre zu verwenden. Sie tragen niemals Rüstung. Allgemein gesprochen bevorzugen die Grippli kleine Waffen, die beim Klettern nicht im Weg sind.',
  'Ein Grippli-Stammdorf besteht aus kleinen Hütten aus Holz und Lehm, die am Boden im tiefen Schatten großer Bäume errichtet werden. Bei seltenen Gelegenheiten findet man ein Grippli-Dorf in den starken Ästen der Bäume. Jedes Dorf wird von einer Stammmutter angeführt (RK 7, TW 3, 1W6+1 Schadenspunkte mit einer Waffe). Einmal pro Tag kann die Stammmutter eine Moschuswolke ausstoßen, die wie ein Stinkende Wolke-Zauber behandelt wird. Sie sieht aus wie jeder andere Grippli, außer dass sie fast 1,2 m groß ist. Sie hat 1W3 Gefährten von übernormal großer Statur (RK 8, TW 2, 1W4+1 Schadenspunkte mit vergifteten Waffen), die 0,9 bis 1 m groß sind. Die Stammmutter soll einen Hauch des Blutes ihres Gottes in sich haben.',
  'Grippli essen Früchte und Insekten. Sie fangen kleine Insekten in großen Mengen und jagen die Riesenvarianten wie Menschen Hirsche jagen. Sie werden ihrerseits von den meisten großen, boden- und baumbasierten Raubtieren gejagt. Riesenschlangen und Spinnen insbesondere mögen Grippli als Mahlzeiten.'
);

-- Guardian Daemon (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
