  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Wächterdämon',
  'Guardian Daemon',
  'MC2 Volume II',
  FALSE,
  'Any',
  'Rare',
  'Solitary',
  'Any',
  'Nil',
  'Average (8-10)',
  'See below',
  'Neutral',
  '1',
  3,
  '9',
  '6',
  6,
  13,
  '3',
  '1-4/1-10/1-10',
  'See ht-low',
  'See below',
  0,
  'M',
  'Elite (14)',
  14,
  2,
  'Diese Dämonen werden von bösen Magiern oder Priestern beschworen, um etwas von Wichtigkeit zu bewachen. Wächterdämonen verteidigen ihren Auftrag stets mit großer Wildheit.',
  'Wächterdämonen können dreimal täglich Feuer atmen in einem Kegel von 9,1 m Länge mit 3 m Basisdurchmesser. Der Schaden hängt von der Art des atmenden Dämons ab. Niedrigste und geringere Dämonen verursachen 3W6 bzw. 5W6 Schadenspunkte, während größere Dämonen 7W6 Punkte pro Atemattacke zufügen. Ein erfolgreicher Rettungswurf gegen Atemwaffe halbiert den Schaden. Wächterdämonen verwenden niemals ihren Feueratem, wenn das Feuer das beschädigen könnte, was sie zu beschützen beauftragt sind.',
  'Wächterdämonen müssen jederzeit innerhalb von 82,3 m des Objekts bleiben, das sie zu beschützen beschworen wurden. Innerhalb dieses 82,3-Meter-Radius ziehen es Wächterdämonen vor, auf Distanz zu bleiben und im Kampf ihre Atemwaffe zu maximalem Vorteil einzusetzen.',
  'Die Beschwörung eines Wächterdämons ist eine gefährliche Angelegenheit. Es gibt eine 10% Chance für jede Stufe, die der Beschwörer über der 7. Stufe ist, dass sein Antrag auf einen Wächterdämon gewährt wird (maximale Chance 90%). Umgekehrt, falls die Beschwörung fehlschlägt, gibt es eine 30% Chance (-2% pro Stufe des Beschwörers über der 10.), dass der Dämon Anstoß nimmt und sich einpfortet, um den Zauberkundigen zu erschlagen.'
);

-- Hag (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Hexe',
  'Hag',
  'Monstrous Manual',
  FALSE,
  'Any land',
  'Very rare',
  'Covey',
  'Night',
  'Carnivore',
  'Very (11-12)',
  '(D)',
  'Chaotic evil',
  '1-3',
  10,
  '15',
  '7+7',
  7,
  13,
  '3',
  '9-16/9-16/3-9',
  'See below',
  'See below',
  20,
  'L',
  'Champion (15)',
  15,
  4,
  'Hexen sind hexenähnliche Wesen, die Verwüstung und Zerstörung verbreiten, ihre Magie wirken und alle erschlagen, denen sie begegnen.',
  'Die Kampffähigkeiten von Hexen variieren je nach Art siehe unten für Details, aber alle Hexen besitzen folgendes: Stärke von 18/00 oder höher, eine gewisse Magieresistenz und die zauberähnliche Fähigkeit, sich nach Belieben zu verwandeln. Hexen nutzen diese letzte Fähigkeit, um Opfer anzulocken, indem sie sich häufig als junge Menschen- oder Halbmenschenfrauen, hilflose alte Frauen oder gelegentlich als Orks oder Hobgoblins ausgeben. Eine verkleidete Hexe enthüllt ihre wahre Gestalt und springt zum Angriff über, wenn schwache Gegner in die Nähe kommen. Gegen gut bewaffnete und gerüstete Gruppen behalten Hexen ihre Verkleidung bei und wenden weitere Tricks an, die darauf ausgelegt sind, das beabsichtigte Opfer in eine verwundbarere Position zu bringen. Diese Tricks können verschiedene Formen annehmen, einschließlich verbaler Überredung, das Opfer in eine vorbereitete Falle zu locken und so weiter.',
  'Hexen leben allein oder in Zirkeln von drei. Sie wählen immer trostlose, abgelegene Orte als Wohnstätte. Sie koexistieren manchmal mit Ogern oder bösen Riesen. Erstere fungieren als Diener oder Wachen für Hexen, aber Riesen werden mit Respekt behandelt aus offensichtlichen Gründen und kooperieren oft mit Hexen, um Taten großen Übels gegen die Außenwelt zu vollbringen.',
  'Hexen haben einen unersättlichen Appetit und können menschengroße Kreaturen in nur 10 Runden verschlingen. Sie bevorzugen Menschenfleisch, begnügen sich aber bei Bedarf mit Ork oder Halbmensch. Diese mutwillige Zerstörung hat den Hexen einige mächtige Feinde eingebracht. Neben der Menschheit im Allgemeinen jagen sowohl gute Riesen als auch gute Drachen Hexen und erschlagen sie, wann immer möglich. Dennoch vermehren sich Hexen schnell, indem sie ihre Fähigkeit zur Selbstverwandlung nutzen, um allein angetroffenen Männern als schöne Jungfrauen zu erscheinen. Hexennachkommen sind immer weiblich. Legenden besagen, dass Hexen ihr ungeborenes Kind gegen das einer menschlichen Frau austauschen können, während sie schläft. Sie besagen weiter, dass jede Mutter, die ein solches Kind austrägt, dann von dem Hexenkind getötet wird, das sie trägt. Glücklicherweise wurden solche grauenhaften Geschichten nie bewiesen.'
);

-- Halfling (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Halbling',
  'Halfling',
  'Monstrous Manual',
  FALSE,
  'Pastoral',
  'Uncommon',
  'Community',
  'Day',
  'Omnivore',
  'Very (11-12)',
  'K (B)',
  'Lawful good',
  '2-12 (2d6)',
  7,
  '6 (9)',
  '1-6 hit points',
  1,
  20,
  '1',
  '1-6 (weapon)',
  '+3 with bows and slings',
  'See below',
  0,
  'S',
  'Steady (11-12)',
  11,
  35,
  'Halblinge sind ein arbeitsames Volk friedlicher Bürger. Ihre Gemeinden ähneln denen der Menschen, obwohl sie gewöhnlich viele Erdhöhlen zusätzlich zu oberirdischen Häuschen enthalten.',
  'Halblinge kämpfen mit großer Erbitterung zur Verteidigung des Guten oder ihrer Heime. Sie sind sehr geschickt sowohl mit der Schleuder als auch dem Bogen (sie erhalten einen +3 Bonus auf alle Angriffswürfe) und nutzen diese Waffen zu großem Vorteil im Kampf. Ihre Taktiken umfassen oft Finten, um ihre Angreifer ins Freie zu locken, wo sie einem Hagel von Geschossen aus der Deckung unterworfen werden können.',
  'Halblingdörfer haben gewöhnlich zwischen 30 und 300 (30W10) Einwohner. Für je 30 Halblinge in einer bestimmten Gemeinde gibt es zwei Kämpfer der 2. Stufe und einen Priester der 3. Stufe. Werden mehr als 90 Halblinge angetroffen, gibt es einen zusätzlichen Anführer mit Kampffähigkeiten der 3. Stufe. Werden mehr als 150 angetroffen, gibt es auch die folgenden zusätzlichen Halblingkrieger in der Gruppe: einen Kämpfer der 9. Stufe, zwei Kämpfer der 4. Stufe und drei Kämpfer der 3. Stufe. Ferner hat eine Gemeinde von 150 Halblingen einen Priester der 5. Stufe.',
  'Halblinge jagen gelegentlich, bevorzugen aber Brot, Gemüse und Früchte mit gelegentlich einem Fasan dazu. Sie haben eine durchschnittliche Lebenserwartung von 100 Jahren.'
);

-- Harpy (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Harpyie',
  'Harpy',
  'Monstrous Manual',
  FALSE,
  'Temperate, tropical land or coast',
  'Rare',
  'Flock',
  'Day',
  'Carnivore',
  'Low (5-7)',
  'R (C)',
  'Chaotic evil',
  '2-12 (2d6)',
  7,
  '6, Fl 15 (C)',
  '7',
  7,
  13,
  '3',
  '1-3/1-3/1-6 or 1-3/1-3/weapon',
  'Singing and charm',
  'Nil',
  0,
  'M',
  'Elite (13-14)',
  13,
  975,
  'Harpyien sind böse Vogel-Bestien, die fast alle Kreaturen jagen, aber das Fleisch von Menschen und Halbmenschen bevorzugen.',
  'Der Gesang der Harpyien hat die Fähigkeit, alle Menschen und Halbmenschen zu bezaubern, die ihn hören (Elfen sind resistent gegen den Zauber). Diejenigen, die ihren Rettungswurf gegen Zauber verfehlen, werden mit aller möglichen Geschwindigkeit zur Harpyie gehen, nur um verzaubert dazustehen, während die Harpyie sie in aller Ruhe tötet. Dieser Zauber hält so lange an, wie die Harpyie weiter singt. Harpyien können sogar während eines Nahkampfes singen.',
  'Harpyien machen ihre Heimat an Küstenlinien in Regionen nahe Schifffahrtsrouten und an viel bereisten Pfaden. Dort nutzen sie ihren Gesang, um Reisende in ihr Verderben zu locken.',
  'Harpyien jagen alle Arten von Bestien und bleiben in einem Gebiet, solange die Nahrungsversorgung anhält. Sie werden von allen Kreaturen, die schwächer sind als sie selbst, verachtet und sehr gefürchtet.'
);

-- Hatori (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Hatori',
  'Hatori',
  'Monstrous Manual',
  FALSE,
  'Deserts',
  'Rare',
  'Solitary/Small herds',
  'Any',
  'Carnivore',
  'Low (5-7)',
  'U',
  'Chaotic neutral',
  '1 or 2-5',
  2,
  '15',
  '1-5',
  1,
  20,
  '2',
  '3-18/1-12',
  'Swallow whole',
  'Nil',
  0,
  'L',
  'Average (9)',
  9,
  0,
  'Hatori, manchmal als "Krokodile der Wüste" bezeichnet, sind riesige Reptilien, die in sandigen Wüstenöden leben. Die harte, knorrige Haut der Hatori reicht farblich von grau-weiß bis rot-braun und ist praktisch nicht von Stein zu unterscheiden. Hatori nutzen diese Ähnlichkeit zu ihrem großen Vorteil, indem sie sich vom Wind teilweise unter dem Sand begraben lassen, sodass ein flüchtiger Beobachter glauben könnte, er blicke auf Felsbrocken anstatt auf Ungeheuer der Wüste.',
  'Das Einzige, was Hatori in den Kampf treiben kann, ist Hunger. Unglücklicherweise haben Hatori unersättlichen Appetit und Nahrung ist in ihrer Heimatumgebung selten, daher lassen sie niemals eine Gelegenheit aus, aus einem vorbeiziehenden Reisenden - oder sogar einer ganzen Karawane - eine Mahlzeit zu machen. Die bevorzugte Jagdmethode der Hatori ist es, sich entlang eines vielgenutzten Wanderpfads oder einer Karawanenroute zu positionieren. Wenn eine potenzielle Mahlzeit nahe vorbeigeht und die Hatori für nichts weiter als einen Felsvorsprung hält, schlagen die Hatori zu.',
  'Hatori leben in den sandigen Regionen großer Wüsten. Da sie jedoch ständig nach Nahrung suchen, werden sie tendenziell in der Nähe von Wanderpfaden oder entlang belebter Karawanenrouten angetroffen. Sie bleiben in einem ertragreichen Gebiet, bis Nahrung knapp wird.',
  'Hatori fressen alles, obwohl sie Edelsteine oder magische Rüstungen und Waffen nicht verdauen können. Diese Gegenstände neigen dazu, sich über ihre langen Lebenszeiten in ihren Mägen anzusammeln. Hatori haben keine natürlichen Feinde (außer einander zur Paarungszeit), obwohl es Gerüchte gibt, dass bestimmte Arten von Drachen bekanntermaßen kleinere Hatori in Zeiten des Hungers angegriffen haben. Legenden sprechen von einem verborgenen Hatori-Friedhof, wo uralte Hatori hingehen, um zu sterben. Falls ein solcher Friedhof existiert, ist er sicherlich voller Edelsteine und magischer Rüstungen.'
);

-- Haunt (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Haunt',
  'Haunt',
  'Monstrous Manual',
  FALSE,
  'Any',
  'Very rare',
  'Individual',
  'Any',
  'Nil',
  'Non- (0)',
  'Nil',
  'Any',
  '1',
  10,
  '6/as victim',
  '5/victim''s hp',
  0.5,
  15,
  '1/1, as 5-HD monster',
  'See below/by weapon',
  'See below',
  'See below',
  0,
  'M',
  'Champion (16)',
  16,
  2,
  '(Anmerkung: Bei durch Schrägstrich getrennten Statistiken beziehen sich die linken Werte auf den natürlichen Zustand, die rechten auf ein besessenes Opfer.)',
  'Ein Haunt muss innerhalb von 54,9 m von seinem Todesort bleiben, es sei denn, er übernimmt die Kontrolle über den Körper eines Opfers. Dieser 54,9-Meter-Radius wird die Domäne des Haunts genannt.',
  'Die genaue zu vollendende Aufgabe variiert, aber die Beweggründe sind immer mächtig - Rache, Gier, Liebe, Hass. Oft müssen große Entfernungen zurückgelegt werden, bevor eine Aufgabe vollendet werden kann, und Haunts werden ihre Wirte gnadenlos zum Ziel treiben und dabei das Bedürfnis nach Nahrung oder Schlaf ignorieren.',
  'Haunts klammern sich allein durch Willenskraft an diese Welt. Sie haben keinen eigenen Schatz, es sei denn, er steht im Zusammenhang mit ihrer Suche. Sie jagen nur Menschen und Halbmenschen.'
);

-- Hawk (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Habicht',
  'Hawk',
  'MC2 Volume II',
  FALSE,
  'Subarctic to tropical/Any land',
  'Uncommon',
  'Pair',
  'Day',
  'Carnivore',
  'Animal (1)',
  'See below',
  'Nil',
  '1-2',
  6,
  'Fl 33 (B)',
  '1',
  1,
  19,
  '3',
  '1-2/1-2/1',
  'See below',
  'Nil',
  0,
  'S',
  'Average (9)',
  9,
  65,
  'Habichte sind auf der ganzen Welt verbreitet, von tropischen bis zu subarktischen Gebieten. Sie leben hauptsächlich von Ungeziefer und Nagetieren und werden daher in vielen Gegenden geschätzt.',
  'Habichte greifen über sturzflugartige Sturzflüge an, normalerweise aus einer Höhe von 30,5 m oder mehr. Dieser Sturzflug verleiht ihnen einen +2 Bonus auf ihren Angriffswurf und ihr Schwung ermöglicht es ihren Krallen, doppelten normalen Schaden zu verursachen. Habichte können nicht mit ihren Schnäbeln angreifen in der Runde, in der sie einen Sturzangriff ausführen.',
  'Habichte bauen ihre Nester in hohen Bäumen oder versteckt zwischen felsigen Hängen. Dort legt das Weibchen im frühen Frühling ein bis drei Eier. Die Eier schlüpfen zum Sommerende und danach arbeiten sowohl Männchen als auch Weibchen daran, die Nestlinge zu füttern und sie vor Wintereinbruch zu stärken.',
  'Wenn sie jung gefangen und von einem Experten trainiert werden, können Habichte zur Jagd ausgebildet werden. Deswegen zahlen viele Tierdresseure gut für gesunde Nestlinge. Der Preis für einen Nestling beträgt etwa 500 Goldstücke auf dem freien Markt. Trainierte Habichte verkaufen sich für bis zu 1.200 Goldstücke das Stück.'
);

-- Hell Hound (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Höllenhund',
  'Hell Hound',
  'Monstrous Manual',
  FALSE,
  'Any land',
  'Very rare',
  'Pack',
  'Any',
  'Carnivore',
  'Low (5-7)',
  'C',
  'Lawful evil',
  '2-8',
  4,
  '12',
  '4-7',
  4,
  4,
  '1',
  '1-10',
  'Breathe fire',
  'See below',
  0,
  'M',
  'Elite (13)',
  13,
  4,
  'Höllenhunde sind feuerspeiende Hundeartige von einer anderen Existenzebene, die hierher im Dienste böser Wesen gebracht wurden.',
  'Höllenhunde sind clevere Jäger, die in Rudeln operieren. Sie bellen nicht wie normale Hunde während der Jagd. Sie bewegen sich mit großer Heimlichkeit und verhängen eine -5 Strafe auf die Überraschungswürfe ihrer Gegner. Ein oder zwei aus dem Rudel schleichen sich an die Beute heran, während die anderen einen Ring um sie bilden. Der erste Höllenhund springt dann aus dem Hinterhalt hervor, greift das nächste Opfer an und versucht die anderen zum Rest des Rudels zu treiben. Wenn die Beute nicht wegläuft, rückt der Rest des Rudels innerhalb von 1W4+2 Runden näher heran. Wenn Höllenhunde fliehende Beute verfolgen, könnten sie bellen.',
  'Höllenhunde sind heimisch in jenen außerdimensionalen Ebenen, die für ihre heißen, feurigen Landschaften bekannt sind. Dort streifen sie in Rudeln von 2W20 Tieren umher. Die Höllenhunde auf der Materiellen Hauptebene werden dorthin beschworen, um den Bedürfnissen böser Kreaturen zu dienen. Die meisten von ihnen entkommen später in die Wildnis.',
  'Höllenhunde haben wenig Platz in der Ökologie der normalen Welt. Sie sind gefährliche Plagen, die dazu neigen, Brände zu verursachen, wo immer sie jagen. Höllenhunde verursachen mehr Waldbrände als jede andere Kreatur außer Humanoiden. Höllenhunde haben jedoch ihre Verwendung. Wegen ihrer Fähigkeit, verborgene oder unsichtbare Kreaturen leicht zu entdecken, geben Höllenhunde ausgezeichnete Wachhunde ab, besonders für intelligente Monster wie Feuerriesen.'
);

-- Hornet, Giant (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Riesenhornisse',
  'Hornet, Giant',
  'MC1 Volume I (w/binder #1)',
  FALSE,
  'Any forest or cave',
  'Uncommon',
  'Solitary',
  'Day',
  'Omnivore',
  'Semi- (2-4)',
  'Nil',
  'Neutral',
  '1',
  2,
  '6, Fl 24 (B)',
  '5',
  5,
  15,
  '1',
  '1d4',
  'Poison and paralysis',
  'Nil',
  0,
  'M',
  'Average (8-10)',
  8,
  650,
  'Riesenhornissen sind nichts weiter als fantastisch vergrößerte Versionen normaler Insekten. Im Gegensatz zu ihren gewöhnlicheren Verwandten sind sie oft feindselig und aggressiv.',
  'Riesenhornissen sind Einzelgänger, die bei Sichtkontakt angreifen. Sie stürzen sich auf ihre Beute herab und halten sie mit ihren Beinen fest, während ihr Stachel in den Körper des Opfers sticht. Zusätzlich zu 1-4 Schadenspunkten injiziert der Stachel auch ein starkes Gift. Wird ein Rettungswurf gegen Gift nicht geschafft, verursacht das Gift 5-30 Schadenspunkte und lähmt das Opfer für 2-12 (2W6) Stunden.',
  'Riesenhornissen sollen das Ergebnis fehlgeschlagener magischer Experimente sein. Abgesehen von der Tatsache, dass sie viel aggressiver als gewöhnliche Hornissen sind, hat ihre gigantische Größe ihr instinktives Verhalten nicht verändert.',
  'Die Riesenhornissen sind das Ergebnis absichtlicher Manipulation der Natur. Sie durchstreifen die Welt gedankenlos und folgen ihrem ursprünglichen Instinkt zur Fortpflanzung.'
);

-- Human (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
