  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Mensch',
  'Human',
  'Monstrous Manual',
  FALSE,
  NULL,
  'Common',
  NULL,
  NULL,
  NULL,
  NULL,
  'Nil',
  'Any',
  '1-100',
  10,
  '',
  '1-6 hp',
  1,
  20,
  '1',
  '',
  NULL,
  NULL,
  0,
  'M',
  'Average (9)',
  9,
  15,
  'Diese primitiven Menschen werden in ansonsten unbewohnten Gebieten gefunden. Für alle 10 Ureinwohner gibt es einen Kämpfer der 3. Stufe. Ureinwohnerstämme werden immer von einem Häuptling (ein Kämpfer der 5. Stufe) und 1-4 Unterhäuptlingen (Kämpfer der 4. Stufe) angeführt. Für alle 10 angetroffenen Ureinwohner besteht eine 10%ige Chance, dass sie einen Schamanen (Priester der 3. Stufe) bei sich haben.',
  'Dies sind NSC-Gegenstücke zur SC-Gruppe, Gruppen von Kämpfern, Dieben, Priestern und Magiern, die sich zusammenschließen auf der Suche nach Ruhm, Reichtum und Macht. Typische Abenteuergruppen bestehen aus zwei bis acht Mitgliedern. Einzelne Abenteurer könnten von ihrer Gruppe getrennt, verloren, fortgeschrittene Späher oder alleinige Überlebende dezimierter Gruppen sein.',
  'Banditen sind ländliche Diebe, die offen Reisende und abgelegene Behausungen ausrauben. Sie reisen in Gruppen von 20-200, normalerweise angeführt von hochstufigen Kämpfern, Schurken, Magiern und Priestern. Für alle 20 angetroffenen Banditen gibt es einen zusätzlichen Kämpfer der 3. Stufe. Wenn 100+ angetroffen werden, ist der Anführer mindestens 8. Stufe.',
  'Barbaren gehören zu primitiven Kulturen, die rudimentäre Fertigkeiten wie Tierhaltung und einfache Herstellung (Weben, Schnitzen) besitzen. Sie können in Dörfern mit einfachen Gebäuden leben oder in tragbaren Strukturen wie Zelten, Tipis, Jurten oder Wagen. In aquatischen Gebieten können sie auf Wasserfahrzeugen wie Kanus oder Flößen leben.'
);

