  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Hydra',
  'Hydra',
  'Monstrous Manual',
  FALSE,
  'Any swamp',
  'Uncommon',
  'Solitary',
  'Any',
  'Carnivore',
  'Semi- (2-4)',
  'Nil',
  'Neutral',
  '1',
  5,
  '9',
  '5-12',
  5,
  20,
  '5-12',
  'See below',
  'Nil',
  'Nil',
  0,
  'G',
  'Average (8-10)',
  8,
  2,
  'Hydras sind gewaltige reptilische Monster mit mehreren Köpfen. Für jeden Trefferwürfel, den die Hydra hat, besitzt sie einen Kopf. Die obige Tabelle listet den ETW0-Wert für Hydras, die Anzahl der Köpfe und den Schaden auf, den sie bei jedem Biss verursachen.',
  'Hydras haben immer 8 Punkte auf jedem ihrer Trefferwürfel und alle Köpfe müssen abgetrennt werden, bevor die Hydra stirbt. Eine Hydra kann bis zu vier Köpfe gegen einen einzelnen Gegner einsetzen und mit jedem einmal beißen.',
  'Hydras sind Einzelgänger, die düstere Umgebungen bevorzugen. Sie versammeln sich nur zur Paarung.',
  'Trotz der Größe der Hydra und ihrer mehrfachen Angriffe werden sie oft von Drachen gejagt. Sie sind unmöglich zu trainieren.'
);

-- Hyena (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Hyäne',
  'Hyena',
  'MC1 Volume I (w/binder #1)',
  FALSE,
  'Warm plains',
  'Common',
  'Pack',
  'Day',
  'Scavenger',
  'Animal (1)',
  'Nil',
  'Neutral',
  '2-12 (2d6)',
  7,
  '12',
  '3',
  3,
  17,
  '1',
  '2-8 (2d4)',
  'Nil',
  'Nil',
  0,
  'S',
  'Unsteady (5-7)',
  5,
  65,
  'Hyänen sind Hundeartige, die in warmen Grasländern und Ebenen umherstreifen. Sie sind in erster Linie Aasfresser, jagen aber gelegentlich auch kleineres Wild. Ihre kräftigen Kiefer verleihen ihnen einen gefährlichen Biss.',
  'Hyänen sind Feiglinge. Sie greifen nicht an, außer ihr Opfer ist hilflos, in der Unterzahl oder bereits tot.',
  'Hyänen durchstreifen die offenen Ebenen warmer, grasiger Regionen. Sie werden normalerweise in Sichtweite einer Herde von Tieren wie Zebras und Antilopen gefunden. Gewöhnlich gibt es 1 Hyäne für jeweils 10 Herdentiere, denen sie folgt. Ein typisches Hyänenrudel kann mit einem menschengroßen Tier alle drei Tage überleben. Wenn sie ein Tier angreifen und töten, werden sie es in kürzester Zeit bis auf die Knochen abfressen. Jedes Aas, das sie antreffen, wird ebenfalls verzehrt.',
  'Hyänen sind aktive Aasfresser, die sich von den Kadavern ernähren, die von anderen, größeren Raubtieren zurückgelassen werden. Sie sind auch in der Lage, lebende Beute zu reißen, obwohl sie ihre Jagd normalerweise auf kleine, junge, alte oder kranke Tiere beschränken. Sie haben eine starke Konstitution und einen Verdauungstrakt, der es ihnen ermöglicht, sogar krankes Fleisch sicher zu verdauen.'
);

