-- Insect Swarm (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Insektenschwarm',
  'Insect Swarm',
  'Monstrous Manual',
  FALSE,
  'Tropical, subtropical or temperate/Forest, hills,and plains',
  'Very rare',
  'Swarm',
  'Day',
  'Omnivore',
  'Animal (1)',
  'Nil',
  'Neutral',
  'See below',
  8,
  '6',
  'See below',
  1,
  20,
  '1',
  'See below',
  'Poison',
  'Nil',
  0,
  'T',
  'Unsteady (6)',
  6,
  0,
  'Als Einzeltiere sind Samtameisen, Grashüpfer und Heuschrecken relativ harmlos. Aber in Schwärmen können diese Insekten immense Schäden an Feldern und Wäldern verursachen und das Leben aller Kreaturen in ihrem Weg bedrohen.',
  'Ein Samtameisenschwarm frisst alles in seinem Weg, sowohl tierische Materie als auch Vegetation. Um die Größe eines Schwarms zu bestimmen, würfle 1W100 und multipliziere das Ergebnis mit 1.000. Es gibt etwa 100 Ameisen pro 0,09 m²; daher bildet ein Schwarm von 10.000 Ameisen einen Block von etwa 3 m je Seite. Wenn ein Schwarm mit einem Hindernis in Kontakt kommt, wendet er sich um 90° und setzt seinen Weg fort. Ein Opfer, das mit einem Schwarm in Kontakt steht, hat eine 80%ige Chance pro Runde, gebissen zu werden und 1W4 Schadenspunkte zu erleiden. Das Opfer muss einen erfolgreichen Rettungswurf gegen Gift würfeln oder intensive Schmerzen für die nächsten 2W4 Runden erleiden, wodurch alle Angriffs- und Schadenswürfe während dieser Zeit mit einem Malus von -2 belegt werden.',
  'Insektenschwärme sind wandernd und schlafen nachts, wo immer sie sich gerade befinden. Weibchen legen jedes Jahr bis zu 100 Eier. Diese Insekten haben keine Anführer oder spezialisierte Arbeiter. Sie sammeln keine Schätze.',
  'Samtameisen fressen Samen, Gräser und Fleisch und bevorzugen besonders Aas. Das Gift der Samtameisen macht sie für Fleischfresser ungenießbar.'
);

-- Ixitxachitl (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Ixitxachitl',
  'Ixitxachitl',
  'Monstrous Manual',
  FALSE,
  'Shallow tropical waters',
  'Very rare',
  'Tribe',
  'Day',
  'Carnivore',
  'Average to High (8-14)',
  'P,R,S (in lair only)',
  'Chaotic evil',
  '5-12 (1d8+4)',
  6,
  'Sw 12',
  '1+1 to 4+4',
  1,
  1,
  '1',
  '3-12',
  'Spells, see below',
  'Spells, see below',
  0,
  'S',
  'Elite (13)',
  13,
  35,
  'Ixitxachitl sind eine Rasse intelligenter, aquatischer Wesen, die kleinen Mantarochen mit Stachelschwänzen ähneln. Sie haben eine böse Veranlagung und verehren böse Mächte; sie lieben es, maritime Humanoide zu jagen und ihre Beute dann zu opfern oder zu verschlingen.',
  'Eine bevorzugte Taktik der Ixitxachitl ist es, sich im Sand des Meeresbodens zu verstecken, zu warten bis Beute vorbeikommt, dann hervorzuspringen und sie zu beißen. Die Kreaturen sind nicht sehr heimlich, und diese Taktik gibt ihnen normale Chancen, ihre Beute zu überraschen.',
  'Obwohl sie gelegentlich in Flüssen angetroffen werden, leben Ixitxachitl in seichten Meerestiefen. Sie haben gewöhnlich eine Gemeinschaft von 10-100 Individuen, die in einem Labyrinth von Korridoren innerhalb eines Korallenriffs lebt. Eine Gemeinschaft hat gewöhnlich 20-200 humanoide Sklaven, die schwere Arbeit für sie verrichten, wie das Graben von Korridoren. Der Eingang der Gemeinschaft ist versteckt.',
  'Ixitxachitl haben keine natürlichen Feinde, obwohl sie viele Gegner haben, von Sahuagin bis hin zu Menschen. Sie sind bösartige Räuber, die fast jede lebende Kreatur jagen; sie überjagen oft eine Region und eliminieren alle Lebensformen, was die Ixitxachitl zwingt, neue Jagdgründe zu finden.'
);

-- Jackal (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
