) VALUES (
  'Schakal',
  'Jackal',
  'MC1 Volume I (w/binder #1)',
  FALSE,
  'Warm plains and deserts',
  'Common',
  'Pack',
  'Night',
  'Scavenger',
  'Semi- (2-4)',
  'Nil',
  'Neutral',
  '1-6',
  7,
  '12',
  '½ (1-4 hp)',
  1,
  20,
  '1',
  '1-2',
  'Nil',
  'Nil',
  0,
  'S',
  'Unreliable (2-4)',
  2,
  7,
  'Schakale sind kleine, hundeartige Aasfresser, die durch die warmen Grasländer der Welt streifen. Sie sind weder wild noch mutig, aber durchaus häufig anzutreffen. Es gibt drei bekannte Schakalarten in der Welt: Asiatische, Schabrackenschakale und Streifenschakale. Abgesehen von ihren Markierungen sind diese Tiere sehr ähnlich.',
  'In der Regel wird jeder Schakal fliehen, wenn er von einem anderen Raubtier angegriffen oder bedroht wird. Tatsächlich werden sie sogar ihre Jagdbemühungen aufgeben, wenn sich herausstellt, dass ihre Beute mehr Leben in sich hat, als sie erwartet hatten.',
  'Schakale bewohnen Ebenen, Wüsten und Grasländer in den wärmeren Regionen der Welt. Während des Tages, wenn die Sonne zu heiß für ihren Geschmack ist, bleiben sie in Löchern, die sie in den Boden gegraben haben.',
  'Schakale sind zurückhaltende Raubtiere und ihre Position in der Nahrungskette ist die eines Aasfressers statt eines Jägers. Indem sie kranke oder schwache Tiere jagen und töten, spielen sie eine wichtige Rolle im Prozess der natürlichen Selektion. Zusätzlich würde das Aas, das sie verzehren, andernfalls verrotten und zu einem potentiellen Gesundheitsrisiko und Nährboden für Krankheiten werden.'
);

-- Kelpie (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Kelpie',
  'Kelpie',
  'MC2 Volume II',
  FALSE,
  'Temperate or tropical/Saltwater',
  'Very rare',
  'Solitary',
  'Any',
  'Photosynthesis',
  'Low-Average (5-10)',
  'D',
  'Neutral evil',
  '1-4',
  3,
  '9, Sw 12',
  '5',
  5,
  15,
  'Nil',
  'Nil',
  'See below',
  'See below',
  0,
  'M',
  'Elite (13)',
  13,
  420,
  'Der Kelpie ist eine Form intelligenten, aquatischen Pflanzenlebens, das seine Gestalt verändern und einen Charme-Zauber wirken kann. Sein Zweck ist es, Toren zu ertränken.',
  'Ein Kelpie verfügt nicht über echte Offensivfähigkeiten. Wenn sich ein humanoider Mann nähert, formt sich der Kelpie in die Gestalt einer Frau oder eines Reittiers um. Obwohl das Ergebnis eine groteske Nachäffung ist, die bei Tageslicht zu 95% als abstoßend erkennbar ist, kann der Kelpie seine Täuschung durch Magie verstärken.',
  'Eine Legende erzählt, dass der Kelpie von einem rachsüchtigen Meeresgott geschaffen wurde, um Männer zu bestrafen, die unbesonnen genug waren, die Meere zu befahren, ohne dem Meeresgott seine rechtmäßige Ehrerbietung zu erweisen. Da zu jener Zeit wenige Frauen Seefahrerinnen waren, blieben sie vom Fluch des Kelpie verschont. Eine weniger weit verbreitete Legende berichtet, wie Kelpies von Olhydra, der Elementarprinzessin der bösen Wasserkreaturen, erschaffen wurden. Aus Respekt vor ihrem eigenen Geschlecht machte Olhydra alle Frauen immun gegen die Charme ihrer Schöpfungen.',
  'Kelpie-Sprösslinge sind 500 GM wert. Die Sprösslinge sind anfangs zu klein, um Magie zu nutzen, können aber in einem Monat zu ausgewachsenen Kelpies heranwachsen, wenn sie ausreichende Pflege erhalten. Kelpies können sich mit mächtigen Kreaturen verbünden und bewachen gelegentlich versunkene Schätze.'
);

-- Kenku (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Kenku',
  'Kenku',
  'Monstrous Manual',
  FALSE,
  'Any land',
  'Uncommon',
  'Clan',
  'Any',
  'Omnivore',
  'Average (8-10)',
  'F',
  'Neutral',
  '2-8',
  5,
  '6, Fl 18 (D)',
  '2-5',
  2,
  2,
  '3 or 1',
  '1-4/1-4/1-6 or by weapon',
  'Nil',
  'See below',
  30,
  'M',
  'Elite (13)',
  13,
  2,
  'Kenku sind zweibeinige, humanoide Vögel, die ihre Kräfte nutzen, um Menschen und Halbmenschen zu belästigen und ihnen Unannehmlichkeiten zu bereiten.',
  'Alle Kenku verfügen über die Fertigkeiten eines Diebes der 4. Stufe. Sie sind erfahrene Kämpfer und greifen gewöhnlich mit einem Krummsäbel oder Kampfstab an. Sind sie unbewaffnet, attackieren sie entweder mit beiden Klauenpaaren (zwei Angriffe für je 1W4 Schadenspunkte) und ihrem Schnabel (1W6 Schadenspunkte). Sind sie zu Fuß unterwegs, nutzen sie die Handklauen. Im Flug werden die Fußklauen eingesetzt. Normalerweise töten sie nicht, es sei denn, ihr eigenes Leben wird durch das Überleben ihres Feindes bedroht. Alle Kenku verfügen über gut entwickelte Verkleidungsfertigkeiten. Sie haben eine 50%ige Chance, für Menschen gehalten zu werden, obwohl ihre Verkleidungen oft verräterisch große Nasen aufweisen.',
  'Kenku sind eine geheimnisvolle Rasse, die unter Menschen und Halbmenschen lebt, ohne dass der Großteil der Bevölkerung jemals ihre Anwesenheit bemerkt.',
  'Häuslich aufgezogene Kenku werden als Diener geschätzt. Kenku-Eier werden gewöhnlich für 250 GM verkauft, Jungtiere für 300-500 GM. Dies ist jedoch eine Form des Sklavenhandels mit allen damit verbundenen Komplikationen. Entdeckt ein Kenku gefangene Kenku, wird er versuchen, den Gefangenen heimlich zu befreien und, wenn möglich, den Sklavenhändler oder Besitzer zu entführen. Sie werden getötete Kenku rächen.'
);

-- Killmoulis (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Killmoulis',
  'Killmoulis',
  'MC2 Volume II',
  FALSE,
  'Human areas',
  'Uncommon',
  'Solitary',
  'Nocturnal',
  'Omnivore, scavenger',
  'Average (8-10)',
  'K',
  'Neutral (chaotic good)',
  '1-3',
  6,
  '15',
  '½',
  1,
  20,
  'Nil',
  'Nil',
  'See below',
  'See below',
  20,
  'T',
  'Average (8-10)',
  8,
  35,
  'Killmoulis sind winzige Wesen, die gerne nützliche Dienste verrichten, aber auch Schabernack treiben.',
  'Killmoulis sind grundsätzlich harmlose Wesen. Ihnen fehlt jede echte Fähigkeit, Menschen oder Halbmenschen anzugreifen. Sie mögen Nadeln benutzen, um Ratten zu stechen; solche Angriffe verursachen 1 Schadenspunkt.',
  'Killmoulis leben immer an Orten, wo Menschen oder Halbmenschen irgendeiner Form von Gewerbe nachgehen, vorzugsweise dort, wo Nahrungsmittel verarbeitet werden. Sie machen ihre Heime unter Böden, in Wänden oder auf dunklen Dachsparren. Sie kommen nur heraus, wenn die Arbeiter fort sind. Wie ihre entfernten Verwandten, die Brownies, sind die Killmoulis zwischen der wohlwollenden Verrichtung nützlicher Pflichten und einem schelmischen Hang zu harmlosen Streichen zerrissen. Killmoulis sind unermüdliche Arbeiter, die geschickt einfache Aufgaben verrichten.',
  'Killmoulis sind eine Rasse, die sich an eine symbiotische Lebensweise angepasst hat. Weise Menschen und Halbmenschen heißen diese geheimnisvollen Assistenten willkommen: trotz des Killmoulis-Appetits ist ihre Arbeit meist wertvoller als die Nahrung, die sie verzehren. Killmoulis fungieren auch als Wächter gegen gemeinsame Bedrohungen wie Ungeziefer und Feuer.'
);

-- Ki-rin (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
