  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Ki-rin',
  'Ki-rin',
  'Monstrous Manual',
  FALSE,
  'Sky',
  'Very rare',
  'Solitary',
  'Any',
  'Herbivore',
  'Supra-genius (19-20)',
  'I,S,T',
  'Lawful good',
  '1',
  -5,
  '24, Fl 48 (B)',
  '12',
  12,
  9,
  '3',
  '2-8/2-8/3-18',
  'Magic use',
  'See below',
  90,
  'H',
  'Fanatic (18)',
  18,
  11,
  'Kontrolle über das Leblose, Reisen, Gedankenlesen.',
  'Der Ki-rin kann körperlich mit seinen mächtigen Hufen angreifen (jeweils 2W4 Schadenspunkte) oder einem einhornartigen Horn, das einen +3-Bonus auf seinen Angriffswurf erhält und 3W6 Schadenspunkte verursacht.',
  'Die Ki-rin sind eine Rasse von Luftwesen, die selten ihre Hufe auf festen Boden setzen. Nur die Männchen nähern sich jemals dem Boden. Noch nie wurde eine Begegnung mit einem weiblichen Ki-rin verzeichnet, obwohl sicher ist, dass solche Wesen existieren. Ebenso wurde noch nie ein junger Ki-rin angetroffen, daher sind Details über ihre Fortpflanzung unbekannt. Ki-rin sind zurückhaltend bei diesen Themen.',
  'Ki-rin verbringen die meiste Zeit damit, ihre eigenen Angelegenheiten zu verfolgen. Sie überwachen oft die Aktivitäten mächtiger böser Kreaturen und Wesen. Wenn solche Wesen zu bösartig werden, handeln die Ki-rin gegen sie.'
);

-- Korred (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Korred',
  'Korred',
  'MC1 Volume I (w/binder #1)',
  FALSE,
  'Temperate forest and sylvan settings',
  'Very rare',
  'Clan',
  'Any',
  'Omnivore',
  'Very (11-12)',
  'E',
  'Chaotic neutral',
  '1-4',
  5,
  '9',
  '6+1',
  6,
  15,
  '1',
  '3-6 (1d2+4) or by weapon +4',
  'See below',
  'See below',
  25,
  'S',
  'Elite (13-14)',
  13,
  1,
  'Wenn Reisende durch die waldreichen Wälder der Welt wandern, sollten sie sich vor Musik und Gelächter hüten, die aus einer Lichtung kommen. Höchstwahrscheinlich ist die Ursache der tanzliebende Korred, eine Rasse, die der Natur nahesteht und ihre Lebensweise eifersüchtig beschützt.',
  'Korred haben große Stärke (durchschnittlich 18/76) und nutzen sie, um Felsbrocken bis zu 30 m zu schleudern (Schaden 2W8). Sie verwenden auch Knüppel (Schaden 1W6+4) oder Scheren, die sich in ihren Beuteln befinden (Schaden 1W4+4). Ohne Waffe kann der Korred für 1 oder 2 Schadenspunkte zuschlagen, wobei seine große Stärke +4 zu dieser Summe hinzufügt.',
  'Bewaldete Hügel und waldreiche Umgebungen werden von den Korred bevorzugt, die normalerweise in Höhlen oder Bauen hausen. Die Korred sind sippenorientiert und verwenden das Wort "Sippe" als Titel (zum Beispiel Sippe Korefyr). Im Einklang mit ihrer chaotischen Natur haben sie keine strukturierten Gemeinschaften. Typischerweise gibt es 1-4 Erwachsene und 2-8 (2W4) Kinder pro Familie, wobei 2-8 (2W4) Familien zu jeder einzelnen Sippe gehören. Diese Familien sind über ein Gebiet von etwa acht Kilometern verstreut.',
  'Diese magische Rasse wird für die Erschaffung verschiedener magischer Gegenstände gesucht. Ihr Haar ist eine Schlüsselzutat für Verstrickungsseile und Fangnetze. Die fermentierten Fruchtgetränke, die die Korred konsumieren, können auch als Komponente für Liebestränke und Tränke der Menschenbeherrschung verwendet werden.'
);

-- Lamprey (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Neunauge',
  'Lamprey',
  'MC2 Volume II',
  FALSE,
  'Deep waters',
  'Uncommon',
  'Solitary',
  'Any',
  'Carnivore',
  'Non- (0)',
  'Nil',
  'Neutral',
  '1-2',
  7,
  'Sw 12',
  '1+2',
  1,
  18,
  '1',
  '1-2',
  'Drain blood',
  'Nil',
  0,
  'S',
  'Unsteady (7)',
  7,
  65,
  'Neunaugen sind blutegelähnliche Aale, die in tiefen Süß- und Salzgewässern leben. Sie ernähren sich, indem sie ihre Opfer beißen, sich mit ihren Zähnen festhalten und das Blut ihrer Beute aussaugen.',
  'Sie ernähren sich, indem sie ihre Opfer beißen und sich mit ihren sphinkterartigen Mäulern festhalten. Sobald sie angeheftet sind und der anfängliche Schaden dem Opfer zugefügt wurde, beginnt das Neunauge in der nächsten und den folgenden Runden Blut zu entziehen. Die Rate des Blutentzugs entspricht 2 Trefferpunkten pro Trefferwürfel des Neunauges. Somit entzieht ein normales Neunauge pro Runde Blut für 2 Schadenspunkte.',
  'Neunaugen bewohnen Tiefwassergebiete und hausen in natürlichen Höhlen oder Korallenformationen. Neunaugen haben einen unfehlbaren Heimfindungsinstinkt, der es ihnen ermöglicht, bis zu 3,2 km von ihrem Bau entfernt umherzustreifen.',
  'In Salzwasserumgebungen fressen Haie gerne Riesenneunaugen. Man könnte argumentieren, dass die Anwesenheit dieser Meerneunaugen die Anzahl der Haiangriffe auf Küstengemeinden niedrig hält.'
);

-- Living Wall (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Lebende Wand',
  'Living Wall',
  'Monstrous Manual',
  FALSE,
  'Any',
  'Very Rare',
  'Solitary',
  'Any',
  'Assimilation (see below)',
  'Variable (3-18)',
  'Variable',
  'Chaotic evil',
  '1',
  8,
  'Nil',
  '8 (Base)',
  8,
  20,
  'Variable',
  'Variable',
  'See below',
  'See below',
  20,
  'L',
  'Fearless (20)',
  20,
  2,
  'Lebende Wände erscheinen als normale Wände aus Stein oder Ziegeln, obwohl sie sowohl Böses als auch Magie ausstrahlen, falls dies entdeckt wird. Infrasicht erkennt keine besonderen Muster. Ein Charakter, der jedoch einen Zauber der wahren Sicht wirkt oder durch einen Edelstein des Sehens blickt, sieht durch die Illusion hindurch: Die Wand besteht tatsächlich aus grauem und sehnigem Fleisch - aus Gesichtern, Händen, gebrochenen Knochen, Füßen und Zehen, die aus der Oberfläche hervorragen. Charaktere in 4,6 m Entfernung zur Wand können leise Stöhnen des Grauens, Schmerzes und der Trauer von ihr ausgehen hören. Selbst wenn ein Zauber der Stille gewirkt wird, steigen die Klagen weiter auf.',
  'Eine lebende Wand beginnt niemals einen Kampf, außer gegen ihren Erschaffer, den sie verabscheut. Wenn eine solche Wand angegriffen wird, führt jede Kreatur, die Teil der Wand ist, einen Gegenangriff pro Schlag gegen die Wand aus. Wenn eine Wand aus 12 Kreaturen besteht und eine Kreatur einen Treffer gegen die Wand landet, ist der Angreifer einem Dutzend Gegenangriffen der Wand ausgesetzt.',
  'Lebende Wände pflanzen sich niemals fort und bleiben immer aktiv, bis sie getötet werden. Lebende Wände, die in den Bauten bösartiger Kreaturen angetroffen werden, dienen oft als Teil einer Folterkammer oder um die wahren Öffnungen zu geheimen Durchgängen oder Korridoren zu verdecken.',
  'Chaotisch böse Magier erschaffen gelegentlich diese Monolithen. Die genaue Methode ist unbekannt, aber mehrere Jahre der Vorbereitung und des Zauberwirkens sind erforderlich. Mindestens drei Leichen sind für die Zauber notwendig.'
);

-- Lizard (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Echse',
  'Lizard',
  'Monstrous Manual',
  FALSE,
  'Any warm land',
  'Very rare',
  'Solitary',
  'Day',
  'Carnivore',
  'Animal (1)',
  'B,Q(×10),S,T',
  'Neutral',
  '1-4',
  3,
  '9',
  '10',
  10,
  11,
  '3',
  '1-8/1-8/2-16',
  'See below',
  'See below',
  0,
  'G',
  'Steady (11-12)',
  11,
  3,
  'Feuerechsen ähneln flügellosen roten Drachen und werden manchmal "falsche Drachen" genannt. Sie sind grau gefärbt mit gesprenkeltem rot-braunem Rücken und rötlicher Unterseite. Jungtiere sind hellgrau gefärbt und dunkeln mit dem Alter nach.',
  'Feuerechsen greifen mit einer Kombination aus kratzenden Klauen und Biss an. Sie können gleichzeitig einen feurigen Kegel atmen, der am Maul 1,5 m breit, am Ende 3 m breit und 4,6 m lang ist und 2-12 Punkte feuerbasierten Schaden verursacht (die Hälfte bei erfolgreichem Rettungswurf gegen Atemwaffe). Feuerechsen sind immun gegen feuerbasierte Angriffe.',
  'Feuerechsen bevorzugen unterirdische Baue, kommen aber alle vierzehn Tage heraus, um frische Beute zu jagen. Die Beute wird zurück zum Bau geschleppt für eine gemütliche Mahlzeit; die Überreste bilden den Schatzhort. Feuerechsen bewegen sich langsam und schlafen 50% der Zeit. Ihre Baue können 1-4 Eier enthalten (10% Chance, Marktwert 5.000 GM je Ei). Jungtiere verlassen sofort den Bau, um allein zu jagen. Glänzende Gegenstände locken Feuerechsen an; Edelsteine und Metalle bilden den Großteil der in ihren Höhlen gefundenen Schätze.',
  'Feuerechsen sind vielleicht ein ursprünglicher Drachentyp oder Ableger eines gemeinsamen Vorfahren. Echte Drachen meiden diese "falschen Drachen", die 50-100 Jahre alt werden. Feuerechseneier sind 5.000 GM wert, Jungtiere 7.500 GM.'
);

-- Lurker (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Lauerer',
  'Lurker',
  'Monstrous Manual',
  FALSE,
  'Subterranean',
  'Uncommon',
  'Solitary',
  'Any',
  'Omnivore',
  'Non- (0)',
  'C,Y',
  'Neutral',
  '1 (1-4)',
  6,
  '1, Fl 9 (B)',
  '10',
  10,
  11,
  '1',
  '1-6',
  'See below',
  'Nil',
  0,
  'H',
  'Steady (11)',
  11,
  2,
  'Der Lauerer ist ein fleischfressender Aasfresser, der nur in unterirdischen Umgebungen anzutreffen ist. Er ähnelt einem großen Manta-Rochen; sein gräulicher Bauch hat eine steinähnliche Struktur. Der Lauerer heftet sich typischerweise an eine Decke, wo er sehr schwer zu entdecken ist (nur 10% Chance), es sei denn, er wird tatsächlich angestoßen.',
  'Lauerer sind langsam bewegende Kreaturen, die warten müssen, bis ihre Beute in Reichweite kommt. Lauerer warten an der Decke, dann lassen sie sich fallen und umhüllen ihre Beute. Lauerer verursachen eine -4 Strafe auf die Überraschungswürfe der Gegner. Die Umklammerung verursacht 1W6 Schadenspunkte pro Runde und Erstickung innerhalb von 1W4+1 Runden, unabhängig vom erlittenen Schaden des Opfers. Dieser Schaden tritt automatisch jede Runde ein, es sei denn, das Opfer befreit sich oder der Lauerer stirbt. Lauerer hören nicht auf anzugreifen, bis sie tot sind. Die Beute kann nur mit kurzen Waffen kämpfen, die in der Hand waren, als der Lauerer angriff.',
  'Lauerer sind Einzelgänger. Die Weibchen legen Eier in einen klebrigen Haufen nahe der Decke. Die Schlüpflinge fallen zu Boden und ernähren sich von Ungeziefer, bis sie groß genug sind zu fliegen. Junge ähneln rechteckigen Moosflächen.',
  'Lauerer sind opportunistische Fresser, die mit allem vorlieb nehmen, was vorbeikommt. Der Lauerer fliegt mittels Gasen, die in Säcken erzeugt werden. Diese Gase können bei der Herstellung eines Tranks des Schwebens verwendet werden. Lauerer-Eier oder Schlüpflinge können als lebende Verteidigung an diejenigen verkauft werden, die sie wollen. Lauerer-, Fallensteller- und Minen-Eier können alle für 900 GM verkauft werden, Schlüpflinge für 1.100 GM.'
);

-- Mammal (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
