-- Mammal, Herd I (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Säugetier, Herdentier I',
  'Mammal, Herd I',
  'Monstrous Manual',
  FALSE,
  'Any land',
  'Common',
  'Herd',
  'Day',
  'Herbivore',
  'Animal to semi- (1-4)',
  'Nil',
  'Nil',
  '1-12',
  7,
  '21',
  '3',
  3,
  17,
  '1',
  '1-4',
  'Spitting',
  'Nil',
  0,
  'L',
  'Unreliable (3)',
  3,
  65,
  'Herdentiere leben in allen Klimazonen und Geländearten, von eisiger Tundra (Trampeltier) über gemäßigte Hügel (Wildrind) bis hin zu tropischen Ebenen (Antilope). Obwohl normalerweise friedlich, können Herdentiere gefährlich werden, wenn sie verärgert oder erschreckt sind.',
  'Die meisten Herdentiere greifen durch Beißen an. Büffel verteidigen sich mit ihren Hörnern und greifen normalerweise an, wenn man ihnen zu nahe kommt (1,8 m oder weniger); wenn sie aus einer Entfernung von mindestens 12 m anstürmen, verursacht ein Büffel 3-18 TP Spießschaden plus 1-4 TP Trampelschaden. Bösartige Kamele haben eine 50%ige Chance, Personen anzuspucken, die versuchen, auf ihnen zu reiten oder sie als Lasttiere zu benutzen; das Opfer eines Spuckangriffs hat eine 25%ige Chance, für 1-3 Runden geblendet zu werden. Rinder, Antilopen und Schafe fliehen normalerweise vor Gefahr, greifen aber an, wenn sie in die Enge getrieben oder bedroht werden. Ein männliches Antilopen- oder Schafsmännchen, das seine Herde verteidigt, wird anstürmen und 1-4 TP Rammschaden verursachen, wenn es aus mindestens 12 m Entfernung angreift. Männliche Rinder greifen zu 75% an, wenn Eindringlinge sich nähern, bevor die Herde eine Chance zur Flucht hatte.',
  'Herdentiere weiden auf offenem Gelände und wandern in ein neues Territorium, wenn die Nahrungsversorgung des alten erschöpft ist. Die Herdengröße variiert von einer Familie mit vier Büffeln bis zu einer kommerziellen Schafherde mit 1.000 Tieren. Das größte und älteste Männchen dient normalerweise als Anführer, lenkt die Bewegung seiner Herde und hält nach Raubtieren Ausschau. Herdentiere sammeln keine Schätze.',
  'Herdentiere fressen Gras, Getreide und Sträucher. Sie sind die bevorzugte Beute von Fleischfressern, einschließlich Löwen, Tigern und Drachen. Menschen domestizieren Herdentiere oft wegen ihres Fleisches, ihrer Milch, ihres Fells (Decken und Kleidung) und ihrer Haut (Schuhe und Zelte). Getrockneter Dung von Herdentieren kann als Brennstoff verbrannt werden.'
);

-- Mammal, Minimal (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Säugetier, Minimal',
  'Mammal, Minimal',
  'MC2 Volume II',
  FALSE,
  NULL,
  'Very Rare',
  NULL,
  NULL,
  NULL,
  NULL,
  NULL,
  'Neutral (chaotic)',
  'As full size but 50% likely for twice the number rolled',
  2,
  '⅔ of full size',
  '1',
  1,
  20,
  'As full size or fewer (see below)',
  '',
  '+1 to surprise for carnivores',
  '-1 to attacker''s surprise',
  2,
  'M',
  'Unreliable to Average (2-10)',
  2,
  0,
  'Minimale sind halbgroße Züchtungen ansonsten normaler Tiere. Sie haben die gleichen körperlichen und Verhaltensmerkmale wie ihre normalgroßen Verwandten, obwohl die meisten nicht so gefährlich sind.',
  'Minimale kämpfen auf die gleiche Weise wie die normalen Züchtungen. Einige der Fleischfresser sind sogar noch aggressiver.',
  'Minimale (die populäre Kurzform für "kleine Tiere") wurden mittels Zaubersprüchen erschaffen, die ähnlich denen sind, die zur Erschaffung von Riesenreptilien, Insekten und dergleichen verwendet werden. Minimale sind meist nur in isolierten oder abgeschlossenen Gebieten zu finden. Dort sind sie zu 80% die einzigen Säugetierarten in der Umgebung. Sie existieren selten in Gebieten mit großen Fleischfressern, da sie schnell ausgerottet würden.',
  'Minimale sind das Ergebnis absichtlicher Manipulation der Natur durch magische Mittel. Abgesehen von ihrer geringeren Größe haben sie die gleichen Eigenschaften und Bedürfnisse wie ihre normalgroßen Verwandten. Anders als die meisten vergrößerten Monster haben die winzigen Minimalen erhöhte Nützlichkeit und Überlebensfähigkeit, da sie weniger Nahrung und Territorium benötigen. Minimale Häute und Felle sind ⅔ des Wertes der normalgroßen Arten wert.'
);

-- Medusa, Maedar (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
