  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Medusa, Maedar',
  'Medusa, Maedar',
  'Monstrous Manual',
  FALSE,
  'Subterranean',
  'Very rare',
  'Solitary',
  'Any',
  'Carnivore',
  'Very (11-12)',
  'P,Q(×10),X,Y',
  'Lawful Evil',
  '1',
  5,
  '9',
  '6',
  6,
  15,
  '2',
  '2-8/2-8',
  'See below',
  'See below',
  0,
  'M',
  'Elite (13-14)',
  13,
  975,
  '(1,5-2,1 m)',
  'Maedar greifen mit mächtigen Fäusten an, die jeweils 2W4 Schadenspunkte verursachen. Alle drei Runden kann der Maedar Stein zu Fleisch durch Berührung verwandeln. Maedar können mit ihrer normalen Bewegungsrate durch Stein hindurchgehen. Sie benötigen eine Runde der Konzentration davor; in dieser Runde kann keine andere Aktivität unternommen werden. Maedar, die von einem Phasentür-Zauber getroffen werden, während sie durch Stein gehen, werden sofort getötet.',
  'Maedar sind die wenig bekannte männliche Version der Medusen. Sie sind jedoch extrem selten (weitaus seltener als die Häufigkeitsangabe andeuten würde), und nur wenige Medusen finden jemals einen Maedar als Partner.',
  'Maedar können mit rechtschaffen bösen Kreaturen wie Kobolden und Orks zusammenarbeiten, im Austausch für Sicherheit oder Belohnung. Wenn sie gezwungen werden, einer anderen Kreatur zu helfen, suchen Maedar bei der ersten Gelegenheit Rache.'
);

-- Merman (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
