  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Meermann',
  'Merman',
  'Monstrous Manual',
  FALSE,
  'Temperate/Oceans',
  'Uncommon',
  'Community',
  'Any',
  'Omnivore',
  'Average-Very (8-12)',
  'C,R',
  'Neutral',
  '20-200',
  7,
  '1, Sw 18',
  '1+1',
  1,
  19,
  '1',
  'By weapon type',
  'Grapple ship',
  'Nil',
  0,
  'M',
  'Average (10)',
  10,
  1,
  'Meermänner sind meeresbewohnende, amphibische Humanoide mit dem Oberkörper eines Menschen und dem Unterkörper eines Fisches.',
  'Meermanngemeinschaften sind gut bewaffnet. Die von Meermännern verwendeten Waffen sind folgende:',
  'Für jeden 20 angetroffenen Meermänner gibt es einen Patrouillenfüherer (2-3 TW) und 1-3 Barrakudas (RK 6; Bewegung 30; TW 3; #AT 1; Schaden 2W4). Für jeden 40 Meermänner gibt es einen Anführer (4 TW). Für jeden 120 angetroffenen Meermänner gibt es einen Häuptling (6 TW) und zwei Wachen (4 TW). Für jeden zehn Meermänner besteht eine 10%ige Chance auf einen Schamanen (3 TW, mit den Zaubern eines Priesters 3. Stufe).',
  'Meermänner sind Allesfresser, aber sie bevorzugen eine Diät aus Fischen, Hummern, Krabben und Schalentieren. Sie kochen diese Kreaturen nicht, müssen sie aber vor dem Verzehr filetieren. Sie können eine Stunde außerhalb des Wassers überleben, bevor sie zu dehydrieren beginnen. Wenn dehydriert, verlieren sie 2 Trefferpunkte pro Stunde und sterben, wenn sie null erreichen; das Eintauchen in Süß- oder Salzwasser stellt diese verlorenen Trefferpunkte sofort wieder her.'
);

-- Mist, Crimson Death (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
