  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Nebel, Karmesinroter Tod',
  'Mist, Crimson Death',
  'Monstrous Manual',
  FALSE,
  'Bogs, swamps',
  'Very rare',
  'Solitary',
  'Night',
  'Carnivore',
  'Genius (17-18)',
  'Z',
  'Neutral evil',
  '1',
  10,
  'Fl 12, Fl 6 after feeding (B)',
  '13',
  13,
  7,
  '1',
  '3-30',
  'See below',
  'See below',
  95,
  'M',
  'Champion (15-16)',
  15,
  9,
  'Der karmesinrote Tod ist eine bösartige, dampfförmige Kreatur, die sich von den Körperflüssigkeiten ihrer Opfer nährt.',
  'Das Monster greift nur an, um sich zu nähren oder sich zu verteidigen. Es umgibt sein Opfer mit dampfförmigen Tentakeln. Wann immer es trifft, entziehen die Tentakel Körperflüssigkeiten und verursachen 3W10 Schadenspunkte.',
  'Der karmesinrote Tod wohnt in den Sümpfen und Mooren, wo Kälte und Feuchtigkeit vorherrschen. Die Kreatur ist in ihrem natürlichen Lebensraum nahezu unsichtbar.',
  'Der karmesinrote Tod ist ein gefährlicher Jäger, der die Sümpfe wie ein lebender Geist durchstreift. Ein karmesinroter Tod kann gesammelt und in einem luftdichten Behälter eingesperrt werden. Dies schadet ihm nicht. Ein karmesinroter Tod in einem solchen Behälter kann für einen eingesperrten Dschinn oder magischen Dampf gehalten oder falsch etikettiert werden. Wenn jemand den karmesinroten Tod freilässt, greift die hungernde Kreatur sofort ihren unwissenden Retter an.'
);

-- Mist, Vampiric (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
