  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Nebel, Vampirischer',
  'Mist, Vampiric',
  'Monstrous Manual',
  FALSE,
  'Non-arctic/Swamps, subterranean',
  'Rare',
  'Solitary',
  'Night',
  'Blood',
  'Average (8-10)',
  '(D)',
  'Neutral evil',
  '1-3',
  4,
  '12 (6 when substantial)',
  '3',
  3,
  20,
  '1',
  '1-8',
  'See below',
  'See below',
  0,
  'M',
  'Elite (13-14)',
  13,
  270,
  'Diese gasförmigen Monster jagen alle lebenden Kreaturen, umhüllen sie mit ihren gasförmigen Ranken und entziehen ihnen dann das Blut als Nahrung.',
  'Vampirische Nebel spüren automatisch die Anwesenheit jeder warmblütigen Kreatur in 15,2 m Entfernung. Hungrige Nebel nehmen den kürzesten Weg zum Opfer, navigieren durch Berührung und fließen mühelos über Wasser oder durch schmale Risse. Ihr Pfad kann durch nicht-poröse Hindernisse blockiert werden, aber vampirische Nebel sind intelligent und falls ein vernünftiger Weg existiert, werden sie ihn finden.',
  'Diese schrecklichen Monster bewohnen sowohl Sümpfe, wo sie sich kriechend mit Morgen- und Nachtnebel vermischen, als auch unterirdische Höhlen, wo sie Beute in absoluter Dunkelheit jagen. Vampirische Nebel greifen nachts oder früh morgens an und fließen über den Boden auf der Suche nach warmblütigen Opfern. Sie bevorzugen einzelne Opfer, aber hungrige Nebel überfallen manchmal nachts Städte, töten Vieh und entziehen schlafenden Opfern Blut, bevor sie bei Tagesanbruch davonschlüpfen.',
  'Zunächst für unreife Formen des Purpurnen Todes gehalten, ist nun bekannt, dass diese Scheusale absichtlich von einem mächtigen Vampir-Magier erschaffen wurden.'
);

