-- Moldman (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Schimmelmann',
  'Moldman',
  'Monstrous Manual',
  FALSE,
  'Tropical or subtropical moist forests and caverns',
  'Very rare',
  'Tribe',
  'Any',
  'Carnivore',
  'Low (5-7)',
  'O,P',
  'Neutral',
  '6-24 or 30-300',
  4,
  '12',
  '1 to 6',
  1,
  1,
  '1',
  '1-6 or by weapon',
  'See below',
  'See below',
  0,
  'S',
  'Average (8-10)',
  8,
  1,
  'Schimmelmänner, manchmal abwertend als Vegepygmäen oder sogar Schimmlinge bezeichnet, sind kleine, zweibeinige Pilzkreaturen. Sie haben scharfe, dornenartige Klauen, und blattartige Ranken bilden einen Saum an ihren Schultern, Bäuchen und Gliedmaßen. Ein Haarschopf aus diesen Ranken sitzt am höchsten Punkt des Kopfes eines Vegepygmäen.',
  'Gruppen von Schimmelmännern jagen nahe ihrer Baue. In ihrem Heimatterritorium verschmelzen Schimmelmänner mit ihrer Umgebung, sodass Gegner einen Malus von -2 auf Überraschungswürfe erhalten.',
  'Schimmelmänner bilden primitive, sesshafte Stämme. Ihre Baue finden sich normalerweise in warmen unterirdischen Gebieten, obwohl manche Stämme Baue im Unterholz tiefer, dunkler Wälder und Dschungel haben. Stämme sind sehr territorial.',
  'Schimmelmänner leben durch Aasfraß und Jagd. Sie fressen Fleisch in jedem Zustand, von frisch bis verwest. In Zeiten großer Not fressen sie bekanntermaßen andere Schimmelmänner oder sogar Myconiden, obwohl sie selten Mitglieder ihres eigenen oder eines verbündeten Stammes angreifen.'
);

-- Mongrelman (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Mongrelman',
  'Mongrelman',
  'Monstrous Manual',
  FALSE,
  'Any',
  'Rare',
  'Tribal',
  'Night',
  'Omnivore',
  'Low to Average (5-10)',
  '(C)',
  'Lawful neutral',
  '1-100',
  5,
  '9',
  '1-4',
  1,
  1,
  '1',
  '1-4 (1 HD), 1-6 (2 HD), 1-8 (3 HD), 1-10 (4 HD) or by weapon type',
  'Nil',
  'Camouflage, Mimicry',
  0,
  'M',
  'Steady (12)',
  12,
  1,
  'Mongrelmen sind eine Mischung aus dem Blut vieler Spezies: Menschen, Orks, Gnolls, Oger, Zwerge, Hobgoblins, Elfen, Bugbears, Bullywugs und viele andere. Ihr Aussehen variiert stark und kombiniert die schlechtesten Eigenschaften ihrer Elternstämme. Sie sind meist in schmutzige Lumpen gekleidet; sie schämen sich ihres Aussehens und versuchen ihre Körper zu verbergen, besonders unter Fremden. Sie haben keine eigene Sprache, sondern sprechen ein entartetes Gemeinsprech, vermischt mit Grunzen, Pfeifen, Knurren und Gesten. Ihre Namen ahmen oft Tiergeräusche nach.',
  'Mongrelmen haben drei besondere Fähigkeiten, die ihnen beim Überleben helfen: Nachahmung, Taschendiebstahl und Tarnung.',
  'Für jeden 10 angetroffenen Mongrelmen gibt es mindestens einen mit 2 Trefferwürfeln; für jeden 30 gibt es einen mit 3 Trefferwürfeln; und für jeden 40 gibt es einen mit 4 Trefferwürfeln. In einer Gemeinschaft, wo sie nicht als Sklaven gehalten werden, gibt es normalerweise einen Anführer (RK 4, Bewegung 12, TW 5, Schaden 1W12, +1 Bonus auf Angriffswurf) und fünf Leibwächter (TW 4).',
  'Mongrelmen sind Allesfresser, aber ihre Zähne sind am effizientesten beim Fleischverzehr. Die Lebensspanne eines freien Mongrelman liegt zwischen 25 und 35 Jahren; der durchschnittliche Sklave lebt nur 15 bis 20 Jahre. Ihre Säuglingssterblichkeitsrate ist sehr hoch. Ihre Hauptfeinde sind Stämme wandernder Humanoider, die sie zum Sport jagen.'
);

-- Naga, Dark (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Dunkle Naga',
  'Naga, Dark',
  'Monstrous Manual',
  FALSE,
  'Any except arctic/any land',
  'Very rare',
  'Trios, pairs, alone or work with other lawful evil creatures',
  'Any',
  'Carnivore',
  'Exceptional (16)',
  'S,T,W',
  'Lawful evil',
  '1-3 (usually 1)',
  6,
  '13',
  '9',
  9,
  11,
  '2',
  '1-4/2-8',
  'See below',
  'Nil',
  0,
  'L',
  'Champion (15)',
  15,
  4,
  'Dunkle Naga sind Feenwesen mit menschenähnlichen Gesichtern (mit Reißzähnen) auf lederartigen, schlangenähnlichen Körpern. Sie arbeiten gewöhnlich mit anderen bösen Wesen zum gegenseitigen Vorteil oder Überleben zusammen. Dunkle Naga sind meist schwarz, violett-schwarz oder sehr dunkelblau gefärbt, und ihre gehäubten Köpfe und glatten, nahezu unsichtbaren Schuppen lassen sie eher wie riesige Aale als wie Schlangen aussehen.',
  'Dunkle Naga besitzen natürliche Gedankenlese-Kräfte (24 m Reichweite) und setzen diese Fähigkeit ständig ein.',
  'Dunkle Naga nisten in felsigen Orten wie Höhlen oder Ruinen; sie mögen ein Zuhause, wo sie Dinge verstecken können (wie Schätze und Zauberbücher), das mehr als einen Ein- oder Ausgang hat und mindestens einen Ort, der schmal genug ist, dass sie ihn mit ihrem Körper blockieren und im Alleingang Eindringlinge abwehren können. Dunkle Naga lieben Fallen und werden diese entwickeln (oder andere Kreaturen damit beauftragen, sie zu installieren), wann immer möglich.',
  'Dunkle Naga fressen nicht freiwillig andere dunkle Naga, aber sie fressen fast alles andere, sowohl lebend als auch tot. Sie fressen einige Flechten und gelegentlich grüne Pflanzen, aber ihre Hauptnahrung ist Fleisch. Sie schätzen besonders heißes, noch frisches Blut.'
);

