) VALUES (
  'Quaggoth',
  'Quaggoth',
  'Monstrous Manual',
  FALSE,
  'Subterranean caves',
  'Rare',
  'Tribal',
  'Any',
  'Carnivore',
  'Low (5-7)',
  'Nil (O,R)',
  'Neutral',
  '2-24',
  6,
  '12',
  '2+2',
  2,
  19,
  '2 or 1',
  '1-4/1-4 or by weapon',
  'Berserk rage',
  'Immune to poison',
  0,
  'L',
  'Elite (15-16)',
  15,
  175,
  'Wissenschaft: Telekinese; Andachten: Flammen kontrollieren, molekulare Erregung.',
  'Quaggoth-Stämme beanspruchen ein bestimmtes Territorium für sich und patrouillieren es auf der Jagd nach Nahrung. Alle entdeckten Tiere oder Kreaturen (wie eine Abenteurergruppe) ziehen sicherlich einen Angriff nach sich.',
  'Quaggoths sind nomadische Jäger. Sie wechseln regelmäßig ihre Territorien. In jedem neuen Territorium beanspruchen sie eine zentrale Höhle als Bau und hinterlassen Schätze bei einigen wenigen Wachen. Der Rest des Stammes jagt und kehrt regelmäßig zurück, um zu rasten und die Wachen zu wechseln.',
  'Quaggoths stellen einige wenige Artefakte her, meist grob geschnitzte Steingegenstände. Einige scheinen talentiert darin zu sein, Halsketten mit hölzernen, knöchernen oder steinernen Perlen zu fertigen.'
);

-- Ray (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Rochen',
  'Ray',
  'MC1 Volume I (w/binder #1)',
  FALSE,
  'Shallow tropical waters',
  'Uncommon',
  'Solitary',
  'Day',
  'Carnivore',
  'Non- (0)',
  'J-N×10,Q×5,X',
  'Neutral',
  '1',
  6,
  'Sw 18',
  '8-11',
  8,
  8,
  '1 tail or 1 bite',
  '3-12 (bite) or 3-20 (sting)',
  'See below',
  'Nil',
  0,
  'G',
  'Elite (13)',
  13,
  8,
  'Rochen, auch Seefledermäuse genannt, stammen aus warmen tropischen Flachwassern. Sie sind breite, flache Kreaturen mit Augen auf der oberen, dunkelfarbigen Oberfläche ihres Körpers und Maul und Kiemen auf der helleren Unterseite. Ihre Brustflossen sind riesig, was ihnen ein fledermausähnliches Aussehen verleiht, und sie nutzen ihren kurzen Schwanz als Ruder. Sie ernähren sich von Weichtieren und Krustentieren und greifen nur selten Menschen an, mit Ausnahme der bösartigen Ixitxachitl. Diese langen, flachen Kreaturen vergraben sich im Schlick und Sand des Meeresbodens, um ihre Beute zu überraschen.',
  NULL,
  NULL,
  NULL
);

-- Rot Grub (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Fäulniswurm',
  'Rot Grub',
  'MC2 Volume II',
  FALSE,
  'Any land',
  'Uncommon',
  'Swarm',
  'Any',
  'Scavenger',
  'Non- (0)',
  'Nil',
  'Neutral',
  '5-20',
  9,
  '1',
  '1 hp',
  1,
  20,
  '0',
  'Nil',
  'See below',
  'Nil',
  0,
  'T',
  'Unsteady (5)',
  5,
  15,
  'Fäulniswürmer sind widerliche kleine Kreaturen, die Maden ähneln. Sie wären als unbedeutend zu betrachten, wenn nicht ihre entsetzliche Angriffsform wäre.',
  'Diese kleinen Kreaturen graben sich bösartig in jedes lebende Fleisch, das sie berührt, da sie solche Kost sehr gerne verspeisen. Der Angriff ist automatisch erfolgreich - kein Angriffswurf ist notwendig, sofern sie von bloßer Haut berührt wurden. Falls fraglich ist, ob bloße Haut einem Fäulniswurm ausgesetzt war, multipliziere die Rüstungsklasse des potentiellen Opfers mit 10, ohne Schilde zu berücksichtigen. Dies ist die Chance, gewürfelt mit Prozentwürfeln, dass die Fäulniswürmer bloße Haut berühren.',
  'Fäulniswurmschwärme werden gelegentlich in Haufen von Abfall oder Dung gefunden. Sie werden selten in Decken, Böden oder Wänden gefunden, aber es ist möglich. Manchmal tragen Untote wie Ghule, Ghäste, Zombies oder Wichte Fäulniswürmer mit sich, obwohl die kleinen Bestien keine Wirkung auf diese untoten Wirte haben. In Dschungel- und Sumpfgebieten können Fäulniswürmer in Haufen verrottender Pflanzen gefunden werden. Jeder, der so töricht ist, barfuß in solchen Gebieten zu laufen, bekommt was er verdient!',
  'Fäulniswürmer werden oft von Attentätern gesucht. Einen oder zwei davon auf ein schlafendes Opfer zu platzieren gewährleistet normalerweise einen schnellen, stillen Tod. Außerdem kann, falls ein Arzt nicht weiß wonach er suchen soll, die Todesursache nicht bestimmt werden.'
);

-- Scorpion (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Skorpion',
  'Scorpion',
  'Monstrous Manual',
  FALSE,
  'Warm wilderness and subterranean areas',
  'Uncommon',
  'Swarm',
  'Any',
  'Carnivore',
  'Non- (0)',
  'D',
  'Neutral',
  '1-6',
  5,
  '9',
  '2+2',
  2,
  19,
  '3',
  '1-4/1-4/1',
  'Poison sting',
  'Nil',
  0,
  'S',
  'Average (8)',
  8,
  175,
  'Riesenskorpione sind bösartige Raubtiere, die fast überall leben, einschließlich relativ kalter Orte wie Verliese, obwohl sie Wüsten und warme Länder bevorzugen. Diese Kreaturen sind Riesenversionen der normalen 10 cm langen Skorpione, die man in Wüstengebieten findet.',
  'Der Riesenskorpion wird mit 95%iger Wahrscheinlichkeit jede Kreatur angreifen, die sich nähert. Die Kreatur hat einen harten, chitinösen Panzer, der ihr Rüstungsklasse 3 verleiht. Dieses Monster greift an, indem es Beute mit seinen beiden riesigen Scheren packt und dabei jeweils 1-10 Schadenspunkte zufügt, während es mit seinem Schwanz nach vorn peitscht, um zu stechen. Somit kann es drei Gegner gleichzeitig bekämpfen. Wenn ein Riesenskorpion es schafft, ein Opfer in einer Schere zu packen, fügt er automatisch jede Runde 1-10 Schadenspunkte zu, bis er das Opfer loslässt. Das Opfer hat nur eine Chance zu entkommen. Wenn es seinen Wurf für Eisenstangen biegen/Tore heben schafft, wird es der Klaue entkommen. Dies kann jedoch die einzige Handlung des Charakters in dieser Runde sein und nur einmal pro Kampf versucht werden. Wird der Stich gegen ein nicht gefangenes Opfer eingesetzt, ist ein Angriffswurf für einen erfolgreichen Angriff erforderlich, aber ein gefangener Charakter wird automatisch von jedem gegen ihn gerichteten Stichangriff getroffen, ohne dass ein Angriffswurf nötig ist.',
  'Riesenskorpione leben in unterirdischen Bauten oder Verliesen. Jeder Bau kann (20%) 5W4 Skorpioneier enthalten. Diese Bestien fressen jede lebende Kreatur, die das Pech hat, zu nah an ihren Bau zu geraten. Alle gefundenen Schätze stammen von den Körpern menschlicher oder halbmenschlicher Opfer, die hierher geschleppt wurden, um verzehrt zu werden. Rüstungen findet man selten intakt, da der Skorpion sicherlich seine Scheren benutzt hat, um seine Beute zu zerstückeln.',
  'Diese bizarren Insekten tragen zum Ökosystem bei, indem sie sich von anderen Riesenversionen von Insekten wie Spinnen und Ameisen ernähren. Sie selbst sind Beute für Purpurwürmer und andere riesige, unterirdische Kreaturen. Alchemisten und Meuchelmörder schätzen das Gift des Skorpions wegen seiner Wirksamkeit.'
);

-- Sea Horse, Giant (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Riesenseepferdchen',
  'Sea Horse, Giant',
  'MC2 Volume II',
  FALSE,
  'All except arctic/Ocean',
  'Common',
  'Schools',
  'Any',
  'Herbivore',
  'Semi- (2-4)',
  'Nil',
  'Neutral',
  '1-20',
  7,
  'Sw 21',
  '2-4',
  2,
  2,
  '1',
  '1-4, 2-5, or 2-8',
  'Constriction',
  'Nil',
  0,
  'L',
  'Average (10)',
  10,
  2,
  'Riesenseepferdchen sind einfach eine riesige Spezies der gewöhnlicheren Seepferdchen. Sie haben die charakteristischen pferdeartigen Köpfe und sich verjüngenden Schwänze aller Seepferdchen.',
  'Ein Seepferdchen kann normalerweise nur mit einem Kopfstoß angreifen, aber ein Seepferdchen, das von Locathah oder Wasserelfen als Reittier ausgebildet wurde, kann auch seinen langen, sich windenden Schwanz einsetzen, um Feinde einzuschnüren und festzuhalten. Das Seepferdchen muss geritten werden, um den Befehl zur Einschnürung ordnungsgemäß zu befolgen und muss dann einen erfolgreichen Angriffswurf schaffen. Ein gefangener Gegner kann sich mit einem erfolgreichen Türen-öffnen-Wurf mit -1 Malus befreien. Der Schwanz eines Riesenseepferdchens ist so lang, dass er denselben Gegner angreifen kann, den der Kopf stößt, oder denjenigen, den sein Reiter angreift, ohne Malus. Die Länge des Schwanzes schnürt auch den gesamten Körper jeder menschengroßen oder kleineren Kreatur ein, wodurch Zauberwirken oder Nahkampf für eingeschnürte Kreaturen unmöglich wird. Die Einschnürung verursacht keinen Schaden, aber das Seepferdchen kann sich dennoch entscheiden, das hilflose Opfer zu stoßen, falls gewünscht.',
  'In ihrer natürlichen Umgebung versammeln sich Seepferdchen in Schwärmen und ernähren sich von kleinem Plankton und Seetang. Sie haben Schwarmführer und folgen den vorherrschenden Strömungen. Sie sind allgemein scheu und meiden Kontakt außer mit anderen Seepferdchen.',
  'Seepferdchen werden von der üblichen Auswahl ozeanischer Räuber gejagt, nämlich Haien, Riesenkalmaren und einem Kraken oder zwei. Sie haben nur einen besonderen Feind, die bösartigen Sahuagin. Unglücklicherweise für Seepferdchen fressen Sahuagin alles mindestens einmal und sie fanden heraus, dass Riesenseepferdchen tatsächlich eine große Delikatesse waren. Ein kleines und profitables Gewerbe in jeder Sahuagin-Stadt ist die Marktgilde, und die wertvollste Ware ist Seepferdchenfleisch. Viele Adelshäuser spezialisieren sich darauf, diese friedlichen Kreaturen zu jagen und zusammenzutreiben. Sahuagin entscheiden sich dagegen, Seepferdchen zu züchten, da sie glauben, dass der offene Ozean die Pferde zäher und schmackhafter macht.'
);

-- Shark (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Hai',
  'Shark',
  'MC2 Volume II',
  FALSE,
  'All oceans and seas',
  'Common',
  'School',
  'Any',
  'Carnivore',
  'Non- (0)',
  'Nil',
  'Neutral',
  '3-12',
  6,
  'Sw 24',
  '3-8',
  3,
  3,
  '1',
  '2-5, 2-8, or 3-12',
  'Nil',
  'Nil',
  0,
  'M',
  'Average (10)',
  10,
  3,
  'Haie sind große, mit Flossen ausgestattete, gefräßige Fleischfresser, die alle bekannten Ozeane und Meere bewohnen. Sie sind vielleicht die aggressivsten Fressmaschinen, die in den düsteren Tiefen zu finden sind.',
  'Haie spüren Druckveränderungen unter Wasser, die meist durch Geräusche anderer Kreaturen verursacht werden. Umherplätschern im Wasser zieht immer Haie an, da sich normalerweise nur verletzte Fische so verhalten. Haie können diese Bewegungen aus einer Entfernung von bis zu 1,6 km wahrnehmen, und sobald ein Hai Beute entdeckt, folgen bald weitere. Haie greifen auch gnadenlos beim Geruch von Blut an, den sie ebenfalls aus Entfernungen von 1,6 km oder mehr wahrnehmen können.',
  'Haie sind reine Fress- und Tötungsmaschinen, die sich ganz natürlich zu überlegenen Raubtieren entwickelt haben und dann Millionen von Jahren unverändert blieben. Sie sind hauptsächlich Aasfresser, die Kranke und Verwundete jagen, greifen aber frisches Fleisch an, wenn sie dazu verlockt werden. Sie sind sehr territorial und einzelgängerisch.',
  'Haie haben nur zwei natürliche Schwächen. Die erste ist, dass ihre inneren Organe nur schlecht durch eine dicke, flexible Knorpelschicht anstatt eines harten Skeletts geschützt sind. Einige Kreaturen, wie Delfine, nutzen dies aus, indem sie Haie von der Seite rammen. Aufgrund ihrer hochintelligenten Natur sind Delfine die einzigen wahren Feinde der Haie. Sie sind die einzige bekannte Spezies, die diese ansonsten sehr gefürchteten und respektierten Monster aktiv jagt und tötet.'
);

-- Shedu (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Shedu',
  'Shedu',
  'Monstrous Manual',
  FALSE,
  'Any (prefer hot)',
  'Rare',
  'Herd',
  'Hottest part of the day',
  'Herbivore',
  'Exceptional (15-16)',
  'G',
  'Lawful good',
  '2d4',
  4,
  '12, Fl 24 (C)',
  '9+9',
  9,
  11,
  '2',
  '1d6/1d6',
  'Psionics',
  'Psionics',
  25,
  'L',
  'Champion (15-16)',
  15,
  8,
  'Shedu sind in heißen, trockenen Klimazonen beheimatet. Sie haben kraftvolle, stämmige Pferdekörper mit kurzen, starken gefiederten Flügeln. Ihre Köpfe sind groß und menschenähnlich und wirken eher zwergenhaft. Sie haben immer Bärte und Schnurrbärte. Das Haar der Shedu ist sehr borstig und kräuselt sich zu engen Wellen oder Bändern.',
  'Alle Shedu greifen mit kraftvollen Vorderhufen an. Beide Formen der Shedu ziehen es jedoch vor, ihre psionischen Kräfte zu verwenden, wann immer möglich.',
  NULL,
  NULL
);

-- Sirine (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Sirine',
  'Sirine',
  'Monstrous Manual',
  FALSE,
  'Temperate or tropical salt or fresh water, in wilderness areas',
  'Rare (salt water) or very rare (fresh water)',
  'Solitary or family',
  'Any',
  'Omnivore',
  'High to genius (13-18)',
  'L,M,N,Q,X',
  'Any',
  '1 (2d4)',
  3,
  '12, Sw 24',
  '4-7',
  4,
  4,
  '1',
  'By weapon type',
  'Song, spell powers',
  'Spell powers, water-breathing',
  20,
  'M',
  'Steady (11-12)',
  11,
  4,
  'Sirinen sind wunderschöne, menschenähnliche Weibchen, die sich in jeder Wasserumgebung wohlfühlen. Sie haben menschliche Hauttöne, die bis zu einem hellen Gelbgrün reichen, und ihr Haar kann fast jede Farbe haben, obwohl Silber und Dunkelgrün am häufigsten sind. Sirinen haben schöne Figuren und tragen bestenfalls spärliche Kleidung.',
  'Eine einsame Sirine wird immer 6 oder 7 TW haben; jedes Mitglied einer Gruppe hat die gleiche Chance auf 4, 5 oder 6 TW. Alle Mitglieder einer Gruppe haben dieselbe Grundgesinnung (alle böse, alle gut oder alle neutral in Bezug auf gut und böse). Alle Sirinen können ihre Einsamkeit mit einigem Geschick verteidigen.',
  'Sirinen werden nur an einsamen Orten angetroffen, die ansonsten unbewohnt sind. Die meisten leben in der Nähe von felsigen Vorsprüngen oder kleinen Inseln im Meer. Einige entscheiden sich dafür, in Süßwasser zu leben, meiden diese Gebiete aber tendenziell, weil sie normalerweise bevölkert und manchmal schwer zu erreichen sind.',
  'Sirinen schaden ihrer Umgebung in keiner Weise. Sie töten nur genug, um zu essen, und nehmen niemals zu viel aus dem Meer. Sie haben wenige natürliche Feinde und sind mehr als fähig, für sich selbst zu sorgen. Obwohl sie wunderschöne Gewänder aus Muscheln, Fischhaut und Seetang herstellen, gewinnen sie andere Besitztümer und Schätze durch das Plündern von Schiffswracks.'
);

-- Skunk (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Stinktier',
  'Skunk',
  'MC1 Volume I (w/binder #1)',
  FALSE,
  'Temperate or subtropical forests',
  'Common',
  'Solitary or family',
  'Any',
  'Omnivore',
  'Animal (1)',
  'Nil',
  'Neutral',
  '1 or 1-6',
  8,
  '12',
  '1-2 hp',
  1,
  20,
  '1',
  '1',
  'Squirt musk',
  'Squirt musk',
  0,
  'T',
  'Unsteady (5)',
  5,
  35,
  'Stinktiere sind waldbewohnende Allesfresser, die in den meisten gemäßigten und subtropischen Regionen zu finden sind. Sie sind leicht an dem langen weißen Streifen zu erkennen, der von ihren Gesichtern über ihre schwarzfelligen Rücken bis zu den Spitzen ihrer Schwänze verläuft.',
  'Stinktiere reagieren auf jede ernsthafte Bedrohung, indem sie rückwärts auf den Gegner zugehen. Wenn sich die andere Kreatur nicht schnell außer Reichweite begibt, stößt das Stinktier eine übelriechende Wolke aus stinkendem Moschus auf sie aus.',
  'Stinktiere sind wandernde Aasfresser und haben keine Sozialstruktur. Sie bevorzugen es, die Überreste größerer Raubtiere zu fressen und leben immer tief im Wald.',
  'Wie oben erwähnt, fressen Stinktiere fast alles, normalerweise die Überreste anderer Beutetiere. Ihr Moschus wird aus einem kleinen hinteren Sack abgesondert, der stark bemuskelt ist, um das Ausstoßen der Flüssigkeit zu ermöglichen. Die Flüssigkeit bildet einen schweren Nebel, der je nach vorherrschenden Winden und gefülltem Bereich bis zu einer Woche oder länger in einem Gebiet verweilt. Wenn das Stinktier überrascht und schnell getötet wird, besteht eine 50%ige Chance, dass der Moschus geborgen werden kann. Ein auf diese Weise getötetes Riesenstinktier kann ein Preis von fast 200 GM für einen Gelehrten oder Alchemisten sein, da der Moschus ein geschätzter alchemistischer Bestandteil ist (für Stinkwolken-Spruchtinten, Rauchbomben usw.).'
);

-- Slaad (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Slaad',
  'Slaad',
  'Monstrous Manual',
  FALSE,
  'Limbo',
  'Uncommon',
  'Group',
  'Any',
  'Carnivore',
  'Low (5-7)',
  'K,Q',
  'Chaotic neutral',
  '3-18',
  4,
  '6',
  '7+3',
  7,
  13,
  '3',
  '1d4 (×2)/2d8',
  'Stun, egg-pellet',
  'See below',
  30,
  'L',
  'Average (8-10)',
  8,
  2,
  'Die Slaadi sind zweibeinige froschartige Wesen, die auf der Äußeren Ebene des Limbus leben. Sie plündern Schlachtfelder des Blutkrieges, ernähren sich von den Toten und nutzen die Verwundeten als Instrumente in ihrem Fortpflanzungszyklus. Slaadi streben danach, die bestehende Ordnung auf allen Ebenen zu ändern, um sich selbst Macht zu verschaffen, aber ihnen fehlt der Wille, Armeen zu mobilisieren oder sich in die Intrigen anderer Teufel zu verwickeln. Daher verfolgen die mächtigen Arten von Slaad ihre eigenen Ziele und nutzen weniger mächtige Arten als ihre Schläger und Agenten.',
  'Rote Slaadi greifen mit zwei Klauen an (je 1W4 Schaden) und beißen (2W8 Schaden). Sie wählen vorhersehbare, einfallslose Taktiken und sind nicht besonders intelligent.',
  'Slaadi beachten eine informelle und pragmatische Hierarchie, nicht weil sie Regulierung respektieren, sondern weil starke Herrscher ungehorsame Untergebene vernichten.',
  'Obwohl die Slaadi die Äußeren Ebenen bewohnen und durch die Unteren Ebenen reisen, kämpfen sie normalerweise nicht im Blutkrieg zwischen Baatezu und Tanar''ri. (Einige graue Slaadi haben Informationen an beide Seiten verkauft im Austausch gegen mächtige magische Gegenstände.) Jedoch plündern Slaadi die Schlachtfelder der Gefallenen, ernähren sich von Aas und bringen verwundete Opfer in ihre alptraumhaften temporären Gefangenenlager. Nach der Nutzung der Opfer zur Ausbrütung einer neuen Generation trennen sich die Slaadi, die das Lager organisierten, und ziehen weiter, indem sie Gerüchten über neue Schlachten folgen.'
);

