-- Sprite (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Kobold',
  'Sprite',
  'Monstrous Manual',
  FALSE,
  'Meadows and woods',
  'Rare',
  'Tribe',
  'Day',
  'Omnivore',
  'Very (11-12)',
  'C',
  'Neutral (good)',
  '10-100',
  6,
  '9, Fl 18 (B)',
  '1',
  1,
  19,
  '1',
  'By weapon',
  'See below',
  'See below',
  0,
  'S',
  'Steady (11-12)',
  11,
  270,
  'Kobolde sind scheue und zurückgezogene Feenwesen, verwandt mit anderen Feenvölkern wie Brownies und Leprechauns. Es gibt mehrere Arten, einschließlich Pixies und Nixies. Die meisten haben kleine, halb durchsichtige Flügel und elfische Züge. Gewöhnliche Kobolde haben ausgeprägt elfische Züge und leben auf Wiesen und bewaldeten Lichtungen. Die flügellosen Seekobolde machen ihre Heime auf farbenprächtigen Korallenriffen, leben in Harmonie mit den Meereskreaturen, beschützen die empfindliche Umwelt der Riffe und tollen in den Wellen herum. Die natürlich unsichtbaren Pixies sind vielleicht die intelligentesten und schelmischsten der Feen; sie bewohnen idyllische Waldgebiete und erfreuen sich daran, Reisende mit ihren Streichen zu belästigen. Nixies sind Wasserkobolde, die in Süßwasserseen leben und, obwohl sie keinen Groll gegen die Menschheit hegen, sich daran erfreuen, Männer als ihre Lasttiere zu versklaven. Andere Waldkreaturen, die mit Kobolden verwandt sind, schließen die flinken Atomies und die schelmischen Grigs ein, beides Waldbewohner.',
  'Kobolde hassen das Böse und Hässlichkeit und sind zu entschlossenem Kampfgeist fähig, falls ihre abgeschiedenen Heime von Orks oder Schlimmerem heimgesucht werden. Sie kämpfen mit langen, schmalen Schwertern, die Schaden wie ein menschengroßer Dolch verursachen, oder ihren eigenen speziellen Bögen. Bögen haben eine Reichweite von der Hälfte eines menschlichen Kurzbogens und verursachen nur halb so viel Schaden (1-3 Punkte). Die Spitzen ihrer Pfeile sind mit einer speziellen Salbe bestrichen, die von den Kobolden gebraut wird. Jede Kreatur, die von den betäubten Pfeilen getroffen wird, muss unabhängig von Stufe, Rasse oder Magieresistenz einen Rettungswurf gegen Gift schaffen oder in einen tiefen Schlaf fallen, der 1W6 Stunden anhält. Normalerweise tun Kobolde nicht mehr, als ihre Opfer an einen sicheren Ort sehr weit weg zu bringen (oft beschlagnahmen sie dabei ihre Waffen), obwohl böse Kreaturen getötet werden können.',
  'Kobolde ziehen es vor, andere intelligente Wesen zu meiden und leben an Orten, wo sie viele Feiern, Feste und Zusammenkünfte haben können. Sie versammeln sich in den meisten mondhellen Nächten zum Singen und Tanzen, Landkobolde in den Lichtungen und Wasserkobolde in der Brandung. Landkobolde leben in sylvanischen Waldgebieten, sie überwachen und beschützen Wälder und abgeschiedene Lichtungen. Wasserkobolde beschützen ihre wässrigen Territorien ebenso gut.',
  NULL
);

-- Su-Monster (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Su-Monster',
  'Su-Monster',
  'Monstrous Manual',
  FALSE,
  'Dark areas/Wilderness and subterranean',
  'Uncommon',
  'Family/clan',
  'Dawn and Sunset',
  'Omnivorous',
  'Average (8-10)',
  'C,Y',
  'Chaotic (evil)',
  '1d12',
  6,
  '9',
  '5+5',
  5,
  15,
  '5',
  '1d4/1d4/1d4/1d4/2d4',
  'Psionic, ambush',
  'Psionic',
  0,
  'M',
  'Average (8-10)',
  8,
  650,
  'Wissenschaften: keine; Hingabe: Verstärkung.',
  'Su-Monster greifen wenn möglich mit allen vier Gliedmaßen an und reißen mit ihren extrem scharfen Nägeln über ihr Opfer. Sie können auch einen kräftigen Biss mit ihrem hundeähnlichen Maul ausführen. Diese Kreaturen jagen gerne in kleinen Rudeln (1W12 Mitglieder). Ihre bevorzugten Jagdgründe sind vielbenutzte Pfade durch den Dschungel oder Wald. Sie suchen einen stabilen Ast, der über einen Pfad hängt, und hocken in den Bäumen und warten geduldig. Wenn ein Opfer unter ihnen vorbeigeht, können sie sich herabschwingen und dabei ihre Schwänze als Anker benutzen. Auf diese Weise können sie mit allen vier Klauen plus dem Biss angreifen. Opfer dieser Art von Hinterhalt erleiden eine -4 Strafe auf ihre Überraschungswürfe.',
  'Eine Su-Monster-Familie besteht aus zwei Eltern (erwachsenes Männchen und Weibchen) und zwei Jungen. Wenn zwei oder mehr Familien zusammenleben, bilden sie einen Clan. Su-Monster sind sehr territorial und hegen einen besonderen Hass gegen psionisch Begabte.',
  'Su-Monster verstecken ihre Wertsachen gut verborgen in den hohen Stämmen der Bäume in ihrem Territorium. Sie haben keinen Nährwert, da ihr Fleisch schwach giftig ist. Charaktere, die Su-Monster-Fleisch essen, müssen einen Rettungswurf gegen Gift bestehen oder werden krank, und natürliche Heilung ist 1 Woche lang nicht möglich.'
);

-- Tako (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Tako',
  'Tako',
  'Monstrous Manual',
  FALSE,
  'Tropical, subtropical, and temperate ocean',
  'Rare',
  'Tribe',
  'Any',
  'Carnivore',
  'Average (8-10)',
  'J,Q',
  'Lawful neutral',
  '3-12',
  3,
  '3, Sw 9',
  '4',
  4,
  17,
  '7',
  '1-2 (×7)/3-6 or by weapon',
  'Constriction',
  'Camouflage',
  0,
  'M',
  'Steady (12)',
  12,
  270,
  'Die Tako sind eine Rasse intelligenter Oktopusse, die sich an Land bewegen und Waffen sowie andere Werkzeuge verwenden können.',
  'Obwohl normalerweise friedlich, greifen Tako jede Kreatur an, die in ihr Territorium eindringt. Außerdem haben sie einen starken Ehrsinn und werden Angriffe rächen und sich mit Mitgliedern anderer Rassen verbünden, die ihnen helfen. Sie sind listige Gegner. Tako können ihre Farbe und ihr Muster in einer einzigen Runde an jedes natürliche Gelände anpassen. Diese Tarnung macht sie zu 90% unentdeckbar und verändert die Überraschungswürfe der Gegner um -3.',
  'Ein Tako-Stamm besteht aus 3-12 (3W4) Männchen, halb so vielen Jungen und 1-2 Weibchen. Die Weibchen treffen alle Entscheidungen für den Stamm, während die Männchen als Verteidiger und Jäger fungieren. Die Kreaturen errichten ihre Baue in küstennahen Unterwasserhöhlen und unternehmen gelegentliche Raubzüge an Land nach Nahrung, Waffen und Schatzgegenständen. In einigen Gebieten koexistieren Tako mit Menschen und arbeiten zusammen, um Seeungeheuer anzugreifen und Fischern zu helfen, aber solche Fälle sind extrem selten.',
  'Tako fressen Austern, Krebse, Hummer und andere Schalentiere, die sie mit ihren kräftigen Kiefern aufknacken. Sie können kleine Wolken reichhaltiger blauer Tinte ausstoßen, aber die Wolken sind zu begrenzt, um als Verteidigung zu dienen. Menschen schätzen die Tinte jedoch sehr und verwenden sie für Kalligraphie.'
);

-- Thought Eater (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Gedankenfresser',
  'Thought Eater',
  'Monstrous Manual',
  FALSE,
  'Ethereal Plane',
  'Rare',
  'Solitary',
  'Any',
  'Mental energy',
  'Not ratable',
  'Nil',
  'Neutral',
  '1-3',
  9,
  '6 (ethereal plane only)',
  '3',
  3,
  20,
  '0',
  'Nil',
  'Psionics, absorb: psionics, spells, and intelligence',
  'Ethereal existence',
  0,
  'S',
  'Unsteady (5-7)',
  5,
  1,
  'Gedankenfresser sind Bewohner des Grenzätherischen, und sie können nur in ätherischer Form überleben. Sie erscheinen als kränklich graue Skelettleiber mit übergroßen Schnabeltierköpfen. Sie haben schwimmhäutige Skeletttatzen, die zum Schwimmen durch den Äther geeignet sind.',
  'Gedankenfresser sind einzigartig. Sie haben keine Kampffähigkeiten außer ihren angeborenen psionischen Talenten, selbst im Grenzätherischen, daher können sie leicht getötet werden, wenn man ihnen dort begegnet.',
  'Wenig ist über Gedankenfresser bekannt, außer dass sie ausschließlich in der Ätherischen Ebene existieren und sehr einzelgängerische Wesen sind. Magische Forschung hat gezeigt, dass sie nicht bösartig sind; ihre Angriffe dienen allein dem Zweck am Leben zu bleiben, genau wie bei jedem humanoiden Jäger. Einige Gelehrte glauben, dass Gedankenfresser das endgültige Schicksal von Psionikern sind, nachdem sie gestorben sind.',
  'Gedankenfresser tragen keine Schätze. Wenn einer stirbt, fällt er automatisch aus dem Äther heraus und materialisiert sich auf der Materiellen Hauptebene. Natürlich werden sie gewöhnlich als Schnabeltiere abgetan, die an Verhungerung gestorben sind.'
);

-- Thri-kreen (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Thri-kreen',
  'Thri-kreen',
  'Monstrous Manual',
  FALSE,
  'Any land (Temperate or tropical arid land)',
  'Uncommon',
  'Clutch and pack',
  'Constant',
  'Carnivore',
  'Average to high (8-14)',
  'Varies',
  'Chaotic neutral',
  '2d12',
  5,
  '18',
  '6+3',
  6,
  13,
  '5 or 2',
  '1d4 (×4)/1d4+1, or 1d4+1 and by weapon',
  'Paralyzation',
  'Missile dodge',
  0,
  'L',
  'Fanatic (17-18)',
  17,
  1,
  'Die oben angegebenen Werte gelten für geschlechtsreife erwachsene Thri-kreen. Andere haben die folgenden Fähigkeiten, basierend auf ihrem Alter (sie altern eine Alterskategorie pro Jahr, bis sie geschlechtsreife Erwachsene erreichen):',
  'Die Mehrzahl der Thri-kreen sind Jäger, die sich hauptsächlich darum sorgen, genügend Beute zu finden, um das Rudel zu versorgen. Thri-kreen-Jäger greifen selten andere empfindungsfähige Wesen als Nahrung an, aber sie werden sich verteidigen, wenn sie angegriffen werden. Einige Thri-kreen sind vom Jagen abgewichen und haben mit dem Plündern begonnen, diese Thri-kreen sind die Geißel aller anderen Kreaturen. Thri-kreen greifen in einer gut koordinierten Gruppe an, schwächen ihre Feinde generell mit Psionik und Fernkampfwaffen, bevor sie sich im Nahkampf engagieren. Sie pirschen auch Beute an und sind unerbittlich in ihrer Verfolgung. Da Thri-kreen nicht schlafen, ist ihre Fähigkeit im Belagerungskampf überlegen. Eine Plündertruppe kann einen Angriff lange fortsetzen, nachdem ihre Gegner ermüdet sind. Obwohl Thri-kreen die meisten Schlachten durch Gewalt gewinnen können, gewinnen sie manche durch Zermürbung und Ausdauer.',
  'Thri-kreen schlüpfen aus Eiern. Die, die aus derselben Gruppe von Eiern schlüpfen, werden als ein Gelege betrachtet. Die Bindung eines Gelegegenossen geht über Familie oder Freundschaft hinaus. Wenn Thri-kreen in die humanoide Gesellschaft eintreten, fühlen sie sich immer noch verpflichtet, zu einem Gelege zu gehören und akzeptieren oft Humanoide als Gelegegenossen.',
  'Thri-kreen sind Fleischfresser. Sie jagen selten andere intelligente Kreaturen als Nahrung, aber werden dies in Zeiten der Not tun. Mantis-Krieger haben einen bekannten Geschmack für Elfen, was beide Rassen bestenfalls in einem unruhigen Frieden hält. Wenn sie plündern statt einfach zu jagen, sind Thri-kreen selten an Gegenständen mit monetärem Wert interessiert, konzentrieren sich gewöhnlich auf die Dinge, die sie essen können. Thri-kreen-Rudel tragen wenig bei sich, was als Schatz betrachtet werden könnte, obwohl ihre Waffen und Werkzeuge von einigen als wertvoll betrachtet werden. Thri-kreen-Chitin kann auch für Rüstung von Humanoiden verwendet werden, wenn Sorgfalt angewendet wird.'
);

-- Urd (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Urd',
  'Urd',
  'MC2 Volume II',
  FALSE,
  'Temperate to tropical/Hills and mountains',
  'Rare',
  'Gens',
  'Night',
  'Omnivore',
  'Low (5-7)',
  'J (Q×5)',
  'Neutral evil',
  '3-300',
  8,
  '6, Fl 15 (C)',
  '1-5',
  1,
  2,
  '1',
  '1-3 or 1-4 (weapon)',
  'Rock Bomb',
  'Nil',
  0,
  'S',
  'Unsteady (7)',
  7,
  2,
  'Diese aggressiven, fliegenden Humanoiden sind entfernt mit Kobolden verwandt.',
  'Urds jagen nachts in großen Schwärmen und nutzen ihre Infrasicht (18,3 m Reichweite), um Beute am Boden zu erspähen. Urds greifen an, indem sie Steine auf ihre Opfer fallen lassen. Diese "Steinbomben" wiegen 0,9 bis 1,4 kg pro Stück und sind mit gezackten Kanten und Vorsprüngen bedeckt. Urds lassen diese Steine mit großer Genauigkeit fallen. Nichtsahnende Opfer werden für den Angriffswurf als RK 10 behandelt. Aktiv ausweichende Gegner gelten als RK 2 vor Modifikationen durch Geschicklichkeit. Jeder Stein, der trifft, verursacht 2W4 Schadenspunkte. Etwa 75% der angetroffenen Urds tragen je eine Steinbombe. Die restlichen 25% tragen leichte Speere, die entweder als Speere oder als Wurfspieße verwendet werden können. Diese leichten Speere verursachen 1W4 Schadenspunkte pro Treffer.',
  'Urds leben in erweiterten Familien, die Gens genannt werden. Eine einzelne Gens kann 300 oder mehr erwachsene Männchen und Weibchen enthalten, plus eine Anzahl von Jungen und Eiern, die 50 Prozent der gesamten erwachsenen Population entspricht. Jede Gens wird von einem erblichen Häuptling kontrolliert, der beiden Geschlechts sein kann.',
  'Urds legen wenig Wert auf Gold und andere schwere Metalle, da diese für Urds schwierig mitzufliegen sind. Sie schätzen fein gefertigte Lederrüstungen und handeln gerne für solche Gegenstände.'
);

-- Weasel (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Wiesel',
  'Weasel',
  'MC2 Volume II',
  FALSE,
  'Subterranean or forest',
  'Uncommon',
  'Solitary',
  'Night',
  'Carnivore',
  'Animal (1)',
  'Nil',
  'Neutral',
  '1-2',
  6,
  '15',
  '¼',
  1,
  20,
  '1',
  '1',
  'Nil',
  'Nil',
  0,
  'T',
  'Unsteady (7)',
  7,
  7,
  'Wiesel sind in den gemäßigten Wäldern der Welt weit verbreitet und in vielen unterirdischen Umgebungen anzutreffen. Es gibt zahlreiche Arten, aber sie ähneln sich alle in Aussehen und Gewohnheiten.',
  'In der Regel greifen gewöhnliche Wiesel nicht an, es sei denn, sie werden in die Enge getrieben oder überrascht. Wenn sie jedoch zuschlagen, können ihre große Geschwindigkeit und ihre zuckenden Bewegungen sie etwas gefährlich machen. In den meisten Fällen beißen sie jedoch einmal zu und fliehen dann, bevor sich ihr Gegner erholt.',
  'Wiesel sind Einzelgänger, die Nagetiere und ähnliche kleine Tiere als Nahrung jagen. Wenn zwei Tiere angetroffen werden, handelt es sich oft um ein Pärchen.',
  'Bei der Jagd greift das Wiesel gewöhnlich Tiere an, die größer sind als es selbst. Ein häufiges Ziel in besiedelten Gebieten sind domestiziertes Geflügel und ähnliche Vögel. Trotzdem leistet das gewöhnliche Wiesel den Bauern einen großen Dienst, indem es sich von kleinen Tieren ernährt, die andernfalls ihre Ernte schädigen oder zerstören könnten.'
);

-- Wemic (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Wemic',
  'Wemic',
  'Monstrous Manual',
  FALSE,
  'Temperate plains',
  'Very rare',
  'Prides',
  'Day',
  'Carnivore',
  'Average (8-10)',
  'B',
  'Neutral',
  '2-16',
  6,
  '12',
  '5+8',
  5,
  15,
  '2 or 3',
  '1-4/1-4 and weapon',
  'Nil',
  '-2 initiative modifier',
  0,
  'L',
  'Steady (11-12)',
  11,
  270,
  'Wemics sind die löwenartigen Gegenstücke zu Zentauren. Der Körper eines Wemic besteht aus einem Löwenkörper mit einem humanoiden Oberkörper, der dort entspringt, wo bei einem Löwen der Hals wäre. Ein typischer Wemic misst 3 m von Kopf bis Hinterteil. Wenn er sich in zentaurenartiger Haltung aufrichtet, ist der Wemic 1,8 bis 2,1 m groß. Der größte Teil des Körpers ist von dunklem, goldenem Fell bedeckt. Der Schwanz endet in einem Büschel aus langem, schwarzem Haar. Ausgewachsene Männchen haben außerdem eine Mähne aus langem schwarzem Haar; die Mähne bedeckt die Ober- und Rückseite des Kopfes und erstreckt sich bis zu Hals und Schultern. Männliche Jungtiere entwickeln diese Mähne in ihrem dritten Lebensjahr. Der Bauch ist mit kurzem, weißem Fell bedeckt. Die Nase kann schwarz oder rotbraun sein. Die Augen sind golden mit vertikal geschlitzten Pupillen. Die Zehen aller Gliedmaßen enden in Krallen. Die Krallen der Vorderbeine sind einziehbar.',
  'Wemics verwenden Vorderpfoten und Waffen zum Angriff. Eine Kralle führt einen bösartigen Schlag aus, der 1W4 Schadenspunkte verursacht. Normalerweise benutzt der Wemic seine Vorderbeine zum Kratzen und verwendet seine Hände, um eine Waffe zu führen.',
  'Die Gesellschaft der Wemics ist eine Mischung aus löwenartiger und ursprünglich menschlicher Kultur. Sie leben in Gruppen, die Rudel genannt werden. Ein typisches Rudel besteht aus 4W4 ausgewachsenen Männchen, 2W12 ausgewachsenen Weibchen und 1W12 Jungtieren. Bis zu 3W10 Rudel schließen sich oft zu einem Stamm zusammen, der von einem Häuptling angeführt wird. Der Häuptling hat eine Rüstungsklasse von 5, 6+4 Trefferwürfel, und seine Krallen verursachen 1W6 Schadenspunkte. Er erhält einen +1 Bonus auf seine Angriffswürfe mit jeder Waffe.',
  NULL
);

-- Whale (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Wal',
  'Whale',
  'Monstrous Manual',
  FALSE,
  'Oceans',
  'Common',
  'Pod',
  'Any',
  'Plankton',
  'Low (5-7)',
  'Nil',
  'Neutral',
  '1-8',
  4,
  'Sw 18',
  '12 to 36',
  12,
  12,
  '1',
  'See below',
  'Tail',
  'Nil',
  0,
  'G',
  'Champion (15)',
  15,
  2,
  'Wale sind die größten Meeressäugetiere. Sie sind hochintelligente Kreaturen, die eine Reihe ökologischer Nischen besetzen. Zu den gewöhnlichen Walen gehören Plankton-Fresser wie Blau- oder Buckelwale und Fleischfresser wie Pottwale.',
  'Alle gewöhnlichen Wale können mit ihren Schwänzen angreifen. Diese können einen zerschmetternden Schlag versetzen, der Schaden in Höhe der Hälfte der Trefferwürfel des Wals verursacht.',
  'Wale leben in stammesähnlichen Versammlungen, die Schulen genannt werden. Sie pflegen starke persönliche und familiäre Bindungen. Ihre Kultur basiert auf komplexen Gesängen, die unter Wasser meilenweit zu hören sind. Wale sind neugierig auf Humanoide, aber wenn sie angegriffen werden, können sie zu tödlichen Feinden werden. Wale beginnen selten einen Kampf. Wale sind neugierig auf andere intelligente Wesen. Sie begrüßen die Kommunikation mit anderen Lebewesen. Sie lügen nicht, aber sie offenbaren möglicherweise nicht alles, was sie wissen.',
  'Obwohl sie in ihrer Gesinnung gegenüber Humanoiden neutral sind, ist ihre Gesinnung gegenüber dem Meeresleben im Allgemeinen rechtschaffen gut. Mit ihrer gewaltigen Größe, Kraft und Vielfalt sind sie die Herrscher des Meeres. Sie bewahren die Ordnung durch ihre Konflikte mit böse gesinnten Seeungeheuern.'
);

-- Wolverine (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
