-- Yellow Musk Creeper (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Gelbe Moschusschlingpflanze',
  'Yellow Musk Creeper',
  'MC2 Volume II',
  FALSE,
  'Temperate/Forest and subterranean',
  'Rare',
  'Solitary',
  'Any',
  'Carnivore',
  'Non- (0)',
  'B',
  'Neutral',
  '1',
  7,
  '0',
  '3',
  3,
  17,
  '2-12',
  'Special',
  'Gas',
  'See below',
  0,
  'L',
  'Fearless (20)',
  20,
  650,
  'Die Gelbe Moschusschlingpflanze ist eine Pflanze, die Humanoide angreift, ihre Intelligenz entzieht und sie in Gelbe Moschuszombies verwandelt. Der Zombie dient der Pflanze für etwa zwei Monate und stirbt dann, wodurch die neue Pflanze, die in seinem Kopf eingebettet ist, sich von dem Körper ernähren kann.',
  'Die Schlingpflanze ruht, es sei denn, eine Kreatur bewegt sich in 3 m Entfernung zu ihr. Wenn das geschieht, wenden sich die nächsten Blüten der Beute zu und greifen an. Dieser Angriff ist ein Pollenstoß, der nach Moschus riecht und das Gesicht des Opfers trifft, wenn der Angriffswurf erfolgreich ist. Das Opfer muss einen erfolgreichen Rettungswurf gegen Zauber ablegen oder wird verzaubert und läuft in die Pflanze hinein. Es wird jedem Versuch widerstehen, zurückgehalten zu werden. In der Runde, nachdem es in die Schlingpflanze hineingelaufen ist, heften sich Dutzende von Wurzeln an seinen Kopf und bohren sich in zwei Runden in sein Gehirn. Jede Runde danach verliert es 1-4 Punkte Intelligenz, während sein Gehirn verschlungen wird.',
  'Die Schlingpflanze findet sich hauptsächlich in Erdgebieten im Untergrund oder in den Tiefen von Wäldern und Dschungeln, wo wenig Licht auf sie fällt. Sie kann Bäume oder Felsen erklimmen, wie gewöhnlicher Efeu. Sie wird gelegentlich absichtlich gepflanzt, um ein bestimmtes Gebiet zu bewachen. Der Zombie kann sich bis zu 30,5 m von der Schlingpflanze entfernen.',
  'Die Schlingpflanze greift jede Kreatur an, die größer als eine Hauskatze ist und sich nähert, aber sie kann nur Zombies aus menschengroßen Humanoiden erschaffen. Sie ernährt sich von den Körpern und von der Erde, in die sie gepflanzt ist. Die Knochen oder persönlichen Gegenstände derer, die sie tötet, werden von den Zombies nahe der Wurzel begraben. Der Zombie isst nicht, da er teilweise unterstützt und am Leben gehalten wird durch den Sämling in seinem Kopf. Die einzigen natürlichen Feinde der Schlingpflanze sind Krankheiten, Insekten und Nahrungsmangel.'
);

-- Yuan-ti, Histachii (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Yuan-ti, Histachii',
  'Yuan-ti, Histachii',
  'Monstrous Manual',
  FALSE,
  'Tropical jungles',
  'Very rare',
  'Tribe',
  'Any',
  'Carnivore',
  'Low (5-7)',
  'Nil',
  'Chaotic evil',
  '2-20',
  8,
  '12',
  '2+2',
  2,
  19,
  '3',
  '1-2/1-2/1-3',
  'See below',
  'See below',
  0,
  'M',
  'Average (10)',
  10,
  120,
  'Einst Menschen, sind Yuan-ti-Histachii geistlose Abscheulichkeiten, die in reptilienhafte Humanoide verwandelt wurden, um ihren Yuan-ti-Meistern zu dienen. Am häufigsten findet man sie als Wächter der Yuan-ti-Brutkammern.',
  'Histachii greifen jede nichtreptilienhafte Kreatur oder jeden Humanoiden bei Sicht an, es sei denn, ihre Yuan-ti-Meister geben ihnen gegenteilige Befehle. Als primitive Kämpfer stürmen die meisten Histachii direkt auf ihre Gegner zu und greifen mit ihren Klauen und Zähnen an. Um ihre Yuan-ti-Meister zu beschützen, kämpfen Histachii bis zum Tod.',
  'Yuan-ti erschaffen die meisten Histachii-Diener aus menschlichen Gefangenen. Sie können auch menschliche Anbeter verwandeln, die sich freiwillig bereit erklären, Histachii zu werden. Menschen werden zu Histachii, indem sie eine Destillation aus Yuan-ti-Gift gemischt mit bestimmten Kräutern und Wurzeln trinken. (Die Yuan-ti bereiten diese spezielle Mischung zu.) Wenn ein Mensch nicht bereit ist zu trinken, drücken die Yuan-ti ihren Gefangenen zu Boden und schütten ihm die Mischung in den Rachen.',
  'Wie Yuan-ti sind Histachii strikt fleischfressend und fressen Ratten, Würmer und anderes Ungeziefer. Sie essen auch die Reste der Yuan-ti.'
);

-- Yugoloth, Guardian (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Yugoloth, Wächter',
  'Yugoloth, Guardian',
  'Monstrous Manual',
  FALSE,
  'Any',
  'Rare',
  'Solitary',
  'Any',
  'None',
  'Average (8-10)',
  'See below',
  'Neutral',
  '1',
  3,
  '9',
  '6',
  6,
  15,
  '3',
  '1-4/1-10/1-10',
  'See below',
  'See below',
  0,
  'M',
  'Elite (14)',
  14,
  2,
  'Diese Yugoloths werden von bösen Magiern oder Priestern beschworen, um etwas Wichtiges zu bewachen. Yugoloth-Wächter verteidigen ihren Auftrag stets mit großer Wildheit.',
  'Yugoloth-Wächter können dreimal täglich Feuer in einem Kegel von 9,1 m Länge mit 3 m Basisdurchmesser speien. Der Schaden hängt von der Art des atmenden Dämons ab. Niedere und geringere Yugoloths verursachen 3W6 bzw. 5W6 Schadenspunkte, während größere Yugoloths 7W6 Punkte pro Atemangriff zufügen. Ein erfolgreicher Rettungswurf gegen Atemangriff halbiert den Schaden. Yugoloth-Wächter setzen ihren Feueratem niemals ein, wenn das Feuer dem schaden könnte, was sie zu beschützen beauftragt wurden.',
  'Yugoloth-Wächter müssen jederzeit innerhalb von 82,3 m des Objekts bleiben, das sie zu beschützen beschworen wurden. Innerhalb dieses 82,3-Meter-Radius ziehen es Yugoloth-Wächter vor, im Kampf auf Distanz zu bleiben und ihren Atemangriff optimal einzusetzen.',
  'Die Beschwörung eines Wächter-Dämons ist eine gefährliche Angelegenheit. Es besteht eine 10%ige Chance für jede Stufe, die der Beschwörer über der 7. Stufe liegt, dass sein Ersuchen um einen Wächter-Dämon gewährt wird (maximale Chance von 90%). Umgekehrt, falls die Beschwörung fehlschlägt, besteht eine 30%ige Chance (-2% pro Stufe des Beschwörers über der 10.), dass der Dämon Anstoß nimmt und sich hereinportet, um den Zauberkundigen zu erschlagen.'
);

COMMIT;
